public static void main(String[] args) {
    InputReader sc = new InputReader(System.in);
    int n = sc.ni();
    int r = sc.ni();
    int[] arr = sc.nia(n);

    int ans = countInitialOnes(arr);
    int[] h = buildCoverageArray(arr, n, r);

    if (hasUncoveredPosition(h)) {
        w.println(-1);
    } else {
        ans = removeRedundantStations(arr, h, n, r, ans);
        w.println(ans);
    }

    w.close();
}

/** Counts how many elements in the input array are equal to 1. */
private static int countInitialOnes(int[] arr) {
    int cnt = 0;
    for (int v : arr) {
        if (v == 1) cnt++;
    }
    return cnt;
}

/** For every station (value 1) adds its coverage to the helper array h. */
private static int[] buildCoverageArray(int[] arr, int n, int r) {
    int[] h = new int[n];
    for (int i = 0; i < n; i++) {
        if (arr[i] == 1) {
            int left = Math.max(0, i - r + 1);
            int right = Math.min(n - 1, i + r - 1);
            for (int j = left; j <= right; j++) {
                h[j]++;
            }
        }
    }
    return h;
}

/** Returns true if any position is not covered by any station. */
private static boolean hasUncoveredPosition(int[] h) {
    for (int v : h) {
        if (v == 0) return true;
    }
    return false;
}

/**
 * Tries to discard stations that are not essential.
 * If a station’s entire interval has coverage equal to 1, it is essential;
 * otherwise its contribution is removed and the answer is decreased.
 */
private static int removeRedundantStations(int[] arr, int[] h, int n, int r, int ans) {
    for (int i = 0; i < n; i++) {
        if (arr[i] != 1) continue;

        int left = Math.max(0, i - r + 1);
        int right = Math.min(n - 1, i + r - 1);

        boolean essential = false;
        for (int j = left; j <= right; j++) {
            if (h[j] == 1) {
                essential = true;
                break;
            }
        }

        if (!essential) {
            // Station can be removed
            for (int j = left; j <= right; j++) {
                h[j]--;
            }
            ans--;
        } else {
            // Keep the station, boost its interval for later checks
            for (int j = left; j <= right; j++) {
                h[j] += 4;
            }
        }
    }
    return ans;
}

