/* Count how many elements equal 1 */
private static int countOnes(int[] arr) {
    int cnt = 0;
    for (int v : arr) {
        if (v == 1) cnt++;
    }
    return cnt;
}

/* For every position that contains a 1, increase the coverage of its radius */
private static int[] buildCoverage(int[] arr, int r) {
    int n = arr.length;
    int[] h = new int[n];
    for (int i = 0; i < n; i++) {
        if (arr[i] == 1) {
            int left = Math.max(0, i - r + 1);
            int right = Math.min(n - 1, i + r - 1);
            for (int j = left; j <= right; j++) {
                h[j]++;                 // each 1 covers this position
            }
        }
    }
    return h;
}

/* Return true if at least one position is not covered at all */
private static boolean hasUncovered(int[] coverage) {
    for (int v : coverage) {
        if (v == 0) return true;
    }
    return false;
}

/* Adjust the answer by removing redundant 1's or boosting coverage as in the original logic */
private static int refineAnswer(int[] arr, int r, int[] h, int ans) {
    int n = arr.length;
    for (int i = 0; i < n; i++) {
        if (arr[i] == 1) {
            int left = Math.max(0, i - r + 1);
            int right = Math.min(n - 1, i + r - 1);

            boolean hasUnique = false;
            for (int j = left; j <= right; j++) {
                if (h[j] == 1) {        // uniquely covered by this 1
                    hasUnique = true;
                    break;
                }
            }

            if (!hasUnique) {
                // this 1 is not needed; remove its contribution
                for (int j = left; j <= right; j++) {
                    h[j]--;
                }
                ans--;
            } else {
                // keep it and artificially increase coverage (preserves original behaviour)
                for (int j = left; j <= right; j++) {
                    h[j] += 4;
                }
            }
        }
    }
    return ans;
}

