/** Returns a mask encoding: bit 1 → starts with 'B', bit 0 → ends with 'A'. */
private static int boundaryMask(char[] s) {
    int b = 0;
    if (s[0] == 'B') {
        b |= 2;
    }
    if (s[s.length - 1] == 'A') {
        b |= 1;
    }
    return b;
}

/** Counts how many times the substring "AB" appears consecutively in the array. */
private static int countABInString(char[] s) {
    int count = 0;
    for (int j = 0; j < s.length - 1; j++) {
        if (s[j] == 'A' && s[j + 1] == 'B') {
            count++;
        }
    }
    return count;
}

/** Applies the post‑processing logic that uses the accumulated masks. */
private static long finalizeResult(long[] cnt, long ret) {
    ret += Math.max(0, cnt[3] - 1);
    if (cnt[3] > 0 && cnt[1] > 0) {
        ret++;
        cnt[1]--;
    }
    if (cnt[3] > 0 && cnt[2] > 0) {
        ret++;
        cnt[2]--;
    }
    ret += Math.min(cnt[1], cnt[2]);
    return ret;
}

