/**
 * Reads exactly 12 lines from the scanner and fills the provided grid.
 */
private static void fillArea(Scanner sc, int[][] area) {
    for (int i = 0; i < area.length; i++) {
        String line = sc.nextLine();
        char[] nums = line.toCharArray();
        for (int j = 0; j < area.length; j++) {
            area[i][j] = Character.getNumericValue(nums[j]);
        }
    }
}

/**
 * Traverses the grid, counts distinct islands and marks visited cells
 * using the existing {@code checkIsland} routine.
 */
private static int countIslands(int[][] area) {
    int count = 0;
    for (int i = 0; i < area.length; i++) {
        for (int j = 0; j < area.length; j++) {
            if (area[i][j] == 1) {
                count++;
                area = checkIsland(area, i, j);
            }
        }
    }
    return count;
}

