public static void main(String[] args) {
    FastScanner scanner = new FastScanner();
    PrintWriter out = new PrintWriter(System.out);
    int T = scanner.nextInt();
    while (T-- > 0) {
        int N = scanner.nextInt();

        PriorityQueue<Point> queue = buildQueue(scanner, N);
        Result result = processQueue(queue, N);
        printResult(out, result);
    }
    out.flush();
}

/** builds the priority queue that stores the interval endpoints */
private static PriorityQueue<Point> buildQueue(FastScanner scanner, int n) {
    PriorityQueue<Point> queue = new PriorityQueue<>();
    for (int i = 0; i < n; i++) {
        queue.offer(new Point(scanner.nextInt(), true, i));   // start point
        queue.offer(new Point(scanner.nextInt(), false, i));  // end point
    }
    return queue;
}

/** core algorithm – assigns each interval to a group (1 or 2) */
private static Result processQueue(PriorityQueue<Point> queue, int n) {
    int cur = 0;
    int assign = 1;               // 1 = still possible to use a single group
    int[] assignments = new int[n];

    while (!queue.isEmpty()) {
        Point p = queue.poll();
        if (p.start) {
            cur++;
            assignments[p.num] = assign;
        } else {
            cur--;
        }
        if (cur == 0 && !queue.isEmpty()) {
            assign = 2;            // a second group is required
        }
    }
    return new Result(assignments, assign);
}

/** prints the result according to the problem statement */
private static void printResult(PrintWriter out, Result result) {
    if (result.assign == 1) {
        out.println(-1);
    } else {
        for (int i = 0; i < result.assignments.length; i++) {
            if (i > 0) out.print(' ');
            out.print(result.assignments[i]);
        }
        out.println();
    }
}

/** simple holder for algorithm output */
private static class Result {
    final int[] assignments;
    final int assign;   // 1 = only one group used, 2 = two groups used

    Result(int[] assignments, int assign) {
        this.assignments = assignments;
        this.assign = assign;
    }
}

public static void main(String[] args) {
    FastScanner scanner = new FastScanner();
    PrintWriter out = new PrintWriter(System.out);
    int T = scanner.nextInt();

    while (T-- > 0) {
        int N = scanner.nextInt();
        PriorityQueue<Point> queue = buildQueue(N, scanner);
        AssignmentResult result = assignSegments(queue, N);
        printResult(result, out);
    }

    out.flush();
}

/* ------------ Chunk 1 : input → priority queue ------------ */
private static PriorityQueue<Point> buildQueue(int n, FastScanner scanner) {
    PriorityQueue<Point> q = new PriorityQueue<>();
    for (int i = 0; i < n; i++) {
        q.offer(new Point(scanner.nextInt(), true, i));
        q.offer(new Point(scanner.nextInt(), false, i));
    }
    return q;
}

/* ------------ Chunk 2 : core algorithm ------------ */
private static AssignmentResult assignSegments(PriorityQueue<Point> queue, int n) {
    int cur = 0;
    int assign = 1;
    int[] outArr = new int[n];

    while (!queue.isEmpty()) {
        Point next = queue.poll();
        if (next.start) {
            cur++;
            outArr[next.num] = assign;
        } else {
            cur--;
        }
        if (cur == 0 && !queue.isEmpty()) {
            assign = 2;               // we have crossed the first component boundary
        }
    }
    boolean feasible = assign != 1;   // true → a valid assignment exists
    return new AssignmentResult(outArr, feasible);
}

/* Helper holder for the algorithm result */
private static class AssignmentResult {
    final int[] assignments;
    final boolean feasible;

    AssignmentResult(int[] assignments, boolean feasible) {
        this.assignments = assignments;
        this.feasible = feasible;
    }
}

/* ------------ Chunk 3 : output ------------ */
private static void printResult(AssignmentResult res, PrintWriter out) {
    if (!res.feasible) {
        out.println(-1);
        return;
    }
    int[] arr = res.assignments;
    for (int i = 0; i < arr.length; i++) {
        if (i > 0) out.print(' ');
        out.print(arr[i]);
    }
    out.println();
}

