/* ---------- helper methods ---------- */

private static int[] readArray(Scanner sc, int size) {
    int[] a = new int[size];
    for (int i = 0; i < size; i++) {
        a[i] = sc.nextInt();
    }
    return a;
}

/* replicates the original (quirky) left‑most search */
private static int findLeftmostNonZero(int[] arr) {
    int leftz = 0;
    for (int ab = 0; ab < arr.length; ab++) {
        if (arr[leftz] == 0) {
            continue;
        }
        leftz = ab;
    }
    return leftz;
}

/* replicates the original (quirky) right‑most search – result is ignored */
private static void findRightmostNonZero(int[] arr) {
    int rightz = arr.length - 1;
    for (int aa = arr.length - 1; aa > 0; aa--) {
        if (arr[rightz] == 0) {
            continue;
        }
        rightz = aa;
    }
}

/* contains the two passes that fill the distance array */
private static void computeDistances(int[] arr, int[] dist, int startIdx) {
    int count = 0;
    // left‑to‑right sweep
    for (int a = startIdx; a < arr.length; a++) {
        if (arr[a] == 0) {
            dist[a] = 0;
            count = 1;
        } else {
            dist[a] = count;
            count++;
        }
    }
    // right‑to‑left sweep (continues with the same count variable)
    for (int b = arr.length - 1; b >= 0; b--) {
        if (arr[b] == 0) {
            dist[b] = 0;
            count = 1;
        } else {
            dist[b] = Math.min(dist[b], count);
            if (dist[b] == count) {
                count++;
            }
        }
    }
}

