 */
private static void computeBackwardDistances(int[] arr, int[] dist) {
    int count = 0;
    for (int i = arr.length - 1; i >= 0; i--) {
        if (arr[i] == 0) {
            dist[i] = 0;
            count = 1;
        } else {
            dist[i] = Math.min(dist[i], count);
            if (dist[i] == count) {
