private static long computeAnswer(long n, long m) {
    if (n % 2 == 0) {
        return computeEven(n, m);
    } else {
        return computeOdd(n, m);
    }
}

private static long computeEven(long n, long m) {
    long half = n / 2;
    return (m <= half) ? m + 1 : m - 1;
}

private static long computeOdd(long n, long m) {
    long half = (n + 1) / 2;
    return (m < half) ? m + 1 : m - 1;
}

