/**
 * Reads the input pairs, stores them in {@code sugrobs} and builds the
 * undirected adjacency list {@code rebra}.
 */
private static ArrayList<Integer>[] buildAdjacency(Scanner s, int n, Pair[] sugrobs) {
    @SuppressWarnings("unchecked")
    ArrayList<Integer>[] rebra = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        rebra[i] = new ArrayList<>();
    }

    for (int i = 0; i < n; i++) {
        Pair temp = new Pair(s.nextInt(), s.nextInt());
        sugrobs[i] = temp;
        for (int j = 0; j < i; j++) {
            if (temp.i1 == sugrobs[j].i1 || temp.i2 == sugrobs[j].i2) {
                rebra[i].add(j);
                rebra[j].add(i);
            }
        }
    }
    return rebra;
}

/**
