 * Relies on the existing {@code used} boolean array and {@code dfs} method.
 */
private static int countCoupledComponents(ArrayList<Integer>[] rebra, int n) {
    used = new boolean[n];
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (!used[i]) {
            count++;
            dfs(i, rebra);
        }
    }
    return count;
}

