void solve(FastReader in, PrintWriter out) {
    char[] A = in.nextToken().toCharArray();

    // Chunk 1 – initial validation
    if (!validateInitial(A, out)) {
        return;                     // validation already printed the answer
    }

    // Chunk 2 – core stack processing
    Integer result = processCharacters(A, out);
    if (result != null) {
        out.println(result);
    }
}

/**
 * Validates the very first conditions: empty input and first character feasibility.
 * Returns true if processing can continue; otherwise prints the appropriate answer.
 */
private boolean validateInitial(char[] A, PrintWriter out) {
    if (A.length == 0) {
        out.println(0);
        return false;
    }
    if (!f(A[0])) {
        out.println("Impossible");
        return false;
    }
    return true;
}

/**
 * Executes the main algorithm: pushes opening symbols, matches them with closing
 * symbols, counts mismatches, and checks that the stack is empty at the end.
 * Returns the computed result, or null if an "Impossible" case was already printed.
 */
private Integer processCharacters(char[] A, PrintWriter out) {
    int res = 0;
    Stack<Character> S = new Stack<>();

    // first character is already known to be an opening symbol
    S.add(A[0]);

    for (int i = 1; i < A.length; i++) {
        if (f(A[i])) {                     // opening symbol
            S.add(A[i]);
        } else {                           // closing symbol
            if (S.isEmpty()) {
                out.println("Impossible");
                return null;
            }
            res += (S.peek() == g(A[i]) ? 0 : 1);
            S.pop();
        }
    }

    if (!S.isEmpty()) {
        out.println("Impossible");
        return null;
    }
    return res;
}

