        ans = Math.max(ans, readSegmentArea(sc, (long) h));
        // two vertical segments (width multiplier)
        ans = Math.max(ans, readSegmentArea(sc, (long) w));
        ans = Math.max(ans, readSegmentArea(sc, (long) w));

