/**
 * Reads a segment description: an integer k followed by k coordinate values.
 * Returns the area contributed by this segment, i.e. (last - first) * multiplier.
 */
private static long readSegmentArea(Scanner sc, long multiplier) {
    int k = sc.nextInt();
    long first = 0L;
    long last = 0L;

    for (int i = 0; i < k; i++) {
        long x = sc.nextLong();
        if (i == 0) {
            first = x;
        }
        if (i == k - 1) {
            last = x;
        }
    }
    return (last - first) * multiplier;
}

public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int t = sc.nextInt();

    for (int zzz = 0; zzz < t; zzz++) {
        int w = sc.nextInt();
        int h = sc.nextInt();

        long ans = 0L;

        // first vertical side (initialize ans)
        int k = sc.nextInt();
        ans = processSegment(sc, k, (long) h, ans, true);

        // opposite vertical side (keep max)
        k = sc.nextInt();
        ans = processSegment(sc, k, (long) h, ans, false);

        // first horizontal side (keep max)
        k = sc.nextInt();
        ans = processSegment(sc, k, (long) w, ans, false);

        // opposite horizontal side (keep max)
        k = sc.nextInt();
        ans = processSegment(sc, k, (long) w, ans, false);

        System.out.println(ans);
    }
}

/**
 * Reads {@code k} long coordinates, computes the span between the first
 * and the last coordinate, multiplies it by {@code multiplier} to obtain an area,
 * and returns the updated answer.
 *
 * @param sc         scanner positioned at the first coordinate
 * @param k          number of coordinates to read
 * @param multiplier either width (w) or height (h) of the rectangle
 * @param currentAns current best area
 * @param initialize if true, the result replaces {@code currentAns};
 *                   otherwise the larger of the two is kept
 * @return the updated best area
 */
private static long processSegment(Scanner sc, int k, long multiplier,
                                   long currentAns, boolean initialize) {
    long first = 0L;
    long last = 0L;
    for (int i = 0; i < k; i++) {
        long x = sc.nextLong();
        if (i == 0) {
            first = x;
        } else if (i == k - 1) {
            last = x;
        }
    }
    long area = (last - first) * multiplier;
    return initialize ? area : Math.max(currentAns, area);
}

