/**
 * Returns the minimum number of steps required to move from (x1,y1) to (x2,y2)
 * while staying within the vertical bounds [a, b].
 *
 * The logic mirrors the original implementation:
 * • If the two points share the same column, the answer is the vertical distance.
 * • Otherwise, we count the horizontal distance, clamp both y‑coordinates to the
 *   allowed range (adding the needed extra steps), and finally add the vertical
 *   distance between the clamped positions.
 */
private static int computeDistance(int[] query, int a, int b) {
    int x1 = query[0];
    int y1 = query[1];
    int x2 = query[2];
    int y2 = query[3];

    if (x1 == x2) {
        // Chunk A – same column, just vertical movement
        return Math.abs(y1 - y2);
    }

    // Chunk B – different columns, need horizontal movement and possible clamping
    int steps = Math.abs(x1 - x2);

    // Clamp first y‑coordinate and account for the moves needed to clamp
    if (y1 > b) {
        steps += y1 - b;
        y1 = b;
    } else if (y1 < a) {
        steps += a - y1;
        y1 = a;
    }

    // Clamp second y‑coordinate and account for the moves needed to clamp
    if (y2 > b) {
        steps += y2 - b;
        y2 = b;
    } else if (y2 < a) {
        steps += a - y2;
        y2 = a;
    }

    // Final vertical movement after both y‑coordinates are inside [a, b]
    steps += Math.abs(y1 - y2);
    return steps;
}

