/** Dispatches to the appropriate distance calculation based on column equality. */
private static int computeDistance(int[] q, int a, int b) {
    int x1 = q[0];
    int y1 = q[1];
    int x2 = q[2];
    int y2 = q[3];

    if (x1 == x2) {
        return distanceSameColumn(y1, y2);
    } else {
        return distanceWithClamping(x1, y1, x2, y2, a, b);
    }
}

/** Simple vertical distance when both cells lie in the same column. */
private static int distanceSameColumn(int y1, int y2) {
    return Math.abs(y1 - y2);
}

/**
 * Handles the general case:
 * 1. Horizontal distance (difference of column indices).
 * 2. Moves each row into the allowed interval [a, b], adding the steps needed.
 * 3. Adds the vertical distance after clamping.
 */
private static int distanceWithClamping(int x1, int y1, int x2, int y2, int a, int b) {
    int count = Math.abs(x1 - x2);

    // Clamp first row
    if (y1 > b) {
        count += y1 - b;
        y1 = b;
    } else if (y1 < a) {
        count += a - y1;
        y1 = a;
    }

    // Clamp second row
    if (y2 > b) {
        count += y2 - b;
        y2 = b;
    } else if (y2 < a) {
        count += a - y2;
        y2 = a;
    }

    // Vertical distance after clamping
    count += Math.abs(y1 - y2);
    return count;
}

