public void run() {
    int n = in.nextInt();
    int[] sticks = in.nextIntArray(n);
    int[] cnt = new int[MAX];
    for (int l : sticks) {
        cnt[l]++;
    }

    State state = new State(-1, 0);
    for (int l = MAX - 2; l >= 1; l--) {
        if (cnt[l + 1] == 1) {
            // we can pair a stick of length l+1 with a stick of length l
            cnt[l + 1]--;
            if (cnt[l] > 0) {
                cnt[l]--;
                updateResult(l, state);
                // skip the next length because we already used it
                l++;
            }
        } else if (cnt[l] >= 2) {
            // we have at least two sticks of the same length
            cnt[l] -= 2;
            updateResult(l, state);
            l++; // skip the next length for the same reason
        }
    }
    System.out.println(state.res);
    out.close();
}

/** Holds the mutable aggregation state used while scanning the lengths. */
private static class State {
    long prev; // the length waiting for its partner, -1 if none
    long res;  // accumulated rectangle area

    State(long prev, long res) {
        this.prev = prev;
        this.res = res;
    }
}

/**
 * Updates the aggregation state with a newly found side of length {@code length}.
 * If a previous side is already waiting, the two form a rectangle and its area
 * is added to {@code state.res}; otherwise the current length becomes the
 * pending side.
 */
private static void updateResult(int length, State state) {
    if (state.prev != -1) {
        state.res += state.prev * length;
        state.prev = -1;
    } else {
        state.prev = length;
    }
}

