private int roundResult(char a, char b) {
    // 0 – tie, 1 – first player (s) wins, 2 – second player (p) wins
    if (a == 'R') {
        if (b == 'P') return 2;
        if (b == 'S') return 1;
        return 0;
    } else if (a == 'P') {
        if (b == 'S') return 2;
        if (b == 'R') return 1;
        return 0;
    } else { // a == 'S'
        if (b == 'R') return 2;
        if (b == 'P') return 1;
        return 0;
    }
}

private int[] computeCycleResults(String s, String p, int lcm, int[] a) {
    int c1 = 0, c2 = 0;
    int l1 = s.length();
    int l2 = p.length();
    for (int i = 0; i < lcm; i++) {
        char ch1 = s.charAt(i % l1);
        char ch2 = p.charAt(i % l2);
        int win = roundResult(ch1, ch2);
        a[i] = win;
        if (win == 1) {
            c1++;
        } else if (win == 2) {
            c2++;
        }
    }
    return new int[]{c1, c2}; // [wins of s, wins of p] for one full LCM cycle
}

private void addRemainderCounts(int[] a, int r, int[] totals) {
    // totals[0] = wins of p, totals[1] = wins of s
    for (int i = 0; i < r; i++) {
        if (a[i] == 1) {
            totals[1]++;   // s wins
        } else if (a[i] == 2) {
            totals[0]++;   // p wins
        }
    }
}

public void solve(int testNumber, Scanner in, PrintWriter out) {
    int n = in.nextInt();
    String s = in.next(), p = in.next();

    int l1 = s.length();
    int l2 = p.length();
    int gcd = (int) IntegerUtils.gcd(l1, l2);
    int lcm = (l1 * l2) / gcd;

    int q = n / lcm;   // full cycles
    int r = n % lcm;   // remaining rounds

    int[] cycleArray = new int[lcm];
    int[] cycleCounts = computeCycleResults(s, p, lcm, cycleArray);
    int c1 = cycleCounts[0] * q; // total wins of s
    int c2 = cycleCounts[1] * q; // total wins of p

    int[] totals = new int[]{c2, c1};
    addRemainderCounts(cycleArray, r, totals);

    out.println(totals[0] + " " + totals[1]);
}

