/** Updates cnt[] and the TreeMap that stores how many numbers have a given count. */
private static void updateFrequency(int value, int[] cnt, TreeMap<Integer, Integer> freqMap) {
    if (cnt[value] > 0) {
        int oldCount = cnt[value];
        int oldFreq = freqMap.get(oldCount) - 1;
        if (oldFreq == 0) {
            freqMap.remove(oldCount);
        } else {
            freqMap.put(oldCount, oldFreq);
        }
    }
    cnt[value]++;

    int newCount = cnt[value];
    freqMap.put(newCount, freqMap.getOrDefault(newCount, 0) + 1);
    // the original code always removed a possible zero‑key entry
    freqMap.remove(0);
}

/** Returns whether the prefix a[0..i] consists of a single repeated element. */
private static boolean updateSameFlag(int i, int[] a, boolean sameSoFar) {
    if (i > 0 && a[i] != a[i - 1]) {
        return false;
    }
    return sameSoFar;
}

/** Computes the new answer based on the current state of the frequency map. */
private static int computeAnswer(int i, int[] a, boolean same, TreeMap<Integer, Integer> freqMap, int currentAns) {
    // all numbers appear exactly once
    if (freqMap.size() == 1 && freqMap.firstKey() == 1) {
        return i + 1;
    }
    // the whole prefix is made of the same number
    if (same) {
        return i + 1;
    }
    // two distinct frequencies – check the two admissible patterns
    if (freqMap.size() == 2) {
        int lowKey = freqMap.firstKey();
        int highKey = freqMap.lastKey();

        // one number appears once, the rest share the same higher count
        if (lowKey == 1 && freqMap.get(lowKey) == 1) {
            return i + 1;
        }
        // one number has count higher by one and appears only once
        if (highKey - 1 == lowKey && freqMap.get(highKey) == 1) {
            return i + 1;
        }
    }
    return currentAns;
}

