    for (int i = 0; i < n; i++) {
        // Chunk A – keep frequency structures up‑to‑date
        updateFrequencies(cnt, a[i], freqMap);

        // Chunk B – handle the “all elements equal so far” case
        same = updateSameFlagAndAnswer(same, a[i], i > 0 ? a[i - 1] : -1, i, ansHolder);

        // Chunk C – general answer‑updating rules
        tryUpdateAnswer(freqMap, i, ansHolder);
    }

    out.println(ansHolder[0]);
    out.flush();
}

/** Chunk A – updates count array and the TreeMap that maps “frequency → how many numbers have that frequency”. */
private static void updateFrequencies(int[] cnt, int value, TreeMap<Integer, Integer> freqMap) {
    if (cnt[value] > 0) {
        int oldFreq = cnt[value];
        int oldCount = freqMap.get(oldFreq) - 1;
        if (oldCount == 0) {
            freqMap.remove(oldFreq);
        } else {
            freqMap.put(oldFreq, oldCount);
        }
    }
    cnt[value]++;

    int newFreq = cnt[value];
    freqMap.put(newFreq, freqMap.getOrDefault(newFreq, 0) + 1);
    freqMap.remove(0);                      // keep map clean – identical to original logic
}

/** Chunk B – updates the `same` flag and possibly `ans` when the prefix consists of a single repeated value. */
private static boolean updateSameFlagAndAnswer(boolean sameSoFar, int current, int previous, int index, int[] ansHolder) {
    boolean same = sameSoFar;
    if (index > 0 && current != previous) {
        same = false;
    }
    if (same) {
        ansHolder[0] = index + 1;
    }
    return same;
}

/** Chunk C – checks the three patterns that allow the current prefix to be a valid answer. */
private static void tryUpdateAnswer(TreeMap<Integer, Integer> freqMap, int index, int[] ansHolder) {
    // Pattern 1: all numbers appear exactly once
    if (freqMap.size() == 1 && freqMap.firstKey() == 1) {
        ansHolder[0] = index + 1;
        return;
    }

    // Pattern 2: exactly two different frequencies
    if (freqMap.size() == 2) {
        int lowFreq = freqMap.firstKey();
        int highFreq = freqMap.lastKey();

        // a) one number occurs once, all others occur highFreq times
        if (lowFreq == 1 && freqMap.get(lowFreq) == 1) {
            ansHolder[0] = index + 1;
            return;
        }

        // b) one number occurs (highFreq) times, all others occur (highFreq‑1) times
        if (highFreq - 1 == lowFreq && freqMap.get(highFreq) == 1) {
            ansHolder[0] = index + 1;
        }
    }
}

