/**
 * Performs the linear scan used when ternary search is not needed.
 * It moves {@code curIt} forward while the next line yields a larger value,
 * then returns the value of the selected line.
 */
private long evaluateLinear(long x) {
    curIt = MaxMin.Min(curIt, A.size() - 1);

    while (curIt < A.size() - 1 &&
           A.get(curIt) * x + B.get(curIt) <= A.get(curIt + 1) * x + B.get(curIt + 1)) {
        curIt++;
    }
    return A.get(curIt) * x + B.get(curIt);
}

/**
 * Performs a ternary search over the convex hull to find the maximum
 * value of {@code A[i] * x + B[i]} for the given {@code x}.
 */
private long evaluateTernary(long x) {
    int l = 0;
    int r = A.size();

    // Narrow the interval until it contains at most three candidates
    while (r - l > 2) {
        int mid1 = (l * 2 + r) / 3;
        int mid2 = (l + 2 * r) / 3;

        long val1 = A.get(mid1) * x + B.get(mid1);
        long val2 = A.get(mid2) * x + B.get(mid2);

        if (val1 == val2) {
            l = mid1;
            r = mid2;
        } else if (val1 < val2) {
            l = mid1;
        } else {
            r = mid2;
        }
    }

    // Evaluate the remaining at most three positions and pick the maximum
    long ret = (long) -1e18;
    for (int i = l; i <= r; i++) {
        ret = MaxMin.Max(ret, A.get(i) * x + B.get(i));
    }
    return ret;
}

