/**
 * Applies the specific increments on the three diagonals and
 * normalises any cell that became 10 back to 1.
 */
private static void transformBoard(int[][] a) {
    // Increment the three diagonal groups
    a[0][0]++; a[1][3]++; a[2][6]++;
    a[3][1]++; a[4][4]++; a[5][7]++;
    a[6][2]++; a[7][5]++; a[8][8]++;

    // Wrap 10 → 1
    for (int i = 0; i < 9; ++i) {
        for (int j = 0; j < 9; ++j) {
            if (a[i][j] == 10) {
                a[i][j] = 1;
            }
        }
    }
}

