/**
 * Core DP‑like computation used when n > 1 and age > 1.
 *
 * @return the final answer (already includes the trailing “+2” from the original code)
 */
private static long computeAnswer(int n, int age) {
    int[] arr = new int[n - 1];
    Arrays.fill(arr, 1);
    long ans = 0;

    for (int i = age - 1; i > 0; i--) {
        ans = (ans + sumArray(arr)) % mod;
        updatePrefixSums(arr, i, age);
    }

    // original code added 2 after the loop
    return (ans + 2) % mod;
}

/**
 * Returns the sum of all elements in {@code arr} modulo {@code mod}.
 */
private static long sumArray(int[] arr) {
    long sum = 0;
    for (int v : arr) {
        sum = (sum + v) % mod;
    }
    return sum;
}

/**
 * Rewrites {@code arr} to contain cumulative sums.
 * Direction (forward or backward) depends on the parity of {@code i} and {@code age}.
 */
private static void updatePrefixSums(int[] arr, int i, int age) {
    int cumulative = 0;
    if ((i % 2) != (age % 2)) {
        // backward prefix sums
        for (int j = arr.length - 1; j >= 0; j--) {
            cumulative = (cumulative + arr[j]) % mod;
            arr[j] = cumulative;
        }
    } else {
        // forward prefix sums
        for (int j = 0; j < arr.length; j++) {
            cumulative = (cumulative + arr[j]) % mod;
            arr[j] = cumulative;
        }
    }
}

