    ok &= checkConditions(
            candidate.substring(candidateLen - suffixLen),
            pattern.substring(patternLen - suffixLen));

    // 3. Middle part (the part that '*' expands to) must not contain any good char
    for (int j = wildcardPos; j < candidateLen - patternLen + wildcardPos + 1; j++) {
        if (set.contains(candidate.charAt(j))) {
            ok = false;
            break;
        }
    }
    return ok;
}

