/**
 * Extracts the first integer from the line.
 * This integer represents the number of values that follow.
 */
private static int parseCount(String line) {
    int n = 0;
    for (int i = 0; i < line.length(); i++) {
        char c = line.charAt(i);
        if (c == ' ') {
            return n;
        }
        n = n * 10 + (c - '0');
    }
    // If there is no space, the whole line is the count.
    return n;
}

/**
 * Populates the provided array with the integers that appear after
 * the first space in the line. Numbers are separated by spaces.
 */
private static void fillNumbers(String line, int[] nums) {
    int idx = 0;
    int i = 0;

    // Skip the first integer and the following space.
    while (i < line.length() && line.charAt(i) != ' ') {
        i++;
    }
    i++; // move past the space

    for (; i < line.length(); i++) {
        char c = line.charAt(i);
        if (c == ' ') {
            idx++;
        } else {
            nums[idx] = nums[idx] * 10 + (c - '0');
        }
    }
}

public static int[] readNums(BufferedReader bf) throws Exception {
    String line = bf.readLine();

