        for (int j = M; j >= 1; j--) {
            dp2[i][j] = a[i][j] + Math.max(dp2[i + 1][j], dp2[i][j + 1]);
        }
    }
}

private static void fillDp3() {
    for (int i = N; i >= 1; i--) {
        for (int j = 1; j <= M; j++) {
            dp3[i][j] = a[i][j] + Math.max(dp3[i + 1][j], dp3[i][j - 1]);
        }
    }
}

private static void fillDp4() {
    for (int i = 1; i <= N; i++) {
        for (int j = M; j >= 1; j--) {
            dp4[i][j] = a[i][j] + Math.max(dp4[i - 1][j], dp4[i][j + 1]);
        }
    }
}

private static int calculateMax() {
    int max = -1;
    for (int i = 2; i < N; i++) {
        for (int j = 2; j < M; j++) {
            int sum = 0;
            sum += dp1[i][j - 1] + dp2[i][j + 1];
            sum += dp3[i + 1][j] + dp4[i - 1][j];
            max = Math.max(max, sum);

            sum = 0;
            sum += dp3[i][j - 1] + dp4[i][j + 1];
            sum += dp1[i - 1][j] + dp2[i + 1][j];
            max = Math.max(max, sum);
        }
    }
    return max;
}

public static void main(String[] args) {
    readInputAndAllocate();
    fillDpTables();
    int max = evaluateMaximumMeetingSum();
    System.out.println(max);
}

/** Reads N, M and the matrix a, and allocates all DP tables. */
private static void readInputAndAllocate() {
    N = NI();
    M = NI();
    a = new int[N + 1][M + 1];
    dp1 = new int[N + 4][M + 4];
    dp2 = new int[N + 4][M + 4];
    dp3 = new int[N + 4][M + 4];
    dp4 = new int[N + 4][M + 4];

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            a[i + 1][j + 1] = NI();
        }
    }
}

/** Fills the four DP tables that store best‑path sums from each corner. */
private static void fillDpTables() {
    // dp1: from top‑left moving down/right
    for (int i = 1; i <= N; i++) {
        for (int j = 1; j <= M; j++) {
            dp1[i][j] = a[i][j] + Math.max(dp1[i - 1][j], dp1[i][j - 1]);
        }
    }

    // dp2: from bottom‑right moving up/left
    for (int i = N; i >= 1; i--) {
        for (int j = M; j >= 1; j--) {
            dp2[i][j] = a[i][j] + Math.max(dp2[i + 1][j], dp2[i][j + 1]);
        }
    }

    // dp3: from bottom‑left moving up/right
    for (int i = N; i >= 1; i--) {
        for (int j = 1; j <= M; j++) {
            dp3[i][j] = a[i][j] + Math.max(dp3[i + 1][j], dp3[i][j - 1]);
        }
    }

    // dp4: from top‑right moving down/left
    for (int i = 1; i <= N; i++) {
        for (int j = M; j >= 1; j--) {
            dp4[i][j] = a[i][j] + Math.max(dp4[i - 1][j], dp4[i][j + 1]);
        }
    }
}

/** Evaluates the two possible crossing configurations and returns the maximum sum. */
private static int evaluateMaximumMeetingSum() {
    int max = -1;
    for (int i = 2; i < N; i++) {
        for (int j = 2; j < M; j++) {
            // First crossing pattern
            int sum1 = dp1[i][j - 1] + dp2[i][j + 1]   // paths that go through (i, j) horizontally
                     + dp3[i + 1][j] + dp4[i - 1][j]; // paths that go through (i, j) vertically
            max = Math.max(max, sum1);

            // Second crossing pattern (paths swapped)
            int sum2 = dp3[i][j - 1] + dp4[i][j + 1]
                     + dp1[i - 1][j] + dp2[i + 1][j];
            max = Math.max(max, sum2);
        }
    }
    return max;
}

