/** Applies all (a[i], b[i], q[i]) updates to the given “or” tree. */
private static void populateOrTree(RangeTree tree, int[] a, int[] b, int[] q) {
    for (int i = 0; i < a.length; i++) {
        tree.update(a[i], b[i], q[i], 0);
    }
}

/** Constructs the “and” tree where each position i gets the value from the “or” tree. */
private static RangeTree buildAndTree(int n, RangeTree or) {
    RangeTree and = new RangeTree(n, 1);
    for (int i = 0; i < n; i++) {
        long val = or.query(i, i, 0);
        and.update(i, i, val, 1);
    }
    return and;
}

/** Returns true iff all original constraints are satisfied by the “and” tree. */
private static boolean constraintsHold(RangeTree and, int[] a, int[] b, int[] q) {
    for (int i = 0; i < a.length; i++) {
        long aux = and.query(a[i], b[i], 1);
        if (aux != q[i]) {
            return false;
        }
    }
    return true;
}

