private static String solve(InputData data) {
    int n = data.n;
    int m = data.m;
    int[] a = data.a;
    int[] b = data.b;
    int[] q = data.q;

    // build OR‑range tree
    RangeTree or = new RangeTree(n, 0);
    for (int i = 0; i < m; i++) {
        or.update(a[i], b[i], q[i], 0);
    }

    // build AND‑range tree from the OR results
    RangeTree and = new RangeTree(n, 1);
    for (int i = 0; i < n; i++) {
        and.update(i, i, or.query(i, i, 0), 1);
    }

    // verify the constraints
    boolean fail = false;
    for (int i = 0; i < m; i++) {
        long aux = and.query(a[i], b[i], 1);
        if (aux != q[i]) {
            fail = true;
            break;
        }
    }

    // produce output
    StringBuilder sb = new StringBuilder();
    if (!fail) {
        sb.append("YES\n");
        sb.append(or.query(0, 0, 0));
        for (int i = 1; i < n; i++) {
            sb.append(' ').append(or.query(i, i, 0));
        }
        sb.append('\n');
    } else {
        sb.append("NO\n");
    }
    return sb.toString();
}

