private static class InputData {
    final int n;
    final int m;
    final int[] a;
    final int[] b;
    final int[] q;

    InputData(int n, int m, int[] a, int[] b, int[] q) {
        this.n = n;
        this.m = m;
        this.a = a;
        this.b = b;
