    for (int i = 0; i < m; i++) {
        a[i] = sc.nextInt() - 1;
        b[i] = sc.nextInt() - 1;
        q[i] = sc.nextInt();
    }

    RangeTree orTree = buildOrTree(n, a, b, q);
    RangeTree andTree = buildAndTree(n, orTree);
    boolean fail = !verifyConstraints(andTree, a, b, q);

    PrintWriter out = new PrintWriter(System.out);
