    out.flush();
    out.close();
}

/* Builds the OR‑type RangeTree and applies all updates. */
private static RangeTree buildOrTree(int n, int[] a, int[] b, int[] q) {
    RangeTree or = new RangeTree(n, 0);
    for (int i = 0; i < a.length; i++) {
        or.update(a[i], b[i], q[i], 0);
    }
    return or;
}

/* Constructs the AND‑type RangeTree using the values stored in the OR tree. */
private static RangeTree buildAndTree(int n, RangeTree or) {
    RangeTree and = new RangeTree(n, 1);
    for (int i = 0; i < n; i++) {
        and.update(i, i, or.query(i, i, 0), 1);
    }
    return and;
}

/* Checks whether every original constraint is satisfied by the AND tree. */
private static boolean verifyConstraints(RangeTree and,
                                          int[] a, int[] b, int[] q) {
    for (int i = 0; i < a.length; i++) {
        long result = and.query(a[i], b[i], 1);
        if (result != q[i]) {
            return false;
        }
    }
    return true;
}

/* Prints “YES” plus the final array or “NO” if the constraints fail. */
private static void outputResult(PrintWriter out,
                                 boolean fail,
                                 RangeTree or,
                                 int n) {
    if (!fail) {
        out.println("YES");
        out.print(or.query(0, 0, 0));
        for (int i = 1; i < n; i++) {
            out.print(' ');
            out.print(or.query(i, i, 0));
        }
        out.println();
    } else {
        out.println("NO");
    }
}

