/**
 * Converts a string consisting of 'R', 'G', 'B' into an int array:
 * R → 0, G → 1, B → 2.
 */
private static int[] toNumericArray(String s, int n) {
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        char ch = s.charAt(i);
        if (ch == 'R') {
            arr[i] = 0;
        } else if (ch == 'G') {
            arr[i] = 1;
        } else { // 'B'
            arr[i] = 2;
        }
    }
    return arr;
}

/**
 * Builds a prefix‑sum array where each position holds the number of mismatches
 * between the original colour array and a repeating pattern shifted by {@code shift}.
 * The pattern repeats 0,1,2 (i.e. R,G,B) with the given shift.
 */
private static int[] buildPrefix(int[] arr, int shift) {
    int n = arr.length;
    int[] pref = new int[n];
    for (int i = 0; i < n; i++) {
        if (arr[i] != (i + shift) % 3) {
            pref[i] = 1;
        }
        if (i > 0) {
            pref[i] += pref[i - 1];
        }
    }
    return pref;
}

/**
 * Returns the minimal number of repaint operations needed for any sub‑array of length {@code k}
 * using the three pre‑computed prefix arrays.
 */
private static int minimalChanges(int[] pref0, int[] pref1, int[] pref2, int k) {
    int n = pref0.length;
    int min = Integer.MAX_VALUE;

    for (int start = 0; start + k - 1 < n; start++) {
        int end = start + k - 1;

        int mism0 = pref0[end] - (start > 0 ? pref0[start - 1] : 0);
        int mism1 = pref1[end] - (start > 0 ? pref1[start - 1] : 0);
        int mism2 = pref2[end] - (start > 0 ? pref2[start - 1] : 0);

        min = Math.min(min, Math.min(mism0, Math.min(mism1, mism2)));
    }
    return min;
}

public static void main(String[] args) throws NumberFormatException, IOException {
