        int n = sc.nextInt();
        int k = sc.nextInt();
        String s = sc.next();

        int[] colours = mapColors(s);
        int[] pref0 = buildPrefix(colours, 0); // pattern starting with R
        int[] pref1 = buildPrefix(colours, 1); // pattern starting with G
        int[] pref2 = buildPrefix(colours, 2); // pattern starting with B

        int answer = minimalChanges(pref0, pref1, pref2, k);
        pw.println(answer);
    }
    pw.flush();
}

/**
 * Converts the characters R, G, B into integers 0, 1, 2 respectively.
 */
private static int[] mapColors(String s) {
    int n = s.length();
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        char ch = s.charAt(i);
        if (ch == 'R')
            arr[i] = 0;
        else if (ch == 'G')
            arr[i] = 1;
        else // ch == 'B'
            arr[i] = 2;
    }
    return arr;
}

/**
 * Builds a prefix‑sum array where each entry tells how many positions up to i
 * do NOT match the cyclic pattern (i + offset) % 3.
 */
private static int[] buildPrefix(int[] colours, int offset) {
    int n = colours.length;
    int[] pref = new int[n];
    for (int i = 0; i < n; i++) {
        if (colours[i] != ((i + offset) % 3)) {
            pref[i] = 1;
        }
        if (i > 0) {
            pref[i] += pref[i - 1];
        }
    }
    return pref;
}

/**
 * Slides a window of length k over the three prefix arrays and returns the
 * smallest number of changes required.
 */
private static int minimalChanges(int[] p0, int[] p1, int[] p2, int k) {
    int n = p0.length;
    int min = Integer.MAX_VALUE;

    for (int i = 0; i + k - 1 < n; i++) {
        int end = i + k - 1;

        int sum0 = p0[end] - (i > 0 ? p0[i - 1] : 0);
        int sum1 = p1[end] - (i > 0 ? p1[i - 1] : 0);
        int sum2 = p2[end] - (i > 0 ? p2[i - 1] : 0);

        min = Math.min(min, Math.min(sum0, Math.min(sum1, sum2)));
    }
    return min;
}

