private static void readReplacements(Scanner s, int m,
                                     String[] a, String[] b, int[] flag) {
    for (int i = 0; i < m; i++) {
        a[i] = s.next();      // first string of the pair
        b[i] = s.next();      // second string of the pair
        // flag == 1 when a[i] is the shorter (or equal) string
        flag[i] = (a[i].length() <= b[i].length()) ? 1 : 0;
    }
}

