private static String[] readWords(Scanner s, int n) {
    String lastLine = "";
    while (s.hasNext()) {
        lastLine = s.nextLine();   // keep overwriting – ends with last line
    }
    String[] split = lastLine.trim().split("\\s+");
    // The original code assumed exactly n tokens; keep the same contract.
    String[] result = new String[n];
    System.arraycopy(split, 0, result, 0, Math.min(n, split.length));
    return result;
