public double nextDouble() {
    int c = read();
    while (isSpaceChar(c)) {
        c = read();
    }

    int sgn = 1;
    if (c == '-') {
        sgn = -1;
        c = read();
    }

    double value = parseIntegerPart(c);
    return value * sgn;
}

/**
 * Parses the sequence of digits that form the integer part of a double.
 * Handles an optional exponent and delegates to {@link #parseFractionalPart}
 * when a decimal point is encountered.
 *
 * @param c the first character after optional sign handling
 * @return the numeric value represented by the integer (and possible fraction) part
 */
private double parseIntegerPart(int c) {
    double res = 0;

    while (!isSpaceChar(c) && c != '.') {
        if (c == 'e' || c == 'E') {
            // Exponent after integer part
            return res * Math.pow(10, nextInt());
        }
        if (c < '0' || c > '9') {
            throw new InputMismatchException();
        }
        res = res * 10 + (c - '0');
        c = read();
    }

    // Decimal point found – parse the fractional part
    if (c == '.') {
        return parseFractionalPart(res, read());
    }

    // No fractional part, no exponent
    return res;
}

/**
 * Parses the fractional part of a double that follows a decimal point.
 * Handles an optional exponent and validates digit characters.
 *
 * @param integerPart the value already accumulated from the integer part
 * @param c the first character after the decimal point
 * @return the complete numeric value (integer + fraction, with possible exponent)
 */
private double parseFractionalPart(double integerPart, int c) {
    double res = integerPart;
    double factor = 1; // Represents 10⁻¹, 10⁻², ...

    while (!isSpaceChar(c)) {
        if (c == 'e' || c == 'E') {
            // Exponent after fractional part
            return res * Math.pow(10, nextInt());
        }
        if (c < '0' || c > '9') {
            throw new InputMismatchException();
        }
        factor /= 10;
        res += (c - '0') * factor;
        c = read();
    }

    return res;
}

