/** Builds the undirected tree as an adjacency list. */
@SuppressWarnings("unchecked")
private HashSet<Integer>[] buildTree(int n) {
    HashSet<Integer>[] tree = (HashSet<Integer>[]) new HashSet[n + 1];
    for (int i = 0; i <= n; i++) {
        tree[i] = new HashSet<>();
    }
    for (int i = 0; i < n - 1; i++) {
        int a = ni();
        int b = ni();
        tree[a].add(b);
        tree[b].add(a);
    }
    return tree;
}

/** Verifies that the permutation `ar` corresponds to a BFS order
 *  starting from node 1 and always expanding children in the order
 *  they appear in `ar`. */
private boolean isValidBfsOrder(int[] ar, HashSet<Integer>[] tree) {
    if (ar.length == 0 || ar[0] != 1) {
        return false;
    }
    int n = tree.length - 1;
    boolean[] vis = new boolean[n + 1];
    Queue<Integer> q = new LinkedList<>();
    vis[1] = true;
    q.add(1);
    int idx = 1; // next position in ar to match

    while (!q.isEmpty()) {
        int u = q.poll();
        Set<Integer> reachable = new HashSet<>();
        for (int v : tree[u]) {
            if (!vis[v]) {
                reachable.add(v);
                vis[v] = true;
            }
        }
        int cnt = reachable.size();
        while (cnt-- > 0) {
            if (idx >= ar.length) {
                return false; // more expected vertices than provided
            }
            int next = ar[idx++];
            if (reachable.contains(next)) {
                q.add(next);
            } else {
                return false;
            }
        }
    }
    // All vertices must have been consumed
    return idx == ar.length;
}

