/**
 * Builds the power array p where p[i] = 13^i.
 */
private long[] buildPowers(int n) {
    long[] p = new long[n + 1];
    p[0] = 1L;
    for (int i = 1; i <= n; i++) {
        p[i] = p[i - 1] * 13L;
    }
    return p;
}

/**
 * Builds the prefix hash array h.
 * h[i] = Σ_{t=0..i} (s[t]-'0'+1) * p[t]
 */
private long[] buildPrefixHash(String s, long[] p) {
    int n = s.length();
    long[] h = new long[n];
    h[0] = s.charAt(0) - '0' + 1;
    for (int i = 1; i < n; i++) {
        h[i] = h[i - 1] + (s.charAt(i) - '0' + 1) * p[i];
    }
    return h;
}

/**
 * Performs the DP computation and returns d[0][n].
 */
private int computeDP(String s, long[] h, long[] p) {
    int n = s.length();
    int[][] d = new int[n + 1][n + 1];
    d[0][0] = 1;

    for (int k = 1; k <= n; k++) {
        for (int j = k - 1; j >= 0; j--) {
            d[j][k] = d[j + 1][k];

            if (s.charAt(j) > '0') {
                int i = 2 * j - k;
                if (i < 0) {
                    i = 0;
                } else {
                    int hi = k - j, lo = -1;
                    while (lo + 1 < hi) {
                        int mid = (lo + hi) >> 1;
                        long h1 = h[i + mid] - (i > 0 ? h[i - 1] : 0);
                        long h2 = h[j + mid] - (j > 0 ? h[j - 1] : 0);

                        if (h1 * p[j - i] == h2) {
                            lo = mid;
                        } else {
                            hi = mid;
                        }
                    }

                    if (hi == k - j || s.charAt(i + hi) >= s.charAt(j + hi)) {
                        i++;
                    }
                }

                d[j][k] = (d[j][k] + d[i][j]) % mod;
            }
        }
    }
    return d[0][n];
}

