 */
private int computeDP(String s, long[] h, long[] p, int n) {
    int[][] d = new int[n + 1][n + 1];
    d[0][0] = 1;

    for (int k = 1; k <= n; k++) {
        for (int j = k - 1; j >= 0; j--) {
            // propagate the value from the state where the previous segment ends at j+1
            d[j][k] = d[j + 1][k];

            if (s.charAt(j) > '0') {
