        while (lo + 1 < hi) {
            int mid = (lo + hi) >> 1;
            long h1 = h[i + mid] - (i > 0 ? h[i - 1] : 0);
            long h2 = h[j + mid] - (j > 0 ? h[j - 1] : 0);

            if (h1 * p[j - i] == h2) {
