            }
        }

        // if the substrings are equal up to the end of the segment,
        // or the next character of the left part is not larger,
        // we must move i one step forward.
        if (hi == k - j || s.charAt(i + hi) >= s.charAt(j + hi)) {
            i++;
        }
    }
