/**
 * Starting at {@code startIdx} (which is known to contain a 1),
 * multiplies the distances between each consecutive pair of 1's.
 * Returns the resulting product; if there is only a single 1,
 * the product remains 1.
 */
private long computeProductBetweenOnes(int[] arr, int startIdx, int length) {
    long product = 1L;
    int i = startIdx;

    while (i < length) {
        int next = i + 1;
        while (next < length && arr[next] != 1) {
            ++next;
        }
        if (next < length) {
            product *= (next - i);
        }
        i = next; // move to the next '1' (or length, ending the loop)
    }
    return product;
}

