        int left = fixed[i];
        int right = fixed[i + 1];

        for (int j = left + 1; j < right; j++) {
            if (arr[left] <= arr[j] && arr[j] <= arr[right]) {
                if (lis.isEmpty()) {
                    lis.add(arr[j]);
                } else {
