 * computes the longest non‑decreasing subsequence that can stay,
 * then aggregates the deletions needed.
 */
private int computeAnswer(int[] arr, int[] unchangable) {
    int ans = 0;
    for (int i = 0; i < unchangable.length - 1; i++) {
        ArrayList<Integer> lis = new ArrayList<>();

        for (int j = unchangable[i] + 1; j < unchangable[i + 1]; j++) {
            if (arr[unchangable[i]] <= arr[j] && arr[j] <= arr[unchangable[i + 1]]) {
