                    if (idx + 1 == lis.size()) {
                        lis.add(arr[j]);
                    } else {
                        lis.set(idx + 1, arr[j]);
                    }
                }
            }
        }
        ans += unchangable[i + 1] - unchangable[i] - 1 - lis.size();
    }
