/**
 * Binary‑search helper used by {@link #computeAnswer}.
 * Returns the greatest index < list.size() whose element <= target.
 * (Assumes the list is sorted increasingly.)
 */
private int bs(ArrayList<Integer> list, int target) {
    int lo = 0, hi = list.size() - 1, res = -1;
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1;
        if (list.get(mid) <= target) {
            res = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return res;
}

