        if (i == nextDay) {
            curValue = nextValue;
            ind++;
            if (ind < m) {
                nextDay = day[ind];
                nextValue = height[ind];
            } else {
                justAdd = true;
            }
            max = Math.max(max, curValue);
            continue;
        }

        curValue = computeCurrentValue(i, nextDay, nextValue, curValue, justAdd);
        max = Math.max(max, curValue);
    }

