}

/**
 * Calculates the height for day {@code i} when {@code i} is not a known
 * measurement day.
 *
 * @param i          the current day (1‑based)
 * @param nextDay    the next known measurement day
 * @param nextValue  the height on {@code nextDay}
 * @param curValue   the height on the previous day
 * @param justAdd    true if we are past the last known measurement
 * @return the height for day {@code i}
 */
private static int computeCurrentValue(int i, int nextDay, int nextValue,
                                       int curValue, boolean justAdd) {
    int difDay = nextDay - i;
    int difValue = nextValue - curValue;

    if (curValue == -1) {
        // before the first known measurement we can only climb up
        return nextValue + difDay;
    } else if (justAdd || difValue >= 0) {
        // we are either after the last known day or the slope is non‑negative
        return curValue + 1;
    } else {
        // slope is negative – decide whether we must go up or down
        if (difDay >= (curValue + 1) - nextValue) {
            return curValue + 1;
        } else {
            return curValue - 1;
        }
    }
}

