static long recurse(int idx, int want) {
    // ---- base cases ---------------------------------------------------------
    Long base = handleBaseCases(idx, want);
    if (base != null) {
        return base;
    }

    int z = want % 2;
    if (dp[idx][z] != -1) {
        return dp[idx][z];
    }

    // ---- compute the result (single point of nesting) -----------------------
    dp[idx][z] = Long.MIN_VALUE / 100;
    if (idx % 2 == 0) {
        dp[idx][z] = computeEven(idx, want);
    } else {
        dp[idx][z] = computeOdd(idx, want);
    }

    return dp[idx][z];
}

// ---------------------------------------------------------------------------
// Base‑case handling – returns null when no base case matches
private static Long handleBaseCases(int idx, int want) {
    if (want == 0) {
        return 0L;
    }
    if (idx < 0) {
        return Long.MIN_VALUE / 100;
    }
    if (want > idx) {
        return Long.MIN_VALUE / 100;
    }
    return null; // not a base case
}

// ---------------------------------------------------------------------------
// Even index computation
private static long computeEven(int idx, int want) {
    // want*2 == idx is the only scenario where we have a choice
    if (want * 2 == idx) {
        return Math.max(
                arr[idx] + recurse(idx - 2, want - 1),
                arr[idx - 1] + recurse(idx - 3, want - 1));
    }
    // No valid selection – keep the sentinel value (handled by caller)
    return Long.MIN_VALUE / 100;
}

// ---------------------------------------------------------------------------
// Odd index dispatcher
private static long computeOdd(int idx, int want) {
    if (want * 2 + 1 == idx) {
        return computeOddSpecial(idx, want);
    }
    // regular odd case
    return computeOddRegular(idx, want);
}

// ---------------------------------------------------------------------------
// Special odd case where want*2+1 == idx
private static long computeOddSpecial(int idx, int want) {
    long best = Math.max(
            arr[idx] + recurse(idx - 2, want - 1),
            arr[idx - 1] + recurse(idx - 3, want));
    // consider skipping the current element
    best = Math.max(best, recurse(idx - 1, want));
    return best;
}

// ---------------------------------------------------------------------------
// Regular odd case (no special equality)
private static long computeOddRegular(int idx, int want) {
    return arr[idx] + recurse(idx - 2, want - 1);
}

