/** Core DP that returns the minimum possible sum of segment ranges. */
private int computeMinimumDifference(int[] a, int n, int k) {
    int x = n / k;
    int k1 = k - (n % k);   // number of groups of size x
    int k2 = n % k;         // number of groups of size x+1

    int[][] dp = initializeDpTable(k1, k2);
    dp[0][0] = 0;

    for (int i = 0; i <= k1; i++) {
        for (int j = 0; j <= k2; j++) {
            int cur = x * i + (x + 1) * j;

            if (i != k1) {
                int cost = a[cur + x - 1] - a[cur];
                dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + cost);
            }
            if (j != k2) {
                int cost = a[cur + x] - a[cur];
                dp[i][j + 1] = Math.min(dp[i][j + 1], dp[i][j] + cost);
            }
        }
    }
    return dp[k1][k2];
}

/** Creates a DP table filled with Integer.MAX_VALUE. */
private int[][] initializeDpTable(int rows, int cols) {
    int[][] dp = new int[rows + 1][cols + 1];
    for (int i = 0; i <= rows; i++) {
        for (int j = 0; j <= cols; j++) {
            dp[i][j] = Integer.MAX_VALUE;
        }
    }
    return dp;
}

