static void dfs(int parent, int u, int level, int odd, int even) {
    // Bump 1 → extracted
    int a = computeAdjustedValue(u, level, odd, even);
    init[u] = a;

    // Bump 2 → extracted (may modify odd/even)
    int[] updated = processMismatch(u, level, odd, even);
    odd = updated[0];
    even = updated[1];

    for (int v : adj[u]) {
        if (v == parent) {
            continue;
        }
        dfs(u, v, level + 1, odd, even);
    }
}

/** Returns the value of node *u* after applying the parity‑based XOR. */
private static int computeAdjustedValue(int u, int level, int odd, int even) {
    int a = init[u];
    if (level % 2 == 0) {
        a ^= (even % 2);
    } else {
        a ^= (odd % 2);
    }
    return a;
}

/**
 * If the current value of node *u* differs from its goal, performs the required
 * side‑effects (output, counter updates, value correction) and returns the
 * possibly updated odd/even counters.
 */
private static int[] processMismatch(int u, int level, int odd, int even) {
    if (init[u] != goal[u]) {
        ans.append(u + 1).append('\n');
        if (level % 2 == 0) {
            even++;
        } else {
            odd++;
        }
        init[u] = goal[u];
        count++;
    }
    return new int[]{odd, even};
}

