/** reads n integers from the next line */
private static int[] readArray(BufferedReader br, int n) throws IOException {
    StringTokenizer st = new StringTokenizer(br.readLine());
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = Integer.parseInt(st.nextToken());
    }
    return arr;
}

/** returns indices sorted by (value, index) */
private static Integer[] sortedIndices(int[] aa) {
    int n = aa.length;
    Integer[] idx = new Integer[n];
    for (int i = 0; i < n; i++) idx[i] = i;
    Arrays.sort(idx, (i, j) -> aa[i] != aa[j] ? aa[i] - aa[j] : i - j);
    return idx;
}

/** for each position stores the previous index with the same value (-1 if none) */
private static int[] buildPrevSame(int[] aa, Integer[] sortedIdx) {
    int n = aa.length;
    int[] pp = new int[n];
    for (int i = 0, j; i < n; i = j) {
        j = i + 1;
        while (j < n && aa[sortedIdx[j]] == aa[sortedIdx[i]]) j++;
        int prev = -1;
        for (int h = i; h < j; h++) {
            pp[sortedIdx[h]] = prev;
            prev = sortedIdx[h];
        }
    }
    return pp;
}

/** bb[i][h] = last index ≤ i having bit h set (or -1) */
private static int[][] buildPrevBit(int[] aa, int K) {
    int n = aa.length;
    int[][] bb = new int[n][K];
    for (int h = 0; h < K; h++) {
        int last = -1;
        for (int i = 0; i < n; i++) {
            bb[i][h] = last;
            if ((aa[i] & (1 << h)) != 0) last = i;
        }
    }
    return bb;
}

/** dd[i][h] = first index ≥ i having bit h set (or n) */
private static int[][] buildNextBit(int[] aa, int K) {
    int n = aa.length;
    int[][] dd = new int[n][K];
    for (int h = 0; h < K; h++) {
        int next = n;
        for (int i = n - 1; i >= 0; i--) {
            dd[i][h] = next;
            if ((aa[i] & (1 << h)) != 0) next = i;
        }
    }
    return dd;
}

/** dp[i] = max previous index with a zero‑bit in any position */
private static int[] computeDp(int[] aa, int[][] bb, int K) {
    int n = aa.length;
    int[] dp = new int[n];
    for (int i = 0; i < n; i++) {
        int best = -1;
        for (int h = 0; h < K; h++) {
            if ((aa[i] & (1 << h)) == 0) {
                best = Math.max(best, bb[i][h]);
            }
        }
        dp[i] = best;
    }
    return dp;
}

/** dq[i] = min next index with a zero‑bit in any position */
private static int[] computeDq(int[] aa, int[][] dd, int K) {
    int n = aa.length;
    int[] dq = new int[n];
    for (int i = n - 1; i >= 0; i--) {
        int best = n;
        for (int h = 0; h < K; h++) {
            if ((aa[i] & (1 << h)) == 0) {
                best = Math.min(best, dd[i][h]);
            }
        }
        dq[i] = best;
    }
    return dq;
}

/** final answer calculation */
private static long computeAnswer(int[] dp, int[] dq, int[] pp, int n) {
    long ans = (long) n * (n + 1) / 2;
    for (int i = 0; i < n; i++) {
        int left = Math.max(dp[i], pp[i]);
        ans -= (long) (i - left) * (dq[i] - i);
    }
    return ans;
}

public static void main(String[] args) throws IOException {
    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    int n = Integer.parseInt(br.readLine());

    int[] aa = parseArray(br.readLine(), n);
    Integer[] sortedIdx = sortIndicesByValueAndIndex(aa);
    int[] pp = computePrevSameValue(aa, sortedIdx);
    int[][] bb = computePrevBitIndices(aa);
    int[][] dd = computeNextBitIndices(aa);
    int[] dp = computeDp(aa, bb);
    int[] dq = computeDq(aa, dd);
    long ans = computeAnswer(n, pp, dp, dq);

    System.out.println(ans);
}

