}

/* dp[i] = max previous index (or -1) such that all bits missing in aa[i] are 0 */
private static int[] computeDp(int[] aa, int[][] bb) {
    int n = aa.length;
    int[] dp = new int[n];
    for (int i = 0; i < n; i++) {
        int best = -1;
        for (int h = 0; h < K; h++) {
            if ((aa[i] & (1 << h)) == 0) {
                best = Math.max(best, bb[i][h]);
            }
        }
        dp[i] = best;
    }
