}

/* dq[i] = min next index (or n) such that all bits missing in aa[i] are 0 */
private static int[] computeDq(int[] aa, int[][] dd) {
    int n = aa.length;
    int[] dq = new int[n];
    for (int i = n - 1; i >= 0; i--) {
        int best = n;
        for (int h = 0; h < K; h++) {
            if ((aa[i] & (1 << h)) == 0) {
                best = Math.min(best, dd[i][h]);
            }
        }
        dq[i] = best;
    }
    return dq;
}

/* final answer computation */
private static long computeAnswer(int n, int[] pp, int[] dp, int[] dq) {
    long total = (long) n * (n + 1) / 2;
    for (int i = 0; i < n; i++) {
        int left = Math.max(dp[i], pp[i]);
        long contribution = (long) (i - left) * (dq[i] - i);
        total -= contribution;
    }
    return total;
}

