}

/* 3️⃣ Build link to previous equal value */
private static int[] buildPrevEqualLinks(int[] aa, Integer[] sortedIdx) {
    int n = aa.length;
    int[] pp = new int[n];
    for (int i = 0, j; i < n; i = j) {
        j = i + 1;
        while (j < n && aa[sortedIdx[j]] == aa[sortedIdx[i]]) {
            j++;
        }
        int prev = -1;
        for (int h = i; h < j; h++) {
            pp[sortedIdx[h]] = prev;
            prev = sortedIdx[h];
        }
    }
    return pp;
}

/* 4️⃣ Previous position for each bit */
private static int[][] buildPrevBitPositions(int[] aa) {
    int n = aa.length;
    int[][] bb = new int[n][K];
    for (int h = 0; h < K; h++) {
        int prev = -1;
        for (int i = 0; i < n; i++) {
            bb[i][h] = prev;
            if ((aa[i] & (1 << h)) != 0) {
                prev = i;
            }
        }
    }
    return bb;
}

/* 5️⃣ Next position for each bit */
private static int[][] buildNextBitPositions(int[] aa) {
    int n = aa.length;
    int[][] dd = new int[n][K];
    for (int h = 0; h < K; h++) {
        int next = n;
        for (int i = n - 1; i >= 0; i--) {
            dd[i][h] = next;
            if ((aa[i] & (1 << h)) != 0) {
                next = i;
            }
        }
    }
    return dd;
}

/* 6️⃣ Left bound (dp) */
private static int[] computeLeftBound(int[] aa, int[][] bb) {
    int n = aa.length;
    int[] dp = new int[n];
    for (int i = 0; i < n; i++) {
        int best = -1;
        for (int h = 0; h < K; h++) {
            if ((aa[i] & (1 << h)) == 0) {
                best = Math.max(best, bb[i][h]);
            }
        }
        dp[i] = best;
    }
    return dp;
}

/* 7️⃣ Right bound (dq) */
private static int[] computeRightBound(int[] aa, int[][] dd) {
    int n = aa.length;
    int[] dq = new int[n];
    for (int i = n - 1; i >= 0; i--) {
        int best = n;
        for (int h = 0; h < K; h++) {
            if ((aa[i] & (1 << h)) == 0) {
                best = Math.min(best, dd[i][h]);
            }
        }
        dq[i] = best;
    }
    return dq;
}

/* 8️⃣ Final answer calculation */
private static long computeAnswer(int n, int[] pp, int[] dp, int[] dq) {
    long totalSubarrays = (long) n * (n + 1) / 2;
    long subtract = 0;
    for (int i = 0; i < n; i++) {
        int left = Math.max(dp[i], pp[i]);
        subtract += (long) (i - left) * (dq[i] - i);
    }
    return totalSubarrays - subtract;
}

