/**
 * Counts how many times each possible value appears in the input.
 * The method mutates the supplied frequency array.
 */
private static void fillFrequencyArray(long[] freq, InputReader in, int n) {
    for (int i = 0; i < n; ++i) {
        int value = in.nextInt();
        freq[value]++;
    }
}

/**
 * Returns the number of unordered pairs (i, j) such that
 * the bitwise XOR of i and j has exactly k set bits.
 */
private static long countPairsWithBitDifference(long[] freq, int k) {
    long total = 0;
    int len = freq.length;

    for (int i = 0; i < len; ++i) {
        if (freq[i] == 0) continue;
        for (int j = i; j < len; ++j) {
            if (freq[j] == 0) continue;
            if (Integer.bitCount(i ^ j) == k) {
                if (i != j) {
                    total += freq[i] * freq[j];
                } else {
                    total += (freq[i] * (freq[i] - 1)) / 2;
                }
            }
        }
    }
    return total;
}

