/* Returns the length of the shortest segment whose cumulative GCD becomes 1.
   - Returns 0 if any element is already 1.
   - Returns -1 if no such segment exists. */
private static int findShortestGcdOneSegment(int[] arr) {
    int n = arr.length;
    int min = -1;
    int i = 0;

    while (i < n && min != 0) {
        int currentGcd = arr[i];
        int j = i;

        while (j + 1 < n && currentGcd != 1) {
            j++;
            currentGcd = gcd(currentGcd, arr[j]);
        }

        if (currentGcd == 1) {
            int segmentLength = j - i;          // distance, not inclusive of start
            min = (min == -1) ? segmentLength : Math.min(min, segmentLength);
        }
        i++;
    }
    return min;
}

/* Counts how many elements equal 1 in the array */
private static int countOnes(int[] arr) {
    int cnt = 0;
    for (int value : arr) {
        if (value == 1) {
            cnt++;
        }
    }
    return cnt;
}

/* Translates the `min` value into the final answer required by the problem */
private static int computeResult(int min, int n, int[] arr) {
    if (min == 0) {                           // at least one 1 exists
        int ones = countOnes(arr);
        return n - ones;
    }
    if (min == -1) {                          // no segment can reach GCD 1
        return -1;
    }
    // general case: need (min) extra moves plus (n‑1) operations
    return min + n - 1;
}

