private static long[] mergeSortedArrays(long[] arr1, long[] arr2) {
    int i = 0, j = 0, k = 0;
    long[] merged = new long[arr1.length + arr2.length];

    // main merge loop
    while (i < arr1.length && j < arr2.length) {
        if (arr1[i] <= arr2[j]) {
            merged[k++] = arr1[i++];
        } else {
            merged[k++] = arr2[j++];
        }
    }

    // copy any remaining elements from the non‑exhausted array
    copyRemaining(arr1, i, merged, k);
    copyRemaining(arr2, j, merged, k + (arr1.length - i));

    return merged;
}

