 * Copies the tail of {@code source} starting at {@code srcPos}
 * into {@code dest} starting at {@code destPos}.
 */
private static void copyRemaining(long[] source, int srcPos, long[] dest, int destPos) {
    while (srcPos < source.length) {
        dest[destPos++] = source[srcPos++];
    }
}

