/** Builds the two segment trees that use consecutive Fibonacci slices. */
private SegmentTree[] initializeTrees(long[] A) {
    long[] F = getFibonnaci(A.length);
    long[] F1 = Arrays.copyOfRange(F, 0, A.length);
    long[] F2 = Arrays.copyOfRange(F, 1, A.length + 1);
    SegmentTree tree1 = new SegmentTree(A, F1);
    SegmentTree tree2 = new SegmentTree(A, F2);
    return new SegmentTree[]{tree1, tree2};
}

/** Handles operation type 1 – point update on both trees. */
private void processUpdate(int index, long value,
                           SegmentTree tree1, SegmentTree tree2) {
    tree1.update(index, value);
    tree2.update(index, value);
}

/** Handles operation type 2 – range query and answer computation. */
private long processQuery(int l, int r,
                          SegmentTree tree1, SegmentTree tree2) {
    if (l == 0) {
        return tree2.query(l, r);
    }
    long v1 = tree1.query(l, r);
    long v2 = tree2.query(l, r);
    long ans = mod_add(mod_time(F[l], v1), -1L * mod_time(F[l - 1], v2));
    if (l % 2 == 0) {
        ans = -ans;
    }
    return (ans + MOD) % MOD;
}

/** Handles operation type 3 – range addition on both trees. */
private void processRangeAdd(int l, int r, long delta,
                             SegmentTree tree1, SegmentTree tree2) {
    tree1.incrange(l, r, delta);
    tree2.incrange(l, r, delta);
}

