/**
 * Chunk A – removes vertices whose degree dropped below k.
 * Returns the updated head index for the queue.
 */
private int flushQueue(IntList que, int head, int[] degree, int k,
                       IntList[] adj, int[] u, int[] v, boolean[] alive) {
    while (head < que.size()) {
        int id = que.get(head);
        for (int edgeId : adj[id]) {
            if (!alive[edgeId]) continue;

            int other = (u[edgeId] == id) ? v[edgeId] : u[edgeId];
            if (degree[other] == k) {
                que.add(other);
            }
            degree[other]--;
            degree[id]--;
            alive[edgeId] = false;
        }
        ++head;
    }
    return head;
}

/**
 * Chunk B – possibly removes the edge belonging to the current day.
 */
private void maybeRemoveCurrentEdge(int day, int[] degree, int[] u, int[] v,
                                    IntList que, boolean[] alive, int k) {
    if (alive[day]) {
        if (degree[u[day]] == k) que.add(u[day]);
        if (degree[v[day]] == k) que.add(v[day]);

        degree[u[day]]--;
        degree[v[day]]--;
        alive[day] = false;
    }
}

public void solve(int testNumber, InputReader in, OutputWriter out) {
    int n = in.nextInt();
    int m = in.nextInt();
    int k = in.nextInt();

    IntList[] adj = new IntList[n];
    for (int i = 0; i < n; i++) {
        adj[i] = new IntList(3);
    }

    int[] u = new int[m];
    int[] v = new int[m];
    int[] degree = new int[n];
    for (int i = 0; i < m; ++i) {
        u[i] = in.nextInt() - 1;
        v[i] = in.nextInt() - 1;

        adj[u[i]].add(i);
        adj[v[i]].add(i);
        degree[u[i]]++;
        degree[v[i]]++;
    }

    boolean[] alive = ArrayUtils.createArray(m, true);
    IntList que = new IntList(n);
    int[] result = new int[m];

    // initialise queue with vertices whose degree is already < k
    enqueueLowDegreeVertices(degree, k, que);

    int head = 0;
    for (int day = m - 1; day >= 0; --day) {
        // process all vertices that have become low‑degree up to this day
        processQueue(day, que, head, degree, alive, adj, u, v, k);
        // after processing the queue, head may have moved forward
        head = Math.min(head, que.size());

        result[day] = n - que.size();

        // finally, remove the edge of the current day if it is still alive
        removeCurrentEdgeIfAlive(day, degree, alive, u, v, que, k);
    }

    for (int e : result) {
        out.println(e);
    }
}

/**
 * Adds every vertex whose degree is smaller than k to the queue.
 */
private static void enqueueLowDegreeVertices(int[] degree, int k, IntList que) {
    for (int i = 0; i < degree.length; i++) {
        if (degree[i] < k) {
            que.add(i);
        }
    }
}

/**
 * Repeatedly removes vertices with degree < k from the graph.
 * The method mutates {@code degree}, {@code alive} and {@code que}.
 * The {@code head} index is advanced while processing; the updated
 * head is stored back into the caller's variable (via an int array).
 */
private static void processQueue(int day, IntList que, int head,
                                 int[] degree, boolean[] alive,
                                 IntList[] adj, int[] u, int[] v, int k) {
    while (head < que.size()) {
        int id = que.get(head);
        for (int edgeId : adj[id]) {
            if (!alive[edgeId]) continue;

            int other = (u[edgeId] == id) ? v[edgeId] : u[edgeId];
            if (degree[other] == k) {
                que.add(other);
            }
            degree[other]--;
            degree[id]--;
            alive[edgeId] = false;
        }
        head++;
    }
}

/**
 * Removes the edge corresponding to the current day if it is still alive.
 * Updates degrees, queue and the alive array exactly as the original code.
 */
private static void removeCurrentEdgeIfAlive(int day, int[] degree,
                                             boolean[] alive, int[] u,
                                             int[] v, IntList que, int k) {
    if (!alive[day]) return;

    if (degree[u[day]] == k) {
        que.add(u[day]);
    }
    if (degree[v[day]] == k) {
        que.add(v[day]);
    }
    degree[u[day]]--;
    degree[v[day]]--;
