/* ---------- helper methods ---------- */

private static long[] readArray(InputReader sc, int n) {
    long[] arr = new long[n];
    for (int i = 0; i < n; ++i) {
        arr[i] = sc.nextLong();
    }
    return arr;
}

/** Build Pair objects (index, value) and sort them by value. */
private static Pair[] buildSortedPairs(long[] values) {
    int n = values.length;
    Pair[] pairs = new Pair[n];
    for (int i = 0; i < n; ++i) {
        pairs[i] = new Pair(i, values[i]);
    }
    Arrays.sort(pairs, (p1, p2) -> Long.compare(p1.val, p2.val));
    return pairs;
}

/** Dynamic‑programming core of the solution. */
private static long[][] computeDp(Pair[] p) {
    int n = p.length;
    long INF = Long.MAX_VALUE;
    long[][] dp = new long[n][3];
    for (int i = 0; i < n; ++i) {
        Arrays.fill(dp[i], INF);
    }
    dp[0][0] = -p[0].val;

    for (int i = 1; i < n; ++i) {
        if (dp[i - 1][2] != INF)
            dp[i][0] = dp[i - 1][2] - p[i].val + p[i - 1].val;
        if (dp[i - 1][0] != INF)
            dp[i][1] = dp[i - 1][0];
        if (dp[i - 1][2] != INF)
            dp[i][2] = dp[i - 1][2];
        if (dp[i - 1][1] != INF && dp[i - 1][1] < dp[i][2]) {
            dp[i][2] = dp[i - 1][1];
        }
    }
    return dp;
}

/** Reconstruct the team assignment from the DP table. */
private static ReconstructionResult reconstructTeams(Pair[] p, long[][] dp) {
    int n = p.length;
    int[] teams = new int[n];
    int members = 3;
    int curTeam = 1;

    for (int i = n - 1; i >= 0; --i) {
        teams[p[i].ind] = curTeam;
        if (i == 0) break;

        if (members == 3) {
            if (dp[i - 1][1] == dp[i][2])
                members = 2;
        } else if (members == 2) {
            members = 1;
        } else {
            curTeam++;
            members = 3;
        }
    }
    return new ReconstructionResult(teams, curTeam);
}

/* ---------- small data holder ---------- */
private static class ReconstructionResult {
    final int[] teams;
    final int teamCount;

    ReconstructionResult(int[] teams, int teamCount) {
        this.teams = teams;
        this.teamCount = teamCount;
    }
}

public void solve(int testNumber, InputReader sc, PrintWriter out) {
    int n = sc.nextInt();

    // 1️⃣ read numbers and sort them together with their original indices
    Pair[] pairs = readAndSortPairs(sc, n);

    // 2️⃣ compute the DP table that stores the optimal cost for each prefix
    long[][] dp = computeDP(pairs);

    // 3️⃣ rebuild the team assignment from the DP table
    AssignmentResult assignment = assignTeams(pairs, dp);

    // output the minimal total cost and the number of teams
    out.println((dp[n - 1][2] + pairs[n - 1].val) + " " + assignment.teamCount);
    for (int i = 0; i < n; ++i) {
        out.print(assignment.teams[i] + " ");
    }
}

/* ---------- helper 1: input & sorting ---------- */
private Pair[] readAndSortPairs(InputReader sc, int n) {
    long[] a = new long[n];
    for (int i = 0; i < n; ++i) {
        a[i] = sc.nextLong();
    }

    Pair[] p = new Pair[n];
    for (int i = 0; i < n; ++i) {
        p[i] = new Pair(i, a[i]);
    }
    Arrays.sort(p, new Comparator<Pair>() {
        @Override
        public int compare(Pair o1, Pair o2) {
            return Long.compare(o1.val, o2.val);
        }
    });
    return p;
}

/* ---------- helper 2: DP computation ---------- */
private long[][] computeDP(Pair[] p) {
    int n = p.length;
    long[][] dp = new long[n][3];
    for (int i = 0; i < n; ++i) {
        Arrays.fill(dp[i], Long.MAX_VALUE);
    }

    dp[0][0] = -p[0].val;
    for (int i = 1; i < n; ++i) {
        if (dp[i - 1][2] != Long.MAX_VALUE) {
            dp[i][0] = dp[i - 1][2] - p[i].val + p[i - 1].val;
        }
        if (dp[i - 1][0] != Long.MAX_VALUE) {
            dp[i][1] = dp[i - 1][0];
        }
        if (dp[i - 1][2] != Long.MAX_VALUE) {
            dp[i][2] = dp[i - 1][2];
        }
        if (dp[i - 1][1] != Long.MAX_VALUE && dp[i - 1][1] < dp[i][2]) {
            dp[i][2] = dp[i - 1][1];
        }
    }
    return dp;
}

/* ---------- helper 3: team reconstruction ---------- */
private AssignmentResult assignTeams(Pair[] p, long[][] dp) {
    int n = p.length;
    int[] teams = new int[n];
    int members = 3;
    int curTeam = 1;

    for (int i = n - 1; i >= 0; --i) {
        teams[p[i].ind] = curTeam;

        if (i == 0) {
