/**
 * Tries to adjust a[i] so that:
 *   – it becomes a value in [1..M] if it was larger,
 *   – or it is moved to a still‑available value when its current
 *     count exceeds the target v.
 *
 * @return true if a change was made, false otherwise
 */
private static boolean fixElement(int idx, int[] a, int[] c, int M, int v) {
    if (a[idx] > M) {                         // case 1: value out of range
        int target = findAvailable(c, M, v);
        if (target != -1) {
            c[target]++;                     // occupy the new value
            a[idx] = target;
            return true;
        }
    } else if (c[a[idx]] > v) {               // case 2: over‑represented value
        int target = findAvailable(c, M, v);
        if (target != -1) {
            c[target]++;                     // add new occurrence
            c[a[idx]]--;                     // remove old occurrence
            a[idx] = target;
            return true;
        }
    }
    return false;
}

/**
 * Returns the first value j (1 ≤ j ≤ M) whose current count is below v,
 * or -1 if none exists (the algorithm guarantees this never happens).
 */
private static int findAvailable(int[] c, int M, int v) {
    for (int j = 1; j <= M; j++) {
        if (c[j] < v) {
            return j;
        }
    }
    return -1;
}

/** Computes the minimal count among the M buckets. */
private static int computeMin(int[] c, int M) {
    int min = Integer.MAX_VALUE;
    for (int i = 1; i <= M; i++) {
        min = Math.min(c[i], min);
    }
    return min;
}

