private static int handleValueGreaterThanM(int[] a, int[] c, int M, int v, int idx) {
    for (int j = 1; j <= M; j++) {
        if (c[j] < v) {
            c[j]++;          // occupy one slot of value j
            a[idx] = j;      // rewrite the element
            return 1;        // one modification performed
        }
    }
    return 0;                // should never happen with correct input
}

/**
 * Handles a[i] when its current value is in range but its count exceeds v.
 * Moves this occurrence to the first under‑filled value j.
 */
private static int handleOverflowCount(int[] a, int[] c, int M, int v, int idx) {
    for (int j = 1; j <= M; j++) {
        if (c[j] < v) {
            c[j]++;                 // occupy a slot of the new value
            c[a[idx]]--;            // release a slot of the old value
            a[idx] = j;             // rewrite the element
            return 1;               // one modification performed
        }
    }
    return 0;                       // should never happen with correct input
}

/**
 * Computes the smallest frequency among the values 1..M after redistribution.
 */
private static int computeMinimumCount(int[] c, int M) {
    int min = Integer.MAX_VALUE;
    for (int i = 1; i <= M; i++) {
        min = Math.min(c[i], min);
    }
    return min;
}

