public static void main(String[] args) throws FileNotFoundException {
    PrintWriter out = new PrintWriter(System.out);
    Scanner in = new Scanner();
    int n = in.nextInt();
    int q = in.nextInt();
    int[] data = new int[n];
    int[] time = new int[n];
    Arrays.fill(time, -1);
    LinkedList<Point> tmp = new LinkedList<>();
    int total = 0;
    int last = 0;

    for (int i = 0; i < q; i++) {
        int t = in.nextInt();
        int v = in.nextInt();

        if (t == 1) {                     // add operation
            total++;
            handleAdd(v, i, data, tmp);
        } else if (t == 2) {              // reset operation
            total += handleReset(v, i, data, time);
        } else {                          // query operation
            if (last < v) {
                int left = v - last;
                last = v;
                total += processQueue(left, tmp, time, data);
            }
        }
        out.println(total);
    }
    out.close();
}

/* Handles a type‑1 command: record a new point. */
private static void handleAdd(int v, int i, int[] data, LinkedList<Point> queue) {
    data[v - 1]++;                         // increment count for this value
    queue.add(new Point(v - 1, i));        // remember when it was added
}

/* Handles a type‑2 command: reset a value. Returns the change to total. */
private static int handleReset(int v, int i, int[] data, int[] time) {
    time[v - 1] = i;                       // mark the reset moment
    int removed = data[v - 1];             // how many active entries we discard
    data[v - 1] = 0;                       // clear the count
    return -removed;                       // total must be decreased by this amount
}

/* Processes pending queue entries for a query. Returns the change to total. */
private static int processQueue(int count,
                                 LinkedList<Point> queue,
                                 int[] time,
                                 int[] data) {
    int delta = 0;
    for (int j = 0; j < count; j++) {
        Point p = queue.poll();            // remove oldest entry
        if (p == null) break;              // safety guard
        if (time[p.x] < p.y) {             // entry is still valid
            data[p.x]--;
            delta--;                       // one active entry disappears
        }
    }
    return delta;
}

