/* ------------------------------------------------------------------ *
 *  Helper methods – each encapsulates one logical “chunk” of the code *
 * ------------------------------------------------------------------ */

/**
 * Reads the colour grid and the transition grid from the scanner.
 */
private void readGrids(inputClass sc) {
    // colour grid
    char[][] color = new char[n][m];
    for (int i = 0; i < n; i++) {
        color[i] = sc.nextLine().toCharArray();
    }
    // transition grid
    char[][] tra = new char[n][m];
    for (int i = 0; i < n; i++) {
        tra[i] = sc.nextLine().toCharArray();
    }
    // store into instance fields (assumed to exist)
    this.color = color;
    this.tra = tra;
}

/**
 * Builds the binary‑lifting table {@code bin}.
 * The first column is filled using {@code next(i, j)}.
 * Subsequent columns are filled using the standard doubling technique.
 *
 * @return a {@code n*m} × 21 integer matrix.
 */
private int[][] buildBinaryTable() {
    int[][] bin = new int[n * m][21];

    // first column: direct successor
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            bin[i * m + j][0] = next(i, j);
        }
    }

    // binary lifting (doubling)
    for (int step = 1; step < 21; step++) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                int prev = bin[i * m + j][step - 1];
                bin[i * m + j][step] = bin[prev][step - 1];
            }
        }
    }
    return bin;
}

/**
 * Counts distinct final states after 2^20 jumps.
 *
 * @param bin the binary‑lifting table produced by {@link #buildBinaryTable()}.
 * @return an int array where {@code [0]} = number of distinct states,
 *         and {@code [1]} = number of distinct states that start on a '0' cell.
 */
private int[] countDistinctStates(int[][] bin) {
    HashMap<Integer, Integer> allStates = new HashMap<>();
    HashMap<Integer, Integer> zeroStart = new HashMap<>();

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int finalPos = bin[i * m + j][20];
            allStates.put(finalPos, 1);
            if (color[i][j] == '0') {
                zeroStart.put(finalPos, 1);
            }
        }
    }
    return new int[]{allStates.size(), zeroStart.size()};
}

public void solve(int testNumber, inputClass sc, PrintWriter out) {
