    while (t-- > 0) {
        n = sc.nextInt();
        m = sc.nextInt();

        char[][] color = readGrid(sc, n, m);
        tra = readGrid(sc, n, m);          // transition grid

        int[][] bin = buildBinaryLiftingTable(n, m);
        int[] counts = countDistinctRoots(bin, color, n, m);

        out.println(counts[0] + " " + counts[1]);
    }
}

/** Reads a grid of size rows×cols from the scanner. */
private char[][] readGrid(inputClass sc, int rows, int cols) {
    char[][] grid = new char[rows][cols];
    for (int i = 0; i < rows; i++) {
        grid[i] = sc.nextLine().toCharArray();
    }
    return grid;
}

/** Builds the binary‑lifting table used by the algorithm. */
private int[][] buildBinaryLiftingTable(int rows, int cols) {
    int[][] bin = new int[rows * cols][21];

    // level 0
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            bin[i * cols + j][0] = next(i, j);
        }
    }

    // higher levels
    for (int level = 1; level < 21; level++) {
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                int prev = bin[i * cols + j][level - 1];
                bin[i * cols + j][level] = bin[prev][level - 1];
            }
        }
    }
    return bin;
}

/**
 * Counts distinct final positions (the 20‑th ancestor) for all cells
 * and separately for cells whose colour is '0'.
 *
 * @return an int[2] where [0] = total distinct roots,
 *                [1] = distinct roots of colour‑'0' cells.
 */
private int[] countDistinctRoots(int[][] bin, char[][] color, int rows, int cols) {
    java.util.HashSet<Integer> allRoots = new java.util.HashSet<>();
    java.util.HashSet<Integer> zeroRoots = new java.util.HashSet<>();

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            int root = bin[i * cols + j][20];
            allRoots.add(root);
            if (color[i][j] == '0') {
                zeroRoots.add(root);
            }
        }
    }
    return new int[]{allRoots.size(), zeroRoots.size()};
}

