private static String buildMixedPattern(int a, int b, int c) {
    // build the repeated zeros and ones that will be inserted later
    StringBuilder zeros = new StringBuilder();
    for (int i = 0; i < a; i++) {
        zeros.append('0');
    }
    StringBuilder ones = new StringBuilder();
    for (int i = 0; i < c; i++) {
        ones.append('1');
    }

    // build the alternating core: 0 1 0 1 ... up to length b+1
    StringBuilder core = new StringBuilder();
    for (int i = 0; i <= b; i++) {
        core.append((i % 2 == 0) ? '0' : '1');
    }

    // insert the pre‑computed blocks before their first occurrence
    core.insert(core.indexOf('0'), zeros);
    core.insert(core.indexOf('1'), ones);
    return core.toString();
}

