    core.insert(core.indexOf("0"), zero);
    // Insert the one‑buffer before the first '1' (after the zero‑buffer)
    core.insert(core.indexOf("1"), one);

    return core.toString();
}

/* Helper – builds the alternating 0/1 core of length b+1, starting with 0 */
private static String buildAlternatingCore(int b) {
    StringBuilder sb = new StringBuilder();
