/**
 * Builds the alternating 0/1 pattern in matrix x.
 */
private static void initializePattern(int n, int[][] x) {
    x[0][0] = 0;
    for (int i = 1; i < n; i++) {
        x[0][i] = 1 - x[0][i - 1];
    }
    for (int j = 1; j < n; j++) {
        x[j][0] = 1 - x[j - 1][0];
    }
    for (int i = 1; i < n; i++) {
        for (int j = 1; j < n; j++) {
            x[i][j] = 1 - x[i][j - 1];
        }
    }
}

/**
 * Translates the 0/1 pattern into 'W'/'B' characters.
 */
private static void fillCharBoard(int n, int[][] x, char[][] a) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            a[i][j] = (x[i][j] == 0) ? 'W' : 'B';
        }
    }
}

/**
 * Prints the character board line by line.
 */
private static void printBoard(char[][] a) {
    for (char[] row : a) {
        for (char cell : row) {
            System.out.print(cell);
        }
        System.out.println();
    }
}

