/**
 * Handles queries where the interval wraps around the end of the array.
 * The original interval [l1, r1] is split into [l1, n‑1] and [0, r1].
 * Depending on whether a value follows, it performs an update on both parts
 * or prints the minimum of the two range queries.
 */
private static void handleWrapCase(int l1, int r1, StringTokenizer st,
                                   SegmantTreeWithLazy s, PrintWriter pw, int n) {
    int leftStart = l1;
    int leftEnd = n - 1;
    int rightStart = 0;
    int rightEnd = r1;

    if (st.hasMoreTokens()) {
        int c = Integer.parseInt(st.nextToken());
        s.updateRange(leftStart, leftEnd, c);
        s.updateRange(rightStart, rightEnd, c);
    } else {
        int leftMin = s.getRange(leftStart, leftEnd);
        int rightMin = s.getRange(rightStart, rightEnd);
        pw.println(Math.min(leftMin, rightMin));
    }
}

