/**
 * Handles queries where the interval wraps around the end of the array.
 * The original logic:
 *   - treat the interval as two parts: [l1, n‑1] and [0, r1]
 *   - if an extra token exists, perform an update on both parts
 *   - otherwise, output the minimum of the two range queries.
 */
private static void processWrapAround(int l1, int r1, int n,
                                      SegmantTreeWithLazy s, PrintWriter pw,
                                      StringTokenizer st) {
    int l2 = 0;
    int r2 = r1;          // second part ends at the original r1
    int newR1 = n - 1;    // first part ends at the last index

    if (st.hasMoreTokens()) {
        int c = Integer.parseInt(st.nextToken());
        s.updateRange(l1, newR1, c);
        s.updateRange(l2, r2, c);
    } else {
        int min = Math.min(s.getRange(l1, newR1), s.getRange(l2, r2));
        pw.println(min);
    }
}

/**
 * Handles normal (non‑wrapping) queries.
 * If an extra token is present, it is treated as an update value;
 * otherwise the range query result is printed.
 */
private static void processNormal(int l1, int r1,
                                  SegmantTreeWithLazy s, PrintWriter pw,
                                  StringTokenizer st) {
    if (st.hasMoreTokens()) {
        int c = Integer.parseInt(st.nextToken());
        s.updateRange(l1, r1, c);
    } else {
        pw.println(s.getRange(l1, r1));
    }
}

