/**
 * Checks whether the two strings can be built from a common repeating pattern.
 * Returns true when processing may continue; false when the answer is known to be 0.
 */
private static boolean arePrefixesCompatible(String s1, String s2) {
    int n1 = s1.length();
    int n2 = s2.length();

    if (n1 == n2) {
        // identical length – they must be exactly equal
        return s1.equals(s2);
    }
    if (n1 <= n2) {
        // s1 must be a prefix of s2
        if (!s2.substring(0, n1).equals(s1)) {
            return false;
        }
    }
    if (n2 <= n1) {
        // s2 must be a prefix of s1
        if (!s1.substring(0, n2).equals(s2)) {
            return false;
        }
    }
    return true;
}

/**
 * Returns a list of all positive integers that divide both lengths.
 * The list contains each divisor only once.
 */
private static List<Integer> collectCommonDivisors(int n1, int n2) {
    List<Integer> divisors = new ArrayList<>();
    int limit = Math.min(n1, n2);

    for (int d = 1; d <= limit; d++) {
        if (n1 % d == 0 && n2 % d == 0) {
            if (!divisors.contains(d)) {
                divisors.add(d);
            }
            // n1/d is also a divisor of n1; add it when it also divides n2
            int counterpart = n1 / d;
            if (n2 % counterpart == 0 && !divisors.contains(counterpart)) {
                divisors.add(counterpart);
            }
        }
    }
    return divisors;
}

/**
 * Counts how many divisors from the provided list can generate s2 by repeating
 * the corresponding prefix of s1.
 */
private static int countMatchingRepetitions(String s1, String s2, List<Integer> candidates) {
    int n2 = s2.length();
    int matches = 0;

    for (int p : candidates) {
        String token = s1.substring(0, p);
        String repeated = repeat(token, n2 / p);
        if (repeated.equals(s2)) {
            matches++;
        }
    }
    return matches;
}

/**
 * Helper that repeats a given string {@code times} times.
 */
private static String repeat(String str, int times) {
    StringBuilder sb = new StringBuilder(str.length() * times);
    for (int i = 0; i < times; i++) {
        sb.append(str);
    }
    return sb.toString();
}

