/** Returns true when s1 and s2 cannot possibly form a repeat relationship. */
private static boolean isImpossible(String s1, String s2) {
    int n1 = s1.length();
    int n2 = s2.length();

    if (n1 == n2 && !s1.equals(s2)) {
        return true;
    }
    if (n1 <= n2 && !s2.substring(0, n1).equals(s1)) {
        return true;
    }
    if (n2 <= n1 && !s1.substring(0, n2).equals(s2)) {
        return true;
    }
    return false;
}

/** Collects all divisor lengths that divide both n1 and n2 (including complementary divisors of n1). */
private static List<Integer> collectCommonDivisors(int n1, int n2) {
    List<Integer> divisors = new ArrayList<>();
    int limit = Math.min(n1, n2);

    for (int d = 1; d <= limit; d++) {
        if (n1 % d == 0 && n2 % d == 0) {
            if (!divisors.contains(d)) {
                divisors.add(d);
            }
            int complement = n1 / d;
            if (n2 % complement == 0 && !divisors.contains(complement)) {
                divisors.add(complement);
            }
        }
    }
    return divisors;
}

/** Counts how many divisors produce s2 by repeating the prefix of s1 of length p. */
private static int countRepeatingPrefixes(String s1, String s2, List<Integer> divisors) {
    int n2 = s2.length();
    int matches = 0;

    for (int p : divisors) {
        String prefix = s1.substring(0, p);
        int repetitions = n2 / p;
        StringBuilder sb = new StringBuilder(repetitions * p);
        for (int i = 0; i < repetitions; i++) {
            sb.append(prefix);
        }
        if (sb.toString().equals(s2)) {
            matches++;
        }
    }
    return matches;
}

