        }

        // 2️⃣ Find all common divisors of the two lengths
        List<Integer> commonDivisors = findCommonDivisors(s1.length(), s2.length());

        // 3️⃣ Count how many divisors produce a repetition that matches s2
        int result = countMatchingRepetitions(s1, s2, commonDivisors);
