/**
 * Returns true if the shorter string is a prefix of the longer one
 * (or both strings are equal). Otherwise returns false.
 */
private static boolean hasValidPrefix(String s1, String s2) {
    int n1 = s1.length();
    int n2 = s2.length();

    if (n1 == n2) {
        return s1.equals(s2);
    }
    if (n1 < n2) {
        return s2.substring(0, n1).equals(s1);
    }
    // n2 < n1
    return s1.substring(0, n2).equals(s2);
}

/**
 * Returns a list of all integers that divide both n1 and n2.
 * The original algorithm also added the complementary divisor n1/d
 * when it also divides n2.
 */
private static List<Integer> findCommonDivisors(int n1, int n2) {
    List<Integer> divisors = new ArrayList<>();
    int limit = Math.min(n1, n2);
    for (int d = 1; d <= limit; d++) {
        if (n1 % d == 0 && n2 % d == 0) {
            if (!divisors.contains(d)) {
                divisors.add(d);
            }
            int complement = n1 / d;
            if (n2 % complement == 0 && !divisors.contains(complement)) {
                divisors.add(complement);
            }
        }
    }
    return divisors;
}

/**
 * For each divisor p, builds the string consisting of (s1[0:p]) repeated
 * (s2.length()/p) times and checks whether it equals s2.
 * Returns the number of divisors that satisfy this condition.
 */
private static int countMatchingRepetitions(String s1, String s2, List<Integer> divisors) {
    int count = 0;
    int n2 = s2.length();

    for (int p : divisors) {
        String token = s1.substring(0, p);
        int repetitions = n2 / p;
        StringBuilder sb = new StringBuilder(repetitions * p);
        for (int i = 0; i < repetitions; i++) {
            sb.append(token);
        }
        if (sb.toString().equals(s2)) {
            count++;
        }
    }
    return count;
}

