public long nextLong() throws IOException {
    if (!hasNext()) throw new NullPointerException();
    boolean negative = readNegativeSign();
    long magnitude = readUnsignedLong();
    return negative ? -magnitude : magnitude;
}

private boolean readNegativeSign() throws IOException {
    if (buf[now] == '-') {
        // Consume the minus sign; if nothing follows, propagate error
        if (!move()) throw new NumberFormatException();
        return true;
    }
    return false;
}

private long readUnsignedLong() throws IOException {
    long result = 0L;
    while (!isSpaceChar(buf[now])) {
        if (isNum(buf[now])) {
            result = result * 10 + (buf[now] - '0');
        } else {
            throw new NumberFormatException();
        }
        if (!move()) break;
    }
    return result;
}

