		InputReader in = new InputReader();

		int N = in.nextInt();
		int[][] S = new int[N][];
		int[] S_min = new int[N];
		boolean[] ascent = new boolean[N];
		for (int i = 0; i < N; i++) {
			int L = in.nextInt();
			S[i] = new int[L];
			for (int j = 0; j < L; j++) {
				S[i][j] = in.nextInt();
			}
		}
		for (int i = 0; i < N; i++) {
			for (int j = 1; j < S[i].length; j++) {
				if (S[i][j - 1] < S[i][j]) {
					ascent[i] = true;
					break;
				}
			}
		}

		List<Integer> max_list = new ArrayList<>();
		for (int i = 0; i < N; i++) {
			if (ascent[i]) {
				continue;
			}
			int min = Integer.MAX_VALUE;
			int max = Integer.MIN_VALUE;
			for (int j = 0; j < S[i].length; j++) {
				if (min > S[i][j]) {
					min = S[i][j];
				}
				if (max < S[i][j]) {
					max = S[i][j];
				}
			}
			S_min[i] = min;
			max_list.add(max);
		}
		Collections.sort(max_list);

		SortedMap<Integer, Integer> map = new TreeMap<>();
		for (int i = max_list.size() - 1; i >= 0; i--) {
			map.put(max_list.get(i), i);
		}

		long ans = 0;
		for (int i = 0; i < N; i++) {
			if (ascent[i]) {
				ans += N;
				continue;
			}
			SortedMap<Integer, Integer> tailMap = map.tailMap(S_min[i] + 1);
			int idx = tailMap.isEmpty() ? max_list.size() : tailMap.get(tailMap.firstKey());
			ans += N - idx;
		}

		System.out.println(ans);
	}

