private static boolean[] computeAscent(int[][] S) {
    boolean[] ascent = new boolean[S.length];
    for (int i = 0; i < S.length; i++) {
        for (int j = 1; j < S[i].length; j++) {
            if (S[i][j - 1] < S[i][j]) {
                ascent[i] = true;
                break;
            }
        }
    }
    return ascent;
}

/**
 * For each non‑ascent sequence stores its minimum in {@code S_min}
 * and returns a list containing its maximum.
