    for (int i = 0; i < S.length; i++) {
        if (ascent[i]) {
            continue;
        }
        int min = Integer.MAX_VALUE;
        int max = Integer.MIN_VALUE;
        for (int value : S[i]) {
            if (value < min) {
                min = value;
            }
            if (value > max) {
                max = value;
            }
        }
        S_min[i] = min;
        maxList.add(max);
    }
    return maxList;
}

/**
 * Builds a map from each maximum value to its rank (0‑based)
 * when the list of maxima is sorted in ascending order.
 */
private static SortedMap<Integer, Integer> buildMaxRankMap(List<Integer> sortedMaxList) {
    SortedMap<Integer, Integer> map = new TreeMap<>();
    for (int i = sortedMaxList.size() - 1; i >= 0; i--) {
        map.put(sortedMaxList.get(i), i);
    }
    return map;
}

/**
 * Calculates the final answer using the ascent flags,
 * the minima of non‑ascent sequences and the rank map.
 */
private static long computeAnswer(int N, boolean[] ascent, int[] S_min,
                                  SortedMap<Integer, Integer> maxRankMap,
                                  int maxListSize) {
    long ans = 0;
    for (int i = 0; i < N; i++) {
        if (ascent[i]) {
            ans += N;
            continue;
        }
        SortedMap<Integer, Integer> tail = maxRankMap.tailMap(S_min[i] + 1);
        int idx = tail.isEmpty() ? maxListSize : tail.get(tail.firstKey());
        ans += N - idx;
    }
    return ans;
}

