 */
private static boolean[] detectAscent(int[][] S) {
    int N = S.length;
    boolean[] ascent = new boolean[N];
    for (int i = 0; i < N; i++) {
        for (int j = 1; j < S[i].length; j++) {
            if (S[i][j - 1] < S[i][j]) {
                ascent[i] = true;
                break;
            }
        }
    }
    return ascent;
}

/**
 * For non‑ascent sequences computes the minimum value (stores in S_min)
 * and collects the maximum values into a list.
 */
private static List<Integer> collectMinAndMax(int[][] S, boolean[] ascent, int[] S_min) {
    List<Integer> maxList = new ArrayList<>();
    for (int i = 0; i < S.length; i++) {
        if (ascent[i]) {
            continue;
        }
        int min = Integer.MAX_VALUE;
        int max = Integer.MIN_VALUE;
        for (int value : S[i]) {
            if (value < min) {
                min = value;
            }
            if (value > max) {
                max = value;
            }
        }
        S_min[i] = min;
        maxList.add(max);
    }
    Collections.sort(maxList);
    return maxList;
}

/**
 * Builds a map that maps each maximum value to its rank (0‑based from the
 * largest element) – used for fast tail‑map look‑ups.
 */
private static SortedMap<Integer, Integer> buildMaxIndexMap(List<Integer> maxList) {
    SortedMap<Integer, Integer> map = new TreeMap<>();
    for (int i = maxList.size() - 1; i >= 0; i--) {
        map.put(maxList.get(i), i);
    }
    return map;
}

/**
 * Calculates the final answer using the prepared structures.
 */
private static long calculateAnswer(int N, boolean[] ascent, int[] S_min,
                                   SortedMap<Integer, Integer> maxIndexMap, int maxListSize) {
    long ans = 0;
    for (int i = 0; i < N; i++) {
        if (ascent[i]) {
            ans += N;               // every pair with an ascending sequence counts
            continue;
        }
        SortedMap<Integer, Integer> tailMap = maxIndexMap.tailMap(S_min[i] + 1);
        int idx = tailMap.isEmpty() ? maxListSize : tailMap.get(tailMap.firstKey());
        ans += N - idx;
    }
    return ans;
}

