/**
 * Tries to extend a Fibonacci‑like sequence that starts with (x, y).
 *
 * @return the length of the longest sequence found for this ordered pair.
 */
private int exploreSequence(long x, long y,
                            IntHashMap valz,
                            HashSet<Long> posV,
                            IntHashMap map) {
    long key = x + 1_000_000_000L * y;          // unique identifier for ordered pair
    if (posV.contains(key)) {
        // this ordered pair has already been processed
        return 2;
    }
    posV.add(key);
    map.clear();
    map.add(x);
    map.add(y);
    int length = 2;

    while (valz.keySet().contains(x + y) && map.get(x + y) < valz.get(x + y)) {
        map.add(x + y);
        y = x + y;
        x = y - x;                               // previous value of x
        length++;
    }
    return length;
}

