/**
 * Tries to extend a Fibonacci‑like sequence that starts with {@code first, second}.
 * Returns the length of the sequence found, or 0 if the pair has already been processed.
 */
private int evaluateDirection(long first, long second,
                              Set<Long> used,
                              IntHashMap valz,
                              IntHashMap tmp) {
    long uniqueKey = first + 1_000_000_000L * second;
    // If this ordered pair was already examined, skip it.
    if (!used.add(uniqueKey)) {
        return 0;
    }

    tmp.clear();
    tmp.add(first);
    tmp.add(second);
    int length = 2;
    long x = first;
    long y = second;

    while (valz.keySet().contains(x + y) && tmp.get(x + y) < valz.get(x + y)) {
        tmp.add(x + y);
        y = x + y;
        x = y - x;   // old x becomes y‑x (i.e., previous x)
        length++;
    }
    return length;
}

