public void solve(InputReader in, PrintWriter out) {
    long n = in.nextLong();
    long k = in.nextLong();

    // trivial Yes case
    if (isTrivialYes(n, k)) {
        out.println("Yes");
        return;
    }

    // any condition that forces a No answer
    if (isImpossibleByK(n, k) ||
        isImpossibleByEven(n, k) ||
        hasDuplicateRemainder(n, k) ||
        isPerfectSquareWithinK(n, k)) {
        out.println("No");
        return;
    }

    out.println("Yes");
}

/*--- extracted helpers ----------------------------------------------------*/

private boolean isTrivialYes(long n, long k) {
    return n == 1 && k <= 2;
}

private boolean isImpossibleByK(long n, long k) {
    return k >= n;
}

private boolean isImpossibleByEven(long n, long k) {
    return n % 2 == 0 && k > 1;
}

private boolean hasDuplicateRemainder(long n, long k) {
    HashSet<Long> rem = new HashSet<>();
    long limit = Math.min(k, MAX);
    for (long i = 1; i <= limit; i++) {
        long r = n % i;
        if (!rem.add(r)) {       // add returns false if r already present
            return true;         // duplicate found → No
        }
    }
    return false;
}

private boolean isPerfectSquareWithinK(long n, long k) {
    long sqrt = (long) Math.sqrt(n);
    return sqrt * sqrt == n && sqrt <= k;
}

