}

/** Reads n integers from the input scanner. */
private int[] readArray(int n) {
    int[] a = new int[n];
    for (int i = 0; i < n; i++) {
        a[i] = in.nextInt();
    }
    return a;
}

/** Creates a list of consecutive‑value segments from the array. */
private List<Segment> buildSegments(int[] a) {
    List<Segment> segs = new ArrayList<>();
    for (int l = 0, r = 0; l < a.length; ) {
        while (r < a.length && a[r] == a[l]) {
            r++;
        }
        segs.add(new Segment(l, r, a[l], r - l));
        l = r;
    }
    return segs;
}

/** Links each segment with its predecessor and successor. */
private void linkNeighbors(List<Segment> segs) {
    segs.get(0).next = segs.get(1);
    segs.get(segs.size() - 1).prev = segs.get(segs.size() - 2);
    for (int i = 1; i < segs.size() - 1; i++) {
        Segment cur = segs.get(i);
        cur.prev = segs.get(i - 1);
        cur.next = segs.get(i + 1);
    }
}

/** Executes the merging process and returns the number of steps performed. */
private int runSimulation(List<Segment> segs) {
    TreeSet<Segment> set = new TreeSet<>();
    for (Segment seg : segs) {
        set.add(seg);
    }

    int ans = 0;
    while (!set.isEmpty()) {
        ans++;
        Segment seg = set.pollFirst();

        // No neighbours – this is the last segment.
        if (seg.prev == null && seg.next == null) {
            break;
        }

        if (seg.prev == null) {
            // Only a right neighbour.
            seg.next.prev = null;
        } else if (seg.next == null) {
            // Only a left neighbour.
            seg.prev.next = null;
        } else {
            // Both neighbours exist.
            if (seg.prev.x != seg.next.x) {
                // Different values – just bypass the removed segment.
                seg.prev.next = seg.next;
                seg.next.prev = seg.prev;
            } else {
                // Same value – merge left and right neighbours.
                Segment left = seg.prev.prev;
                Segment right = seg.next.next;

                set.remove(seg.prev);
                set.remove(seg.next);

                Segment merged = new Segment(
                        seg.prev.l,
                        seg.next.r,
                        seg.prev.x,
                        seg.prev.sz + seg.next.sz
                );

                merged.prev = left;
                if (left != null) {
                    left.next = merged;
                }
                merged.next = right;
                if (right != null) {
                    right.prev = merged;
                }

                set.add(merged);
            }
        }
    }
    return ans;
}

