    int lastHash = findLastHashPosition(s);
    StringBuilder transformed = new StringBuilder();

    int balance = buildPrefixWithReplacements(s, lastHash, transformed);
    balance = adjustBalanceAfterLastHash(s, lastHash, balance);
    appendClosingParentheses(transformed, balance);
    appendSuffix(s, lastHash, transformed);

    if (!isBalanced(transformed.toString())) {
        out.println(-1);
        return;
    }

    printHashReplacements(s, lastHash, balance);
}

/* 1️⃣ Find the index of the right‑most ‘#’ */
private int findLastHashPosition(String s) {
    int pos = -1;
    for (int i = 0; i < s.length(); i++) {
        if (s.charAt(i) == '#') {
            pos = i;
        }
    }
    return pos;
}

/* 2️⃣ Build the part up to (and including) the last ‘#’, treating ‘#’ as a single ‘)’ */
private int buildPrefixWithReplacements(String s, int lastHash, StringBuilder outBuilder) {
    int balance = 0;
    for (int i = 0; i <= lastHash; i++) {
        char ch = s.charAt(i);
        if (ch == '(') {
            balance++;
            outBuilder.append(ch);
        } else if (ch == '#') {
            // ‘#’ is replaced by one ‘)’
            balance--;          // count it as a closing parenthesis
            outBuilder.append(')');
        } else { // ')'
            balance--;
            outBuilder.append(ch);
        }
    }
    return balance;
}

/* 3️⃣ Update balance for the remaining characters after the last ‘#’ */
private int adjustBalanceAfterLastHash(String s, int lastHash, int currentBalance) {
    for (int i = lastHash + 1; i < s.length(); i++) {
        char ch = s.charAt(i);
        if (ch == '(') {
            currentBalance++;
        } else {
            currentBalance--;
        }
    }
    return currentBalance;
}

/* 4️⃣ Append the extra closing parentheses needed to neutralise the remaining balance */
private void appendClosingParentheses(StringBuilder outBuilder, int count) {
    for (int i = 0; i < count; i++) {
        outBuilder.append(')');
    }
}

/* 5️⃣ Append the unchanged suffix (characters after the last ‘#’) */
private void appendSuffix(String s, int lastHash, StringBuilder outBuilder) {
    for (int i = lastHash + 1; i < s.length(); i++) {
        outBuilder.append(s.charAt(i));
    }
}

/* 6️⃣ Validate that the fully built string is a correct parentheses sequence */
private boolean isBalanced(String str) {
    java.util.Stack<Integer> stack = new java.util.Stack<>();
    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) == '(') {
            stack.push(1);
        } else {
            if (stack.isEmpty()) {
                return false;
            }
            stack.pop();
        }
    }
    return stack.isEmpty();
}

/* 7️⃣ Output the number of ‘)’ each ‘#’ should be replaced with */
private void printHashReplacements(String s, int lastHash, int finalBalance) {
    for (int i = 0; i < s.length(); i++) {
        if (s.charAt(i) == '#') {
            int replacement = (i == lastHash ? finalBalance : 0) + 1;
            out.println(replacement);
        }
    }
}

public void solve() throws IOException {
    String s = in.next();

    int hashPos = findLastHash(s);
    int[] extraClosing = new int[1];               // holds the number of extra ')' to add

    String transformed = buildTransformedString(s, hashPos, extraClosing);

    if (!isBalanced(transformed)) {
        out.println(-1);
        return;
    }

    outputHashReplacements(s, hashPos, extraClosing[0]);
}

/* 1️⃣ Find the position of the last ‘#’ in the input */
private int findLastHash(String s) {
    int pos = -1;
    for (int i = 0; i < s.length(); i++) {
        if (s.charAt(i) == '#') {
            pos = i;
        }
    }
    return pos;
}

/* 2️⃣ Build the string that will be checked for balance.
   While doing so we also compute how many additional ')' are needed
   (stored in extraClosing[0]). */
private String buildTransformedString(String s, int hashPos, int[] extraClosing) {
    StringBuilder sb = new StringBuilder();
    int balance = 0;

    // part before and including the last '#'
    for (int i = 0; i <= hashPos; i++) {
        char ch = s.charAt(i);
        if (ch == '(') {
            balance++;
        } else {
            balance--;                 // ')' or '#'
        }

        if (ch == '#') {
            sb.append(')');
        } else {
            sb.append(ch);
        }
    }

    // remaining part – only updates the balance
    for (int i = hashPos + 1; i < s.length(); i++) {
        char ch = s.charAt(i);
        if (ch == '(') {
            balance++;
        } else {
            balance--;
        }
    }

    // append the extra closing parentheses needed to close all unmatched '('
    for (int i = 0; i < balance; i++) {
        sb.append(')');
    }
    extraClosing[0] = balance;   // remember it for the final output

    // finally, copy the untouched suffix of the original string
    for (int i = hashPos + 1; i < s.length(); i++) {
        sb.append(s.charAt(i));
    }

    return sb.toString();
}

/* 3️⃣ Verify that the transformed string is a correct parenthesis sequence. */
private boolean isBalanced(String str) {
    java.util.Stack<Integer> stack = new java.util.Stack<>();
    for (int i = 0; i < str.length(); i++) {
        char c = str.charAt(i);
        if (c == '(') {
            stack.push(1);
        } else {
            if (stack.isEmpty()) {
                return false;
            }
            stack.pop();
        }
    }
    return stack.isEmpty();
}

/* 4️⃣ Output how many ')' each ‘#’ should represent. */
private void outputHashReplacements(String s, int lastHashPos, int extraClosing) {
    for (int i = 0; i < s.length(); i++) {
        if (s.charAt(i) == '#') {
            int count = (i == lastHashPos ? extraClosing : 0) + 1;
            out.println(count);
        }
    }
}

