/* ---------- 2️⃣ Dijkstra + train edges ---------- */
private static DijkstraResult runDijkstra(List<Map<Integer, Long>> g, int n, int k) throws IOException {
    long[] dist = new long[n];
    int[] parType = new int[n];
    fill(dist, LBIG);

    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[1], b[1]));
    // ordinary source vertex
    dist[0] = 0;
    pq.offer(new long[]{0, 0});

    // train edges are treated as additional sources
    for (int i = 0; i < k; ++i) {
        int s = rni() - 1;
        int y = ni();
        dist[s] = min(dist[s], y);
        parType[s] = 1;               // provisional “train‑used” flag
        pq.offer(new long[]{s, y});
    }

    // classic Dijkstra loop
    while (!pq.isEmpty()) {
        long[] e = pq.poll();
        long d = e[1];
        int v = (int) e[0];
        if (d > dist[v]) continue;

        for (int to : g.get(v).keySet()) {
            long w = g.get(v).get(to);
            if (dist[to] > dist[v] + w) {
                dist[to] = dist[v] + w;
                pq.offer(new long[]{to, dist[to]});
            }
        }
    }
    return new DijkstraResult(dist, parType);
}

/* ---------- 3️⃣ Post‑processing & output ---------- */
private static void outputResult(List<Map<Integer, Long>> g, long[] dist,
                                 int[] parType, int n, int k) {
    // vertices that can be reached through a shortest‑path edge are not train‑used
    for (int i = 0; i < n; ++i) {
        for (int j : g.get(i).keySet()) {
            long w = g.get(i).get(j);
            if (dist[j] == dist[i] + w) {
                parType[j] = 0;
            }
