/* ---------- Chunk 1 ---------- */
private static List<Map<Integer, Long>> buildGraph(int n, int m) throws IOException {
    List<Map<Integer, Long>> g = new ArrayList<>(n);
    for (int i = 0; i < n; ++i) {
        g.add(new HashMap<>());
    }
    for (int i = 0; i < m; ++i) {
        int u = rni() - 1;
        int v = ni() - 1;
        int w = ni();
        // keep the smallest weight for parallel edges
        g.get(u).put(v, Math.min(w, g.get(u).getOrDefault(v, LBIG)));
        g.get(v).put(u, Math.min(w, g.get(v).getOrDefault(u, LBIG)));
    }
    return g;
}

/* ---------- Chunk 2 ---------- */
private static void initialiseDistances(long[] dist) {
    Arrays.fill(dist, LBIG);
    dist[0] = 0;                     // source vertex
}

private static void addTrainEdges(int k, int[] parentType, long[] dist,
                                  PriorityQueue<long[]> pq) throws IOException {
    for (int i = 0; i < k; ++i) {
        int s = rni() - 1;
        int y = ni();
        dist[s] = Math.min(dist[s], y);
        parentType[s] = 1;           // marked as reachable by a train initially
        pq.offer(new long[] {s, dist[s]});
    }
}

/* Dijkstra’s algorithm on the constructed graph */
private static void runDijkstra(List<Map<Integer, Long>> graph, long[] dist,
                                PriorityQueue<long[]> pq) {
    while (!pq.isEmpty()) {
        long[] entry = pq.poll();
        long curDist = entry[1];
        int u = (int) entry[0];
        if (curDist > dist[u]) {
            continue;                // outdated entry
        }
        for (Map.Entry<Integer, Long> e : graph.get(u).entrySet()) {
            int v = e.getKey();
            long w = e.getValue();
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                pq.offer(new long[] {v, dist[v]});
            }
        }
    }
}

/* ---------- Chunk 3 ---------- */
private static void markShortestTreeEdges(List<Map<Integer, Long>> graph, long[] dist,
                                          int[] parentType) {
    for (int i = 0; i < graph.size(); ++i) {
        for (Map.Entry<Integer, Long> e : graph.get(i).entrySet()) {
            int j = e.getKey();
            long w = e.getValue();
            if (dist[j] == dist[i] + w) {
                parentType[j] = 0;    // edge (i, j) belongs to a shortest‑path tree
            }
        }
    }
}

/* Count trains that were not needed */
private static int computeUnusedTrains(int k, int[] parentType) {
    int used = 0;
    for (int flag : parentType) {
        used += flag;
    }
    return k - used;
}

