/**
 * Reads the input, builds a frequency map, writes the frequencies into
 * {@code problem[1..N]}, sorts that segment and returns the effective size N.
 */
private static int buildProblemArray(Scanner sc, long[] problem) {
    Map<Long, Integer> freq = new HashMap<>();
    int n = sc.nextInt();
    for (int i = 1; i <= n; i++) {
        long val = sc.nextInt();
        // merge inserts 1 if absent, otherwise adds 1 to the existing count
        freq.merge(val, 1, Integer::sum);
    }

    int N = 0;
    for (int count : freq.values()) {
        problem[++N] = count;
    }
    // sort only the populated part (indices 1 … N)
    Arrays.sort(problem, 1, N + 1);
    return N;
}

/**
 * Executes the original nested‑loop logic that determines the maximal
 * attainable value {@code ans}.
 */
private static long computeMaximum(long[] problem, int N) {
    long ans = -1;
    if (problem[N] == 1) {
        return 1;
    }

    for (int i = 1; i <= problem[N]; i++) {
        long tot = i;
        ans = Math.max(ans, tot);
        long lastT = i;
        boolean toBreak = false;

        for (int j = N - 1; j >= 1; j--) {
            if (lastT % 2 == 1) {
                ans = Math.max(ans, tot);
                toBreak = true;
            }
            if (toBreak) {
                break;
            }
            lastT /= 2;
            if (problem[j] < lastT) {
                ans = Math.max(ans, tot);
                break;
            }
            tot += lastT;
            ans = Math.max(ans, tot);
        }
    }
