/**
 * Computes the maximal XOR of the two topmost elements of a monotonic decreasing
 * stack while scanning the array in the given direction.
 *
 * @param a      the input array
 * @param start  inclusive start index
 * @param end    exclusive end index (the loop stops before reaching this index)
 * @param step   +1 for forward scan, –1 for reverse scan
 * @return the maximum XOR found during this pass
 */
private static int computePass(int[] a, int start, int end, int step) {
    Stack<Integer> st = new Stack<>();
    int max = 0;
    for (int i = start; i != end; i += step) {
        while (!st.isEmpty() && a[i] > st.peek()) {
            st.pop();
        }
        st.push(a[i]);
        if (st.size() >= 2) {
            int t1 = st.pop();
            int t2 = st.pop();
            max = Math.max(max, t1 ^ t2);
            st.push(t2);
            st.push(t1);
        }
    }
    return max;
}

