/**
 * Scans the string once and records:
 *   - first and last positions of any non‑dot character,
 *   - the first occurrence of 'R',
 *   - the leftmost occurrence of 'L'.
 */
private static Indices extractIndices(int N, String s) {
    int startIndex = -1;
    int endIndex = -1;
    int rIndex = -1;
    int lIndex = N + 1;

    for (int i = 1; i <= N; i++) {
        char ch = s.charAt(i - 1);
        if (ch != '.') {
            if (startIndex == -1) {
                startIndex = i;
            }
            endIndex = i;

            if (ch == 'R' && rIndex == -1) {
                rIndex = i;
            } else if (ch == 'L') {
                lIndex = Math.min(lIndex, i);
            }
        }
    }
    return new Indices(startIndex, endIndex, rIndex, lIndex);
}

/**
 * Computes the start and end values based on the collected indexes.
 * Returns an array where result[0] = start and result[1] = end.
 */
private static int[] computeInterval(Indices idx, int N) {
    int start;
    int end;

    if (idx.lIndex == N + 1) {                // no 'L' found
        start = idx.startIndex;
        end = idx.endIndex + 1;
    } else if (idx.rIndex == -1) {            // no 'R' found
        start = idx.endIndex;
        end = idx.startIndex - 1;
    } else {                                  // both 'R' and 'L' exist
        start = idx.startIndex;
        end = idx.lIndex - 1;
    }
    return new int[]{start, end};
}

/** Simple holder for the indexes gathered during the scan. */
private static class Indices {
    final int startIndex;
    final int endIndex;
    final int rIndex;
    final int lIndex;

    Indices(int startIndex, int endIndex, int rIndex, int lIndex) {
        this.startIndex = startIndex;
        this.endIndex = endIndex;
        this.rIndex = rIndex;
        this.lIndex = lIndex;
    }
}

