/** Builds the adjacency list where `parents[v]` contains all vertices u such that (u -> v) exists. */
private static ArrayList<Integer>[] buildParents(FastScanner sc, int n, int m) {
    @SuppressWarnings("unchecked")
    ArrayList<Integer>[] parents = new ArrayList[n + 1];
    Arrays.setAll(parents, i -> new ArrayList<>());
    for (int i = 0; i < m; i++) {
        int u = sc.nextInt();
        int v = sc.nextInt();
        parents[v].add(u);
    }
    return parents;
}

/** Holds the outcome of the graph evaluation: number of deleted vertices and their list as a string. */
private static class DeletionResult {
    final int count;
    final String deleted;

    DeletionResult(int count, String deleted) {
        this.count = count;
        this.deleted = deleted;
    }
}

/** Executes the original type‑propagation algorithm and returns the result. */
private static DeletionResult evaluateGraph(ArrayList<Integer>[] parents) {
    StringBuilder deleted = new StringBuilder();
    int[] type = new int[parents.length];
    int ct = 0;

    for (int root = 1; root < parents.length; root++) {
        for (int p : parents[root]) {
            if (type[p] == 0) {
                type[root] = Math.max(type[root], 1);
            } else if (type[p] == 1) {
                type[root] = 2;
            }
        }
        if (type[root] == 2) {
            ct++;
            deleted.append(root).append(' ');
        }
    }
    return new DeletionResult(ct, deleted.toString());
}

