    buildGraphAndJumpInfo(n, m, in, g, canJumpOver, last);

    boolean[] blockers = new boolean[n];
    int nBlockers = 0;
    int ans = 0;

    for (int i = n - 2; i >= 0; i--) {
        int node = p[i] - 1;
        if (!canJumpOver[node]) {
            blockers[node] = true;
            nBlockers++;
        } else {
            if (isSwappable(node, g, blockers, nBlockers)) {
                ans++;
            } else {
                blockers[node] = true;
                nBlockers++;
            }
        }
    }

    out.println(ans);
}

/**
 * Fills adjacency lists and records vertices that can jump directly to the
 * final position.
 */
private void buildGraphAndJumpInfo(int n, int m, FastScanner in,
                                   List<Integer>[] g, boolean[] canJumpOver,
                                   int last) {
    for (int i = 0; i < n; i++) {
        g[i] = new LinkedList<>();
    }
    for (int i = 0; i < m; i++) {
        int u = in.ni() - 1;
        int v = in.ni() - 1;
        g[u].add(v);
        if (v == last) {
            canJumpOver[u] = true;
        }
    }
}

/**
 * Returns true if every outgoing edge of {@code node} leads to a blocker,
 * i.e. the number of blocked neighbours equals the current total of blockers.
 */
private boolean isSwappable(int node, List<Integer>[] g,
                            boolean[] blockers, int totalBlockers) {
    int swaps = 0;
    for (int v : g[node]) {
        if (blockers[v]) {
            swaps++;
        }
    }
    return swaps == totalBlockers;
}

