 * @param c original character array
 * @param i 1‑based start position
 * @param n length of the array
 * @return the constructed candidate array
 */
private static char[] buildCandidate(char[] c, int i, int n) {
    int len = n - i + 1;                 // length of the suffix that stays in order
    char[] x = new char[n];

    // copy the suffix (positions i‑1 … n‑1) to the front of x
    for (int j = i - 1; j < n; j++) {
        x[j - i + 1] = c[j];
    }

    if (len % 2 == 0) {
        // even length: copy the prefix unchanged after the suffix
        for (int j = 0; j < i - 1; j++) {
            x[len + j] = c[j];
        }
    } else {
        // odd length: copy the prefix in reverse order after the suffix
        int ind = len;
        for (int j = i - 2; j >= 0; j--) {
            x[ind++] = c[j];
        }
    }
    return x;
}

