/**
 * Bump 1 – reads the input values, builds the frequency array {@code needOnF}
 * and the list of distinct values {@code unique}.
 */
private void populateFrequencyAndList(int n, int[] f, int[] needOnF, ArrayList<Integer> unique)
{
    for (int i = 0; i < n; i++)
    {
        f[i] = in.nextInt();
        needOnF[f[i]]++;
        if (!unique.contains(f[i]))
        {
            unique.add(f[i]);
        }
    }
