/**
 * Bump 2 – performs the core calculation that was originally inside the
 * while‑loop and returns the final {@code sum}.
 */
private int computeSum(ArrayList<Integer> values, int[] haveOnF, int[] needOnF, int k)
{
    int sum = 0;
    int rem = haveOnF[0] - needOnF[0];
    int ind = 0;
    int fl = 0;

    ind++;                               // move to the first distinct value after 0
    while (rem > 0 && ind < values.size())
    {
        fl = values.get(ind);
        int take = Math.min(rem, k);
        rem -= take;
        sum += (fl - values.get(ind - 1));
        haveOnF[fl] += take;
        haveOnF[values.get(ind - 1)] -= take;

        if (rem > 0)
        {
            sum += (fl - values.get(ind - 1));
        }
        else
        {
            rem = haveOnF[fl] - needOnF[fl];
            ind++;
        }
    }
    sum += values.get(ind - 1) - values.get(0);
    return sum;
}

