/** Reads exactly {@code count} lines from {@code in}. */
private String[] readWords(MyReader in, int count) throws IOException {
    String[] result = new String[count];
    for (int i = 0; i < count; i++) {
        result[i] = in.readLine();
    }
    return result;
}

/** Fills the 26×26 matrix with {@code Integer.MIN_VALUE}. */
private void initializeMatrix(int[][] m) {
    for (int i = 0; i < 26; i++) {
        for (int j = 0; j < 26; j++) {
            m[i][j] = Integer.MIN_VALUE;
        }
    }
}

/** Core DP update: for each word, propagate its length through the matrix. */
private void updateMatrixWithWords(String[] words, int[][] m) {
    for (String w : words) {
        int first = w.charAt(0) - 'a';
        int last  = w.charAt(w.length() - 1) - 'a';
        // extend existing paths that end with ‘first’
        for (int j = 0; j < 26; j++) {
            int candidate = m[j][first] + w.length();
            if (candidate > m[j][last]) {
                m[j][last] = candidate;
            }
        }
        // start a new path directly from first to last
        if (m[first][last] < w.length()) {
            m[first][last] = w.length();
        }
    }
}

/** Returns the largest value on the diagonal of the matrix. */
private int computeMaxDiagonal(int[][] m) {
    int max = 0;
    for (int i = 0; i < 26; i++) {
        if (m[i][i] > max) {
            max = m[i][i];
        }
    }
    return max;
}

