/* ---- extracted helpers ---- */

private static long partitionBits(long x, int[] free, int[] must) {
    int freeIdx = 0, mustIdx = 0;
    long ans = 0;
    for (int i = 63; i >= 0; i--) {
        if (BitUtil.test(x, i)) {
            ans |= 1L << i;
            must[mustIdx++] = i;
        } else {
            free[freeIdx++] = i;
        }
    }
    return ans;
