private static long[] buildReducedArray(long[] original, int[] mustBits) {
    int n = original.length;
    long[] reduced = new long[n];
    for (int i = 0; i < n; i++) {
        long v = original[i];
        for (int bit : mustBits) {
            v = removeBit(v, bit);
        }
        reduced[i] = v;
    }
    return reduced;
