private static long computeMaximumXor(long[] values) {
    ArrayList<Long> basis = new ArrayList<>();
    for (long v : values) {
        for (long b : basis) {
            v = Math.min(v, v ^ b);
        }
        if (v != 0) {
            basis.add(v);
        }
    }
    Collections.sort(basis, Collections.reverseOrder());

    long max = 0;
    for (long b : basis) {
        max = Math.max(max, max ^ b);
    }
    return max;
}

private static long composeH(long y, int[] freeBits) {
    long h = 0;
    for (int i = 0; i < freeBits.length; i++) {
        if (BitUtil.test(y, i)) {
            h |= 1L << freeBits[freeBits.length - 1 - i];
