public static void solve(StringBuilder out) {
    int n = In.ni();
    long[] a = In.nl(n);

    // Chunk 1 – compute ans and split bit positions into rs (zero bits) and rm (one bits)
    long[] rs = new long[64];
    long[] rm = new long[64];
    int rsSize = 0, rmSize = 0;
    long ans = computeAnsAndCollectMasks(a, rs, rm);
    // shrink the temporary arrays to their actual size
    int[] zeroBits = new int[rsSize = (int) rsSize];
    int[] oneBits  = new int[rmSize = (int) rmSize];
    for (int i = 0; i < rsSize; i++) zeroBits[i] = (int) rs[i];
    for (int i = 0; i < rmSize; i++) oneBits[i] = (int) rm[i];

    // Chunk 2 – clear the one‑bits from every element and build the basis
    long[] b = clearOneBits(a, oneBits);
    List<Long> basis = buildLinearBasis(b);

    // Chunk 3 – maximum XOR from the basis and reconstruction of the missing part
    long y = maxXorFromBasis(basis);
    long h = rebuildMissingPart(y, zeroBits);
    out.append(ans + (h << 1));
}

/* ----------- Chunk 1 helpers ----------------------------------- */
private static long computeAnsAndCollectMasks(long[] a, long[] rs, long[] rm) {
    long x = 0;
    for (long e : a) x ^= e;               // overall XOR of the input
    long ans = 0;
    int ri = 0, mi = 0;
    for (int i = 63; i >= 0; i--) {
        if (BitUtil.test(x, i)) {
            ans |= 1L << i;
            rm[mi++] = i;
        } else {
            rs[ri++] = i;
        }
    }
    // store the actual sizes in the first element of the buffers (used later)
    rs[0] = ri;
    rm[0] = mi;
    return ans;
}

/* ----------- Chunk 2 helpers ----------------------------------- */
private static long[] clearOneBits(long[] a, int[] oneBits) {
    long[] b = new long[a.length];
    for (int i = 0; i < a.length; i++) {
        long v = a[i];
        for (int bit : oneBits) {
            v = removeBit(v, bit);
        }
        b[i] = v;
    }
    return b;
}

private static List<Long> buildLinearBasis(long[] values) {
    List<Long> basis = new ArrayList<>();
    for (long v : values) {
        for (long b : basis) {
            v = Math.min(v, v ^ b);
        }
        if (v != 0) {
            basis.add(v);
        }
    }
    // sort descending to make the later max‑xor step deterministic
    basis.sort(Collections.reverseOrder());
    return basis;
}

/* ----------- Chunk 3 helpers ----------------------------------- */
private static long maxXorFromBasis(List<Long> basis) {
    long y = 0;
    for (long e : basis) {
        y = Math.max(y, y ^ e);
    }
    return y;
}

private static long rebuildMissingPart(long y, int[] zeroBits) {
    long h = 0;
    // zeroBits are stored from most‑significant to least‑significant;
    // we need to map the i‑th set bit of y to the appropriate position.
    for (int i = 0; i < zeroBits.length; i++) {
        if (BitUtil.test(y, i)) {
            h |= 1L << zeroBits[zeroBits.length - 1 - i];
        }
    }
    return h;
}

