/* -------------------------------------------------------------
   Helper: perform all work that belongs to a single dequeued node
   ------------------------------------------------------------- */
private static void processNode(int id) {
    // accumulate the answer for this node
    for (int i = 1; i <= k; i++) {
        answer += node[id].cost[i];
    }

    int father = node[id].father;

    long[] nb   = new long[k + 1];
    long[] cost = new long[k + 1];

    // merge current node's data into temporary arrays
    betweenfather_sun(nb, cost, node[id].nb, node[id].cost);

    // combine temporary arrays with the father's aggregates
    betweensuns(node[father].nb, node[father].cost, nb, cost);

    // finally merge the current node directly into the father
    betweenfather_sun(node[father].nb, node[father].cost, node[id].nb, node[id].cost);

    // mark that one more child of the father has been processed
    node[father].finiched++;
}

