   ------------------------------------------------------------- */
private static void maybeEnqueueFather(int id, LinkedList<Integer> next) {
    int father = node[id].father;

    if (father == 1) {
        if (node[father].finiched == node[father].neighbers.size()) {
            next.add(father);
        }
    } else if (node[father].finiched == node[father].neighbers.size() - 1) {
        next.add(father);
    }
