/**
 * Returns the minimum number of bracket replacements required to make the
 * string a correct bracket sequence, or -1 if it is impossible.
 */
private int computeMinChanges(String s) {
    Stack<Character> stack = new Stack<>();
    int min = 0;

    for (int i = 0; i < s.length(); ++i) {
        char c = s.charAt(i);
        if (isOpening(c)) {
            stack.push(c);
        } else { // closing bracket
            if (stack.isEmpty()) {
                return -1; // impossible
            }
            char open = stack.pop();
            if (!isMatching(open, c)) {
                // a mismatch that cannot be fixed by swapping the same type
                // (e.g., '(' with ']') counts as one replacement
                min++;
            }
        }
    }

    // any leftover opening brackets make the string impossible
    return stack.isEmpty() ? min : -1;
}

/** Returns true if the character is one of '(', '[', '{', '<'. */
private boolean isOpening(char c) {
    return "([{<".indexOf(c) >= 0;
}

/** Returns true if the pair (open, close) is a correct matching pair. */
private boolean isMatching(char open, char close) {
    return (open == '(' && close == ')')
        || (open == '[' && close == ']')
        || (open == '{' && close == '}')
        || (open == '<' && close == '>');
}

