/**
 * Populates dpLeft where dpLeft[i] is the length of the longest prefix of t
 * that can be matched using s[0..i] (inclusive) scanning from left to right.
 */
private static void fillDpLeft(char[] s, char[] t, int[] dpLeft) {
    int n = s.length;
    int m = t.length;
    int i = 0, j = 0, prev = 0;
    while (i < n && j < m) {
        if (s[i] == t[j]) {
            dpLeft[i++] = ++j;
            prev++;
        } else {
            dpLeft[i++] = prev;
        }
    }
    // If t is exhausted early, the rest of dpLeft should keep the last value.
    while (i < n) {
        dpLeft[i++] = prev;
    }
}

/**
 * Populates dpRight where dpRight[i] is the length of the longest suffix of t
 * that can be matched using s[i..n‑1] scanning from right to left.
 */
private static void fillDpRight(char[] s, char[] t, int[] dpRight) {
    int i = s.length - 1;
    int j = t.length - 1;
    int prev = 0;
    while (i >= 0 && j >= 0) {
        if (s[i] == t[j]) {
            dpRight[i--] = t.length - j;
            j--;
            prev++;
        } else {
            dpRight[i--] = prev;
        }
    }
    // If t is exhausted early, the remaining positions keep the last value.
    while (i >= 0) {
        dpRight[i--] = prev;
    }
}

