    for (int i = 0; i < N; ++i) {
        if (visited[i]) continue;

        int count = 1;
        visited[i] = true;
        ArrayDeque<Integer> q = new ArrayDeque<>();
        q.add(i);

        while (!q.isEmpty()) {
            int pos = q.poll();
            for (int j = 0; j < N; ++j) {
                if (!visited[j] && g[pos][j]) {
                    ++count;
                    q.add(j);
                    visited[j] = true;
                }
            }
        }

        if (count % 2 == 0) {
            ++ec;
        } else {
            ++oc;
        }
    }
    return new int[]{ec, oc};
}

/**
 * Returns the final game outcome.
 *
 * @param taroEven true if the expression ((N*(N-1))/2 - E) is odd
 * @param ec number of even‑sized components
 * @param oc number of odd‑sized components
 * @return true if Taro can force a win, false otherwise
 */
private static boolean isWinningPosition(boolean taroEven, int ec, int oc) {
    if (taroEven) {
        int turnTaro = ((ec + oc) - 1) / 2;
        return oc <= turnTaro * 2;
    } else {
        int turnHanako = ((ec + oc) - 2) / 2;
        return !(oc <= turnHanako * 2);
    }
}

