/* -------------------------------------------------------------------------- *
 * Helper structures and functions
 * -------------------------------------------------------------------------- */
private static class InputData {
    int n, m, k;
    long[] a;
    long[][] v;
}

/** Reads all input and returns a filled {@link InputData} instance. */
private static InputData readInput(BufferedReader br) throws IOException {
    InputData d = new InputData();
    StringTokenizer st;

    // first line: n m k
    st = getst(br);
    d.n = nextInt(st);
    d.m = nextInt(st);
    d.k = nextInt(st);

    // array a
    d.a = new long[d.n];
    st = getst(br);
    for (int i = 0; i < d.n; i++) {
        d.a[i] = nextInt(st);
    }

    // matrix v (sparse, only k entries)
    d.v = new long[d.n][d.n];
    for (int i = 0; i < d.k; i++) {
        st = getst(br);
        int from = nextInt(st) - 1;
        int to   = nextInt(st) - 1;
        long w   = nextInt(st);
        d.v[from][to] = w;
    }
    return d;
}

/**
 * Executes one DP iteration. It updates {@code dp} using {@code next},
 * swaps the maps and clears the old map for the next round.
 *
 * @return the new dp map for the next iteration
 */
private static HashMap<Integer, long[]> runIteration(
        HashMap<Integer, long[]> dp,
        HashMap<Integer, long[]> next,
        long[] a,
        long[][] v,
        int n) {

    for (int mask : dp.keySet()) {
        for (int j = 0; j < n; j++) {
            int newMask = mask | (1 << j);
            if (newMask == mask) continue;               // already selected

            // ensure a bucket for the new mask exists
            if (!next.containsKey(newMask)) {
                next.put(newMask, new long[n]);
                Arrays.fill(next.get(newMask), -1);
            }

            long best = 0;
            long[] prevValues = dp.get(mask);
            for (int t = 0; t < n; t++) {
                if (prevValues[t] >= 0) {
                    best = Math.max(best, prevValues[t] + v[t][j]);
                }
            }
            best += a[j];

            long[] bucket = next.get(newMask);
            bucket[j] = Math.max(bucket[j], best);
        }
    }

    // swap maps and clear the old one
    HashMap<Integer, long[]> temp = dp;
    dp = next;
    next = temp;
    next.clear();
    return dp;
}

/** Returns the maximal value stored in any DP state. */
private static long computeAnswer(HashMap<Integer, long[]> dp) {
    long ans = 0;
    for (int mask : dp.keySet()) {
        for (long v : dp.get(mask)) {
            ans = Math.max(ans, v);
        }
    }
    return ans;
}

