/* ----------- helper methods ------------------------------------------------ */

private static long[] readArray(BufferedReader br, int n) throws IOException {
    StringTokenizer st = getst(br);
    long[] arr = new long[n];
    for (int i = 0; i < n; i++) {
        arr[i] = nextInt(st);
