private static long[][] readValues(BufferedReader br, int k, int n) throws IOException {
    long[][] matrix = new long[n][n];
    for (int i = 0; i < k; i++) {
        StringTokenizer st = getst(br);
        int from = nextInt(st) - 1;
        int to   = nextInt(st) - 1;
        matrix[from][to] = nextInt(st);
    }
