}

/**
 * Creates the initial DP map with a single state (mask = 0) whose
 * value array is filled with -1.
 */
private static HashMap<Integer, long[]> createInitialDP(int n) {
    HashMap<Integer, long[]> dp = new HashMap<>();
    dp.put(0, new long[n]);
    Arrays.fill(dp.get(0), -1L);
    return dp;
}

/**
 * Executes the DP for {@code m} steps. The method mutates {@code dp}
 * and {@code next} maps – after the call {@code dp} contains the final
 * states.
 */
private static void runDP(HashMap<Integer, long[]> dp,
                          HashMap<Integer, long[]> next,
                          long[][] v,
                          long[] a,
                          int m,
                          int n) {

    for (int step = 0; step < m; step++) {
        for (int mask : dp.keySet()) {
            for (int j = 0; j < n; j++) {
                int newMask = mask | (1 << j);
                if (newMask == mask) continue;               // already visited

                // ensure a container for the new mask
                if (!next.containsKey(newMask)) {
                    long[] init = new long[n];
                    Arrays.fill(init, -1L);
                    next.put(newMask, init);
                }

                long best = 0L;
                long[] prevVals = dp.get(mask);
                for (int t = 0; t < n; t++) {
                    if (prevVals[t] >= 0) {
                        best = Math.max(best, prevVals[t] + v[t][j]);
                    }
                }
                best += a[j];

                long[] target = next.get(newMask);
                target[j] = Math.max(target[j], best);
            }
        }

        // rotate maps: dp <- next, next <- empty
        HashMap<Integer, long[]> temp = dp;
        dp = next;
        next = temp;
        next.clear();

        // optional debug output
        if (DEBUG) {
            for (int mask : dp.keySet()) {
                debug(Integer.toString(mask, 2) + " " + Arrays.toString(dp.get(mask)));
            }
            debug("");
        }
    }
}

/**
 * Returns the maximum value among all DP states.
 */
private static long computeMax(HashMap<Integer, long[]> dp, int n) {
    long ans = 0L;
    for (int mask : dp.keySet()) {
        long[] vals = dp.get(mask);
        for (int i = 0; i < n; i++) {
            ans = Math.max(ans, vals[i]);
        }
    }
    return ans;
}

