private static Map<Integer, long[]> initDp(int n) {
    Map<Integer, long[]> dp = new HashMap<>();
    dp.put(0, new long[n]);
    Arrays.fill(dp.get(0), -1);
    return dp;
}

/**
 * Executes the core DP loop for {@code m} iterations.
 * Returns the map that holds the DP results after the last iteration.
 */
private static Map<Integer, long[]> runIterations(
        int n, int m, long[] a, long[][] v,
        Map<Integer, long[]> dp, Map<Integer, long[]> next) {

    for (int step = 0; step < m; step++) {
        for (int mask : dp.keySet()) {
            for (int j = 0; j < n; j++) {
                int newMask = mask | (1 << j);
