                    }
                }
                best += a[j];

                long[] targetRow = next.get(newMask);
                targetRow[j] = Math.max(targetRow[j], best);
            }
        }

        // swap containers for the next iteration
        Map<Integer, long[]> tmp = dp;
        dp = next;
        next = tmp;
        next.clear();

        // optional debug output
        if (DEBUG) {
            for (int mask : dp.keySet()) {
                debug(Integer.toString(mask, 2) + " " + Arrays.toString(dp.get(mask)));
            }
            debug("");
        }
    }
    return dp;
}

/** Returns the maximum value among all DP states. */
private static long computeAnswer(Map<Integer, long[]> dp, int n) {
    long ans = 0;
    for (long[] row : dp.values()) {
        for (int i = 0; i < n; i++) {
            ans = Math.max(ans, row[i]);
        }
    }
