/** Chunk 1 – allocate and seed the helper arrays. */
private void initializeSieve(int n) {
    isP = new boolean[n];
    S   = new int[n];

    // Initialise odd indices
    for (int i = 3; i < n; i += 2) {
        isP[i] = true;
        S[i - 1] = 2;   // smallest factor for even numbers > 2
        S[i] = i;       // each odd starts as its own smallest factor
    }

    // Initialise the even prime 2
    isP[2] = true;
    S[1] = 1;
}

/** Chunk 2 – classic Eratosthenes marking loop. */
private void runSieve(int n) {
    for (int i = 3; i * i <= n; i += 2) {
        if (!isP[i]) {
            continue;
        }
        for (int j = i * i; j < n; j += i) {
            isP[j] = false;
            if (S[j] == j) {
                S[j] = i;       // store smallest prime factor
            }
        }
    }
}

/** Chunk 3 – collect found primes into P and return the count. */
private int buildPrimeArray(int n) {
    P = new int[n];
    P[0] = 2;
    int count = 1;               // we already placed prime 2

    for (int i = 3; i < n; i += 2) {
        if (isP[i]) {
            P[count++] = i;
        }
    }

    // Trim the array to the actual number of primes
    P = java.util.Arrays.copyOf(P, count);
    return count;
}

