void solve() {
    int n = in.nextInt();
    in.nextLine();
    String s = in.nextLine();
    String t = in.nextLine();

    Counts counts = countColumns(s, t, n * 2);
    GameState state = initGameState(counts.col3);
    state = playTurns(state, counts);
    // add any remaining columns after the turn‑based loop
    state.sum1 += counts.col1;
    state.sum2 += counts.col2;

    printResult(state.sum1, state.sum2);
}

/* ---------- helper data structures ---------- */
private static class Counts {
    int col1; // s=1, t=0
    int col2; // s=0, t=1
    int col3; // s=1, t=1
}

/* Holds the mutable parts of the game */
private static class GameState {
    int res;   // whose turn it is: 1 = First, 2 = Second
    int sum1;  // points of the first player
    int sum2;  // points of the second player
}

/* ---------- extracted chunks ---------- */

/** Counts occurrences of the three column types. */
private static Counts countColumns(String s, String t, int length) {
    Counts c = new Counts();
    char[] ss = s.toCharArray();
    char[] tt = t.toCharArray();
    for (int i = 0; i < length; i++) {
        if (ss[i] == '1' && tt[i] == '1') {
            c.col3++;
        } else {
            if (ss[i] == '1' && tt[i] == '0') {
                c.col1++;
            }
            if (tt[i] == '1' && ss[i] == '0') {
                c.col2++;
            }
        }
    }
    return c;
}

/** Initializes the starting player and the first player's initial score
 *  based on the parity of col3. */
private static GameState initGameState(int col3) {
    GameState gs = new GameState();
    if (col3 % 2 == 1) {
        gs.res = 2;   // second player moves first
        gs.sum1 = 1;  // first player already gains one point
    } else {
        gs.res = 1;   // first player moves first
        gs.sum1 = 0;
    }
    gs.sum2 = 0;
    return gs;
}

/** Simulates the alternating picking of columns (col1 vs col2). */
private static GameState playTurns(GameState gs, Counts c) {
    while (c.col1 != 0 || c.col2 != 0) {
        if (gs.res == 1) {               // first player's turn
            if (c.col1 == 0) {
                break;
            }
            c.col1--;
            gs.sum1++;
            gs.res = 2;                  // next turn is second player's
        } else {                         // second player's turn
            if (c.col2 == 0) {
                break;
            }
            c.col2--;
            gs.sum2++;
            gs.res = 1;                  // next turn is first player's
        }
    }
    // if the loop ended because first player cannot move but second still has columns
    if (gs.res == 1 && c.col2 > 0) {
        c.col2--;
    }
    return gs;
}

/** Prints the final outcome based on the two scores. */
private static void printResult(int sum1, int sum2) {
    if (sum1 == sum2) {
        out.println("Draw");
    } else if (sum1 > sum2) {
        out.println("First");
    } else {
        out.println("Second");
    }
}

