    int[][][] maxPosition = new int[n + 1][toChange + 1][2];
    ArrayUtils.fill(minPosition, INF);
    ArrayUtils.fill(maxPosition, -INF);
    Arrays.fill(minPosition[0][0], 0);
    Arrays.fill(maxPosition[0][0], 0);

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j <= toChange; j++) {
            for (int k = 0; k < 2; k++) {
                // case: we do NOT change the i‑th command
                applyNoChange(i, j, k, commands, minPosition, maxPosition);

                // case: we change the i‑th command (only possible if j > 0)
                if (j > 0) {
                    applyWithChange(i, j, k, commands, minPosition, maxPosition);
                }
            }
        }
    }

    int answer = 0;
    for (int j = toChange % 2; j <= toChange; j += 2) {
        for (int k = 0; k < 2; k++) {
            answer = Math.max(answer, -minPosition[n][j][k]);
            answer = Math.max(answer, maxPosition[n][j][k]);
        }
    }
    out.println(answer);
}

/**
 * Updates {@code minPosition[i][j][k]} and {@code maxPosition[i][j][k]} when the
 * i‑th command is taken as‑is (no mutation).
 */
private static void applyNoChange(int i, int j, int k,
                                 char[] commands,
                                 int[][][] minPos,
                                 int[][][] maxPos) {
    if (commands[i] == 'T') {
        // turn: direction flips, position stays the same
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j][1 - k]);
    } else {
        // move forward in current direction
        int delta = toward(k);
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j][k] + delta);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j][k] + delta);
    }
}

/**
 * Updates {@code minPosition[i][j][k]} and {@code maxPosition[i][j][k]} when the
 * i‑th command is flipped (i.e., we spend one change on it).
 */
private static void applyWithChange(int i, int j, int k,
                                   char[] commands,
                                   int[][][] minPos,
                                   int[][][] maxPos) {
    if (commands[i] == 'T') {
        // changed ‘T’ into a move: keep direction, move forward
        int delta = toward(k);
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j - 1][k] + delta);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j - 1][k] + delta);
    } else {
        // changed a move into a turn: direction flips, position unchanged
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j - 1][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j - 1][1 - k]);
    }
}

/**
 * Returns +1 for direction “right” (k == 0) and –1 for direction “left” (k == 1).
 * The method is assumed to exist elsewhere; kept here for completeness.
 */
private static int toward(int k) {
    return k == 0 ? 1 : -1;
}

public void solve(int testNumber, QuickScanner in, ExtendedPrintWriter out) {
    char[] commands = (" " + in.next()).toCharArray();
    int n = commands.length - 1;
    int toChange = in.nextInt();

    int[][][] minPosition = new int[n + 1][toChange + 1][2];
    int[][][] maxPosition = new int[n + 1][toChange + 1][2];
    ArrayUtils.fill(minPosition, INF);
    ArrayUtils.fill(maxPosition, -INF);
    Arrays.fill(minPosition[0][0], 0);
    Arrays.fill(maxPosition[0][0], 0);

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j <= toChange; j++) {
            for (int k = 0; k < 2; k++) {
                applyNoChange(commands[i], minPosition, maxPosition, i, j, k);
                if (j > 0) {
                    applyWithChange(commands[i], minPosition, maxPosition, i, j, k);
                }
            }
        }
    }

    int answer = computeBestDistance(minPosition, maxPosition, n, toChange);
    out.println(answer);
}

/** Updates min/max tables for the case where we don't consume a change at position i. */
private void applyNoChange(char command,
                           int[][][] minPos,
                           int[][][] maxPos,
                           int i,
                           int j,
                           int k) {
    if (command == 'T') {
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j][1 - k]);
    } else {
        int delta = toward(k);
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j][k] + delta);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j][k] + delta);
    }
}

/** Updates min/max tables for the case where we consume one change at position i. */
private void applyWithChange(char command,
                             int[][][] minPos,
                             int[][][] maxPos,
                             int i,
                             int j,
                             int k) {
    if (command == 'T') {
        int delta = toward(k);
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j - 1][k] + delta);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j - 1][k] + delta);
    } else {
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j - 1][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j - 1][1 - k]);
    }
}

/** Computes the maximal absolute distance reachable after processing the whole string. */
private int computeBestDistance(int[][][] minPos,
                                int[][][] maxPos,
                                int n,
                                int toChange) {
    int best = 0;
    for (int j = toChange % 2; j <= toChange; j += 2) {
        for (int k = 0; k < 2; k++) {
            best = Math.max(best, -minPos[n][j][k]);
            best = Math.max(best, maxPos[n][j][k]);
        }
    }
    return best;
}

