    char[] commands = (" " + in.next()).toCharArray();
    int n = commands.length - 1;
    int toChange = in.nextInt();
    int[][][] minPosition = new int[n + 1][toChange + 1][2];
    int[][][] maxPosition = new int[n + 1][toChange + 1][2];
    ArrayUtils.fill(minPosition, INF);
    ArrayUtils.fill(maxPosition, -INF);
    Arrays.fill(minPosition[0][0], 0);
    Arrays.fill(maxPosition[0][0], 0);

    for (int i = 1; i <= n; i++) {
        for (int j = 0; j <= toChange; j++) {
            for (int k = 0; k < 2; k++) {
                applyNoChange(i, j, k, commands[i], minPosition, maxPosition);
                if (j > 0) {
                    applyWithChange(i, j, k, commands[i], minPosition, maxPosition);
                }
            }
        }
    }

    int answer = 0;
    for (int j = toChange % 2; j <= toChange; j += 2) {
        for (int k = 0; k < 2; k++) {
            answer = Math.max(answer, -minPosition[n][j][k]);
            answer = Math.max(answer, maxPosition[n][j][k]);
        }
    }
    out.println(answer);
}

/**
 * Updates {@code minPosition} and {@code maxPosition} for the current step
 * when the current command is used without spending a change.
 */
private void applyNoChange(int i, int j, int k, char command,
                           int[][][] minPos, int[][][] maxPos) {
    if (command == 'T') {
        minPos[i][j][k] = Math.min(minPos[i][j][k], minPos[i - 1][j][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k], maxPos[i - 1][j][1 - k]);
    } else {
        minPos[i][j][k] = Math.min(minPos[i][j][k],
                minPos[i - 1][j][k] + toward(k));
        maxPos[i][j][k] = Math.max(maxPos[i][j][k],
                maxPos[i - 1][j][k] + toward(k));
    }
}

/**
 * Updates {@code minPosition} and {@code maxPosition} for the current step
 * when the current command is used after spending one change.
 */
private void applyWithChange(int i, int j, int k, char command,
                             int[][][] minPos, int[][][] maxPos) {
    if (command == 'T') {
        minPos[i][j][k] = Math.min(minPos[i][j][k],
                minPos[i - 1][j - 1][k] + toward(k));
        maxPos[i][j][k] = Math.max(maxPos[i][j][k],
                maxPos[i - 1][j - 1][k] + toward(k));
    } else {
        minPos[i][j][k] = Math.min(minPos[i][j][k],
                minPos[i - 1][j - 1][1 - k]);
        maxPos[i][j][k] = Math.max(maxPos[i][j][k],
                maxPos[i - 1][j - 1][1 - k]);
    }
}

