/**
 * Converts a string of exactly 10 numeric characters into an int array
 * where each element holds the corresponding digit value.
 */
private int[] parseDigits(String s) {
    int[] a = new int[10];
    for (int i = 0; i < 10; i++) {
        a[i] = s.charAt(i) - '0';
    }
    return a;
}

/**
 * Repeatedly combines adjacent digits modulo 10 until only the first
 * element holds the final result, then returns that value.
 */
private int reduceDigits(int[] a) {
    for (int i = 0; i < 10; i++) {
        for (int j = 0; j < 9 - i; j++) {
            a[j] = (a[j] + a[j + 1]) % 10;
        }
    }
    return a[0];
}

