/**
 * Updates the scores, goals and fouls for the two teams described by a match line.
 *
 * @param data split result of a line of the form "TeamA-TeamB X:Y"
 * @param team the list of all commands (teams)
 */
private static void processMatch(String[] data, List<Command> team) {
    int num1 = Integer.parseInt(data[2]);
    int num2 = Integer.parseInt(data[3]);

    if (num1 == num2) {                     // draw
        for (Command c : team) {
            if (data[0].equals(c.name) || data[1].equals(c.name)) {
                c.scores++;
                c.goals += num1;
                c.fols  += num2;
            }
        }
    } else if (num1 > num2) {               // first team wins
        for (Command c : team) {
            if (data[0].equals(c.name)) {
                c.scores += 3;
                c.goals  += num1;
                c.fols   += num2;
            }
            if (data[1].equals(c.name)) {
                c.goals += num2;
                c.fols  += num1;
            }
        }
    } else {                                // second team wins
        for (Command c : team) {
            if (data[1].equals(c.name)) {
                c.scores += 3;
                c.goals  += num2;
                c.fols   += num1;
            }
            if (data[0].equals(c.name)) {
                c.goals += num1;
                c.fols  += num2;
            }
        }
    }
}

/**
 * Prints the names of the top half of the sorted teams, in alphabetical order.
 *
 * @param team sorted list of commands
 * @param n    original number of teams
 */
private static void printTopHalfNames(List<Command> team, int n) {
    Set<String> names = new TreeSet<>();
    for (int i = 0; i < n / 2; i++) {
        names.add(team.get(i).name);
    }
    for (String name : names) {
        System.out.println(name);
    }
}

