/**
 * Fills the {@code precomp} matrix.
 * For each position {@code at} and each possible digit {@code i},
 * stores the number of bits that must be switched to turn the current
 * display into digit {@code i}, or -1 if the transformation is impossible.
 */
private static void computePrecompTable(int n) {
    for (int at = 0; at < n; at++) {
        for (int i = 9; i >= 0; i--) {
            boolean achievable = true;
            int dist = 0;
            for (int bit = 0; bit < 8; bit++) {
                if (((digits[i] & (1 << bit)) == 0) && ((a[at] & (1 << bit)) != 0)) {
                    achievable = false;
                }
                if (((digits[i] & (1 << bit)) != 0) && ((a[at] & (1 << bit)) == 0)) {
                    dist++;
                }
            }
            precomp[at][i] = achievable ? dist : -1;
        }
    }
}

/**
 * Reconstructs the lexicographically largest possible number
 * using the already‑filled {@code dp} table and {@code precomp} data.
 *
 * @return an array of length {@code n} containing the chosen digits
 */
private static int[] reconstructResult(int n, int k) {
    int[] res = new int[n];
    int left = k;
    for (int at = 0; at < n; at++) {
        for (int i = 9; i >= 0; i--) {
            int dist = precomp[at][i];
            boolean good = false;

            if (at + 1 == n) {
                good = (dist == left);
            } else if (dist != -1 && left - dist >= 0 && dp[at + 1][left - dist] != null) {
                good = dp[at + 1][left - dist];
            }

            if (good && dist != -1) {
                res[at] = i;
                left -= Integer.bitCount(digits[i] ^ a[at]);
                break;
            }
        }
    }
    return res;
}

