/** Computes the distance table `precomp` used by the DP. */
private static void computePrecomp(int n) {
    for (int at = 0; at < n; at++) {
        for (int i = 9; i >= 0; i--) {
            boolean achievable = true;
            int dist = 0;
            for (int bit = 0; bit < 8; bit++) {
                if (((digits[i] & (1 << bit)) == 0) && ((a[at] & (1 << bit)) != 0)) {
                    achievable = false;
                }
                if (((digits[i] & (1 << bit)) != 0) && ((a[at] & (1 << bit)) == 0)) {
                    dist++;
                }
            }
            precomp[at][i] = achievable ? dist : -1;
        }
    }
}

/** Reconstructs the optimal digit sequence and prints it. */
private static void outputResult(int n, int k, PrintWriter out) {
    int[] res = new int[n];
    int left = k;

    for (int at = 0; at < n; at++) {
        for (int i = 9; i >= 0; i--) {
            int dist = precomp[at][i];
            boolean good = false;

            if (at + 1 == n) {
                good = (dist == left);
            } else if (dist != -1 && left - dist >= 0 && dp[at + 1][left - dist] != null) {
                good = dp[at + 1][left - dist];
            }

            if (good && dist != -1) {
                res[at] = i;
                left -= Integer.bitCount(digits[i] ^ a[at]);
                break;
            }
        }
    }

    for (int digit : res) {
        out.print(digit);
    }
}

