/**
 * Simulates the boarding process.
 *
 * @param bus the bus representation (capacity per row and current occupants)
 * @param passengers the number of passengers that try to find a seat
 */
private static void placePassengers(List<Entry<Integer, List<Boolean>>> bus, int passengers) {
    int lastPlaced = -1;

    for (int i = 0; i < passengers; i++) {
        int j = 0;

        if (lastPlaced + 1 == ROWS) {
            lastPlaced = -1;
        }

        for (Entry<Integer, List<Boolean>> row : bus) {
            if (row.getKey() != row.getValue().size() && j > lastPlaced) {
                row.getValue().add(true);
                lastPlaced = j;
                break;
            }
            j++;
        }
    }
}

