    String[] endWith = {"|D|)", "|.|", "..|", "|.|)"};

    System.out.println(border);

    for (int i = 0; i < ROWS; i++) {
        System.out.print('|');

        int rowLength = bus.get(i).getValue().size();
        int rowCapacity = bus.get(i).getKey();

        // occupied seats
        for (int j = 0; j < rowLength; j++) {
            System.out.print("O.");
        }

        // empty seats
