/* ---------- helper methods ---------- */

private static void initResMatrix() {
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < k; j++) {
            res[i][j] = (i == j) ? 0 : inf;
        }
    }
}

private static void readPoints(LinkedList<Point> points) throws Exception {
    for (int i = 0; i < k; i++) {
        points.addLast(new Point(in(), i));
    }
}

/**
 * Populates the array {@code a} using the countdown stored in {@code points}.
 * The original loop mutated the first element of each point until it reached zero.
 */
private static void fillArrayAFromPoints(LinkedList<Point> points) {
    int idx = 0;
    while (!points.isEmpty()) {
        Point p = points.getFirst();
        if (p.x == 0) {
            points.removeFirst();
            continue;
        }
        a[idx++] = p.y;
        p.x--;
    }
}

/**
 * Reads {@code m} edges from input and stores them in a priority queue ordered by weight.
 */
private static PriorityQueue<tri> readEdges(int m) throws Exception {
    PriorityQueue<tri> q = new PriorityQueue<>();
    for (int i = 0; i < m; i++) {
        q.offer(new tri(in() - 1, in() - 1, in()));
    }
    return q;
}

/**
 * Processes all edges whose weight is non‑positive.
 * Sets distance 0 between different groups and builds the initial DSU.
 */
private static void processZeroWeightEdges(PriorityQueue<tri> q) {
    while (!q.isEmpty()) {
        if (q.peek().d > 0) break;

        tri e = q.poll();
        int f = e.from;
        int t = e.to;

        if (a[f] != a[t]) {
            res[a[f]][a[t]] = res[a[t]][a[f]] = 0;
        }
        if (dsu.isSameSet(f, t)) continue;
        dsu.union(f, t);
    }
}

/**
 * Processes the remaining edges (weight > 0) and updates the distance matrix.
 */
private static void processRemainingEdges(PriorityQueue<tri> q) {
    while (!q.isEmpty()) {
        tri e = q.poll();
        int f = e.from;
        int t = e.to;
        int d = e.d;

        if (a[f] != a[t]) {
            long cur = res[a[f]][a[t]];
            long cand = d;
            if (cand < cur) {
                res[a[f]][a[t]] = res[a[t]][a[f]] = cand;
            }
        }
        if (dsu.isSameSet(f, t)) continue;
        dsu.union(f, t);
    }
}

/**
 * Floyd‑Warshall algorithm to compute the shortest distance between every pair of groups.
 */
private static void computeAllPairsShortestPath() {
    for (int v = 0; v < k; v++) {
        for (int i = 0; i < k; i++) {
            for (int j = 0; j < k; j++) {
                long viaV = res[i][v] + res[v][j];
                if (viaV < res[i][j]) {
                    res[i][j] = viaV;
                }
            }
        }
    }
}

