private static void prepareData() {
    LinkedList<Point> list = new LinkedList<>();
    res = new long[k][k];
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < k; j++) {
            res[i][j] = (i == j) ? 0 : inf;
