        q.offer(new tri(in() - 1, in() - 1, in()));
    }

    while (!q.isEmpty()) {
        tri cur = q.peek();
        if (cur.d > 0) break;

        int f = cur.from;
        int t = cur.to;
        q.poll();

        if (a[f] != a[t]) {
            res[a[f]][a[t]] = res[a[t]][a[f]] = 0;
        }
        if (dsu.isSameSet(f, t)) continue;
        dsu.union(f, t);
    }

    return check();
}

