/** Builds a frequency map of the values in the array. */
private static TreeMap<Integer, Integer> buildFrequencyMap(int[] arr) {
    TreeMap<Integer, Integer> tm = new TreeMap<>();
    for (int value : arr) {
        if (tm.containsKey(value)) {
            tm.put(value, tm.get(value) + 1);
        } else {
            tm.put(value, 1);
        }
    }
    return tm;
}

/** Calculates the minimal value when the array contains k. */
private static int computeMinWhenKExists(int[] arr, int k) {
    int n = arr.length;
    int min = Integer.MAX_VALUE;
    for (int i = 0; i < n; i++) {
        if (arr[i] == k) {
            if (i > (n - i - 1)) {
                int diff = i - (n - i - 1);
                if (min > diff) {
                    min = diff;
                }
            } else {
                if (i == n - i - 1) {
                    min = 0;
                } else {
                    int candidate = n - i - i - 1;
                    if (min > candidate) {
                        min = candidate - 1;   // mirrors original: n-i-i-1-1
                    }
                }
            }
        }
    }
    return min;
}

/** Calculates the minimal value when the array does NOT contain k. */
private static int computeMinWhenKAbsent(int[] arr, int k) {
    int n = arr.length;
    int i;
    for (i = 0; i < n; i++) {
        if (arr[i] > k) {
            break;
        }
    }
    int min;
    if (i > n - i) {
        min = 2 * i - n;
    } else {
        if (i == n - i) {
            min = 0;
        } else {
            min = n - 2 * i - 1;
        }
    }
    min++;   // mirrors original post‑processing step
    return min;
}

