public static int min(int index, int pos, int n, int direction) {
    // base cases
    if (index == inp.length() && n == 0)
        return Math.abs(pos);
    if (index == inp.length())
        return Integer.MIN_VALUE;

    // memoisation
    if (dp[index][pos + 100][n][direction + 1] != -1)
        return dp[index][pos + 100][n][direction + 1];

    int result;
    if (n == 0) {
        // single step when no moves remain
        result = (inp.charAt(index) == 'T')
                ? min(index + 1, pos, n, -direction)
                : min(index + 1, pos + direction, n, direction);
    } else {
        // more than zero moves left – delegate to specialised helpers
        if (inp.charAt(index) == 'T') {
            result = computeMaxForT(index, pos, n, direction);
        } else {
            result = computeMaxForNonT(index, pos, n, direction);
        }
    }

    dp[index][pos + 100][n][direction + 1] = result;
    return result;
}

/**
 * Handles the case where the current character is 'T' and n > 0.
 */
private static int computeMaxForT(int index, int pos, int n, int direction) {
    int max = min(index + 1, pos, n, -direction);
    for (int i = 1; i <= n; i++) {
        if (i % 2 == 0) {
            max = Math.max(max, min(index + 1, pos, n - i, -direction));
        } else {
            max = Math.max(max, min(index + 1, pos + direction, n - i, direction));
        }
    }
    return max;
}

/**
 * Handles the case where the current character is not 'T' and n > 0.
 */
private static int computeMaxForNonT(int index, int pos, int n, int direction) {
    int max = min(index + 1, pos + direction, n, direction);
    for (int i = 1; i <= n; i++) {
        if (i % 2 == 0) {
            max = Math.max(max, min(index + 1, pos + direction, n - i, direction));
        } else {
            max = Math.max(max, min(index + 1, pos, n - i, -direction));
        }
    }
    return max;
}

