            sum[i] += a[i][j];
            curMax = Math.max(curMax, a[i][j]);
            prefMax = Math.max(prefMax, sum[i]);   // running prefix sum max
        }
        maxPrefix[i] = prefMax;
        maxElement[i] = curMax;
