private static long computeAnswer(int[] indices,
                                   long[] sum,
                                   long[] maxPrefix) {
    long runningSum = 0;
    long answer = 0;
    for (int idx : indices) {
        answer = Math.max(answer, maxContSum(idx));
        answer = Math.max(answer, runningSum + maxPrefix[idx]);
        runningSum += sum[idx];
        runningSum = Math.max(maxS[idx], runningSum);
        answer = Math.max(answer, runningSum);
    }
