/**
 * Reads each array, fills {@code a}, and computes:
 *   - total sum per array (s)
 *   - maximum prefix sum per array (maxP)
 *   - maximum single element per array (max2)
 */
private static void readAndPrepareArrays(Scanner sc, int n,
                                         long[] s, long[] maxP, int[] max2) {
    for (int i = 0; i < n; i++) {
        int l = sc.nextInt();
        int maxElem = Integer.MIN_VALUE;
        long maxPrefix = 0;
        a[i] = new int[l];

        for (int j = 0; j < l; j++) {
            a[i][j] = sc.nextInt();
            s[i] += a[i][j];
            maxElem = Math.max(maxElem, a[i][j]);
            maxPrefix = Math.max(maxPrefix, s[i]); // prefix up to j
        }

        maxP[i] = maxPrefix;
        max2[i] = maxElem;
    }
}

/**
 * For each array computes the maximum sum of any suffix.
 * Result is stored in the static field {@code maxS}.
 */
private static void computeSuffixMaximums(int n) {
    for (int i = 0; i < n; i++) {
        long suffixSum = 0;
        long best = 0;
        for (int j = a[i].length - 1; j >= 0; j--) {
            suffixSum += a[i][j];
            best = Math.max(best, suffixSum);
        }
        maxS[i] = best;
    }
}

/**
 * Returns the largest single element among the selected indices.
 */
private static int computeGlobalMax(int[] indices, int[] max2) {
    int best = Integer.MIN_VALUE;
    for (int idx : indices) {
        best = Math.max(best, max2[idx]);
    }
    return best;
}

/**
 * Executes the original core algorithm and returns the optimal answer.
 */
private static long computeAnswer(int[] indices,
                                  long[] s,
                                  long[] maxP,
                                  long[] maxS) {
    long sum = 0;
    long ans = 0;

    for (int idx : indices) {
        // 1) best contiguous sub‑array completely inside current array
        ans = Math.max(ans, maxContSum(idx));

        // 2) best prefix taken from current array together with previous sum
        ans = Math.max(ans, sum + maxP[idx]);

        // 3) update running sum with the whole current array
        sum += s[idx];

        // 4) optionally replace running sum by the best suffix of current array
        sum = Math.max(maxS[idx], sum);

        // 5) track the best overall sum seen so far
        ans = Math.max(ans, sum);
    }
    return ans;
}

