        best = Math.max(best, maxContSum(idx));

        // 2) start a new segment at the current array
        best = Math.max(best, sum + maxPrefix[idx]);

        // 3) extend the running sum with the whole current array
        sum += totalSum[idx];

        // 4) keep the larger of the running sum or the best suffix of the current array
        sum = Math.max(maxSuffix[idx], sum);

        // 5) overall best so far
        best = Math.max(best, sum);
    }
    return best;
}

