/**
 * Executes the algorithm that repeatedly fixes the array by inserting
 * missing indices (or the special value n) until at most 2·n steps are done.
 */
private static void processArray(int[] a, int n, List<Integer> ans) {
    TreeSet<Integer> set = createMissingSet(a, n);
    int cnt = 0;
    while (cnt < 2 * n) {
        if (set.first() == n) {
            // case: we have to place the special value n
            for (int j = 0; j < n; j++) {
                if (a[j] != j) {
                    a[j] = n;
                    ans.add(j + 1);
                    break;
                }
            }
        } else {
            int idx = set.first();          // smallest missing index
            a[idx] = idx;                  // fix it
            ans.add(idx + 1);
        }
        // recompute the set of missing values for the next iteration
        set = createMissingSet(a, n);
        cnt++;
    }
}

/**
 * Builds a TreeSet containing all numbers 0..n that are not present in the
 * current array `a`.  The set is used to quickly obtain the smallest missing
 * index.
 */
private static TreeSet<Integer> createMissingSet(int[] a, int n) {
    TreeSet<Integer> set = new TreeSet<>();
    for (int i = 0; i <= n; i++) {
        set.add(i);
    }
    for (int value : a) {
        set.remove(value);
    }
    return set;
}

