/* ---------- helper methods ---------- */

/** creates a TreeSet containing all integers from 0 to n (inclusive) */
private static TreeSet<Integer> createFullSet(int n) {
    TreeSet<Integer> set = new TreeSet<>();
    for (int i = 0; i <= n; i++) {
        set.add(i);
    }
    return set;
}

/** reads the array a[0..n‑1] and removes each value from the supplied set */
private static void readArrayAndUpdateSet(InputReader in, int n, int[] a, TreeSet<Integer> set) {
    for (int i = 0; i < n; i++) {
        a[i] = in.nextInt();
        set.remove(a[i]);
    }
}

/** rebuilds the missing‑value set from the current content of a[] */
private static void rebuildMissingSet(int[] a, int n, TreeSet<Integer> set) {
    set.clear();
    for (int i = 0; i <= n; i++) {
        set.add(i);
    }
    for (int v : a) {
        set.remove(v);
    }
}

/** core loop that produces the sequence of operations stored in ans */
private static void processIterations(int[] a, int n, List<Integer> ans) {
    TreeSet<Integer> set = createFullSet(n);
    // initial removal of present numbers – same work as readArrayAndUpdateSet,
    // but we start with a fresh set because the original code rebuilds it each
    // iteration; the first rebuild is done here.
    for (int v : a) {
        set.remove(v);
    }

    int cnt = 0;
    while (cnt < 2 * n) {
        int miss = set.first();               // smallest missing number
        if (miss == n) {                       // special case: we need a dummy value
            for (int i = 0; i < n; i++) {
                if (a[i] != i) {               // find a position where a[i] != i
                    a[i] = n;                  // place the dummy value n there
                    ans.add(i + 1);            // store 1‑based index
                    break;
                }
            }
        } else {
            a[miss] = miss;                    // fix position 'miss' with its correct value
            ans.add(miss + 1);                 // store 1‑based index
        }

        // recompute the missing set for the next iteration
        rebuildMissingSet(a, n, set);
        cnt++;
    }
}

