public static int KMPSearch(String txt, String pat) {
    int m = pat.length();
    int n = txt.length();
    int[] lps = new int[m];
    int j = 0;
    int count = 0;
    PrefixTable(pat, m, lps);
    int i = 0;

    while (i < n) {
        // ---- match block (first bump) ----
        if (pat.charAt(j) == txt.charAt(i)) {
            int[] updated = processMatch(i, j);
            i = updated[0];
            j = updated[1];
        }

        // full pattern found
        if (j == m) {
            count++;
            j = lps[j - 1];
        }
        // ---- mismatch block (second bump) ----
        else if (i < n && pat.charAt(j) != txt.charAt(i)) {
            int[] updated = processMismatch(i, j, lps);
            i = updated[0];
            j = updated[1];
        }
    }
    return count;
}

/**
 * Advances both indices when the current characters match.
 */
private static int[] processMatch(int i, int j) {
    return new int[] { i + 1, j + 1 };
}

/**
 * Adjusts indices when a mismatch occurs.
 * If we have a non‑zero prefix length, jump back using the LPS table;
 * otherwise simply move the text index forward.
 */
private static int[] processMismatch(int i, int j, int[] lps) {
    if (j != 0) {
        j = lps[j - 1];
    } else {
        i = i + 1;
    }
    return new int[] { i, j };
}

