/* ------------------------------------------------------------------ */
/* Bump 1 helpers                                                    */
/* ------------------------------------------------------------------ */

/** Allocate global arrays and adjacency list containers. */
private static void initialiseArrays(int n) {
    depths = new int[n];
    pre = new int[n];
    post = new int[n];
    g = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        g[i] = new ArrayList<>();
    }
}

/** Build the rooted tree, compute depths and Euler order, then run DFS. */
private static void buildTree(int n) {
    for (int i = 1; i < n; i++) {
        int p = input.nextInt() - 1;
        depths[i] = depths[p] + 1;
        g[p].add(i);
    }
    cnt = 0;
    dfs(0);
}

/* ------------------------------------------------------------------ */
/* Bump 2 helpers – query processing                                 */
/* ------------------------------------------------------------------ */

/** Iterate over all queries and delegate to the appropriate handler. */
private static void processQueries(int q, IT it, PrintWriter out) {
    for (int i = 0; i < q; i++) {
        int type = input.nextInt();
        if (type == 1) {
            handleUpdate(it);
        } else {
            handleQuery(out);
        }
    }
}

/** Handle a type‑1 (range update) command. */
private static void handleUpdate(IT it) {
    int x = input.nextInt() - 1;
    int v = input.nextInt();
    int k = input.nextInt();
    // add update for the whole subtree of x
    it.add(pre[x], post[x], v, k, depths[x]);
}

/** Handle a type‑2 (point query) command and print the result. */
private static void handleQuery(PrintWriter out) {
    int x = input.nextInt() - 1;
    int original = x;
    x = pre[x];

    long v = it.getVal(x);
    long s = it.getSlope(x);
    long res = (v - depths[original] * s) % mod;
    if (res < 0) {
        res += mod;
    }
    out.println(res);
}

