/** Counts occurrences of '0', '1' and '2' in the input string. */
private static int[] countDigits(String s) {
    int[] cnt = new int[3]; // [0] = zeros, [1] = ones, [2] = twos
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '0') cnt[0]++;
        else if (c == '1') cnt[1]++;
        else cnt[2]++;
    }
    return cnt;
}

/** Computes how many of each digit are still needed to reach n/3. */
private static int[] computeDeficits(int[] counts, int n) {
    int r = n / 3;
    return new int[] {
        r - counts[0], // needed zeros  (z1)
        r - counts[1], // needed ones   (o1)
        r - counts[2]  // needed twos   (t1)
    };
}

/** Adjusts the array so that the required number of '0's is satisfied. */
private static void fixZeroDeficit(char[] a, int[] d) {
    int z1 = d[0], o1 = d[1], t1 = d[2];
    if (z1 > 0) {
        for (int i = 0; i < a.length && z1 > 0; i++) {
            if (a[i] == '2' && t1 < 0) {
                a[i] = '0';
                z1--;
                t1++;
            } else if (a[i] == '1' && o1 < 0) {
                a[i] = '0';
                z1--;
                o1++;
            }
        }
    }
    d[0] = z1; d[1] = o1; d[2] = t1;
}

/** Adjusts the array so that the required number of '2's is satisfied. */
private static void fixTwoDeficit(char[] a, int[] d) {
    int z1 = d[0], o1 = d[1], t1 = d[2];
    if (t1 > 0) {
        for (int i = a.length - 1; i >= 0 && t1 > 0; i--) {
            if (a[i] == '1' && o1 < 0) {
                a[i] = '2';
                t1--;
                o1++;
            } else if (a[i] == '0' && z1 < 0) {
                a[i] = '2';
                t1--;
                z1++;
            }
        }
    }
    d[0] = z1; d[1] = o1; d[2] = t1;
}

/** Adjusts the array so that the required number of '1's is satisfied. */
private static void fixOneDeficit(char[] a, int[] d) {
    int z1 = d[0], o1 = d[1], t1 = d[2];
    if (o1 > 0) {
        // first pass: turn surplus '2' into '1'
        for (int i = 0; i < a.length && o1 > 0; i++) {
            if (a[i] == '2' && t1 < 0) {
                a[i] = '1';
                o1--;
                t1++;
            }
        }
        // second pass: turn surplus '0' into '1'
        for (int i = a.length - 1; i >= 0 && o1 > 0; i--) {
            if (a[i] == '0' && z1 < 0) {
                a[i] = '1';
                o1--;
                z1++;
            }
        }
    }
    d[0] = z1; d[1] = o1; d[2] = t1;
}

