public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    PrintWriter out = new PrintWriter(System.out);
    int n = sc.nextInt();
    String s = sc.nextLine();

    // 1️⃣ count existing digits
    int[] count = new int[3];            // 0→zeros, 1→ones, 2→twos
    countDigits(s, count);

    // 2️⃣ compute how many of each digit we need (target = n/3)
    int target = n / 3;
    int[] diff = new int[3];            // positive → need more, negative → surplus
    diff[0] = target - count[0];        // zeros needed
    diff[1] = target - count[1];        // ones needed
    diff[2] = target - count[2];        // twos needed

    char[] a = s.toCharArray();

    // 3️⃣ perform the three balancing passes
    if (diff[0] > 0) {
        balanceZeros(a, diff, n);
    }
    if (diff[2] > 0) {
        balanceTwos(a, diff, n);
    }
    if (diff[1] > 0) {
        balanceOnes(a, diff, n);
    }

    // 4️⃣ output the final string
    StringBuilder h = new StringBuilder();
    for (int i = 0; i < n; i++) {
        h.append(a[i]);
    }
    out.println(h);
    out.flush();
}

/** Counts occurrences of '0', '1' and '2' in *s* and stores them in *count*. */
private static void countDigits(String s, int[] count) {
    for (int i = 0; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '0') {
            count[0]++;
        } else if (c == '1') {
            count[1]++;
        } else { // c == '2'
            count[2]++;
        }
    }
}

/** Fixes a deficit of zeros using surplus twos or ones (original first loop). */
private static void balanceZeros(char[] a, int[] diff, int n) {
    // diff[0] > 0   → need more zeros
    // diff[2] < 0   → surplus twos
    // diff[1] < 0   → surplus ones
    for (int i = 0; i < n && diff[0] > 0; i++) {
        if (a[i] == '2' && diff[2] < 0) {
            a[i] = '0';
            diff[0]--;
            diff[2]++;
        } else if (a[i] == '1' && diff[1] < 0) {
            a[i] = '0';
            diff[0]--;
            diff[1]++;
        }
    }
}

/** Fixes a deficit of twos using surplus ones or zeros (original second loop). */
private static void balanceTwos(char[] a, int[] diff, int n) {
    // diff[2] > 0   → need more twos
    // diff[1] < 0   → surplus ones
    // diff[0] < 0   → surplus zeros
    for (int i = n - 1; i >= 0 && diff[2] > 0; i--) {
        if (a[i] == '1' && diff[1] < 0) {
            a[i] = '2';
            diff[2]--;
            diff[1]++;
        } else if (a[i] == '0' && diff[0] < 0) {
            a[i] = '2';
            diff[2]--;
            diff[0]++;
        }
    }
}

/** Fixes a deficit of ones using surplus twos (forward pass) and surplus zeros (backward pass). */
private static void balanceOnes(char[] a, int[] diff, int n) {
    // diff[1] > 0   → need more ones
    // diff[2] < 0   → surplus twos
    // diff[0] < 0   → surplus zeros
    // forward pass – replace surplus twos with ones
    for (int i = 0; i < n && diff[1] > 0; i++) {
        if (a[i] == '2' && diff[2] < 0) {
            a[i] = '1';
            diff[1]--;
            diff[2]++;
        }
    }
    // backward pass – replace surplus zeros with ones
    for (int i = n - 1; i >= 0 && diff[1] > 0; i--) {
        if (a[i] == '0' && diff[0] < 0) {
            a[i] = '1';
            diff[1]--;
            diff[0]++;
        }
    }
}

