/** Split a length‑N segment of the original string according to a bit mask.
 *  Characters whose bit is 1 are appended to the first part (preserving order);
 *  characters whose bit is 0 are prepended to the second part, thus building it in reverse.
 *  Returns a two‑element array: [firstPart, secondPart].
 */
private static String[] splitMask(String segment, int N, int mask) {
    StringBuilder first = new StringBuilder();
    StringBuilder second = new StringBuilder();
    for (int j = 0; j < N; j++) {
        if ((mask & (1 << j)) != 0) {
            first.append(segment.charAt(j));
        } else {
            second.insert(0, segment.charAt(j));
        }
    }
    return new String[]{first.toString(), second.toString()};
}

/** Create the list of Node objects for the first half of the string. */
private static List<Node> generateNodeList(String S, int N) {
    List<Node> list = new ArrayList<>();
    String firstHalf = S.substring(0, N);
    int limit = 1 << N;
    for (int mask = 0; mask < limit; mask++) {
        String[] parts = splitMask(firstHalf, N, mask);
        list.add(new Node(parts[0], parts[1]));
    }
    return list;
}

/** Build the nested map for the second half of the string.
 *  Outer key = s1, inner key = s2, value = occurrence count.
 */
private static Map<String, Map<String, Long>> buildSecondHalfMap(String S, int N) {
    Map<String, Map<String, Long>> map = new HashMap<>();
    String secondHalf = S.substring(N);          // characters N … 2N‑1
    int limit = 1 << N;
    for (int mask = 0; mask < limit; mask++) {
        String[] parts = splitMask(secondHalf, N, mask);
        String s1 = parts[0];
        String s2 = parts[1];
        map.computeIfAbsent(s1, k -> new HashMap<>())
           .merge(s2, 1L, Long::sum);
    }
    return map;
}

/** Compute the final answer using the node list and the map built from the second half. */
private static long computeAnswer(List<Node> nodes, Map<String, Map<String, Long>> map) {
    long ans = 0L;
    for (Node node : nodes) {
        Map<String, Long> inner = map.get(node.b);
        if (inner != null) {
            Long cnt = inner.get(node.a);
            if (cnt != null) {
                ans += cnt;
            }
        }
    }
    return ans;
}

public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int N = sc.nextInt();
    String S = sc.next();

    List<Node> nodes = buildNodeList(S, N);
    Map<String, Map<String, Long>> countMap = buildCountMap(S, N);
    long ans = countMatches(nodes, countMap);

    System.out.println(ans);
}

/** Chunk 1 – create all (s1,s2) pairs from the first N characters */
private static List<Node> buildNodeList(String S, int N) {
    List<Node> list = new ArrayList<>();
    int total = 1 << N;                     // 2^N possibilities
    for (int mask = 0; mask < total; mask++) {
        StringBuilder s1 = new StringBuilder();
        StringBuilder s2 = new StringBuilder();
        for (int j = 0; j < N; j++) {
            if ((mask & (1 << j)) != 0) {
                s1.append(S, j, j + 1);
            } else {
                s2.insert(0, S, j, j + 1);   // prepend to reverse order
            }
        }
        list.add(new Node(s1.toString(), s2.toString()));
    }
    return list;
}

/** Chunk 2 – count occurrences of (s1,s2) pairs from the second N characters */
private static Map<String, Map<String, Long>> buildCountMap(String S, int N) {
    Map<String, Map<String, Long>> map = new HashMap<>();
    int total = 1 << N;                     // 2^N possibilities
    for (int mask = 0; mask < total; mask++) {
        StringBuilder s1 = new StringBuilder();
        StringBuilder s2 = new StringBuilder();
        for (int j = 0; j < N; j++) {
            int idx = j + N;                // offset to the second half
            if ((mask & (1 << j)) != 0) {
                s1.append(S, idx, idx + 1);
            } else {
                s2.insert(0, S, idx, idx + 1);
            }
        }
        String key1 = s1.toString();
        String key2 = s2.toString();

        map.computeIfAbsent(key1, k -> new HashMap<>())
           .merge(key2, 1L, Long::sum);
    }
    return map;
}

/** Chunk 3 – sum matches where (s1,s2) from first half appears as (s2,s1) in second half */
private static long countMatches(List<Node> nodes,
                                 Map<String, Map<String, Long>> map) {
    long ans = 0L;
    for (Node node : nodes) {
        Map<String, Long> inner = map.get(node.b);
        if (inner != null) {
            Long cnt = inner.get(node.a);
            if (cnt != null) {
                ans += cnt;
            }
        }
    }
    return ans;
}

