/**
 * Constructs all cycles of the given permutation (1‑based indexing).
 *
 * @param perm permutation array, perm[i] = next index from i
 * @param n    size of the permutation (excluding the dummy 0‑th element)
 * @return list of cycles, each cycle is a list of indices in visitation order
 */
private static List<List<Integer>> buildCycles(int[] perm, int n) {
    List<List<Integer>> cycles = new ArrayList<>();
    boolean[] seen = new boolean[n + 1];

    for (int i = 1; i <= n; i++) {
        if (seen[i]) {
            continue;
        }
        List<Integer> cycle = new ArrayList<>();
        int cur = i;
        cycle.add(cur);
        cur = perm[cur];
        while (cur != i) {
            cycle.add(cur);
            seen[cur] = true;
            cur = perm[cur];
        }
        cycles.add(cycle);
    }
    return cycles;
}

/**
 * Finds the smallest divisor across all cycles such that, for some
 * starting offset, every element spaced by that divisor has the same colour.
 *
 * @param cycles list of cycles obtained from the permutation
 * @param colors colour array (1‑based)
 * @return the minimal divisor that satisfies the condition
 */
private static int findMinimalDivisor(List<List<Integer>> cycles, int[] colors) {
    int minAns = Integer.MAX_VALUE;

    for (List<Integer> cycle : cycles) {
        List<Integer> divs = divisors(cycle.size());
        for (int d : divs) {
            boolean okForThisDiv = false;

            // try every possible offset within the divisor range
            for (int start = 0; start < d; start++) {
                int colour = colors[cycle.get(start)];
                boolean allMatch = true;

                // walk through the cycle stepping by d
                for (int idx = start + d; idx < start + cycle.size(); idx += d) {
                    if (colors[cycle.get(idx % cycle.size())] != colour) {
                        allMatch = false;
                        break;
                    }
                }

                if (allMatch) {
                    okForThisDiv = true;
                    break;
                }
            }

            if (okForThisDiv) {
                minAns = Math.min(minAns, d);
                break; // no need to check larger divisors for this cycle
            }
        }
    }

    return minAns;
}

