/**
 * Constructs all cycles of the permutation `perm` (1‑based, length n).
 * Returns a list where each element is the list of indices belonging to one cycle.
 */
private static List<List<Integer>> buildCycles(int[] perm, int n) {
    List<List<Integer>> cycles = new ArrayList<>();
    boolean[] seen = new boolean[n + 1];

    for (int i = 1; i <= n; i++) {
        if (seen[i]) {
            continue;
        }
        List<Integer> cur = new ArrayList<>();
        cycles.add(cur);

        int temp = i;
        cur.add(temp);
        temp = perm[temp];
        while (temp != i) {
            cur.add(temp);
            seen[temp] = true;
            temp = perm[temp];
        }
    }
    return cycles;
}

/**
 * For a given cycle, returns the smallest divisor `d` such that the cycle can be
 * partitioned into `d` equally‑spaced positions all sharing the same color.
 * If none is found, returns Integer.MAX_VALUE (this mirrors the original logic).
 */
private static int smallestGoodDivisor(List<Integer> cycle, int[] colors) {
    List<Integer> divisors = divisors(cycle.size()); // assumes existing helper
    for (int d : divisors) {
        if (isGoodForDivisor(cycle, colors, d)) {
            return d;
        }
    }
    return Integer.MAX_VALUE;
}

/**
 * Checks whether a particular divisor `d` makes the cycle "good".
 */
private static boolean isGoodForDivisor(List<Integer> cycle, int[] colors, int d) {
    int m = cycle.size();
    for (int start = 0; start < d; start++) {
        int expectedColor = colors[cycle.get(start)];
        boolean ok = true;
        for (int idx = start; idx < m; idx += d) {
            if (colors[cycle.get(idx)] != expectedColor) {
                ok = false;
                break;
            }
        }
        if (ok) {
            return true;
        }
    }
    return false;
}

