private static boolean normalizeAndValidate(StringBuilder s, int n,
                                            boolean[] used, int[] nbHolder) {
    int len = s.length();
    int nb = 0;
    int half = len / 2 + (len % 2 == 0 ? 0 : 1);
    for (int i = 0; i < half; i++) {
        char left = s.charAt(i);
        char right = s.charAt(len - 1 - i);

        if (left == '?' && right == '?') {
            nb++;
            continue;
        }
        if (left == '?' || right == '?') {
            if (left == '?') {
                s.setCharAt(i, right);
                left = right;
            } else {
                s.setCharAt(len - 1 - i, left);
                right = left;
            }
        }
        if (left != right) {
            return false;               // impossible palindrome
        }
        used[left - 'a'] = true;
    }
    nbHolder[0] = nb;
    return true;
