public void solve(int testNumber, inputClass sc, PrintWriter out) {
    int n = sc.nextInt();
    StringBuilder s = new StringBuilder(sc.nextLine());
    boolean[] used = new boolean[n];

    // Block A – resolve palindrome constraints and count double‑? pairs
    int nb = preprocess(s, used);
    if (nb == -1) {
        out.println("IMPOSSIBLE");
        return;
    }

    // Block B – how many distinct letters are still missing
    int toadd = countMissing(used);
    if (toadd > nb) {                     // Block C – feasibility check
        out.println("IMPOSSIBLE");
        return;
    }

    // Block D – fill the remaining '?' positions
    int[] nbHolder = new int[]{nb};
    fillRemaining(s, n, nbHolder, toadd, used);
    out.println(s);
}

/* Block A */
private int preprocess(StringBuilder s, boolean[] used) {
    int len = s.length();
    int nb = 0;
    int limit = len / 2 + (len % 2 == 0 ? 0 : 1);
    for (int i = 0; i < limit; i++) {
        char left = s.charAt(i);
        char right = s.charAt(len - 1 - i);

        if (left == '?' && right == '?') {
            nb++;
            continue;
        }
        if (left == '?' || right == '?') {
            if (left == '?')
                s.setCharAt(i, right);
            else
                s.setCharAt(len - 1 - i, left);
        }
        if (s.charAt(i) != s.charAt(len - 1 - i)) {
            return -1;                     // impossible
        }
        used[s.charAt(i) - 'a'] = true;
    }
    return nb;
}

/* Block B */
private int countMissing(boolean[] used) {
    int missing = 0;
    for (boolean b : used) {
        if (!b) missing++;
    }
    return missing;
}

/* Block D */
private void fillRemaining(StringBuilder s, int n, int[] nb, int toadd, boolean[] used) {
    int nxt = 0;
    while (nxt < n && used[nxt]) nxt++;   // first unused letter
    int len = s.length();
    int limit = len / 2 + (len % 2 == 0 ? 0 : 1);

    for (int i = 0; i < limit; i++) {
        if (s.charAt(i) != '?')
            continue;

        if (nb[0] > toadd) {
            s.setCharAt(i, 'a');
            s.setCharAt(len - 1 - i, 'a');
            nb[0]--;
        } else {
            s.setCharAt(i, (char) (nxt + 'a'));
            s.setCharAt(len - 1 - i, (char) (nxt + 'a'));
            nxt++;
            while (nxt < n && used[nxt]) nxt++;
        }
    }
}

