    long[] c = IntegerUtils.generateBinomialCoefficients(rowCount + 1, MOD)[rowCount];
    long[] c2 = new long[rowCount + 1];

    // 1️⃣ Prepare powered coefficient arrays
    preparePowers(rowCount, columnCount, MOD, c, c2);

    // 2️⃣ Run the DP using the prepared multipliers
    updateAnswers(rowCount, total, answer, c, c2, MOD, columnCount);

    out.printLine(answer[total]);
