/** Fills `c` and `c2` with the required powers of the binomial coefficients. */
private static void preparePowers(int rowCount, long columnCount, long MOD,
                                 long[] c, long[] c2) {
    // c2 uses exponent floor(columnCount / rowCount)
    for (int i = 0; i <= rowCount; i++) {
        c2[i] = IntegerUtils.power(c[i], columnCount / rowCount, MOD);
    }
    // c uses exponent ceil(columnCount / rowCount)
    for (int i = 0; i <= rowCount; i++) {
        c[i] = IntegerUtils.power(c[i], columnCount / rowCount + 1, MOD);
    }
}

/** Executes the DP that builds `answer` using the appropriate multiplier array. */
private static void updateAnswers(int rowCount, int total, long[] answer,
                                 long[] c, long[] c2, long MOD,
                                 long columnCount) {
    int threshold = (int) (columnCount % rowCount);
    for (int i = 0; i < rowCount; i++) {
        long[] multiplier = (i < threshold) ? c : c2;
        for (int j = Math.min(total, (i + 1) * rowCount); j >= 0; j--) {
            for (int k = 1; k <= rowCount && k <= j; k++) {
                answer[j] += answer[j - k] * multiplier[k] % MOD;
            }
            answer[j] %= MOD;
        }
    }
}

