private Set<Integer> findCriticalEdges(int n, int d, HashSet<Integer> special, ArrayList<int[]>[] graph) {
    Set<Integer> result = new HashSet<>();
    int[] vis = new int[n];
    Arrays.fill(vis, -1);
    LinkedList<int[]> queue = new LinkedList<>();

    for (int node : special) {
        vis[node] = node;
        queue.add(new int[] { node, node, 0 });
    }

    while (!queue.isEmpty()) {
        int levelSize = queue.size();
        while (levelSize-- > 0) {
            int[] q = queue.poll();
            int node = q[0];
            int root = q[1];
            int dist = q[2];

            for (int[] edge : graph[node]) {
                int adj = edge[0];
                int edgeId = edge[1];

                if (vis[adj] == root) {
                    continue;
                }
                if (vis[adj] != -1) {
                    result.add(edgeId);
                } else {
                    if (dist == d) {
                        result.add(edgeId);
                    } else {
                        vis[adj] = root;
                        queue.add(new int[] { adj, root, dist + 1 });
                    }
                }
            }
        }
    }
    return result;
}

