/** Holds the intermediate values produced by the binary‑search phase. */
private static class SearchState {
    final long ans;
    final long larger;
    final long smaller;

    SearchState(long ans, long larger, long smaller) {
        this.ans = ans;
        this.larger = larger;
        this.smaller = smaller;
    }
}

/**
 * Executes the binary‑search‑like loop that determines how many
 * “larger” and “smaller” elements are used and updates the partial answer.
 *
 * @return a {@link SearchState} containing the partial answer and the remaining counts.
 */
private static SearchState runBinarySearch(int n, int x, int pos, long mod) {
    long ans = 1L;
    long larger = n - x;   // numbers greater than x
    long smaller = x - 1;  // numbers smaller than x
    int lo = 0;
    int hi = n;

    while (lo < hi) {
        int mid = (lo + hi) / 2;
        if (mid > pos) {
            hi = mid;
            ans = (ans * larger) % mod;
            larger--;
        } else if (mid < pos) {
            lo = mid + 1;
            ans = (ans * smaller) % mod;
            smaller--;
        } else { // mid == pos
            lo = mid + 1;
            if (lo == n - 1) {
                ans = (ans * larger) % mod;
                larger--;
                break;
            }
        }
    }
    return new SearchState(ans, larger, smaller);
}

/**
 * Multiplies the remaining unused numbers (the factorial of {@code smaller + larger})
 * into the partial answer.
 *
 * @param state the intermediate result from {@link #runBinarySearch}
 * @return the final answer modulo {@code mod}
 */
private static long applyRemainingMultiplication(SearchState state, long mod) {
    long ans = state.ans;
    long rem = state.smaller + state.larger; // total numbers left to arrange

    for (long i = 1; i <= rem; i++) {
        ans = (ans * i) % mod;
    }
    return ans;
}

