// builds the array of segment trees and inserts the first `rows` rows of `a`
private static SegmentTree[] buildAndInitTrees(int n, int m, long[][] a, int rows) {
    SegmentTree[] tree = new SegmentTree[m];
    for (int i = 0; i < m; i++) {
        tree[i] = new SegmentTree(n);
    }
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < m; j++) {
            tree[j].update_point(i + 1, a[i][j]);
        }
    }
    return tree;
}

// computes the sum of all tree queries and fills the `print` array
private static long computeCurrentSum(SegmentTree[] tree, int m, long[] print) {
    long sum = 0;
    for (int l = 0; l < m; l++) {
        sum += (print[l] = tree[l].query());
    }
    return sum;
}

// slides a window of size `windowSize` over rows [windowSize .. n)
// updating trees in‑place, keeping `print` up‑to‑date, and returns
// true as soon as a window satisfies the condition `curr <= k`
private static boolean slideWindow(int windowSize, int n, int m, long[][] a,
                                   long k, SegmentTree[] tree, long[] print) {
    boolean can = false;
    for (int i = 0, j = windowSize; j < n && !can; i++, j++) {
        // remove row i
        for (int l = 0; l < m; l++) {
            tree[l].update_point(i + 1, 0L);
        }
        // add row j
        for (int l = 0; l < m; l++) {
            tree[l].update_point(j + 1, a[j][l]);
        }
        long curr = 0;
        for (int l = 0; l < m; l++) {
            curr += (print[l] = tree[l].query());
        }
        if (curr <= k) {
            can = true;
        }
    }
    return can;
}

