private static SegmentTree[] buildSegmentTrees(int m, int n) {
    SegmentTree[] trees = new SegmentTree[m];
    for (int i = 0; i < m; i++)
        trees[i] = new SegmentTree(n);
    return trees;
}

/** loads rows [from, to) (0‑based) of matrix a into the segment trees. */
private static void loadRowsIntoTrees(SegmentTree[] trees, long[][] a, int from, int to) {
    int m = trees.length;
    for (int i = from; i < to; i++)
        for (int j = 0; j < m; j++)
            trees[j].update_point(i + 1, a[i][j]);
}

/** Queries every tree, stores each result into *out* and returns the total sum. */
private static long queryAllTrees(SegmentTree[] trees, long[] out) {
    long sum = 0;
    for (int i = 0; i < trees.length; i++) {
        sum += (out[i] = trees[i].query());
    }
    return sum;
}

/**
 * Slides a window of size {@code windowSize} down the rows.
 * Updates *print* with the last window's per‑column results.
 *
 * @return true if some window satisfies the condition {@code sum <= k}
 */
private static boolean slideWindow(SegmentTree[] trees, long[][] a,
                                   int windowSize, int n, int m, long k, long[] print) {
    for (int i = 0, j = windowSize; j < n; i++, j++) {
        // remove row i
        for (int col = 0; col < m; col++)
            trees[col].update_point(i + 1, 0L);
        // add row j
        for (int col = 0; col < m; col++)
            trees[col].update_point(j + 1, a[j][col]);

        long curSum = queryAllTrees(trees, print);
        if (curSum <= k) {
            return true;
        }
    }
    return false;
}

