}

/* ---------- helper methods ---------- */

private static Node[] readNodes(SC scan, int n) {
    Node[] a = new Node[n];
    for (int i = 0; i < n; i++) a[i] = new Node(i);
    for (int i = 0; i < n; i++) a[i].p = scan.nextInt();
    for (int i = 0; i < n; i++) a[i].c = scan.nextInt();
    return a;
}

private static void computeAnswers(Node[] sortedByP,
                                   PriorityQueue<Node> pq,
                                   long[] ans,
                                   int k) {
    for (int i = 0; i < sortedByP.length; i++) {
        Node cur = sortedByP[i];
        ans[cur.i] = cur.c;               // base value for this index
        accumulateFromQueue(cur, pq, ans, k);
    }
}

/* extracts the inner “k‑times” logic and uses guard‑clauses */
private static void accumulateFromQueue(Node cur,
                                        PriorityQueue<Node> pq,
                                        long[] ans,
                                        int k) {
    Stack<Node> temp = new Stack<>();
    int taken = 0;

    while (taken < k && !pq.isEmpty()) {
        Node top = pq.peek();

        // guard‑clause: element not eligible → discard and retry same iteration
        if (top.p >= cur.p) {
            pq.poll();          // remove the ineligible element
            continue;           // do not increase 'taken'
        }

        // eligible element: add its cost and remember it for later reinsertion
        ans[cur.i] += top.c;
        temp.push(pq.poll());
        taken++;
    }

    // put the temporarily removed elements back into the queue
    while (!temp.isEmpty()) {
        pq.add(temp.pop());
    }
}

private static void outputAnswers(PrintWriter pw, long[] ans) {
    for (int i = 0; i < ans.length; i++) {
        pw.print(ans[i] + (i == ans.length - 1 ? "\n" : " "));
    }
}

