/* ------------------------------------------------------------------- */
/* Helper methods – each one has a very low cyclomatic complexity.    */
/* ------------------------------------------------------------------- */

private static PrintWriter initWriter() {
    if (FROM_FILE) {
        try {
            return new PrintWriter(new FileWriter("output.txt"));
        } catch (IOException ignored) {
            // fall back to standard output if the file cannot be opened
        }
    }
    return new PrintWriter(new OutputStreamWriter(System.out));
}

/**
 * Returns the index of the first character that is *not* {@code target}
 * starting at {@code start}.  If the whole tail consists of {@code target},
 * the returned value is {@code str.length}.
 */
private static int countConsecutive(char[] str, int start, char target) {
    int i = start;
    while (i < str.length && str[i] == target) {
        i++;
    }
    return i;
}

/**
 * Multiplies {@code base} by {@code 2^times} modulo {@code mod}.
 * The loop is tiny (times ≤ length of the input) and kept separate
 * to keep the main algorithm readable.
 */
private static int multiplyPowerTwo(int base, int times, int mod) {
    int result = base;
    for (int p = 0; p < times; p++) {
        result = (int) ((long) result * 2 % mod);
    }
    return result;
}

/**
 * Core algorithm: scans the character array, groups consecutive 'a's
 * followed by consecutive 'b's and accumulates the required value.
 * Guard clauses replace deep nesting.
 */
private static long computeResult(char[] str, int mod) {
    int n = str.length;
    int i = countConsecutive(str, 0, 'b'); // skip leading 'b's
    int aPower = 1;
    long res = 0L;

    while (i < n) {
        // run of 'a's
        int aEnd = countConsecutive(str, i, 'a');
        if (aEnd == n) {
            break; // no following 'b' block
        }
        int aCnt = aEnd - i;
        aPower = multiplyPowerTwo(aPower, aCnt, mod);

        // run of 'b's that follows the 'a's
        int bEnd = countConsecutive(str, aEnd, 'b');
        int bCnt = bEnd - aEnd;

        res = (res + bCnt * ((long) aPower - 1)) % mod;
        i = bEnd; // continue after the processed 'b' block
    }
    return res;
}

public static void main(String[] args) {
