 * Mirrors the original behaviour: on IOException the writer stays null.
 */
private static PrintWriter initialiseWriter() {
    PrintWriter out;
    if (FROM_FILE) {
        try {
            out = new PrintWriter(new FileWriter("output.txt"));
        } catch (IOException ignored) {
            out = null;               // behaviour identical to original catch block
        }
    } else {
        out = new PrintWriter(new OutputStreamWriter(System.out));
    }
    return out;
}

/**
 * Core algorithm – computes the required value for the given character array.
 */
private static long computeResult(char[] str, int mod) {
    int n = str.length;
    int i = 0;
    int aPower = 1;
    long res = 0;

    // skip leading 'b's (guard clause style)
    i += countConsecutive(str, i, 'b');

    while (i < n) {
        int aCount = countConsecutive(str, i, 'a');
        if (aCount == 0) break;                     // no 'a' block – end of processing
        // update aPower = 2^aCount (modular)
        aPower = powTwoMod(aPower, aCount, mod);

        int bStart = i + aCount;
        int bCount = countConsecutive(str, bStart, 'b');

        // accumulate result
        res = (res + bCount * ((long) aPower - 1)) % mod;

        // move index to the character after the processed 'b' block
        i = bStart + bCount;
    }
    return res;
}

/**
 * Counts how many consecutive characters equal to {@code target}
 * start at {@code index}. Returns the count (may be zero).
 */
private static int countConsecutive(char[] arr, int index, char target) {
    int start = index;
    while (index < arr.length && arr[index] == target) {
        index++;
    }
    return index - start;
}

/**
 * Computes (base * 2^exp) % mod efficiently using repeated multiplication.
 */
private static int powTwoMod(int base, int exp, int mod) {
    int result = base;
    for (int p = 0; p < exp; p++) {
        result = (int) ((result * 2L) % mod);
    }
    return result;
}

