public void solve(int testNumber, FastScanner in, PrintWriter out) {
    init();
    int n = in.nextInt();
    int m = in.nextInt();
    long L = in.nextInt();
    long R = in.nextInt();
    modulo = in.nextInt();

    long res = 0;
    for (int dx = 1; dx <= n; dx++) {
        long[] bounds = computeBounds(dx, L, R, m);
        if (bounds == null) {
            continue;                     // high < 0  or  left >= right
        }
        long left = bounds[0];
        long right = bounds[1];

        long add = contribution(dx, left, right, n, m);
        res = (res + add) % modulo;
    }

    if (L <= 1) {
        res = (res + ((long) (n + 1) * m + (long) n * (m + 1))) % modulo;
    }
    out.println(res % modulo);
}

/** Returns null when the current dx should be skipped.
 *  Otherwise returns an array {left, right} clamped to [0, m].
 */
private long[] computeBounds(int dx, long L, long R, int m) {
    long low  = L * L - (long) dx * dx;
    long high = R * R - (long) dx * dx;

    if (high < 0) {
        return null;                     // original: continue
    }
    if (low < 0) {
        low = 0;
    }

    long left  = (long) Math.sqrt(low);
    long right = (long) Math.sqrt(high);

    // adjust left so that left^2 + dx^2 < L^2
    while (left > 0 && left * left + (long) dx * dx >= L * L) {
        left--;
    }
    while (left * left + (long) dx * dx < L * L) {
        left++;
    }
    left--;

    // adjust right so that right^2 + dx^2 <= R^2
    while (right > 0 && right * right + (long) dx * dx >= R * R) {
        right--;
    }
    while (right * right + (long) dx * dx <= R * R) {
        right++;
    }
    right--;

    if (left < 0) {
        left = 0;
    }
    if (right > m) {
        right = m;
    }
    if (left >= right) {
        return null;                     // nothing to count for this dx
    }
    return new long[]{left, right};
}

/** Computes the value that must be added to the answer for a given dx and interval. */
private long contribution(int dx, long left, long right, int n, int m) {
    long cntR = right - getCount(dx, (int) right);
    long cntL = left  - getCount(dx, (int) left);
    long cnt  = (cntR - cntL) % modulo;
    if (cnt < 0) {
        cnt += modulo;
    }

    long sumR = right * (right + 1) / 2 - getSum(dx, (int) right);
    long sumL = left  * (left  + 1) / 2 - getSum(dx, (int) left);
    long sum  = sumR - sumL;

    sum = (cnt * (m + 1) % modulo - sum) % modulo;
    if (sum < 0) {
        sum += modulo;
    }

    long term = (2 * sum) % modulo;
    term = term * (n - dx + 1) % modulo;
    return term;
}

public void solve(int testNumber, FastScanner in, PrintWriter out) {
    init();

    int n = in.nextInt();
    int m = in.nextInt();
    long L = in.nextInt();
    long R = in.nextInt();
    int modulo = in.nextInt();

    long res = 0;
    for (long dx = 1; dx <= n; dx++) {
        res = (res + computeContribution(dx, n, m, L, R, modulo)) % modulo;
    }

    if (L <= 1) {
        long extra = ((n + 1L) * m + (long) n * (m + 1L)) % modulo;
        res = (res + extra) % modulo;
    }

    out.println(res % modulo);
}

/* ------------------------------------------------------------------- */

private long computeContribution(long dx, int n, int m,
                                 long L, long R, int modulo) {
    long low  = L * L - dx * dx;
    long high = R * R - dx * dx;

    if (low < 0) low = 0;
    if (high < 0) return 0L;                // nothing inside the circle

    long left  = (long) Math.sqrt(low);
    long right = (long) Math.sqrt(high);

    left  = adjustLeft(dx, left, L);
    right = adjustRight(dx, right, R);

    if (left < 0) left = 0;
    if (right > m) right = m;
    if (left >= right) return 0L;           // empty interval

    long cntR = right - getCount((int) dx, (int) right);
    long cntL = left  - getCount((int) dx, (int) left);
    long cnt  = ((cntR - cntL) % modulo + modulo) % modulo;

    long sumR = right * (right + 1) / 2 - getSum((int) dx, (int) right);
    long sumL = left  * (left  + 1) / 2 - getSum((int) dx, (int) left);
    long sum  = sumR - sumL;

    sum = (cnt * (m + 1) % modulo - sum) % modulo;
    sum = (sum + modulo) % modulo;          // ensure non‑negative

    return (2 * sum % modulo) * (n - dx + 1) % modulo;
}

/* ------------------------------------------------------------------- */

private long adjustLeft(long dx, long left, long L) {
    while (left > 0 && left * left + dx * dx >= L * L) {
        left--;
    }
    while (left * left + dx * dx < L * L) {
        left++;
    }
    return left - 1;
}

private long adjustRight(long dx, long right, long R) {
    while (right > 0 && right * right + dx * dx >= R * R) {
        right--;
    }
    while (right * right + dx * dx <= R * R) {
        right++;
    }
    return right - 1;
}

