/** Fill the whole matrix with the sentinel value MAX. */
private void initCostMatrix(int[][] cost) {
    int size = cost.length;
    for (int i = 0; i < size * size; i++) {
        cost[i / size][i % size] = MAX;
    }
}

/** Read the directed edges and store their weights. */
private void readEdges(Scanner in, int[][] cost, int edgeCount) {
    for (int i = 0; i < edgeCount; i++) {
        int a = in.nextInt();
        int b = in.nextInt();
        int w = in.nextInt();
        cost[a][b] = w;
    }
}

/** First DP pass: propagate values forward along increasing indices. */
private void computeFirstPass(int[][] cost, int[] dp, int n) {
    for (int s = 1; s < n; s++) {
        for (int i = 0; i <= s; i++) {
            if (cost[i][s] == MAX) {
                continue; // guard clause – skip unavailable edge
            }
            dp[s] = Math.max(dp[s], dp[i] + cost[i][s]);
        }
    }
}

/** Second DP pass: relax all remaining edges. */
private void computeSecondPass(int[][] cost, int[] dp, int n) {
    for (int s = 0; s < n; s++) {
        for (int i = 0; i < n; i++) {
            if (cost[s][i] == MAX) {
                continue; // guard clause – skip unavailable edge
            }
            dp[i] = Math.max(dp[s] + cost[s][i], dp[i]);
        }
    }
}

