        b = readByte();

        // termination: EOF or non‑printable character
        if (b == -1 || !isPrintableChar(b)) {
            return n;
        }

        // any printable character that is not a digit is illegal
        if (!isDigit(b)) {
            throw new NumberFormatException();
        }
        // otherwise loop continues with the new digit in 'b'
    }
