public static int call(int pos, int cnt, int f) {
    // Guard 1: exceed allowed occurrences
    if (cnt > times) {
        return 0;
    }
    // Guard 2: reached end of the number string
    if (pos == number.length()) {
        return cnt == times ? 1 : 0;
    }
    // Guard 3: memoised result
    if (digitDP[pos][cnt][f] != -1) {
        return digitDP[pos][cnt][f];
    }

    int res = 0;
    int limit = (f == 0) ? number.charAt(pos) - '0' : 9;

    for (int dgt = 0; dgt <= limit; ++dgt) {
        int nextCnt = nextCount(dgt, cnt);
        // Guard inside loop: prune branches that would exceed `times`
        if (nextCnt > times) {
            continue;
        }
        int nextFlag = nextFlag(f, dgt, limit);
        res += call(pos + 1, nextCnt, nextFlag);
    }

    digitDP[pos][cnt][f] = res;
    return res;
}

/**
 * Returns the updated occurrence count after placing digit {@code dgt}.
 */
private static int nextCount(int dgt, int cnt) {
    return (dgt == digit) ? cnt + 1 : cnt;
}

/**
 * Computes the next flag value.
 * <p>
 * {@code f == 0} means we are still tied to the prefix of {@code number};
 * choosing a digit smaller than the current limit breaks the tie (flag becomes 1).
 * Otherwise the flag stays as it is.
 * </p>
 */
private static int nextFlag(int f, int dgt, int limit) {
    return (f == 0 && dgt < limit) ? 1 : f;
}

