public static void sort(int[] arr) {
    // Guard clause – nothing to do for null or trivial arrays
    if (arr == null || arr.length < 2) {
        return;
    }

    int n = arr.length;
    int last = n - 1;
    int[] res = new int[n];

    // Bottom‑up merge‑sort: increase the size of merged runs (s) each pass
    for (int s = 1; s <= last; s <<= 1) {
        // Process each pair of runs starting at position l
        for (int l = 0; l <= last; l += (s << 1)) {
            int h   = Math.min(l + (s << 1) - 1, last); // end of right run
            int mid = Math.min(l + s - 1, last);        // end of left run

            mergeSegment(arr, res, l, mid, h);
