private static void mergeSegment(int[] src, int[] dst, int left, int mid, int right) {
    int i = left;      // index in left run
    int j = mid + 1;   // index in right run
    int k = left;      // index in destination

    // Merge while both runs contain elements
    while (i <= mid && j <= right) {
        dst[k++] = (src[i] <= src[j]) ? src[i++] : src[j++];
    }

    // Copy any remaining elements from the left run
    while (i <= mid) {
        dst[k++] = src[i++];
    }

    // Copy any remaining elements from the right run
    while (j <= right) {
        dst[k++] = src[j++];
    }
}

/**
 * Copies the merged segment dst[left..right] back into src[left..right].
 */
private static void copyBack(int[] src, int[] dst, int left, int right) {
    for (int i = left; i <= right; i++) {
        src[i] = dst[i];
    }
}

public static void sort(int[] arr) {
    int n = arr.length;
    // Guard clause for trivial arrays
    if (n <= 1) {
        return;
    }

    int[] temp = new int[n];
    // size = length of the sub‑arrays to merge (1, 2, 4, …)
    for (int size = 1; size < n; size <<= 1) {
        // left = start index of the first sub‑array in the current pair
        for (int left = 0; left < n; left += size << 1) {
            int mid   = Math.min(left + size - 1, n - 1);
            int right = Math.min(left + (size << 1) - 1, n - 1);
            merge(arr, temp, left, mid, right);
        }
    }
}

/**
 * Merges the two sorted halves [left..mid] and [mid+1..right] from {@code src}
 * into {@code dest}, then copies the merged segment back into {@code src}.
 */
private static void merge(int[] src, int[] dest, int left, int mid, int right) {
    int i = left;     // index in the left half
    int j = mid + 1;  // index in the right half
    int k = left;     // index in the destination buffer

    // Merge while both halves have elements
    while (i <= mid && j <= right) {
        dest[k++] = (src[i] <= src[j]) ? src[i++] : src[j++];
    }
    // Copy any remaining elements from the left half
    while (i <= mid) {
        dest[k++] = src[i++];
    }
    // Copy any remaining elements from the right half
    while (j <= right) {
        dest[k++] = src[j++];
    }
    // Write the merged segment back into the original array
    for (k = left; k <= right; k++) {
        src[k] = dest[k];
    }
}

