boolean empty(long pos) {
    // Guard clauses – the obvious early returns
    if (k == n) {
        return false;
    }
    if (k == 0) {
        return true;
    }

    long free = n - k;

    // Two distinct regimes based on the amount of free space
    if (free <= n / 2) {
        return isEmptyWhenFreeSmall(pos, free);
    } else {
        return isEmptyWhenFreeLarge(pos, free);
    }
}

/* ---------- helpers for the two regimes ---------- */

private boolean isEmptyWhenFreeSmall(long pos, long free) {
    // Only odd positions count and they must fit into the free slots
    return (pos & 1L) == 1L && ((pos + 1) / 2) <= free;
}

private long adjustedA(long free) {
    long a = n - 2 * k + 1;
    // If a is even and still smaller than the number of free slots,
    // bump it to the next odd value
    if ((a & 1L) == 0L && a < free) {
        a++;
    }
    return a;
}

private boolean isEmptyWhenFreeLarge(long pos, long free) {
    long a = adjustedA(free);

    // First check: positions up to the adjusted pivot are always empty
    if (pos <= a) {
        return true;
    }

    // Second check: after the pivot we need an even offset that fits
    long offset = pos - a;
    return (offset & 1L) == 0L && (offset / 2) <= (free - a);
}

