    boolean canPlaceZero = canPlaceZero(index, lr);
    boolean canPlaceOne  = canPlaceOne(index, sm);

    // Compute the two possible scores; -1 denotes an unavailable branch
    int ansZ = canPlaceZero ? computeAnsZero(index, sm, lr) : -1;
    int ansO = canPlaceOne  ? computeAnsOne(index, sm, lr)  : -1;

    // Remember which choice gave the optimal result
    next[index][sm][lr] = (ansZ >= ansO) ? 0 : 1;

    // Store and return the optimal value
    DP[index][sm][lr] = Math.max(ansZ, ansO);
    return DP[index][sm][lr];
