/* ---------- helper methods ---------- */

private static boolean canPlaceZero(int index, int lr) {
    // A zero is forbidden only when the left string has '1' and we are not already
    // in a “greater‑than‑left” state.
    return !(l.charAt(index) == '1' && lr == 0);
}

private static boolean canPlaceOne(int index, int sm) {
    // A one is forbidden only when the right string has '0' and we are not already
    // in a “less‑than‑right” state.
    return !(r.charAt(index) == '0' && sm == 0);
