private static int computeAnsZero(int index, int sm, int lr) {
    // New state for the “smaller‑than‑right” flag after placing a zero
    int newSm = (sm == 1 || r.charAt(index) == '1') ? 1 : 0;
    return get(index + 1, newSm, lr);
}

private static int computeAnsOne(int index, int sm, int lr) {
    // New state for the “larger‑than‑left” flag after placing a one
    int newLr = (lr == 1 || l.charAt(index) == '0') ? 1 : 0;
    return 1 + get(index + 1, sm, newLr);
}

public static int get(int index, int sm, int lr) {
    // Guard clauses – eliminate early branches
    if (index == DP.length) {
        return 0;
    }
    if (DP[index][sm][lr] != -1) {
        return DP[index][sm][lr];
    }

    int ansZ = -1;
    if (canPlaceZero(index, lr)) {
        int newSm = nextSmForZero(sm, index);
        ansZ = get(index + 1, newSm, lr);
    }

    int ansO = -1;
    if (canPlaceOne(index, sm)) {
        int newLr = nextLrForOne(lr, index);
        ansO = 1 + get(index + 1, sm, newLr);
    }

    storeNextChoice(index, sm, lr, ansZ, ansO);
    return DP[index][sm][lr] = Math.max(ansO, ansZ);
