/** Can we place a ‘1’ at position *index* given the current left‑limit state? */
private static boolean canPlaceOne(int index, int sm) {
    // '0' on the right side while we are still constrained on the left → forbidden
    return !(r.charAt(index) == '0' && sm == 0);
}

/** New *sm* (state‑left) after placing a ‘0’. */
private static int nextSmForZero(int sm, int index) {
    // Once we have seen a ‘1’ on the right side or were already “free”, we stay free
    return (sm == 1 || r.charAt(index) == '1') ? 1 : 0;
}

/** New *lr* (state‑right) after placing a ‘1’. */
private static int nextLrForOne(int lr, int index) {
    // Once we have seen a ‘0’ on the left side or were already “free”, we stay free
    return (lr == 1 || l.charAt(index) == '0') ? 1 : 0;
}

/** Record which choice (0 or 1) yields the optimal value. */
private static void storeNextChoice(int index, int sm, int lr, int ansZ, int ansO) {
    // If ansZ is not worse than ansO we chose a ‘0’, otherwise a ‘1’
    next[index][sm][lr] = (ansZ >= ansO) ? 0 : 1;
