public static int get(int index, int sm, int lr) {
    // Guard clauses – base case and memoised result
    if (index == DP.length) {
        return 0;
    }
    if (DP[index][sm][lr] != -1) {
        return DP[index][sm][lr];
    }

    // Delegate the two possible choices to helper methods
    int ansZ = computeAnsZ(index, sm, lr);
    int ansO = computeAnsO(index, sm, lr);

    // Record which choice was better and memoise the result
    next[index][sm][lr] = (ansZ >= ansO) ? 0 : 1;
    return DP[index][sm][lr] = Math.max(ansO, ansZ);
}

/* ---------- Helper methods ---------- */

private static int computeAnsZ(int index, int sm, int lr) {
    if (!canPlaceZero(index, lr)) {
        return -1;                       // illegal to put a '0' here
    }
    int newSm = (sm == 1 || r.charAt(index) == '1') ? 1 : 0;
    return get(index + 1, newSm, lr);   // no cost added for a '0'
}

private static int computeAnsO(int index, int sm, int lr) {
    if (!canPlaceOne(index, sm)) {
        return -1;                       // illegal to put a '1' here
    }
    int newLr = (lr == 1 || l.charAt(index) == '0') ? 1 : 0;
    return 1 + get(index + 1, sm, newLr); // cost of 1 for a '1'
}

private static boolean canPlaceZero(int index, int lr) {
    // A '0' is forbidden when the left string has a '1' and we are not already in a larger‑than‑left state
    return !(l.charAt(index) == '1' && lr == 0);
}

private static boolean canPlaceOne(int index, int sm) {
    // A '1' is forbidden when the right string has a '0' and we are not already in a smaller‑than‑right state
    return !(r.charAt(index) == '0' && sm == 0);
