/* Initialise the 2‑dimensional array of segment trees.
   Only rows 2‥6 are used; the others stay null. */
private static SegmentTree[][] initSegmentTrees(int n) {
    SegmentTree[][] t = new SegmentTree[7][10];
    for (int i = 2; i < 7; i++) {
        for (int j = 0; j < 2 * (i - 1); j++) {
            t[i][j] = new SegmentTree(n);
        }
    }
    return t;
}

/* Fill every segment tree with the initial values. */
private static void buildInitialValues(SegmentTree[][] trees, long[] a) {
    for (int idx = 0; idx < a.length; idx++) {
        for (int j = 0; j < 7; j++) {
            for (int k = 0; k < 2 * (j - 1); k++) {
                trees[j][k].update(idx, a[idx] * getMult(j, k, idx));
            }
        }
    }
}

/* Apply a point update to **all** relevant segment trees. */
private static void updateAll(SegmentTree[][] trees, int pos, long newVal) {
    for (int j = 0; j < 7; j++) {
        for (int k = 0; k < 2 * (j - 1); k++) {
            trees[j][k].update(pos, newVal * getMult(j, k, pos));
        }
    }
}

/* Perform a range query on the appropriate tree. */
private static long queryTree(SegmentTree[][] trees, int l, int r, int z) {
    int shift = l % (2 * (z - 1));
    return trees[z][shift].query(l, r);
}

public static void main(String[] args) {
