    for (int i = 2; i < 7; i++) {
        for (int j = 0; j < 2 * (i - 1); j++) {
            T[i][j] = new SegmentTree(n);
        }
    }
}

private static void buildSegmentTrees(SegmentTree[][] T, long[] A, int n) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < 7; j++) {
            for (int k = 0; k < 2 * (j - 1); k++) {
                T[j][k].update(i, A[i] * getMult(j, k, i));
            }
        }
    }
