/**
 * Rotates the dice until the top face equals the desired value.
 */
private static void rotateToTop(Dice dice, int targetTop) {
    if (targetTop == dice.top) {
        return;                     // already correct
    }
    if (targetTop == dice.front) {
        dice.turnN();
        return;
    }
    if (targetTop == dice.back) {
        dice.turnN(); dice.turnN(); dice.turnN();
        return;
    }
    if (targetTop == dice.left) {
        dice.turnE();
        return;
    }
    if (targetTop == dice.right) {
        dice.turnE(); dice.turnE(); dice.turnE();
        return;
    }
    // targetTop == dice.bottom
    dice.turnN(); dice.turnN();
}

/**
 * Rotates the dice (around the vertical axis) until the front face equals the desired value.
 * Assumes the top face is already positioned correctly.
 */
private static void rotateToFront(Dice dice, int targetFront) {
    if (targetFront == dice.front) {
        return;                     // already correct
    }
    if (targetFront == dice.right) {
        dice.turnR();
        return;
    }
    if (targetFront == dice.left) {
        dice.turnR(); dice.turnR(); dice.turnR();
        return;
    }
    // targetFront == dice.back
    dice.turnR(); dice.turnR();
}

