long go(int last, int phase, int idx) {
    // base case
    if (idx == n) return 0;
    // memoisation check
    if (memo[last][phase][idx] != -1) return memo[last][phase][idx];

    long ans;
    switch (phase) {
        case 0: ans = handlePhase0(last, idx); break;
        case 1: ans = handlePhase1(last, idx); break;
        case 2: ans = handlePhase2(last, idx); break;
        case 3: ans = handlePhase3(last, idx); break;
        default: throw new IllegalArgumentException("Invalid phase: " + phase);
    }
    return memo[last][phase][idx] = ans;
}

// ---------- phase handlers ----------
private long handlePhase0(int last, int idx) {
    // phase 0: either start a new increasing subsequence or skip
    long take = 1 + go(a[idx], 1, idx + 1);
    long skip = go(last, 0, idx + 1);
    return Math.max(take, skip);
}

private long handlePhase1(int last, int idx) {
    // phase 1: already in an increasing segment
    long best = go(last, 1, idx + 1);               // skip current element
    if (last <= a[idx]) {
        best = Math.max(best, 1 + go(a[idx], 1, idx + 1)); // extend increasing
    }
    // option to finish increasing and switch to decreasing
    best = Math.max(best, go(last, 2, idx));
    return best;
}

private long handlePhase2(int last, int idx) {
    // phase 2: in a decreasing segment
    long best = go(last, 2, idx + 1);               // skip current element
    if (last >= a[idx]) {
        best = Math.max(best, 1 + go(a[idx], 2, idx + 1)); // extend decreasing
    }
    // option to finish decreasing and move to final phase
    best = Math.max(best, go(last, 3, idx));
    return best;
}

private long handlePhase3(int last, int idx) {
    // phase 3: final increasing segment (no further phase transition)
    long best = go(last, 3, idx + 1);               // skip current element
    if (last <= a[idx]) {
        best = Math.max(best, 1 + go(a[idx], 3, idx + 1)); // extend increasing
    }
    return best;
}

