public long nextLong() {
    ensureHasNext();

    int c = skipSpaces();                 // first non‑space character
    boolean minus = isNegativeSign(c);

    if (minus) {                           // consume the sign character
        c = readByte();
    }

    long value = readUnsignedLong(c);
    return minus ? -value : value;
}

/*--- Helper methods ---------------------------------------------------*/

private void ensureHasNext() {
    if (!hasNext()) {
        throw new NoSuchElementException();
    }
}

private int skipSpaces() {
    int c = readByte();
    while (isSpaceChar(c)) {
        c = readByte();
    }
    return c;
}

private boolean isNegativeSign(int ch) {
    return ch == '-';
}

/**
 * Reads a sequence of digit characters starting with {@code firstChar}
 * and returns the assembled long value.  Terminates when a whitespace
 * character is encountered.  Throws {@code InputMismatchException}
 * if a non‑digit is found.
 */
private long readUnsignedLong(int firstChar) {
    long result = 0;
    int c = firstChar;

    do {
        if (c < '0' || c > '9') {
            throw new InputMismatchException();
        }
        result = result * 10 + (c - '0');
        c = readByte();
    } while (!isSpaceChar(c));

    return result;
}

