    long[][] mat = new long[sz][sz];

    initMatrix(mat, k);
    fillMatrix(mat, k);
    copyLastColumn(mat, k);
    mat[sz - 1][sz - 1] = 1;

    mat = pow(mat, n - 2);

    long[] arr = initArray(k, sz);
    arr[sz - 1] = add(arr[sz - 1], pow[k + 1], M);

    long ans = computeAnswer(arr, mat, sz);
    pw.println(ans);
}

/* ---------- helper methods ---------- */

private void initMatrix(long[][] mat, int k) {
    // set the lower‑left identity block
    for (int i = 0; i <= k; i++) {
        mat[k + 1 + i][i] = 1;
    }
}

private void fillMatrix(long[][] mat, int k) {
    // fill the two upper blocks with combinatorial values
    for (int c = 0; c <= k; c++) {
        for (int r = 0; r <= c; r++) {
            mat[r][k + 1 + c] = mul(ncr(c, r), pow[c - r], M);
            mat[k + 1 + r][k + 1 + c] = ncr(c, r);
        }
    }
}

private void copyLastColumn(long[][] mat, int k) {
    // duplicate column (2k+1) into column (2k+2)
    for (int i = 0; i <= 2 * k + 1; i++) {
        mat[i][2 * k + 2] = mat[i][2 * k + 1];
    }
}

private long[] initArray(int k, int sz) {
    long[] arr = new long[sz];
    for (int i = 0; i <= k; i++) {
        arr[i] = 1;
    }
    for (int i = k + 1; i <= 2 * k + 1; i++) {
        arr[i] = pow[i - k];
    }
    arr[sz - 1] = 1;   // last element starts at 1
    return arr;
}

private long computeAnswer(long[] arr, long[][] mat, int sz) {
    long ans = 0;
    for (int i = 0; i < sz; i++) {
        ans = add(ans, mul(arr[i], mat[i][sz - 1], M), M);
    }
    return ans;
}

void solve() {
    long n = nl();
    int k = ni();

    // Guard clause – the trivial case
    if (n == 1) {
        pw.println("1");
        return;
    }

    precompute(k + 2);
    int sz = size(k);

    long[][] matrix = buildMatrix(k, sz);
    copyLastColumn(matrix, k);
    matrix[sz - 1][sz - 1] = 1;

    long[][] powered = pow(matrix, n - 2);

    long[] init = buildInitialArray(k, sz);
    init[sz - 1] = add(init[sz - 1], pow[k + 1], M);

    long answer = computeAnswer(init, powered, sz);
    pw.println(answer);
}

/** size of the square matrix for a given k */
private int size(int k) {
    // (k+1) + (k+1) + 1  == 2*k + 3
    return 2 * k + 3;
}

/** Builds the matrix before exponentiation */
private long[][] buildMatrix(int k, int sz) {
    long[][] mat = new long[sz][sz];

    // lower‑left identity‑like block
    for (int i = 0; i <= k; i++) {
        mat[k + 1 + i][i] = 1;
    }

    // fill the combinatorial parts
    for (int c = 0; c <= k; c++) {
        for (int r = 0; r <= c; r++) {
            mat[r][k + 1 + c] = mul(ncr(c, r), pow[c - r], M);
            mat[k + 1 + r][k + 1 + c] = ncr(c, r);
        }
    }
    return mat;
}

/** Copies column 2*k+1 into column 2*k+2 (the last column) */
private void copyLastColumn(long[][] mat, int k) {
    int lastIdx = 2 * k + 1;          // index of the column to copy
    int dstIdx  = lastIdx + 1;        // destination column (sz‑1)
    for (int i = 0; i <= lastIdx; i++) {
        mat[i][dstIdx] = mat[i][lastIdx];
    }
}

/** Creates the initial vector used in the final multiplication */
private long[] buildInitialArray(int k, int sz) {
    long[] arr = new long[sz];
    for (int i = 0; i <= k; i++) {
        arr[i] = 1;
    }
    for (int i = k + 1; i <= 2 * k + 1; i++) {
        arr[i] = pow[i - k];
    }
    arr[sz - 1] = 1;
    return arr;
}

/** Computes the final answer from the vector and the powered matrix */
private long computeAnswer(long[] vec, long[][] mat, int sz) {
    long ans = 0;
    for (int i = 0; i < sz; i++) {
        ans = add(ans, mul(vec[i], mat[i][sz - 1], M), M);
    }
    return ans;
}

