/** reads exactly {@code count} integers from {@code in} into a mutable list */
private static List<Integer> readCards(FastReader in, int count) {
    List<Integer> list = new ArrayList<>(count);
    for (int i = 0; i < count; i++) {
        list.add(in.nextInt());
    }
    return list;
}

/** Executes the card game and returns the number of moves, the winner (1 or 2) and
 *  whether a cycle was detected. */
private static Result playGame(List<Integer> l1, List<Integer> l2) {
    int moves = 0;
    boolean cycle = false;

    Set<List<Integer>> visitedL1 = new HashSet<>();
    Set<List<Integer>> visitedL2 = new HashSet<>();
    visitedL1.add(l1);
    visitedL2.add(l2);

    while (!l1.isEmpty() && !l2.isEmpty()) {
        int card1 = l1.remove(0);
        int card2 = l2.remove(0);

        if (card1 > card2) {
            l1.add(card2);
            l1.add(card1);
        } else {
            l2.add(card1);
            l2.add(card2);
        }
        moves++;

        // Guard: game finished because one pile became empty
        if (l1.isEmpty() || l2.isEmpty()) {
            break;
        }

        // Guard: a previously seen configuration ⇒ cycle
        if (visitedL1.contains(l1) && visitedL2.contains(l2)) {
            cycle = true;
            break;
        }

        // Record the new configuration
        visitedL1.add(l1);
        visitedL2.add(l2);
    }

    int winner = (l2.isEmpty()) ? 1 : 2;   // meaningful only when no cycle
    return new Result(moves, winner, cycle);
}

/** Simple holder for the outcome of the game. */
private static class Result {
    final int moves;
    final int winner;   // 1 or 2 (undefined when cycle == true)
    final boolean cycle;

    Result(int moves, int winner, boolean cycle) {
        this.moves = moves;
        this.winner = winner;
        this.cycle = cycle;
    }
}

public static void main(String[] args) {
    FastReader in = new FastReader();
