                         s2 = new HashSet<>();
    s1.add(l1);
    s2.add(l2);

    while (!l1.isEmpty() && !l2.isEmpty()) {
        playRound(l1, l2);
        ans++;

        // guard‑clause: a player has run out of cards
        if (l1.isEmpty() || l2.isEmpty()) {
            break;
        }

        // guard‑clause: repeated configuration (cycle)
        if (hasCycle(s1, s2, l1, l2)) {
