/**
 * Executes one battle round: each player draws the top card,
 * the higher card wins and both cards are placed at the bottom
 * of the winner's deck (loser’s card first).
 */
private static void playRound(List<Integer> l1, List<Integer> l2) {
    int card1 = l1.remove(0);
    int card2 = l2.remove(0);
    if (card1 > card2) {
        l1.add(card2);
        l1.add(card1);
    } else {
        l2.add(card1);
        l2.add(card2);
    }
}

/**
 * Determines whether the current pair of decks has already been
 * seen (i.e., a cycle). The original implementation stores the
 * mutable lists directly in the sets, so we preserve that exact
 * semantics here.
 */
private static boolean hasCycle(Set<List<Integer>> s1,
                                Set<List<Integer>> s2,
                                List<Integer> l1,
                                List<Integer> l2) {
    return s1.contains(l1) && s2.contains(l2);
}

