}

/* runs the game and returns the result string.
   Returns "-1" when a cycle is detected, otherwise
   "<moves> <winner>" where winner is 1 or 2. */
private static String playWar(List<Integer> deck1, List<Integer> deck2) {
    Set<List<Integer>> seen1 = new HashSet<>();
    Set<List<Integer>> seen2 = new HashSet<>();
    int moves = 0;

    // initial state must be recorded to match original behaviour
    seen1.add(deck1);
    seen2.add(deck2);

    while (!deck1.isEmpty() && !deck2.isEmpty()) {
        int card1 = deck1.remove(0);
        int card2 = deck2.remove(0);

        if (card1 > card2) {
            deck1.add(card2);
            deck1.add(card1);
        } else {
            deck2.add(card1);
            deck2.add(card2);
        }
        moves++;

        // guard‑clause: if a deck became empty the loop will exit naturally
        if (seen1.contains(deck1) && seen2.contains(deck2)) {
            return "-1";                     // cycle detected
        }
        // record current configuration (same mutable objects as original code)
        seen1.add(deck1);
        seen2.add(deck2);
    }

    int winner = deck2.isEmpty() ? 1 : 2;
    return moves + " " + winner;
}

