/* ---------- helper methods ---------- */

private void initFirstDp(char[] s, int[] dp) {
    // dp[1]
    dp[1] = isDivisibleBy3(s[1] - '0') ? 1 : 0;

    if (s.length <= 2) return;               // guard clause – nothing more to init

    // dp[2]
    int d1 = s[1] - '0';
    int d2 = s[2] - '0';
    int mod2 = isDivisibleBy3(d2) ? 1 : 0;
    dp[2] = isDivisibleBy3(d2) ? dp[1] + 1 : 0;
    if (isDivisibleBy3(d1))
        dp[2] = Math.max(dp[2], 1 + mod2);
    if (isDivisibleBy3(d1 + d2))
        dp[2] = Math.max(dp[2], 1);

    if (s.length <= 3) return;               // guard clause – dp[3] not needed

    // dp[3]
    int d3 = s[3] - '0';
    int mod3 = isDivisibleBy3(d3) ? 1 : 0;
    dp[3] = isDivisibleBy3(d3) ? dp[2] + 1 : 0;

    if (isDivisibleBy3(d2))
        dp[3] = Math.max(dp[3], dp[2] + mod3);
    if (isDivisibleBy3(d1))
        dp[3] = Math.max(dp[3], dp[1] + mod3);
    if (isDivisibleBy3(d2 + d3))
        dp[3] = Math.max(dp[3], dp[1] + 1);
    if (isDivisibleBy3(d1 + d2 + d3))
        dp[3] = Math.max(dp[3], 1);
}

private int computeDpAt(int i, char[] s, int[] dp) {
    int z = s[i] - '0';
    int y = s[i - 1] - '0';
    int x = s[i - 2] - '0';

    int best = maxPrev(dp, i);                     // baseline: keep previous best
    if (isDivisibleBy3(z))
        best = Math.max(best, maxPrev(dp, i) + 1); // single digit divisible

    // two‑digit possibilities
    if (isDivisibleBy3(y) || isDivisibleBy3(y + z))
        best = Math.max(best, Math.max(dp[i - 2] + 1, dp[i - 3] + 1));

    // three‑digit possibilities
    if (isDivisibleBy3(x) || isDivisibleBy3(x + y + z))
        best = Math.max(best, dp[i - 3] + 1);

    if (isDivisibleBy3(x + y)) {
        int extra = isDivisibleBy3(z) ? 1 : 0;
        best = Math.max(best, dp[i - 3] + 1 + extra);
    }

    return best;
}

private int maxPrev(int[] dp, int i) {
    return Math.max(dp[i - 1], Math.max(dp[i - 2], dp[i - 3]));
}

private boolean isDivisibleBy3(int v) {
    return v % 3 == 0;
}

