/**
 * Computes the contribution of a single position of string {@code a}
 * to the final answer.
 *
 * @param aChar   current character from {@code a}
 * @param start   left index (inclusive) in {@code b}
 * @param end     right index (inclusive) in {@code b}
 * @param sumZero prefix‑sum of ‘0’ characters in {@code b}
 * @param sumOne  prefix‑sum of ‘1’ characters in {@code b}
 * @return the integer contribution for this position
 */
private static int contribution(char aChar, int start, int end,
                                int[] sumZero, int[] sumOne) {
    int sum = 0;

    if (start > 0) {
        // subtract the count before the window
        sum -= (aChar == '1') ? sumZero[start - 1] : sumOne[start - 1];
    }

    // add the count inside the window
    sum += (aChar == '1') ? sumZero[end] : sumOne[end];

    return sum;
}

