/**
 * Builds a map that, for each original value pair (a[i], b[i]),
 * stores the position i.
 */
private static TreeMap<Triple, Integer> buildIndexMap(int[] a, int[] b) {
    TreeMap<Triple, Integer> map = new TreeMap<>();
    for (int i = 0; i < a.length; i++) {
        map.put(new Triple(a[i], b[i]), i);
    }
    return map;
}

/**
 * Returns the number of successful swaps required.
 * Returns -1 if a required swap cannot be found (i.e., the original algorithm would set {@code failed = true}).
 */
private static int countSwaps(int[] a, int[] b, TreeMap<Triple, Integer> map) {
    int swaps = 0;
    boolean[] swapped = new boolean[a.length];

    for (int i = 0; i < a.length; i++) {
        // Guard clauses – skip already handled or equal elements
        if (swapped[i] || a[i] == b[i]) {
            continue;
        }

        Integer partnerIdx = map.get(new Triple(b[i], a[i]));
        if (partnerIdx == null) {
            return -1;               // failure condition
        }
        if (!swapped[partnerIdx]) {
            swapped[partnerIdx] = true;
            swaps++;
        }
    }
    return swaps;
}

