    Scanner sc = new Scanner(System.in);
    int N = sc.nextInt();
    int[] a = sc.nextIntArray(N);
    int[] b = sc.shuffle(a, N);
    Arrays.sort(b);

    boolean possible = canFormByAtMostOneSwap(a, b);
    System.out.println(possible ? "YES" : "NO");
}

/**
 * Checks whether array {@code a} can be transformed into {@code b}
 * by swapping at most one pair of elements.
 *
 * @return true if the transformation is possible, false otherwise
 */
private static boolean canFormByAtMostOneSwap(int[] a, int[] b) {
    int n = a.length;

    // Build a map from (a[i], b[i]) to its index i
    TreeMap<Triple, Integer> map = new TreeMap<>();
    for (int i = 0; i < n; i++) {
        map.put(new Triple(a[i], b[i]), i);
    }

    boolean[] isSwapped = new boolean[n];
    int swaps = 0;

    for (int i = 0; i < n; i++) {
        // Skip already handled positions or positions that already match
        if (isSwapped[i] || a[i] == b[i]) {
            continue;
        }

        // Look for the reverse pair (b[i], a[i])
        Integer occ = map.get(new Triple(b[i], a[i]));
        if (occ == null) {
            return false;               // no matching element to swap with
        }
        if (isSwapped[occ]) {
            continue;                    // the partner index is already used
        }

        // Record a successful swap
        isSwapped[occ] = true;
        swaps++;
        if (swaps > 1) {
            return false;               // more than one swap required
        }
    }

    return true;                        // zero or one swap was sufficient
}

