/**
 * Determines whether all positions in {@code s} can be covered using the
 * positions in {@code p} with the given maximal distance {@code mid}.
 */
private static boolean canCover(long[] p, long[] s, long mid) {
    int i = 0, j = 0;
    int n = p.length, m = s.length;

    while (i < n && j < m) {
        long toright = rightBound(p[i], s[j], mid);
        while (j < m && s[j] <= toright) {
            j++;
        }
        i++;
    }
    return j == m;
}

/**
 * Computes the farthest point to the right that can be reached when the
 * current person is at {@code pVal} and the nearest uncovered target is
 * {@code sVal}, given the allowed distance {@code mid}.
 *
 * Guard clauses make the three logical cases explicit.
 */
private static long rightBound(long pVal, long sVal, long mid) {
    // Case 1: target already to the right of or at the person.
    if (pVal <= sVal) {
        return pVal + mid;
    }

    // Case 2: target is left but reachable within the budget.
    long diff = pVal - sVal;
    if (diff <= mid) {
        long option1 = mid - 2 * diff;                 // go left first, then right
        long option2 = (mid - diff) / 2;               // split the remaining distance
        return pVal + Math.max(option1, option2);
    }

    // Case 3: target is too far left – cannot cover it.
    return 0;
}

public static void main(String[] args) throws IOException {
    BufferedReader in = new BufferedReader(new InputStreamReader(System.in));
    StringTokenizer tk = new StringTokenizer(in.readLine());
    int n = Integer.parseInt(tk.nextToken());
    int m = Integer.parseInt(tk.nextToken());

    long[] p = new long[n];
    tk = new StringTokenizer(in.readLine());
    for (int i = 0; i < n; i++) {
        p[i] = Long.parseLong(tk.nextToken());
    }

    long[] s = new long[m];
    tk = new StringTokenizer(in.readLine());
    for (int i = 0; i < m; i++) {
        s[i] = Long.parseLong(tk.nextToken());
    }

    long left = 0;
    long right = 100_000_000_000L; // 1e11
    long answer = -1;

    while (left <= right) {
        long mid = (left + right) / 2;
        if (canCoverAll(p, s, mid)) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    System.out.println(answer);
}

private static boolean canCoverAll(long[] p, long[] s, long mid) {
    int i = 0, j = 0;
    while (i < p.length && j < s.length) {
        long toright = computeToright(p[i], s[j], mid);
        while (j < s.length && s[j] <= toright) {
            j++;
        }
        i++;
    }
    return j == s.length;
}

private static long computeToright(long p, long s, long mid) {
    if (p <= s) {
        return p + mid;
    }
    long diff = p - s;
    if (diff <= mid) {
        long option1 = mid - 2 * diff;
        long option2 = (mid - diff) / 2;
        return p + Math.max(option1, option2);
    }
    return 0;
}

