/** updates the DP tables for a single state (l, r, m) */
private void updateTransitions(int l, int r, int m, int cd) {
    long dpVal = dp[l * M1 + r * M2 + m];
    if (dpVal != 0L) {
        for (int d = 0; d < cd; d++) {
            int newR = nextRest[(l + 1) * R1 + r * R2 + d];
            int newM = nextInd[(m << 4) | d];
            cdp[(l + 1) * M1 + newR * M2 + newM] += dpVal;
        }
    }

    long cdpVal = cdp[l * M1 + r * M2 + m];
    if (cdpVal != 0L) {
        int newR = nextRest[(l + 1) * R1 + r * R2 + cd];
        int newM = nextInd[(m << 4) | cd];
        cdp[(l + 1) * M1 + newR * M2 + newM] += cdpVal;
    }
}

/** sums the final results respecting the lcm condition */
private long accumulateResult(int len) {
    long ret = 0L;
    for (int r = 0; r < LCM; r++) {
        for (int m = 0; m < MAXM; m++) {
            if (m != 0 && r % lcm[m] != 0) {
                continue;               // guard clause: skip non‑matching state
            }
            ret += cdp[len * M1 + r * M2 + m];
        }
    }
    return ret;
}

long count(long x) {
    // initialise DP tables
    fill(cdp, 0L);
    cdp[0] = 1L;                     // same as cdp[0 * M1 + 0 * M2 + 0]

    // propagate the states digit by digit
    propagateDigits(x);

    // sum the admissible final states
    return sumValidFinalStates(len(x));
}

/**
 * Walks through the decimal digits of {@code x} (from least‑significant
 * to most‑significant) and updates {@code cdp} using the transition tables.
 */
private void propagateDigits(long x) {
    long t = x;
    for (int l = 0; l < MAXL && t > 0L; ++l, t /= 10L) {
        int currentDigit = (int) (t % 10L);
        for (int r = 0; r < LCM; ++r) {
            for (int m = 0; m < MAXM; ++m) {
                long dpVal = dp[l * M1 + r * M2 + m];
                if (dpVal != 0L) {
                    addTransitionsFromDp(l, r, m, currentDigit, dpVal);
                }

                long cdpVal = cdp[l * M1 + r * M2 + m];
                if (cdpVal != 0L) {
                    addTransitionFromCdp(l, r, m, currentDigit, cdpVal);
                }
            }
        }
    }
}

/** Adds the contributions that come from the original {@code dp} table. */
private void addTransitionsFromDp(int l, int r, int m, int digitLimit, long weight) {
    for (int d = 0; d < digitLimit; ++d) {
        int nextR = nextRest[(l + 1) * R1 + r * R2 + d];
        int nextM = nextInd[(m << 4) | d];
        int idx   = (l + 1) * M1 + nextR * M2 + nextM;
        cdp[idx] += weight;
    }
}

/** Adds the contribution that comes from the already‑filled {@code cdp} entry. */
private void addTransitionFromCdp(int l, int r, int m, int digit, long weight) {
    int nextR = nextRest[(l + 1) * R1 + r * R2 + digit];
    int nextM = nextInd[(m << 4) | digit];
    int idx   = (l + 1) * M1 + nextR * M2 + nextM;
    cdp[idx] += weight;
}

/**
 * Returns the total number of admissible final states.
 * A state is admissible when {@code m == 0} or {@code r % lcm[m] == 0}.
 */
private long sumValidFinalStates(int length) {
    long total = 0L;
    for (int r = 0; r < LCM; ++r) {
        for (int m = 0; m < MAXM; ++m) {
            if (m == 0 || r % lcm[m] == 0) {
                total += cdp[length * M1 + r * M2 + m];
            }
        }
    }
    return total;
}

long count(long x) {
    // initialise DP arrays
    fill(cdp, 0L);
    cdp[0] = 1L;                         // (0 * M1 + 0 * M2 + 0) == 0
    long t = x;

    // DP over the digits of x
    for (int l = 0; l < MAXL && t > 0L; l++, t /= 10L) {
        int curDigit = (int) (t % 10L);
        processDigitLayer(l, curDigit);
    }

    // sum up the answer
    return accumulateResult(len(x));
}

/**
 * Handles one digit layer (position {@code l}) of the DP.
 * Updates {@code cdp} using values from {@code dp} and the
 * already‑computed part of {@code cdp}.
 */
private void processDigitLayer(int l, int curDigit) {
    int nextL = l + 1;
    int baseL      = l     * M1;
    int baseNextL  = nextL * M1;

    for (int r = 0; r < LCM; r++) {
        int baseR      = baseL      + r * M2;
        int baseNextR  = baseNextL  + nextRest[nextL * R1 + r * R2 + curDigit] * M2;

        for (int m = 0; m < MAXM; m++) {
            long dpVal = dp[baseR + m];
            if (dpVal != 0L) {
                updateCdpFromDp(baseNextL, r, m, curDigit, dpVal);
            }

            long cdpVal = cdp[baseR + m];
            if (cdpVal != 0L) {
                int idx = baseNextR + nextInd[(m << 4) | curDigit];
                cdp[idx] += cdpVal;
            }
        }
    }
}

/**
 * Adds contributions from {@code dp} to {@code cdp} for all digits
 * smaller than the current digit.
 */
private void updateCdpFromDp(int baseNextL, int r, int m, int curDigit, long dpVal) {
    for (int d = 0; d < curDigit; d++) {
        int restIdx = nextRest[(baseNextL / M1) * R1 + r * R2 + d];
        int indIdx  = nextInd[(m << 4) | d];
        int idx     = (baseNextL / M1) * M1 + restIdx * M2 + indIdx;
        cdp[idx] += dpVal;
    }
}

/**
 * Sums the final DP values that satisfy the required divisibility
 * constraints.
 */
private long accumulateResult(int len) {
    long result = 0L;
    int base = len * M1;

    for (int r = 0; r < LCM; r++) {
        for (int m = 0; m < MAXM; m++) {
            if (m != 0 && r % lcm[m] != 0) {
                continue;               // guard clause – not a valid state
            }
            result += cdp[base + r * M2 + m];
        }
    }
    return result;
}

