public static void weight(char c) {
    // Guard clause – pieces that have no material value
    if (c == '.' || c == 'K' || c == 'k') {
        return;
    }

    // Determine the material value of the piece (ignoring colour)
    int pieceValue = switch (Character.toUpperCase(c)) {
        case 'Q' -> 9;
        case 'R' -> 5;
        case 'B', 'N' -> 3;
        case 'P' -> 1;
        default -> 0; // safety net; should never be reached with valid input
    };

    // Add the value to the correct side's total
    if (Character.isUpperCase(c)) {
        w += pieceValue;   // white piece
    } else {
        b += pieceValue;   // black piece
    }
}

private static int pieceWeight(char piece) {
    switch (Character.toUpperCase(piece)) {
        case 'Q': return 9;
        case 'R': return 5;
        case 'B':
        case 'N': return 3;
        case 'P': return 1;
        default:  return 0; // King, empty square, or any other char
    }
}

public static void weight(char c) {
    int delta = pieceWeight(c);
    if (delta == 0) {
        // No weight to add (king, empty square, or unrecognized char)
        return;
    }

    if (Character.isUpperCase(c)) {
        w += delta;   // white piece
    } else {
        b += delta;   // black piece (lowercase)
    }
}

