public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner();
    PrintWriter pw = new PrintWriter(System.out);

    int n = sc.nextInt();
    initAdjacency(n);

    in = new boolean[n];
    going = new int[n];

    int m = sc.nextInt();
    k = sc.nextInt();

    int[][] edges = readEdges(sc, m);
    HashSet<Long> edgeSet = buildEdgeHashSet(edges);
    TreeSet<Integer> orderedSet = createOrderedSet(n);

    Arrays.fill(in, true);
    fillDegrees();

    update(orderedSet, edgeSet);

    int[] answer = computeAnswers(edges, orderedSet, edgeSet);
    for (int v : answer) {
        pw.println(v);
    }

    pw.flush();
    pw.close();
}

/* ---------- helper methods ---------- */

private static void initAdjacency(int n) {
    adj = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        adj[i] = new ArrayList<>();
    }
}

private static int[][] readEdges(Scanner sc, int m) {
    int[][] e = new int[m][2];
    for (int i = 0; i < m; i++) {
        e[i][0] = sc.nextInt() - 1;
        e[i][1] = sc.nextInt() - 1;

        adj[e[i][0]].add(e[i][1]);
        adj[e[i][1]].add(e[i][0]);
    }
    return e;
}

/* stores a symmetric hash for an undirected edge */
private static HashSet<Long> buildEdgeHashSet(int[][] edges) {
    HashSet<Long> set = new HashSet<>();
    for (int[] e : edges) {
        set.add(hash(e[0], e[1]));
    }
    return set;
}

private static TreeSet<Integer> createOrderedSet(int n) {
    return new TreeSet<>(new Comparator<Integer>() {
        @Override
        public int compare(Integer i, Integer j) {
            if (going[i] != going[j]) {
                return going[i] - going[j];
            }
            return i - j;
        }
    });
}

/* fills 'going' with the current degree of each vertex */
private static void fillDegrees() {
    for (int i = 0; i < going.length; i++) {
        going[i] = adj[i].size();
    }
}

/* core loop that produces the answer array */
private static int[] computeAnswers(int[][] edges,
                                    TreeSet<Integer> set,
                                    HashSet<Long> edgeHash) {
    int m = edges.length;
    int[] ans = new int[m];

    for (int q = m - 1; q >= 0; q--) {
        ans[q] = set.size();

        int u = edges[q][0];
        int v = edges[q][1];

        if (!(in[u] && in[v])) {
            // No vertex is removed – just recompute reachable set.
            update(set, edgeHash);
            continue;
        }

        // Decrease degree of u
        set.remove(u);
        going[u]--;
        set.add(u);

        // Decrease degree of v
        set.remove(v);
        going[v]--;
        set.add(v);

        // Remove the edge from the hash set
        edgeHash.remove(hash(u, v));

        update(set, edgeHash);
    }
    return ans;
}

public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner();
    PrintWriter pw = new PrintWriter(System.out);

    int n = sc.nextInt();
    adj = new ArrayList[n];
    for (int i = 0; i < n; i++) {
        adj[i] = new ArrayList<>();
    }
    in = new boolean[n];
    going = new int[n];

    int m = sc.nextInt();
    k = sc.nextInt();

    HashSet<Long> edgeSet = new HashSet<>();
    int[][] edges = new int[m][2];
    for (int i = 0; i < m; i++) {
        edges[i][0] = sc.nextInt() - 1;
        edges[i][1] = sc.nextInt() - 1;

        adj[edges[i][0]].add(edges[i][1]);
        adj[edges[i][1]].add(edges[i][0]);

        edgeSet.add(hash(edges[i][0], edges[i][1]));
    }

    TreeSet<Integer> set = new TreeSet<>(vertexComparator());

    Arrays.fill(in, true);
    for (int i = 0; i < n; i++) {
        going[i] = adj[i].size();
        set.add(i);
    }

    update(set, edgeSet);

    int[] ans = new int[m];
    for (int q = m - 1; q >= 0; q--) {
        ans[q] = set.size();
        int u = edges[q][0];
        int v = edges[q][1];

        handleEdgeRemoval(set, edgeSet, u, v);
        update(set, edgeSet);
    }

    for (int i = 0; i < m; i++) {
        pw.println(ans[i]);
    }

    pw.flush();
    pw.close();
}

/**
 * Returns a comparator that orders vertices first by their current degree
 * (stored in {@code going}) and then by their index.
 */
private static Comparator<Integer> vertexComparator() {
    return (i, j) -> {
        if (going[i] != going[j]) {
            return going[i] - going[j];
        }
        return i - j;
    };
}

/**
 * Updates the data structures when the edge (u, v) is removed.
 * If either endpoint is already out of the current graph, the method
 * returns immediately (guard clause).
 */
private static void handleEdgeRemoval(TreeSet<Integer> set,
                                      HashSet<Long> edgeSet,
                                      int u, int v) {
    if (!(in[u] && in[v])) {
        return; // guard clause – nothing to do
    }

    // update vertex u
    set.remove(u);
    going[u]--;
    set.add(u);

    // update vertex v
    set.remove(v);
    going[v]--;
    set.add(v);

    // remove the edge from the set of existing edges
    edgeSet.remove(hash(u, v));
}

