/** Builds the string representing the digit‑wise difference between s and a. */
private static String computeDifferenceString(long a, long s) {
    StringBuilder sb = new StringBuilder();
    while (s > 0 || a > 0) {
        long digitS = s % 10;
        long digitA = a % 10;
        if (digitS >= digitA) {
            sb.append(digitS - digitA);
            s /= 10;
            a /= 10;
        } else {
            long twoDigitsS = s % 100;               // borrow one decimal place
            sb.append(twoDigitsS - digitA);
            s /= 100;
            a /= 10;
        }
    }
    return sb.reverse().toString();
}

/** Constructs the string obtained by adding ans and a digit‑wise (no carries). */
private static String buildSumString(long ans, long a) {
    StringBuilder sb = new StringBuilder();
    while (ans > 0 || a > 0) {
        sb.append((ans % 10) + (a % 10));
        ans /= 10;
        a /= 10;
    }
    return sb.reverse().toString();
}

/** Returns true if the reconstructed sum equals the original s. */
private static boolean isValidResult(long ans, long originalA, long originalS) {
    String sum = buildSumString(ans, originalA);
    if (sum.isEmpty()) {
        sum = "0";
    }
    return Long.parseLong(sum) == originalS;
}

