}

private static void buildAdjList(Scanner sc, int edgeCount) {
    adjList = new ArrayList[V];
    for (int i = 0; i < V; i++) {
        adjList[i] = new ArrayList<>();
    }
    for (int e = 0; e < edgeCount; e++) {
        int u = sc.nextInt() - 1;
        int v = sc.nextInt() - 1;
        int t = sc.nextInt();
        adjList[u].add(new Edge(v, t));
        adjList[v].add(new Edge(u, t));
    }
}

/**
 * Runs Dijkstra from every start vertex.
 */
private static int[][] computeAllShortestPaths(int[] start) {
    int[][] dist = new int[n][V];
    for (int i = 0; i < n; i++) {
        dist[i] = dijkstra(start[i]);
    }
    return dist;
}

/**
 * Binary‑searches the smallest time limit for which at least {@code k}
 * matchings are possible.
 */
private static int findMinimumTime(int k, int[][] dist) {
    int lo = 0, hi = (int) 2e6, ans = -1;
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1;            // avoid overflow
        if (canMatchAtMost(mid, k, dist)) {
            ans = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return ans;
}

/**
 * Returns {@code true} if a matching of size ≥ k exists when the
 * time limit is {@code limit}.
 */
private static boolean canMatchAtMost(int limit, int k, int[][] dist) {
    buildAdjList2(dist, limit);
    return hopcroftKarp() >= k;
}

/**
 * Constructs the bipartite graph used by Hopcroft‑Karp.
 * Left side: sources 1 … n
 * Right side: vertices 1 … V
 */
private static void buildAdjList2(int[][] dist, int limit) {
    adjList2 = new ArrayList[n + 1];
    for (int i = 1; i <= n; i++) {
        adjList2[i] = new ArrayList<>();
        for (int v = 1; v <= V; v++) {
            if (dist[i - 1][v - 1] <= limit) {
                adjList2[i].add(v);
            }
        }
    }
}

