/* -------------------------------------------------------------
 *  2. Compute distances from every start vertex using Dijkstra
 * ------------------------------------------------------------- */
private static int[][] computeAllDistances(int[] starts) {
    int[][] dists = new int[starts.length][V];
    for (int i = 0; i < starts.length; i++) {
        dists[i] = dijkstra(starts[i]);
    }
    return dists;
}

/* -------------------------------------------------------------
 *  3. Build the bipartite graph for a given threshold
 * ------------------------------------------------------------- */
private static void buildAdjacencyForThreshold(int threshold, int[][] dist) {
    adjList2 = new ArrayList[n + 1];
    for (int i = 1; i <= n; i++) {
        adjList2[i] = new ArrayList<>();
        for (int j = 1; j <= V; j++) {
            if (dist[i - 1][j - 1] <= threshold) {
                adjList2[i].add(j);
            }
        }
    }
}

/* -------------------------------------------------------------
 *  4. Binary search the smallest threshold that permits a matching
 * ------------------------------------------------------------- */
private static int findMinimumThreshold(int[][] dist, int requiredMatch) {
    int answer = -1;
    int lo = 0, hi = (int) 2e6;

    while (lo <= hi) {
        int mid = (lo + hi) / 2;

        buildAdjacencyForThreshold(mid, dist);
        if (hopcroftKarp() >= requiredMatch) {
            answer = mid;
            hi = mid - 1;                // try to find a smaller feasible value
        } else {
            lo = mid + 1;                // need a larger threshold
        }
    }
    return answer;
}

