 * built from {@code dist} admits a matching of size at least {@code k}.
 */
private static boolean feasible(int limit, int[][] dist, int n, int V, int k) {
    // rebuild the bipartite adjacency list for the current limit
    adjList2 = new ArrayList[n + 1];
