/**
 * Walks through both lists simultaneously and counts how many times
 * an element from {@code bills} is greater than or equal to the
 * corresponding element from {@code costs}.
 *
 * The algorithm stops as soon as the end of either list is reached.
 *
 * @return the number of successful matches
 */
private static int computeMatches(List<Integer> costs, List<Integer> bills) {
    int i = 0; // index for bills
    int j = 0; // index for costs
    int counter = 0;

    while (i < bills.size() && j < costs.size()) {
        // Guard clause: bill is smaller than cost → skip this cost
        if (bills.get(i) < costs.get(j)) {
            j++;
            continue;
        }

        // At this point bills[i] >= costs[j] → we have a match
        counter++;

        // Guard clause: reached the end of either list after counting
        if (i == bills.size() - 1 || j == costs.size() - 1) {
            break;
        }

        // Advance both pointers for the next comparison
        i++;
        j++;
    }

    return counter;
}

