    }
    for (int i = 0; i < m; i++) {
        bills.add(Integer.parseInt(scanner.next()));
    }

    int counter = countMatches(costs, bills);
    System.out.print(counter);
}

/**
 * Counts how many times a bill is greater than or equal to a cost while iterating
 * through both lists in order. The algorithm stops as soon as the end of either
 * list is reached.
 *
 * @param costs ordered list of costs
 * @param bills ordered list of bills
 * @return the number of matches found
 */
private static int countMatches(List<Integer> costs, List<Integer> bills) {
    int matches = 0;
    int i = 0; // index for bills
    int j = 0; // index for costs

    while (i < bills.size() && j < costs.size()) {
        int bill = bills.get(i);
        int cost = costs.get(j);

        if (bill >= cost) {
            matches++;
            i++;
            j++;
            // Guard: if we have just reached the end of either list, exit early
            if (i == bills.size() || j == costs.size()) {
                break;
            }
        } else {
            // bill is too small → move to the next cost
            j++;
        }
    }
    return matches;
}

