static void updateTree(long[] tree, boolean[] update,
                       int left, int right,
                       int l, int r, long val, int pos) {
    // Guard: no overlap
    if (l > right || r < left) {
        return;
    }

    // Guard: segment fully covered
    if (l <= left && r >= right) {
        applyFullCover(tree, update, pos, val);
        return;
    }

    // Propagate any pending lazy value before descending
    propagateIfNeeded(tree, update, pos);

    int mid = (left + right) >>> 1; // same as (left+right)/2 but safer
    updateTree(tree, update, left, mid, l, r, val, pos * 2);
    updateTree(tree, update, mid + 1, right, l, r, val, pos * 2 + 1);

    // Re‑compute current node from children
    tree[pos] = Math.max(tree[pos * 2], tree[pos * 2 + 1]);
}

private static void applyFullCover(long[] tree, boolean[] update,
                                   int pos, long val) {
    tree[pos] = val;
    update[pos] = true;
}

private static void propagateIfNeeded(long[] tree, boolean[] update,
                                      int pos) {
    if (!update[pos]) {
        return;
    }

    int leftChild = pos * 2;
    int rightChild = leftChild + 1;

    if (leftChild < tree.length && tree[leftChild] != 0) {
        tree[leftChild] = tree[pos];
        update[leftChild] = true;
    }
    if (rightChild < tree.length && tree[rightChild] != 0) {
        tree[rightChild] = tree[pos];
        update[rightChild] = true;
    }
    update[pos] = false;
}

