}

/**
 * Computes DP values for day {@code i} using the activity allowed on that day.
 */
private static void computeDay(int i, int activity,
                               int[] con, int[] gym, int[] rest) {
    int prevCon  = con[i - 1];
    int prevGym  = gym[i - 1];
    int prevRest = rest[i - 1];

    switch (activity) {
        case 0: // no activity possible
            con[i] = Integer.MAX_VALUE;
            gym[i] = Integer.MAX_VALUE;
            rest[i] = Math.min(Math.min(prevCon, prevGym), prevRest) + 1;
            break;
        case 1: // contest only
            con[i] = Math.min(prevGym, prevRest);
            gym[i] = Integer.MAX_VALUE;
            rest[i] = Math.min(Math.min(prevCon, prevRest), prevGym) + 1;
            break;
        case 2: // gym only
            con[i] = Integer.MAX_VALUE;
            gym[i] = Math.min(prevCon, prevRest);
            rest[i] = Math.min(Math.min(prevGym, prevRest), prevCon) + 1;
            break;
        case 3: // both possible
            con[i] = Math.min(prevRest, prevGym);
            gym[i] = Math.min(prevRest, prevCon);
            rest[i] = Math.min(Math.min(prevCon, prevRest), prevGym) + 1;
            break;
        default:
