long findIT(int index, int odd, int even, int parity) {
    // Guard clauses – fast exits
    if (odd < 0) return Integer.MAX_VALUE / 2;
    if (even < 0) return Integer.MAX_VALUE / 2;
    if (index == n) return 0;

    if (dp[index][odd][even][parity] != -1)
        return dp[index][odd][even][parity];

    // Delegate to the appropriate specialised routine
    long result = (arr[index] != 0)
            ? handleKnown(index, odd, even, parity)
            : handleZero(index, odd, even, parity);

    dp[index][odd][even][parity] = result;
    return result;
}

