// Case 1: the current element is already set (non‑zero)
private long handleKnown(int index, int odd, int even, int parity) {
    int currentParity = arr[index] % 2;
    int cost = (currentParity == parity) ? 0 : 1;
    return cost + findIT(index + 1, odd, even, currentParity);
}

// Case 2: the current element is zero – we may put 0 or 1
private long handleZero(int index, int odd, int even, int parity) {
    long best = Integer.MAX_VALUE / 2;

    // Try placing a 0
    int costZero = (0 == parity) ? 0 : 1;
    best = Math.min(best,
            costZero + findIT(index + 1, odd, even - 1, 0));

    // Try placing a 1
    int costOne = (1 == parity) ? 0 : 1;
    best = Math.min(best,
            costOne + findIT(index + 1, odd - 1, even, 1));

    return best;
}

