private int computeDP() {
    int size = set.size();               // number of distinct positions
    int[] dp  = new int[size];
    int[] sum = new int[size + 1];

    dp[0] = 1;
    sum[1] = 1;                          // sum[i] = dp[0] + … + dp[i‑1]

    for (int i = 1; i < size; i++) {
        int j = Arrays.binarySearch(buses, new Bus(-1, i), BUS_END_COMPARATOR);

        // Guard clause – if no bus ends at ‘i’, skip the inner work
        if (j < 0) {
            sum[i + 1] = add(sum[i], dp[i]);
            continue;
        }

        // Move to the first bus whose end equals i
        while (j != 0 && buses[j - 1].t == i) {
            j--;
        }
        // Process every bus that ends at i
        while (j < m && buses[j].t == i) {
            dp[i] = add(dp[i], sum[i] - sum[buses[j].s]);
            j++;
        }
        sum[i + 1] = add(sum[i], dp[i]);
    }
    return dp[size - 1];
}

