 * @param dp    DP array (needed only for the current computation)
 * @param sum   prefix‑sum array
 * @param m     total number of buses
 * @return the DP value for position {@code i}
 */
private int computeDpAt(int i, Bus[] buses, int[] dp, int[] sum, int m) {
    int dpVal = 0;

    int j = Arrays.binarySearch(buses, new Bus(-1, i), BUS_T_COMPARATOR);
    if (j < 0) {
        return dpVal; // guard clause – no bus ends at i
    }

    // Move to the first bus whose end point equals i
    while (j > 0 && buses[j - 1].t == i) {
        j--;
    }

    // Accumulate contributions of all buses ending at i
    while (j < m && buses[j].t == i) {
        dpVal = add(dpVal, sum[i] - sum[buses[j].s]);
        j++;
    }

    return dpVal;
}

