private static void move(int s_x, int s_y, int d_x, int d_y) {
    // Guard clause – reached destination
    if (s_x == d_x && s_y == d_y) {
        return;
    }

    // Determine one step direction toward the target
    int dx = Integer.compare(d_x, s_x); // -1, 0, or +1
    int dy = Integer.compare(d_y, s_y); // -1, 0, or +1

    String dir = direction(dx, dy);
    counter++;
    answer.append(dir).append('\n');

    // Recurse with the new position
    move(s_x + dx, s_y + dy, d_x, d_y);
}

private static String direction(int dx, int dy) {
    if (dx == -1 && dy ==  1) return "LU";
    if (dx == -1 && dy == -1) return "LD";
    if (dx ==  1 && dy ==  1) return "RU";
    if (dx ==  1 && dy == -1) return "RD";
    if (dx ==  0 && dy ==  1) return "U";
    if (dx ==  0 && dy == -1) return "D";
    if (dx ==  1 && dy ==  0) return "R";
    if (dx == -1 && dy ==  0) return "L";
    throw new IllegalStateException("Unexpected step direction");
}

private static void move(int s_x, int s_y, int d_x, int d_y) {
    // Guard clause – nothing to do when already at the destination
    if (s_x == d_x && s_y == d_y) {
        return;
    }

    // Compute a unit step toward the destination
    int stepX = Integer.compare(d_x, s_x); // -1, 0, or +1
    int stepY = Integer.compare(d_y, s_y); // -1, 0, or +1

    // Resolve the textual direction for this step
    String direction = directionFor(stepX, stepY);

    // Record the step and recurse
    counter++;
    answer.append(direction).append('\n');
    move(s_x + stepX, s_y + stepY, d_x, d_y);
}

/**
 * Translates a unit movement (dx, dy) into the corresponding direction string.
 * The pair (dx, dy) is guaranteed to be one of the eight compass moves.
 */
private static String directionFor(int dx, int dy) {
    if (dx == -1 && dy ==  1) return "LU";
    if (dx == -1 && dy == -1) return "LD";
    if (dx ==  1 && dy ==  1) return "RU";
    if (dx ==  1 && dy == -1) return "RD";
    if (dx ==  0 && dy ==  1) return "U";
    if (dx ==  0 && dy == -1) return "D";
    if (dx ==  1 && dy ==  0) return "R";
    if (dx == -1 && dy ==  0) return "L";

    // Should never happen because the caller only passes valid unit steps
    throw new IllegalArgumentException(
        String.format("Invalid step signs: dx=%d, dy=%d", dx, dy));
}

