public static void main(String[] args) {
    Charset charset = Charset.forName("ascii");
    FastIO rd = new FastIO(System.in, System.out, charset);

    long n = rd.readLong();        // board width
    long m = rd.readLong();        // board height

    long x = rd.readLong();        // start column (1‑based)
    long y = rd.readLong();        // start row    (1‑based)

    int k = rd.readInt();          // number of moves
    long steps = 0;

    while (k-- > 0) {
        long dx = rd.readLong();
        long dy = rd.readLong();

        // Guard clause – no movement at all
        if (dx == 0 && dy == 0) {
            continue;
        }

        long[] pos   = {x, y};
        long[] total = {steps};

        applyMove(dx, dy, pos, n, m, total);

        x = pos[0];
        y = pos[1];
        steps = total[0];
    }

    System.out.println(steps);
}

/**
 * Returns the maximal number of steps that can be performed
 * in one direction before reaching the board border.
 *
 * @param delta   movement per step (dx or dy)
 * @param coord   current coordinate (x or y)
 * @param limit   board size in that dimension (n or m)
 * @return maximal steps (Long.MAX_VALUE when delta == 0)
 */
private static long maxSteps(long delta, long coord, long limit) {
    if (delta > 0) {
        return (limit - coord) / delta;          // moving positive direction
    } else if (delta < 0) {
        return (coord - 1) / -delta;             // moving negative direction
    } else {
        return Long.MAX_VALUE;                   // no movement along this axis
    }
}

/**
 * Updates position and total steps according to a single move.
 *
 * @param dx    column displacement per step
 * @param dy    row displacement per step
 * @param pos   mutable array {x, y}
 * @param n     board width
 * @param m     board height
 * @param steps mutable array holding total steps performed
 */
private static void applyMove(long dx, long dy,
                              long[] pos, long n, long m,
                              long[] steps) {
    long stepx = maxSteps(dx, pos[0], n);
    long stepy = maxSteps(dy, pos[1], m);

    if (dx == 0) {                     // vertical only
        steps[0] += stepy;
        pos[1] += stepy * dy;
    } else if (dy == 0) {              // horizontal only
        steps[0] += stepx;
        pos[0] += stepx * dx;
    } else {                           // diagonal – limited by the tighter axis
        long move = Math.min(stepx, stepy);
        steps[0] += move;
        pos[0] += move * dx;
        pos[1] += move * dy;
    }
}

