public void solve(int testNumber, InputReader in, OutputWriter out) {
    int k = in.readInt();
    char[] str = in.readString().toCharArray();

    boolean[] flag = new boolean[str.length];
    int distinct = markFirstOccurrences(str, flag);

    if (distinct < k) {
        out.printLine("NO");
        return;
    }

    trimFlags(flag, str, distinct, k);

    out.print("YES");
    printResult(str, flag, out);
}

private int markFirstOccurrences(char[] str, boolean[] flag) {
    boolean[] seen = new boolean[26];
    int distinct = 0;
    for (int i = 0; i < str.length; i++) {
        int idx = str[i] - 'a';
        if (!seen[idx]) {
            flag[i] = true;
            seen[idx] = true;
            distinct++;
        }
    }
    return distinct;
}

private void trimFlags(boolean[] flag, char[] str, int distinct, int k) {
    for (int i = str.length - 1; i >= 0 && distinct > k; i--) {
        if (flag[i]) {
            flag[i] = false;
            distinct--;
        }
    }
}

private void printResult(char[] str, boolean[] flag, OutputWriter out) {
    for (int i = 0; i < str.length; i++) {
        if (flag[i]) {
            out.printLine();          // line break before this character
        }
        out.print(str[i]);
    }
}

