long dp(int ind, int curIndent) {
    // Guard clauses – simple base cases
    if (ind == n) return 1;
    if (curIndent < 0) return 0;
    if (memo[ind][curIndent] != -1) return memo[ind][curIndent];

    boolean isFor = a[ind] == 'f';
    boolean isLast = lastFor(ind);

    long ans = isFor
            ? computeForCase(ind, curIndent, isLast)
            : computeStmtCase(ind, curIndent, isLast);

    return memo[ind][curIndent] = ans % mod;
}

/** Handles the branch where the current character is 'f'. */
private long computeForCase(int ind, int curIndent, boolean isLast) {
    if (isLast) {
        // last 'for' – only the forward move
        return dp(ind + 1, curIndent + 1);
    } else {
        // not the last 'for' – backtrack and forward move
        return dp(ind, curIndent - 1) + dp(ind + 1, curIndent + 1);
    }
}

/** Handles the branch where the current character is 's'. */
private long computeStmtCase(int ind, int curIndent, boolean isLast) {
    if (isLast) {
        // last statement – simple forward
        return dp(ind + 1, curIndent);
    } else {
        // not the last statement – forward and backtrack
        return dp(ind + 1, curIndent) + dp(ind, curIndent - 1);
    }
}

