    boolean isFor = a[ind] == 'f';
    boolean isLast = lastFor(ind);

    long ans = isFor
            ? handleFor(ind, curIndent, isLast)
            : handleStatement(ind, curIndent, isLast);

    return memo[ind][curIndent] = ans % mod;
}

private long handleFor(int ind, int curIndent, boolean isLast) {
    if (isLast) {
        return dp(ind + 1, curIndent + 1);
    }
    long ans = dp(ind, curIndent - 1);
    ans += dp(ind + 1, curIndent + 1);
    return ans;
}

private long handleStatement(int ind, int curIndent, boolean isLast) {
    if (isLast) {
        return dp(ind + 1, curIndent);
    }
    long ans = dp(ind + 1, curIndent);
    ans += dp(ind, curIndent - 1);
    return ans;
}

