public static int solve(int aR, int bR, int total) {
    // Guard clause – base case of the recursion
    if (total == 2 * n - 1) {
        return 0;
    }

    // Guard clause – memoised result
    if (dp[aR][bR][total] != -oo) {
        return dp[aR][bR][total];
    }

    // Convert the “right‑moves‑so‑far” counters to board coordinates
    int ax = total - aR;
    int ay = aR;
    int bx = total - bR;
    int by = bR;

    // Evaluate the best continuation from the current state
    int best = bestNext(ax, ay, bx, by, aR, bR, total);
    best = (best == -oo) ? 0 : best;

    // Add the value of the cells visited in this step
    int result = best + cellValueSum(ax, ay, bx, by);

    // Memoise and return
    dp[aR][bR][total] = result;
    return result;
}

/**
 * Returns the maximum value obtained by moving either token one step
 * (right or down) if the move stays inside the board.
 */
private static int bestNext(int ax, int ay, int bx, int by,
                           int aR, int bR, int total) {
    int max = -oo;

    // both move right
    if (ax + 1 < n && bx + 1 < n) {
        max = Math.max(max, solve(aR, bR, total + 1));
    }
    // A right, B down
    if (ax + 1 < n && by + 1 < n) {
        max = Math.max(max, solve(aR, bR + 1, total + 1));
    }
    // A down, B right
    if (ay + 1 < n && bx + 1 < n) {
        max = Math.max(max, solve(aR + 1, bR, total + 1));
    }
    // both move down
    if (ay + 1 < n && by + 1 < n) {
        max = Math.max(max, solve(aR + 1, bR + 1, total + 1));
    }

    return max;
}

/**
 * Computes the contribution of the two current cells.
 * If both tokens are on the same cell the value must be counted once.
 */
private static int cellValueSum(int ax, int ay, int bx, int by) {
    int sum = a[ax][ay] + a[bx][by];
    if (ax == bx && ay == by) {
        sum -= a[ax][by]; // avoid double‑counting the shared cell
    }
    return sum;
}

public static int solve(int aR, int bR, int total) {
    // Guard clause for the terminating condition
    if (total == 2 * n - 1) {
        return 0;
    }

    // Memoisation guard: compute only once
    if (dp[aR][bR][total] == -oo) {
        dp[aR][bR][total] = computeValue(aR, bR, total);
    }

    return dp[aR][bR][total];
}

/**
 * Performs the original heavy computation.
 * Extracted to keep {@code solve} simple and to reduce its cyclomatic complexity.
 */
private static int computeValue(int aR, int bR, int total) {
    int ax = total - aR;
    int ay = aR;
    int bx = total - bR;
    int by = bR;

    int best = -oo;

    // Try all four possible moves, keeping the max value.
    best = maxIf(ax + 1 < n && bx + 1 < n, best, solve(aR, bR, total + 1));
    best = maxIf(ax + 1 < n && by + 1 < n, best, solve(aR, bR + 1, total + 1));
    best = maxIf(ay + 1 < n && bx + 1 < n, best, solve(aR + 1, bR, total + 1));
    best = maxIf(ay + 1 < n && by + 1 < n, best, solve(aR + 1, bR + 1, total + 1));

    // If none of the moves were valid, treat the result as 0.
    if (best == -oo) {
        best = 0;
    }

    // Add cell values; avoid double‑counting when both walkers are on the same cell.
    best += a[ax][ay] + a[bx][by];
    if (ax == bx && ay == by) {
        best -= a[ax][by];
    }

    return best;
}

/**
 * Helper that updates the current maximum only when the supplied condition is true.
 */
private static int maxIf(boolean condition, int currentMax, int candidate) {
    return condition ? Math.max(currentMax, candidate) : currentMax;
}

public static int solve(int aR, int bR, int total) {
    // Guard‑clause 1: base case
    if (total == 2 * n - 1) {
        return 0;
    }

    // Guard‑clause 2: memoised result already available
    if (dp[aR][bR][total] != -oo) {
        return dp[aR][bR][total];
    }

    // Compute, store and return the answer
    int ans = computeResult(aR, bR, total);
    dp[aR][bR][total] = ans;
    return ans;
}

/**
 * Evaluates the four possible moves from the current state,
 * adds the cell values and returns the best achievable score.
 */
private static int computeResult(int aR, int bR, int total) {
    int ax = total - aR;
    int ay = aR;
    int bx = total - bR;
    int by = bR;

    int best = -oo;

    // four admissible transitions
    if (ax + 1 < n && bx + 1 < n) {
        best = Math.max(best, solve(aR, bR, total + 1));
    }
    if (ax + 1 < n && by + 1 < n) {
        best = Math.max(best, solve(aR, bR + 1, total + 1));
    }
    if (ay + 1 < n && bx + 1 < n) {
        best = Math.max(best, solve(aR + 1, bR, total + 1));
    }
    if (ay + 1 < n && by + 1 < n) {
        best = Math.max(best, solve(aR + 1, bR + 1, total + 1));
    }

    // If no move was possible, treat the score as 0
    if (best == -oo) {
        best = 0;
    }

    // Add the values of the two current cells
    best += a[ax][ay] + a[bx][by];
    // Subtract the overlap when both walkers are on the same cell
    if (ax == bx && ay == by) {
        best -= a[ax][by];
    }

    return best;
}

