        int L = q[i][0];
        int R = q[i][1];

        while (r < R) add(++r);
        while (r > R) remove(r--);
        while (l < L) remove(l++);
        while (l > L) add(--l);

        ans[q[i][2]] = cur;
    }
    return ans;
}

/* ---------- output phase ---------- */
private void printAnswers(int[] ans) {
    for (int value : ans) {
        out.println(value);
    }
}

