        for (int i = bits.length - 1; i >= 0; i--) {
            boolean isMostSignificant = (i == 0);
            total += contribution(bits[i], carry, isMostSignificant);
            carry = updatedCarry(bits[i], carry, isMostSignificant);
        }

        System.out.println(total);
    } catch (Exception e) {
        // intentionally ignored
    }
