/** Returns the amount that must be added to the total for the current bit. */
private static int contribution(char bit, int carry, boolean isMostSignificant) {
    if (bit == '1' && carry == 0 && !isMostSignificant) {
        return 2;                     // case: '1' without carry, not MSB
    }
    if (bit == '1' && carry == 1) {
        return 1;                     // case: '1' with carry
    }
    if (bit == '0' && carry == 0) {
        return 1;                     // case: '0' without carry
    }
    // bit == '0' && carry == 1
    return 2;                         // case: '0' with carry
}

/** Returns the new carry after processing the current bit. */
private static int updatedCarry(char bit, int carry, boolean isMostSignificant) {
    // Carry is set only when we encounter a '1' without an existing carry,
    // and we are not at the most‑significant position.
    if (carry == 0 && bit == '1' && !isMostSignificant) {
        return 1;
    }
    // In all other situations the carry stays unchanged.
    return carry;
}

