/** Remove elements whose frequency is greater than 1 from the head of the set. */
private static void purgeNonUnique(TreeSet<int[]> set) {
    while (!set.isEmpty() && set.first()[1] > 1) {
        set.pollFirst();
    }
}

/** Output the current answer. */
private static void printResult(PrintWriter pw, TreeSet<int[]> set) {
    if (set.isEmpty()) {
        pw.println("Nothing");
    } else {
        pw.println(set.first()[0]);
    }
}

/** Add a value to the current window, updating both map and set. */
private static void addElement(int value,
                               HashMap<Integer, Integer> occ,
                               TreeSet<int[]> set) {
    int oldCount = occ.getOrDefault(value, 0);
    if (oldCount > 0) {
        set.remove(new int[]{value, oldCount});
    }
    int newCount = oldCount + 1;
    occ.put(value, newCount);
    set.add(new int[]{value, newCount});
}

/** Remove the value that leaves the window, updating map and set. */
private static void removeLeavingElement(int value,
                                          HashMap<Integer, Integer> occ,
                                          TreeSet<int[]> set) {
    Integer countObj = occ.get(value);
    if (countObj == null) return;           // guard – value not present

    int count = countObj;
    set.remove(new int[]{value, count});

    if (count == 1) {
        occ.remove(value);
    } else {
        int newCount = count - 1;
        occ.put(value, newCount);
        set.add(new int[]{value, newCount});
    }
}

public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    PrintWriter pw = new PrintWriter(System.out);

    int n = sc.nextInt();
    int k = sc.nextInt();

    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = sc.nextInt();
    }

    TreeSet<int[]> set = createSet();
    HashMap<Integer, Integer> occ = new HashMap<>();

    initializeWindow(arr, k, occ, set);
    processWindows(arr, n, k, set, occ, pw);

    pw.flush();
    pw.close();
}

/* --------------------------------------------------------------------- */
/* Helper factories and operations                                         */
/* --------------------------------------------------------------------- */
private static TreeSet<int[]> createSet() {
    return new TreeSet<>((a, b) -> {
        if (a[1] != b[1]) {
            return b[1] - a[1];          // higher count first
        }
        return b[0] - a[0];              // higher value first
    });
}

/* Initialise the first window of size k */
private static void initializeWindow(int[] arr, int k,
                                     Map<Integer, Integer> occ,
                                     Set<int[]> set) {
    for (int i = 0; i < k; i++) {
        int v = arr[i];
        occ.put(v, occ.getOrDefault(v, 0) + 1);
    }
    for (int v : occ.keySet()) {
        set.add(new int[]{v, occ.get(v)});
    }
}

/* Process all windows, printing the required answer for each */
private static void processWindows(int[] arr, int n, int k,
                                   TreeSet<int[]> set,
                                   Map<Integer, Integer> occ,
                                   PrintWriter pw) {
    for (int i = k - 1; i < n; i++) {
        cleanSet(set);
        outputCurrent(set, pw);

        // slide the window forward: add the new element
        if (i + 1 < n) {
            addNext(arr[i + 1], occ, set);
        }

        // slide the window forward: remove the old element
        removeOld(arr[i - k + 1], occ, set);
    }
}

/* Remove entries whose count is greater than 1 (they cannot be answers) */
private static void cleanSet(TreeSet<int[]> set) {
    while (!set.isEmpty() && set.first()[1] > 1) {
        set.pollFirst();
    }
}

/* Print the current answer for this window */
private static void outputCurrent(TreeSet<int[]> set, PrintWriter pw) {
    if (set.isEmpty()) {
        pw.println("Nothing");
    } else {
        pw.println(set.first()[0]);
    }
}

/* Add the element that just entered the window */
private static void addNext(int x,
                            Map<Integer, Integer> occ,
                            Set<int[]> set) {
    int oldCount = occ.getOrDefault(x, 0);
    int[] oldKey = new int[]{x, oldCount};

    if (set.contains(oldKey)) {
        set.remove(oldKey);
    }
    occ.put(x, oldCount + 1);
    set.add(new int[]{x, oldCount + 1});
}

/* Remove the element that just left the window */
private static void removeOld(int x,
                              Map<Integer, Integer> occ,
                              Set<int[]> set) {
    int count = occ.getOrDefault(x, 0);
    if (count == 0) {
        return; // nothing to remove
    }

    int[] key = new int[]{x, count};
    if (set.contains(key)) {
        set.remove(key);
    }

    if (count == 1) {
        occ.remove(x);
    } else {
        occ.put(x, count - 1);
        set.add(new int[]{x, count - 1});
    }
}

public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    PrintWriter pw = new PrintWriter(System.out);

    int n = sc.nextInt();
    int k = sc.nextInt();

    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = sc.nextInt();
    }

    TreeSet<int[]> set = new TreeSet<>(new ValueCountComparator());
    HashMap<Integer, Integer> occ = new HashMap<>();

    // initialise first window
    for (int i = 0; i < k; i++) {
        addToWindow(arr[i], occ, set);
    }

    for (int i = k - 1; i < n; i++) {
        cleanTop(set);
        printAnswer(set, pw);

        if (i + 1 < n) {
            addToWindow(arr[i + 1], occ, set);
        }

        removeFromWindow(arr[i - k + 1], occ, set);
    }

    pw.flush();
    pw.close();
}

/* -------------------------------------------------------------------- */
private static void addToWindow(int value,
                                HashMap<Integer, Integer> occ,
                                TreeSet<int[]> set) {
    int oldCount = occ.getOrDefault(value, 0);
    if (oldCount > 0) {
        set.remove(new int[]{value, oldCount});
    }
    int newCount = oldCount + 1;
    occ.put(value, newCount);
    set.add(new int[]{value, newCount});
}

/* -------------------------------------------------------------------- */
private static void removeFromWindow(int value,
                                     HashMap<Integer, Integer> occ,
                                     TreeSet<int[]> set) {
    int currentCount = occ.getOrDefault(value, 0);
    if (currentCount == 0) {
        return;                         // guard: nothing to remove
    }
    set.remove(new int[]{value, currentCount});

    if (currentCount == 1) {
        occ.remove(value);
    } else {
        int newCount = currentCount - 1;
        occ.put(value, newCount);
        set.add(new int[]{value, newCount});
    }
}

/* -------------------------------------------------------------------- */
private static void cleanTop(TreeSet<int[]> set) {
    while (!set.isEmpty() && set.first()[1] > 1) {
        set.pollFirst();                // discard entries that appear >1 time
    }
}

/* -------------------------------------------------------------------- */
private static void printAnswer(TreeSet<int[]> set, PrintWriter pw) {
    if (set.isEmpty()) {
        pw.println("Nothing");
    } else {
        pw.println(set.first()[0]);
    }
}

/* -------------------------------------------------------------------- */
private static class ValueCountComparator implements Comparator<int[]> {
    @Override
    public int compare(int[] a, int[] b) {
        if (a[1] != b[1]) {
            return b[1] - a[1];          // higher count first
        }
        return b[0] - a[0];              // then higher value first
    }
}

