public int compare(node n1, node n2) {
    // Guard clause for the primary value comparison
    int valCmp = Integer.compare(n1.val, n2.val);
    if (valCmp != 0) {
        return valCmp;
    }

    // Values are equal – need to compare types
    if (n1.type != n2.type) {
        return compareTypes(n1.type, n2.type);
    }

    // Both value and type are identical
    return 0;
}

private int compareTypes(int t1, int t2) {
    // Guard clauses reflect the original priority order
    if (t1 == -1) return -1;
    if (t2 == -1) return 1;
    if (t1 == 0)  return -1;
    if (t2 == 0)  return 1;
    // For any other distinct types the original code fell through to 0
    return 0;
}

