/* ------------------------------------------------------------------ */
/* Helper methods – each one has a single responsibility and uses   */
/* guard‑clauses where appropriate, keeping cyclomatic complexity low. */
/* ------------------------------------------------------------------ */

private static int[] buildZeroCount(String s, int n) {
    int[] cnt = new int[n + 1];
    cnt[0] = 0;
    for (int i = 1; i <= n; i++) {
        cnt[i] = cnt[i - 1] + (s.charAt(i - 1) == '0' ? 1 : 0);
    }
    return cnt;
}

private static long[] buildPowers(long base, long mod, int n) {
    long[] pow = new long[n + 1];
    pow[0] = 1;
    for (int i = 1; i <= n; i++) {
        pow[i] = pow[i - 1] * base % mod;
    }
    return pow;
}

/**
 * Returns true if the substrings t[l1..l1+len-1] and t[l2..l2+len-1] are equal.
 * Equality is decided by comparing zero‑counts and two independent rolling
 * hashes.
 */
private static boolean areSubstringsEqual(
        int l1, int l2, int len,
        long[] pow1, long[] pow2,
        long[][] hashEven1, long[][] hashOdd1,
        long[][] hashEven2, long[][] hashOdd2,
        int[] zeroCount,
        long mod1, long mod2) {

    // Guard‑clause: different number of '0's → cannot be equal
    if (zeroCount[l1 + len] - zeroCount[l1] != zeroCount[l2 + len] - zeroCount[l2]) {
        return false;
    }

    long fp1A = fingerprint(l1, l1 + len - 1, pow1, hashEven1, hashOdd1, zeroCount, mod1);
    long fp1B = fingerprint(l2, l2 + len - 1, pow1, hashEven1, hashOdd1, zeroCount, mod1);
    long fp2A = fingerprint(l1, l1 + len - 1, pow2, hashEven2, hashOdd2, zeroCount, mod2);
    long fp2B = fingerprint(l2, l2 + len - 1, pow2, hashEven2, hashOdd2, zeroCount, mod2);

    return fp1A == fp1B && fp2A == fp2B;
}

