/** Returns {xx, yy} – the adjusted grid positions for the current point. */
private long[] adjustedCoordinates(long xi, long yi, long k, long u, long v) {
    long xd = xi / k, yd = yi / k;
    long xm = xi % k, ym = yi % k;

    long xx = xd + ((xm + u) > k ? 2 : ((xm + u) > 0 ? 1 : 0));
    long yy = yd + ((ym + v) > k ? 2 : ((ym + v) > 0 ? 1 : 0));
    return new long[]{xx, yy};
}

/** Feasibility test used by the guard clause. */
private boolean isFeasible(long xi, long yi, long xx, long yy) {
    return !(xi < yy - 1 || yi < xx - 1);
}

/** Computes the new value of v (offset for the x‑axis). */
private long computeV(long xi, long yy, long k, long oldV) {
    return (xi == yy - 1) ? (xi + oldV) - (xi * k) : 0;
}

/** Computes the new value of u (offset for the y‑axis). */
private long computeU(long yi, long xx, long k, long oldU) {
    return (yi == xx - 1) ? (yi + oldU) - (yi * k) : 0;
}

