/* Helper for the 'U' direction */
private void handleU(int row, int col, int[] ans) {
    if (row % 2 == 0) {
        ans[col]++;
    }
}

/* Helper for the 'L' direction */
private void handleL(int row, int col, int[] ans) {
    int target = col - row;
    if (target >= 0) {
        ans[target]++;
    }
}

/* Helper for the 'R' direction */
private void handleR(int row, int col, int[] ans, int m) {
    int target = row + col;
    if (target < m) {
        ans[target]++;
    }
}

