    for (int i = 0; i < n; i++) {
        char[] map = in.nextString().toCharArray();
        for (int j = 0; j < m; j++) {
            processCell(map[j], i, j, m, ans);
        }
    }

    for (int a : ans) {
        out.print(a + " ");
    }
}

/**
 * Updates the answer array according to the symbol at position (row, col).
 * Guard‑clauses are used so each logical branch returns early, keeping the
 * method’s cyclomatic complexity low.
 */
private void processCell(char symbol, int row, int col, int width, int[] ans) {
    if (symbol == 'U') {
        if (row % 2 == 0) {
            ans[col]++;                 // upward move affects current column
        }
        return;
    }
    if (symbol == 'L') {
        int target = col - row;
        if (target >= 0) {
            ans[target]++;              // left move affects column shifted left by row
        }
        return;
    }
    if (symbol == 'R') {
        int target = row + col;
        if (target < width) {
            ans[target]++;              // right move affects column shifted right by row
        }
    }
}

