/**
 * Prints the result when one of the decks is empty.
 * Returns true if the game is over, false otherwise.
 */
private static boolean printResultIfGameOver(List<Integer> s1Cards,
                                             List<Integer> s2Cards,
                                             int moves) {
    if (s2Cards.isEmpty()) {
        System.out.println(moves + " 1");
        return true;
    }
    if (s1Cards.isEmpty()) {
        System.out.println(moves + " 2");
        return true;
    }
    return false;
}

/**
 * Executes a single round of the game, mutating the two decks
 * according to the original rules.
 */
private static void playRound(List<Integer> s1Cards,
                              List<Integer> s2Cards) {
    int c1 = s1Cards.get(0);
    int c2 = s2Cards.get(0);

    if (c1 == c2) {
        s1Cards.add(c1);
        s1Cards.remove(0);
        s2Cards.add(c2);
        s2Cards.remove(0);
    } else if (c1 > c2) {
        s1Cards.add(c2);
        s1Cards.add(c1);
        s1Cards.remove(0);
        s2Cards.remove(0);
    } else { // c1 < c2
        s2Cards.add(c1);
        s2Cards.add(c2);
        s2Cards.remove(0);
        s1Cards.remove(0);
    }
}

