        updateBounds(a, x, y, bounds);
    }

    // bounds[1] == x1, bounds[0] == x0, bounds[3] == y1, bounds[2] == y0
    if (bounds[1] < bounds[0] || bounds[3] < bounds[2]) {
        o.println(0);
    } else {
        o.println("1 " + bounds[0] + " " + bounds[2]);
    }
