/**
 * Adjusts the rectangle limits according to a single constraint line.
 *
 * a[0] – left side (x = constant)   → affects max x0 when a[0] == 0
 * a[1] – top side   (y = constant)   → affects min y1 when a[1] == 0
 * a[2] – right side (x = constant)   → affects min x1 when a[2] == 0
 * a[3] – bottom side(y = constant)   → affects max y0 when a[3] == 0
 */
private static void updateBounds(int[] a, int x, int y, int[] b) {
    if (a[0] == 0) b[0] = Math.max(b[0], x); // x0
    if (a[1] == 0) b[3] = Math.min(b[3], y); // y1
    if (a[2] == 0) b[1] = Math.min(b[1], x); // x1
    if (a[3] == 0) b[2] = Math.max(b[2], y); // y0
}

