public long nextLong() {
    ensureHasNext();

    int b = readByte();
    boolean minus = false;

    // handle optional sign
    if (b == '-') {
        minus = true;
        b = readByte();
    }

    // first character must be a digit
    if (b < '0' || b > '9') {
        throw new NumberFormatException();
    }

    long value = b - '0';
    value = readRemainingDigits(value);

    return minus ? -value : value;
}

/** Guard clause: make sure there is something to read. */
private void ensureHasNext() {
    if (!hasNext()) {
        throw new NoSuchElementException();
    }
}

/**
 * Consumes the rest of the token, building the numeric value.
 * Terminates on EOF or a non‑printable character, returning the
 * accumulated value. Any other printable character causes a
 * {@link NoSuchElementException}, matching the original contract.
 */
private long readRemainingDigits(long current) {
    while (true) {
        int b = readByte();

        if (b >= '0' && b <= '9') {
            current = current * 10 + (b - '0');
        } else if (b == -1 || !isPrintableChar(b)) {
            return current;               // end of token
        } else {
            throw new NoSuchElementException(); // unexpected printable char
        }
    }
}

