static long naive(int source, int steps) {
    // Guard clauses – handle invalid input early
    long earlyResult = checkInvalid(source, steps);
    if (earlyResult != Long.MIN_VALUE) {
        return earlyResult;
    }

    // Base cases
    if (steps == 0) {
        return 0L;
    }
    if (source == n - 1) {
        return l[source];
    }

    // Core recursive search
    long best = maxRecursive(source, steps - 1);
    if (best == -1) {
        return -1;
    }
    return best + l[source];
}

/**
 * Returns -1 for the two invalid‑input situations,
 * otherwise returns a sentinel (Long.MIN_VALUE) indicating that execution should continue.
 */
private static long checkInvalid(int source, int steps) {
    if ((n - source) / minLength > steps || steps < 0) {
        return -1;
    }
    if (steps == 1 && (n - source - 1) >= minLength) {
        return -1;
    }
    return Long.MIN_VALUE; // no early return required
}

/**
 * Recursively computes the maximal value obtainable from the next reachable
 * positions when `remainingSteps` steps are left.
 */
private static long maxRecursive(int source, int remainingSteps) {
    long rez = -1;
    int upper = Math.min(n, source + minLength + 1);
    for (int k = source + 1; k < upper; k++) {
        rez = Math.max(rez, naive(k, remainingSteps));
    }
    return rez;
}

