/** Holds data collected from the input string. */
private static class PatternInfo {
    final Set<Character> distinctLetters = new HashSet<>();
    int zeroCount = 0;
    boolean firstIsLetter = false;
}

/** Analyse the string once and fill a PatternInfo instance. */
private PatternInfo analysePattern(String s) {
    PatternInfo info = new PatternInfo();

    // first character – special handling
    char first = s.charAt(0);
    if (first >= 'A' && first <= 'Z') {
        info.distinctLetters.add(first);
        info.firstIsLetter = true;
    }

    // remaining characters
    for (int i = 1; i < s.length(); i++) {
        char c = s.charAt(i);
        if (c == '?') {
            info.zeroCount++;
        } else if (c >= 'A' && c <= 'Z') {
            info.distinctLetters.add(c);
        }
    }
    return info;
}

/** Compute the BigInteger multiplier based on the pattern information. */
private BigInteger computeMultiplier(PatternInfo info, char firstChar) {
    BigInteger x = BigInteger.ONE;

    // contribution of a leading '?'
    if (firstChar == '?') {
        x = x.multiply(BigInteger.valueOf(9));
    }

    // contribution of distinct letters
    int availableDigits = 10;
    for (int i = 0; i < info.distinctLetters.size(); i++) {
        x = x.multiply(BigInteger.valueOf(availableDigits--));
    }

    // leading letter cannot be zero
    if (info.firstIsLetter) {
        // divide by 10 (the former factor for the leading letter) and multiply by 9 instead
        x = x.divide(BigInteger.valueOf(10)).multiply(BigInteger.valueOf(9));
    }
    return x;
}

/** Print the final answer: the computed number followed by the required trailing zeroes. */
private void printResult(BigInteger value, int trailingZeroes) {
    out.print(value);
    for (int i = 0; i < trailingZeroes; i++) {
        out.print('0');
    }
}

