        int tmp = u;
        u = v;
        v = tmp;
    }

    int log = maxLog(L[u]);

    u = liftToSameDepth(u, v, L, P, log);

    // guard clause – both nodes met at the same vertex
    if (u == v) {
        return u;
    }

