/** Compute floor(log₂(depth)) – the highest exponent usable for binary lifting. */
private static int maxLog(int depth) {
    int log = 1;
    while ((1 << log) <= depth) {
        log++;
    }
    return log - 1;
}

/** Raise `u` until it is on the same depth as `v`. */
private static int liftToSameDepth(int u, int v, int[] L, int[][] P, int log) {
    for (int i = log; i >= 0; i--) {
        if (L[u] - (1 << i) >= L[v]) {
            u = P[u][i];
        }
    }
    return u;
}

/** Simultaneously lift both nodes while their 2ⁱ‑ancestors differ. */
private static int[] liftTogether(int u, int v, int[][] P, int log) {
    for (int i = log; i >= 0; i--) {
        if (P[u][i] != -1 && P[u][i] != P[v][i]) {
            u = P[u][i];
            v = P[v][i];
        }
    }
    return new int[]{u, v};
}

int query(int n, int[] T, int[][] P, int[] L, int u, int v) {
    // 1️⃣ Make sure u is the deeper (or equal) node.
    if (L[u] < L[v]) {
        int tmp = u;
        u = v;
        v = tmp;
    }

    // 2️⃣ Highest power of two needed for binary lifting.
    int maxLog = computeMaxLog(L[u]);

    // 3️⃣ Lift u up so that both nodes are on the same depth.
    u = liftToDepth(u, L[v], maxLog, P, L);
    if (u == v) {
        return u;               // they met – u (or v) is the LCA.
    }

    // 4️⃣ Climb both nodes together until just below the LCA.
    u = climbTogether(u, v, maxLog, P);

    // 5️⃣ Return the representative of the found LCA.
    return T[u];
}

/**
 * Returns the largest exponent `log` such that (1 << log) ≤ depth.
 */
private int computeMaxLog(int depth) {
    int log = 0;
    while ((1 << (log + 1)) <= depth) {
        log++;
    }
    return log;
}

/**
 * Moves `node` up the tree until its depth equals `targetDepth`.
 * `maxLog` is the highest binary‑lifting step that may be needed.
 */
private int liftToDepth(int node, int targetDepth, int maxLog, int[][] P, int[] L) {
    for (int i = maxLog; i >= 0; i--) {
        if (L[node] - (1 << i) >= targetDepth) {
            node = P[node][i];
        }
    }
    return node;
}

/**
 * Simultaneously lifts `u` and `v` while their 2^i‑ancestors differ.
 * Returns the new position of `u` (the caller does not need the new `v`).
 */
private int climbTogether(int u, int v, int maxLog, int[][] P) {
    for (int i = maxLog; i >= 0; i--) {
        if (P[u][i] != -1 && P[u][i] != P[v][i]) {
            u = P[u][i];
            v = P[v][i];
        }
    }
    return u;
}

