public static long getCount(int pos, int count, int isTight, long[][][] dp, String no) {
    // Guard clauses – handle trivial cases early
    if (count > 3) {
        return 0;
    }
    if (pos == no.length()) {
        return 1;
    }
    if (dp[pos][count][isTight] != -1) {
        return dp[pos][count][isTight];
    }

    // Upper bound for the current digit
    int upperBound = (isTight == 1) ? (no.charAt(pos) - '0') : 9;

    long ans = 0;
    for (int i = 0; i <= upperBound; i++) {
        ans += recurseNext(pos, count, isTight, i, upperBound, dp, no);
    }
    return dp[pos][count][isTight] = ans;
}

/**
 * Computes the contribution of choosing digit {@code i} at position {@code pos}.
 * The method isolates the conditional logic that determines the next tight flag
 * and whether the count of non‑zero digits increases.
 */
private static long recurseNext(int pos, int count, int isTight, int i,
                               int upperBound, long[][][] dp, String no) {
    int flag = (i != 0) ? 1 : 0;
    int nextTight = (isTight == 1 && i == upperBound) ? 1 : 0;
    return getCount(pos + 1, count + flag, nextTight, dp, no);
}

