/**
 * Fills the sentinel values and the input array.
 * Returns true if the special case n == 1 was processed (output already printed).
 */
private static boolean initializeArrays(int n, int[] a, int[] l, int[] r) throws IOException {
    a[0] = -(int) 2e9;
    a[n + 1] = -a[0];
    for (int i = 1; i <= n; i++) {
        a[i] = nextInt();
        l[i] = r[i] = 1;
    }
    if (n == 1) {
        pw.print(1);
        return true;
    }
    l[0] = r[0] = l[n + 1] = r[n + 1] = 0;
    return false;
}

/** Computes l[i] = length of longest strictly increasing prefix ending at i */
private static void computeIncreasingPrefixes(int n, int[] a, int[] l) {
    for (int i = 1; i <= n; i++) {
        if (a[i] > a[i - 1]) {
            l[i] = l[i - 1] + 1;
        }
    }
}

/** Computes r[i] = length of longest strictly increasing suffix starting at i */
private static void computeIncreasingSuffixes(int n, int[] a, int[] r) {
    for (int i = n; i >= 1; i--) {
        if (a[i + 1] > a[i]) {
            r[i] = r[i + 1] + 1;
        }
    }
}

/** Evaluates all possibilities and returns the maximal length */
private static int calculateMaximum(int n, int[] a, int[] l, int[] r) {
    int max = 1; // at least one element

    // middle element removal / merge cases
    for (int i = 1; i <= n; i++) {
        int candidate = l[i - 1] + r[i + 1] + 1;

        if (a[i] > a[i - 1] && a[i] < a[i + 1]) {
            max = Math.max(max, candidate);
            continue; // guard clause – other condition not needed
        }

        if (a[i + 1] > a[i - 1] + 1) {
            max = Math.max(max, candidate);
        }
    }

    // extend a left‑only increasing segment by one element
    for (int i = 2; i <= n; i++) {
        max = Math.max(max, l[i - 1] + 1);
    }

    // extend a right‑only increasing segment by one element
    for (int i = 1; i <= n - 1; i++) {
        max = Math.max(max, r[i + 1] + 1);
    }

    return max;
}

