}

/**
 * Reads the sequence, sets the sentinels and initialises l[] and r[] with 1.
 */
private static void initialiseArrays(int n, int[] a, int[] l, int[] r) throws IOException {
    a[0] = -(int) 2e9;
    a[n + 1] = -a[0];

    for (int i = 1; i <= n; i++) {
        a[i] = nextInt();
        l[i] = 1;
        r[i] = 1;
    }

    // sentinel positions are never part of a real increasing segment
    l[0] = r[0] = l[n + 1] = r[n + 1] = 0;
}

/**
 * Fills l[i] with the length of the longest strictly increasing prefix
 * ending at position i.
 */
private static void computeLeftLengths(int[] a, int[] l) {
    for (int i = 1; i < a.length - 1; i++) {
        if (a[i] > a[i - 1]) {
            l[i] = l[i - 1] + 1;
        }
    }
}

/**
 * Fills r[i] with the length of the longest strictly increasing suffix
 * starting at position i.
 */
private static void computeRightLengths(int[] a, int[] r) {
    for (int i = a.length - 2; i >= 1; i--) {
        if (a[i + 1] > a[i]) {
            r[i] = r[i + 1] + 1;
        }
    }
}

/**
 * Executes the three independent passes that can increase the answer.
 */
private static int computeMaximumLength(int[] a, int[] l, int[] r) {
    int max = 1;

    // 1) try to join a left part, the current element (removed) and a right part
    for (int i = 1; i < a.length - 1; i++) {
        if (a[i] > a[i - 1] && a[i] < a[i + 1]) {
            max = Math.max(max, l[i - 1] + r[i + 1] + 1);
        } else if (a[i + 1] > a[i - 1] + 1) {
            max = Math.max(max, l[i - 1] + r[i + 1] + 1);
        }
    }

    // 2) extend a left segment by removing the element right after it
    for (int i = 2; i < a.length - 1; i++) {
        max = Math.max(max, l[i - 1] + 1);
    }

    // 3) extend a right segment by removing the element right before it
    for (int i = 1; i < a.length - 2; i++) {
        max = Math.max(max, r[i + 1] + 1);
    }

    return max;
}

