/** evaluates all possibilities to obtain the longest increasing subsequence
 *  after removing at most one element */
private static int computeMaximumLength(int n, int[] a, int[] l, int[] r) {
    int max = 1;               // minimal answer

    // merge two increasing parts by removing a[i]
    for (int i = 1; i <= n; i++) {
        if (a[i] > a[i - 1] && a[i] < a[i + 1]) {
            max = Math.max(max, l[i - 1] + r[i + 1] + 1);
        } else if (a[i + 1] > a[i - 1] + 1) {
            max = Math.max(max, l[i - 1] + r[i + 1] + 1);
        }
    }

    // extend a left part by one element
    for (int i = 2; i <= n; i++) {
        max = Math.max(max, l[i - 1] + 1);
    }

    // extend a right part by one element
    for (int i = 1; i <= n - 1; i++) {
