/**
 * Fills the {@code origin} and {@code end} arrays for a single input line.
 *
 * @param idx      the index of the current line (used as an identifier)
 * @param g        gate type (1 or 2)
 * @param p        position value
 * @param t        time offset
 * @param w        width of the board (used only for gate type 2)
 * @param h        height of the board (used only for gate type 1)
 * @param origin   the array that stores the origin triples
 * @param end      the array that stores the end triples
 */
private static void fillArrays(int idx, int g, int p, int t,
                               int w, int h,
                               int[][] origin, int[][] end) {
    if (g == 1) { // vertical gate
        origin[idx] = new int[] { idx, p, -t };
        end[idx] = new int[] { p - t, p, h };
        return;
    }
    // g == 2, horizontal gate
    origin[idx] = new int[] { idx, -t, p };
    end[idx] = new int[] { p - t, w, p };
}

