/* ------------ input handling ------------ */
private static void fillArrays(Scanner sc, int n, int w, int h,
                               int[][] origin, int[][] end) {
    for (int i = 0; i < n; i++) {
        int g = sc.nextInt();
        int p = sc.nextInt();
        int t = sc.nextInt();

        if (g == 1) {
            setValuesForG1(i, p, t, h, origin, end);
        } else {                     // g == 2 (the only other valid value)
            setValuesForG2(i, p, t, w, origin, end);
        }
    }
}

private static void setValuesForG1(int i, int p, int t, int h,
                                   int[][] origin, int[][] end) {
    origin[i] = new int[] { i, p, -t };
    end[i]    = new int[] { p - t, p, h };
}

private static void setValuesForG2(int i, int p, int t, int w,
                                   int[][] origin, int[][] end) {
    origin[i] = new int[] { i, -t, p };
    end[i]    = new int[] { p - t, w, p };
}

/* ------------ sorting ------------ */
private static void sortOrigin(int[][] origin) {
    Comparator<int[]> comp = (a, b) -> {
        int sumA = a[1] + a[2];
        int sumB = b[1] + b[2];
        int cmp  = Integer.compare(sumA, sumB);
        if (cmp != 0) {
            return cmp;
        }
        return Integer.compare(a[1] - a[2], b[1] - b[2]);
    };
    Arrays.sort(origin, comp);
}

private static void sortEnd(int[][] end) {
    Comparator<int[]> comp = (a, b) -> {
        int cmp = Integer.compare(a[0], b[0]);
        if (cmp != 0) {
            return cmp;
        }
        return Integer.compare(a[1] - a[2], b[1] - b[2]);
    };
    Arrays.sort(end, comp);
}

/* ------------ mapping & output ------------ */
private static int[][] mapResults(int[][] origin, int[][] end) {
    int n = origin.length;
    int[][] re = new int[n][2];
    for (int i = 0; i < n; i++) {
        int index = origin[i][0];
        re[index] = new int[] { end[i][1], end[i][2] };
    }
    return re;
}

private static void printResult(int[][] re) {
    for (int[] out : re) {
        System.out.println(out[0] + " " + out[1]);
    }
}

