/* Helper for '_' */
private static void handleUnderscore(ParseState st) {
    if (st.len > st.maxLength && !st.insideParen) {
        st.maxLength = st.len;
    }
    if (st.insideParen && st.len > 0) {
        st.words++;
    }
    st.len = 0;
}

/* Helper for '(' */
private static void handleOpenParen(ParseState st) {
    st.insideParen = true;
    if (st.len > st.maxLength) {
        st.maxLength = st.len;
    }
    st.len = 0;
}

/* Helper for ')' */
private static void handleCloseParen(ParseState st) {
    st.insideParen = false;
    if (st.len > 0) {
        st.words++;
    }
    st.len = 0;
}

/* Final length check after the loop */
private static void finalizeMaxLength(ParseState st) {
    if (st.len > st.maxLength) {
        st.maxLength = st.len;
    }
}

