            handleOpenParen(st);
            continue;
        }
        if (c == ')') {
            handleCloseParen(st);
            continue;
        }
        // regular character
        st.len++;
    }

    // post‑loop finalisation
    if (st.len > st.maxLength) {
        st.maxLength = st.len;
    }

    pw.println(st.maxLength + " " + st.words);
}

