    if (st.flag == 1 && st.len > 0) {
        st.words++;
    }
    st.len = 0;
}

/** Process an opening parenthesis '(' */
private static void handleOpenParen(State st) {
    st.flag = 1;
    if (st.len > st.maxLength) {
        st.maxLength = st.len;
    }
    st.len = 0;
}

/** Process a closing parenthesis ')' */
private static void handleCloseParen(State st) {
    st.flag = 0;
    if (st.len > 0) {
        st.words++;
    }
    st.len = 0;
}

