/**
 * Determines whether the sequence of hands satisfies the problem constraints.
 *
 * @param name matrix of name pairs
 * @param pmt  permutation (0‑based)
 * @param n    number of elements
 * @return true if a valid configuration exists, false otherwise
 */
private boolean isPossible(String[][] name, int[] pmt, int n) {
    // Initialise hands with the first pair
    String hand1 = name[pmt[0]][0];
    String hand2 = name[pmt[0]][1];

    for (int i = 1; i < n; i++) {
        String lhand1 = null;
        String lhand2 = null;

        // Guard clause: find a candidate for the first hand
        if (name[pmt[i]][0].compareTo(hand1) > 0 || name[pmt[i]][0].compareTo(hand2) > 0) {
            lhand1 = name[pmt[i]][0];
        }

        // Guard clause: find a candidate for the second hand
        if (name[pmt[i]][1].compareTo(hand1) > 0 || name[pmt[i]][1].compareTo(hand2) > 0) {
            lhand2 = name[pmt[i]][1];
        }

        hand1 = lhand1;
        hand2 = lhand2;

        // Early exit when no hand can be chosen
        if (hand1 == null && hand2 == null) {
            return false;
        }

        // If only one hand is non‑null, duplicate it so both are defined
        if (hand1 == null) {
            hand1 = hand2;
        } else if (hand2 == null) {
            hand2 = hand1;
        }
    }
    return true;
}

