public static <T extends Comparable<? super T>> void sort(T[] arr) {
    // Guard clause – nothing to do for null or 0/1 element arrays
    if (arr == null || arr.length < 2) {
        return;
    }

    int n = arr.length - 1;               // last valid index
    T[] res = arr.clone();                // auxiliary buffer

    for (int s = 1; s <= n; s <<= 1) {    // current sub‑array size
        for (int l = 0; l < n; l += (s << 1)) {
            int h   = Math.min(l + (s << 1) - 1, n); // rightmost index of the pair
            int mid = Math.min(l + s - 1, n);       // end of left sub‑array

            merge(arr, res, l, mid, h);   // merge the two halves into res
            copyBack(arr, res, l, h);    // copy merged segment back to arr
        }
    }
}

/**
 * Merges the two sorted portions [left,mid] and [mid+1,right] from {@code src}
 * into {@code dst}. The result is written into {@code dst[left..right]}.
 */
private static <T extends Comparable<? super T>> void merge(
        T[] src, T[] dst, int left, int mid, int right) {

    int i = left;          // index in left half
    int j = mid + 1;       // index in right half
    int k = left;          // write position in dst

    while (i <= mid && j <= right) {
        if (src[i].compareTo(src[j]) <= 0) {
            dst[k++] = src[i++];
        } else {
            dst[k++] = src[j++];
        }
    }
    while (i <= mid) {
        dst[k++] = src[i++];
    }
    while (j <= right) {
        dst[k++] = src[j++];
    }
}

/**
 * Copies the merged segment {@code dst[left..right]} back into {@code src}.
 */
private static <T> void copyBack(T[] src, T[] dst, int left, int right) {
    for (int k = left; k <= right; k++) {
        src[k] = dst[k];
    }
}

