    }

    int candidate = findCandidate();

    if (candidate == Integer.MIN_VALUE) {          // no suitable vertex
        out.println("NO");
    } else {                                         // YES case
        out.println("YES");
        // candidate == -1 means all edges are monochromatic → any vertex works
        int answerVertex = (candidate == -1) ? 0 : candidate;
        out.println(answerVertex + 1);
    }
}

/**
 * Traverses all edges and returns:
 *   - a vertex index that satisfies the required condition,
 *   - -1 if every edge connects vertices of the same colour (any vertex works),
 *   - Integer.MIN_VALUE if a mismatched edge exists but neither endpoint is good.
 */
private int findCandidate() {
    for (int v = 0; v < g.length; v++) {
        for (int u : g[v]) {
            if (col[v] == col[u]) {
                continue;   // same colour – edge is irrelevant
            }
            if (good(v)) {
                return v;   // v can be the answer
            }
            if (good(u)) {
                return u;   // u can be the answer
            }
            // mismatched colours but neither endpoint is good → answer is NO
            return Integer.MIN_VALUE;
        }
    }
    // No edge with differing colours was found
    return -1;
}

