private long readLong() {
    try {
        int first = findFirstRelevantChar();
        if (first == -1) {                     // EOF before any digit or sign
            return 0L;
        }

        boolean negative = false;
        long value;

        if (first == '-') {
            negative = true;
            value = readDigits();              // may return 0 if no digits follow
        } else {                               // first is a digit
            value = accumulateValue(first);
        }

        return negative ? -value : value;
    } catch (Exception ex) {
        return -1L;
    }
}

/**
 * Skips any characters that are neither a digit nor a minus sign.
 * Returns the first relevant character or -1 if end‑of‑stream is reached.
 */
private int findFirstRelevantChar() throws IOException {
    int c;
    while ((c = br.read()) != -1) {
        if (c == '-') {
            return '-';
        }
        if (c >= '0' && c <= '9') {
            return c;
        }
        // ignore all other characters (e.g., whitespace)
    }
    return -1; // EOF
}

/**
 * Reads a contiguous sequence of digits after a sign has been consumed.
 * Returns the numeric value (0 if no digit follows the sign).
 */
private long readDigits() throws IOException {
    long result = 0;
    int c;
    while ((c = br.read()) != -1 && c >= '0' && c <= '9') {
        result = result * 10 + (c - '0');
    }
    return result;
}

/**
 * Starts accumulation with the already‑read first digit, then continues
 * reading the rest of the number.
 */
private long accumulateValue(int firstDigit) throws IOException {
    long result = firstDigit - '0';
    int c;
    while ((c = br.read()) != -1 && c >= '0' && c <= '9') {
        result = result * 10 + (c - '0');
    }
    return result;
}

public long readLong() {
    try {
        long result = 0;
        boolean started = false;
        boolean negative = false;

        while (true) {
            int c = br.read();

            if (isEndOfStream(c) && started) {
                break;
            }
            if (!started) {
                if (isSign(c)) {
                    negative = true;
                    started = true;
                    continue;
                }
                if (isDigit(c)) {
                    result = digitValue(c);
                    started = true;
                    continue;
                }
                // ignore any other leading characters
                if (isEndOfStream(c)) {
                    break;
                }
                continue;
            }

            // started == true
            if (isDigit(c)) {
                result = accumulateDigit(result, c);
                continue;
            }
            // non‑digit after start or EOF ends the number
            break;
        }
        return negative ? -result : result;
    } catch (Exception ex) {
        return -1;
    }
}

/* ------------------- helper methods ------------------- */
private boolean isDigit(int c) {
    return c >= '0' && c <= '9';
}

private int digitValue(int c) {
    return c - '0';
}

private boolean isSign(int c) {
    return c == '-';
}

private boolean isEndOfStream(int c) {
    return c == -1;
}

private long accumulateDigit(long current, int c) {
    return current * 10 + digitValue(c);
}

