    int cnt = 0;
    for (int i = 2; i * i <= x; i++) {
        if (x % i != 0) {
            continue;
        }
        if (i > b) {
            cnt++;
        }
        int counterpart = x / i;
        if (counterpart > b && counterpart != i) {
            cnt++;
        }
    }
    return cnt;
}

