 * in the current window of {@code a} equals the parity of the total number of '1's in {@code b}.
 */
private static int countParityMatches(char[] a, char[] b) {
    int totalOnesInB = countOnes(b, 0, b.length);
    int windowOnes = countOnes(a, 0, b.length);
    int matches = sameParity(totalOnesInB, windowOnes) ? 1 : 0;

    // slide the window of length b.length across a
    for (int i = 0; i <= a.length - b.length - 1; i++) {
        // remove the leftmost character and add the new rightmost character
        windowOnes += (a[i + b.length] == '1' ? 1 : 0);
        windowOnes -= (a[i] == '1' ? 1 : 0);
        if (sameParity(totalOnesInB, windowOnes)) {
            matches++;
        }
    }
    return matches;
}

