/**
 * Returns 0 if the number of '1's in the specified slice is even,
 * 1 if it is odd.
 */
private static int parity(char[] src, int start, int length) {
    int ones = 0;
    for (int i = 0; i < length; i++) {
        if (src[start + i] == '1') {
            ones++;
        }
    }
    return ones & 1; // same as ones % 2 but faster
}

/**
 * Counts how many substrings of {@code a} having the same length as {@code b}
 * have the same parity (odd/even count of '1's) as {@code b}.
 */
private static int countMatchingParityWindows(char[] a, char[] b) {
    int windowSize = b.length;
    int answer = 0;

    int bParity = parity(b, 0, windowSize);
    int windowParity = parity(a, 0, windowSize);

    if (bParity == windowParity) {
        answer++;
    }

    // slide the window one position at a time
    for (int i = 0; i < a.length - windowSize; i++) {
        // remove leftmost character of the current window
        if (a[i] == '1') {
            windowParity ^= 1; // toggle parity because we removed a '1'
        }
        // add the new rightmost character
        if (a[i + windowSize] == '1') {
            windowParity ^= 1; // toggle parity because we added a '1'
        }
        if (bParity == windowParity) {
            answer++;
        }
    }
    return answer;
}

