/** Returns the number of '1' characters in arr[from .. toExclusive). */
private static int countOnes(char[] arr, int from, int toExclusive) {
    int count = 0;
    for (int i = from; i < toExclusive; i++) {
        count += arr[i] == '1' ? 1 : 0;
    }
    return count;
}

/** true iff the parity (even/odd) of the two counts is the same. */
private static boolean parityMatches(int cnt1, int cnt2) {
    return (cnt1 & 1) == (cnt2 & 1);   // equivalent to cnt1%2 == cnt2%2
}

/** Core algorithm – calculates how many window positions have matching parity. */
private static int computeAnswer(char[] a, char[] b) {
    int cntB = countOnes(b, 0, b.length);          // total '1's in b
    int windowCnt = countOnes(a, 0, b.length);    // '1's in the first window of a

    int matches = parityMatches(cntB, windowCnt) ? 1 : 0;

    int windows = a.length - b.length;             // number of slide steps
    for (int i = 0; i < windows; i++) {
        // slide the window: remove leftmost, add new rightmost
        windowCnt += a[i + b.length] == '1' ? 1 : 0;
        windowCnt -= a[i] == '1' ? 1 : 0;

        matches += parityMatches(cntB, windowCnt) ? 1 : 0;
    }
    return matches;
}

