/* -------------------------------------------------------------------- */
/*  1️⃣  Data container                                                    */
private static final class ProblemData {
    final int[] left;
    final int[] right;
    final int[] cost;
    final int requiredLength;

    ProblemData(int[] left, int[] right, int[] cost, int requiredLength) {
        this.left = left;
        this.right = right;
        this.cost = cost;
        this.requiredLength = requiredLength;
    }
}

/* -------------------------------------------------------------------- */
/*  2️⃣  Read input                                                       */
private static ProblemData readProblemData(BufferedReader reader) throws IOException {
    StringTokenizer st = new StringTokenizer(reader.readLine());
    int n = Integer.parseInt(st.nextToken());
    int req = Integer.parseInt(st.nextToken());

    int[] left = new int[n];
    int[] right = new int[n];
    int[] cost = new int[n];

    for (int i = 0; i < n; i++) {
        st = new StringTokenizer(reader.readLine());
        left[i] = Integer.parseInt(st.nextToken());
        right[i] = Integer.parseInt(st.nextToken());
        cost[i] = Integer.parseInt(st.nextToken());
    }
    return new ProblemData(left, right, cost, req);
}

/* -------------------------------------------------------------------- */
/*  3️⃣  Core algorithm – compute minimal cost                             */
private static int computeMinimalCost(ProblemData d) {
    Integer[] byLeft = orderIndices(d.left);
    Integer[] byRight = orderIndices(d.right);

    TreeMap<Integer, Integer> bestCostByDuration = new TreeMap<>();
    int rightPointer = 0;
    int bestTotal = Integer.MAX_VALUE;

    for (int idx : byLeft) {
        int currentLeft = d.left[idx];

        // advance right‑pointer while intervals are completely left of currentLeft
        while (rightPointer < byRight.length && d.right[byRight[rightPointer]] < currentLeft) {
            int finishedIdx = byRight[rightPointer++];
            addOrImprove(bestCostByDuration,
                         duration(d.left[finishedIdx], d.right[finishedIdx]),
                         d.cost[finishedIdx]);
        }

        int needed = d.requiredLength - duration(d.left[idx], d.right[idx]);
        Integer partnerCost = bestCostByDuration.get(needed);
        if (partnerCost != null) {
            int candidate = partnerCost + d.cost[idx];
            if (candidate < bestTotal) {
                bestTotal = candidate;
            }
        }
    }

    // guard‑clause: no feasible pair found
    return (bestTotal == Integer.MAX_VALUE) ? -1 : bestTotal;
}

/* -------------------------------------------------------------------- */
/*  Helper: order indices by the values stored in `values` array          */
private static Integer[] orderIndices(int[] values) {
    Integer[] order = new Integer[values.length];
    for (int i = 0; i < values.length; i++) {
        order[i] = i;
    }
    Arrays.sort(order, (a, b) -> Integer.compare(values[a], values[b]));
    return order;
}

/* -------------------------------------------------------------------- */
/*  Helper: compute interval length (inclusive)                           */
private static int duration(int left, int right) {
    return right - left + 1;
}

/* -------------------------------------------------------------------- */
/*  Helper: store the cheapest cost for a given duration in the map      */
private static void addOrImprove(TreeMap<Integer, Integer> map, int dur, int cost) {
    Integer current = map.get(dur);
    if (current == null || cost < current) {
        map.put(dur, cost);
    }
}

