        }

        ensurePlayers(points, info.first, info.second);
        addPoints(points, info);
    }

    List<Person> people = buildPeopleList(points, me);
    Collections.sort(people);
    for (Person p : people) {
        out.println(p.name);
    }
}

/* ----- helper structures & methods ----- */

private static class ActionInfo {
    final String first;
    final String second;
    final char action;

    ActionInfo(String first, String second, char action) {
        this.first = first;
        this.second = second;
        this.action = action;
    }
}

/** Parse one input line into its components. */
private static ActionInfo parseActionLine(String line) {
    String[] parts = line.split(" ");
    String first = parts[0];
    // the opponent name is the penultimate token, without the trailing "):"
    String second = parts[parts.length - 2];
    second = second.substring(0, second.length() - 2);
    char action = parts[1].charAt(0);
    return new ActionInfo(first, second, action);
}

/** Does this action involve the player we are interested in? */
private static boolean involvesCurrentPlayer(ActionInfo info, String me) {
    return info.first.equals(me) || info.second.equals(me);
}

/** Make sure both participants have an entry in the map. */
private static void ensurePlayers(Map<String, Integer> map, String a, String b) {
    map.putIfAbsent(a, 0);
    map.putIfAbsent(b, 0);
}

/** Add points for the given action to both participants. */
private static void addPoints(Map<String, Integer> map, ActionInfo info) {
    int delta;
    switch (info.action) {
        case 'p': delta = 15; break;   // "p" – penalty
        case 'c': delta = 10; break;   // "c" – claim
        case 'l': delta = 5;  break;   // "l" – loss
        default:  delta = 0; break;
    }
    map.put(info.first, map.get(info.first) + delta);
    map.put(info.second, map.get(info.second) + delta);
}

/** Build the list of Person objects, excluding the current player. */
private static List<Person> buildPeopleList(Map<String, Integer> points, String me) {
    List<Person> list = new ArrayList<>();
    for (Map.Entry<String, Integer> e : points.entrySet()) {
        if (!e.getKey().equals(me)) {
            list.add(new Person(e.getKey(), e.getValue()));
        }
    }
    return list;
}

