private static long[] prefixSum(long[] k) {
    long[] ps = new long[k.length];
    if (k.length == 0) return ps;
    ps[0] = k[0];
    for (int i = 1; i < k.length; i++) {
        ps[i] = ps[i - 1] + k[i];
    }
    return ps;
}

/* first ‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑ 
* front part (indices 0 … it‑1) */
private static void applyFrontPrefix(long[] arr, long[] psum, int it, int c) {
    for (int i = 0; i < it; i++) {
        arr[i] = ((arr[i] % c) + (psum[i] % c)) % c;
    }
}

/* last ‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑‑ */
private static void applyBackPrefix(long[] arr, long[] psum, int it, int n, int m, int c) {
    for (int i = 0; i < it; i++) {
        int idx = n - i - 1;
        long suffix = psum[m - 1] -
                ((m - 1 - i - 1 < 0) ? 0 : psum[m - 1 - i - 1]);
        arr[idx] = ((arr[idx] % c) + (suffix % c)) % c;
    }
}

/* middle part – indices it … n‑it‑1 */
private static void applyMiddlePrefix(long[] arr, long[] psum, int it,
                                      int steps, int n, int m, int c) {
    int id = m - 2;                       // start index used when it < m
    for (int i = n - it - 1; i >= it; i--) {
        if (it == m) {
            // whole window fits – same addition for every element
            arr[i] = ((arr[i] % c) + (psum[m - 1] % c)) % c;
        } else {
            long addition = (psum[id] - psum[id - steps]) % c;
            arr[i] = ((arr[i] % c) + addition) % c;
            id--;
        }
    }
}

