/* ---------- helper methods ---------- */

private static long[] readArray(FastReader in, int size) {
    long[] a = new long[size];
    for (int i = 0; i < size; i++) {
        a[i] = in.nextLong();
    }
    return a;
}

private static long[] buildPrefixSum(long[] k) {
    long[] ps = new long[k.length];
    if (k.length == 0) return ps;
    ps[0] = k[0];
    for (int i = 1; i < k.length; i++) {
        ps[i] = ps[i - 1] + k[i];
    }
    return ps;
}

/* front part: first ‘it’ positions */
private static void applyFrontUpdates(long[] arr, long[] psum, int c, int it) {
    for (int i = 0; i < it; i++) {
        arr[i] = mod(arr[i], c) + mod(psum[i], c);
        arr[i] %= c;
    }
}

/* back part: last ‘it’ positions */
private static void applyBackUpdates(long[] arr, long[] psum, int c,
                                     int it, int n, int m) {
    long total = psum[m - 1];
    for (int i = 0; i < it; i++) {
        long suffix = total - ( (m - 2 - i >= 0) ? psum[m - 2 - i] : 0 );
        arr[n - 1 - i] = mod(arr[n - 1 - i], c) + mod(suffix, c);
        arr[n - 1 - i] %= c;
    }
}

/* middle part: positions between the two fronts */
private static void applyMiddleUpdates(long[] arr, long[] psum, int c,
                                       int it, int steps, int n, int m) {
    if (it == steps) {
        // no middle section
        return;
    }
    int id = m - 2;
    for (int i = n - it - 1; i >= it; i--) {
        long add = (it == m)
                ? mod(psum[m - 1], c)
                : mod(psum[id] - psum[id - steps], c);
        arr[i] = (mod(arr[i], c) + add) % c;
        id--;
    }
}

/* utility: positive modulo (handles negative intermediate values) */
private static long mod(long value, int mod) {
    long res = value % mod;
    return (res < 0) ? res + mod : res;
}

public static void main(String[] args) {
    FastReader in = new FastReader();
    PrintWriter out = new PrintWriter(System.out);

    int n = in.nextInt();
    int m = in.nextInt();
    int c = in.nextInt();

    long[] arr = readLongArray(in, n);
    long[] k   = readLongArray(in, m);
    long[] psum = buildPrefixSum(k);

    int steps = n - m + 1;
    int it = Math.min(m, steps);

    applyFront(arr, psum, c, it);
    applyBack(arr, psum, c, it, n, m);
    applyMiddle(arr, psum, c, it, steps, m, n);

    StringBuilder ans = new StringBuilder();
    for (long v : arr) {
        ans.append(v).append(' ');
    }
    out.println(ans);
    out.close();
}

/* ---------- helper methods ---------- */

private static long[] readLongArray(FastReader in, int size) {
    long[] a = new long[size];
    for (int i = 0; i < size; i++) {
        a[i] = in.nextLong();
    }
    return a;
}

private static long[] buildPrefixSum(long[] k) {
    long[] ps = new long[k.length];
    ps[0] = k[0];
    for (int i = 1; i < k.length; i++) {
        ps[i] = ps[i - 1] + k[i];
    }
    return ps;
}

/**
 * Update the first {@code it} elements (front side).
 */
private static void applyFront(long[] arr, long[] psum, int mod, int it) {
    for (int i = 0; i < it; i++) {
        arr[i] = (arr[i] % mod + psum[i] % mod) % mod;
    }
}

/**
 * Update the last {@code it} elements (back side).
 */
private static void applyBack(long[] arr, long[] psum, int mod,
                              int it, int n, int m) {
    long total = psum[m - 1];
    for (int i = 0; i < it; i++) {
        long suffix = total - (m - 1 - i - 1 >= 0 ? psum[m - 1 - i - 1] : 0);
        arr[n - i - 1] = (arr[n - i - 1] % mod + suffix % mod) % mod;
    }
}

/**
 * Update the middle region. The algorithm diverges depending on whether
 * {@code it == m}.  Two separate loops eliminate the inner conditional.
 */
private static void applyMiddle(long[] arr, long[] psum, int mod,
                                int it, int steps, int m, int n) {
    if (it == m) {
        // Whole window fits completely – same addition for every position.
        long add = psum[m - 1] % mod;
        for (int i = n - it - 1; i >= it; i--) {
            arr[i] = (arr[i] % mod + add) % mod;
        }
    } else {
        // Sliding window of size {@code steps}.
        int id = m - 2;               // index of the last prefix sum used
        for (int i = n - it - 1; i >= it; i--) {
            long windowSum = (psum[id] - psum[id - steps]) % mod;
            arr[i] = (arr[i] % mod + windowSum) % mod;
            id--;
        }
    }
}

