private static int calc(int a, int b, int first) {
    // Guard: reached the bottom of the recursion
    if (a == down + 1) {
        return 0;
    }

    // Guard: previously computed value
    if (dp[a][b][first] != -1) {
        return dp[a][b][first];
    }

    int f = parity(a);

    // Guard: impossible configuration when `first` is 1 and current column is forced
    if (violatesFirstConstraint(first, a, b, f)) {
        return dp[a][b][first] = INF;
    }

    int sum1 = computeSum1(a, b, f);
    int sum2 = computeSum2(a, b, f);

    int sum = Math.min(sum1, sum2);
    if (sum != INF) {
        sum++;
    }
    return dp[a][b][first] = sum;
}

/*--- helper methods ---------------------------------------------------*/

private static int parity(int a) {
    // even row → f = 1, odd row → f = 0
    return ((a & 1) == 0) ? 1 : 0;
}

/**
 * Returns true when the current state is illegal for the case
 * `first == 1` and the column is forced (`is[a]`).
 */
private static boolean violatesFirstConstraint(int first, int a, int b, int f) {
    if (first != 1 || !is[a]) {
        return false;
    }
    // f == 0  ⇒ we are moving left, must not be left of max[a]
    if (f == 0 && b < max[a]) {
        return true;
    }
    // f == 1  ⇒ we are moving right, must not be right of min[a]
    if (f == 1 && b > min[a]) {
        return true;
    }
    return false;
}

/**
 * Computes the cost of moving to the next row (a+1) when allowed,
 * otherwise returns INF.
 */
private static int computeSum1(int a, int b, int f) {
    boolean canMoveDown = !is[a] ||
                          (f == 0 ? b <= min[a] : b >= max[a]);
    return canMoveDown ? calc(a + 1, b, 1) : INF;
}

/**
 * Computes the cost of moving horizontally within the same row.
 */
private static int computeSum2(int a, int b, int f) {
    if (f == 1) { // moving right
        return (b < m - 1) ? calc(a, b + 1, 0) : INF;
    } else {      // moving left
        return (b > 0) ? calc(a, b - 1, 0) : INF;
    }
}

