public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    int k = sc.nextInt();

    int[][] pasta = new int[n][6];
    int[] menuplan = new int[n];

    for (int i = 0; i < k; i++) {
        int a = sc.nextInt();
        menuplan[a - 1] = sc.nextInt();
    }

    // initialise day 0
    initialiseFirstDay(pasta, menuplan[0]);

    // fill days 1 … n‑1
    for (int i = 1; i < n; i++) {
        updateDay(pasta, i, menuplan[i]);
    }

    // compute final pattern
    int pattern = 0;
    for (int i = 0; i < 6; i++) {
        pattern += pasta[n - 1][i];
    }
    System.out.println(pattern % 10000);
}

/**
 * Sets the values for the first day according to the plan.
 *
 * @param pasta   the DP table
 * @param plan    the menu plan for day 0 (0‑3)
 */
private static void initialiseFirstDay(int[][] pasta, int plan) {
    switch (plan) {
        case 0:
            pasta[0][1] = 1;
            pasta[0][3] = 1;
            pasta[0][5] = 1;
            break;
        case 1:
            pasta[0][1] = 1;
            break;
        case 2:
            pasta[0][3] = 1;
            break;
        case 3:
            pasta[0][5] = 1;
            break;
        default:
            // No action required for unexpected values (should not happen)
            break;
    }
}

/**
 * Updates the DP table for a given day according to the menu plan.
 *
 * @param pasta   the DP table
 * @param dayIdx  the index of the current day (≥ 1)
 * @param plan    the menu plan for this day (0‑3)
 */
private static void updateDay(int[][] pasta, int dayIdx, int plan) {
    final int MOD = 10000;
    int[] prev = pasta[dayIdx - 1];
    int[] cur  = pasta[dayIdx];

    switch (plan) {
        case 0:
            cur[0] = prev[1] % MOD;
            cur[2] = prev[3] % MOD;
            cur[4] = prev[5] % MOD;
            cur[1] = (prev[2] + prev[3] + prev[4] + prev[5]) % MOD;
            cur[3] = (prev[0] + prev[1] + prev[4] + prev[5]) % MOD;
