public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    int k = sc.nextInt();

    int[][] pasta = new int[n][6];
    int[] menuPlan = new int[n];

    for (int i = 0; i < k; i++) {
        int a = sc.nextInt();
        menuPlan[a - 1] = sc.nextInt();
    }

    initFirstDay(pasta, menuPlan);
    for (int i = 1; i < n; i++) {
        updateDay(i, pasta, menuPlan);
    }

    int pattern = sumLastRow(pasta, n);
