}

/* Initialise the first day according to menuPlan[0] */
private static void initFirstDay(int[][] pasta, int[] menuPlan) {
    switch (menuPlan[0]) {
        case 0:
            pasta[0][1] = 1;
            pasta[0][3] = 1;
            pasta[0][5] = 1;
            break;
        case 1:
            pasta[0][1] = 1;
            break;
        case 2:
            pasta[0][3] = 1;
            break;
        case 3:
            pasta[0][5] = 1;
            break;
        default:
            // no action needed – all cells stay 0
    }
}

/* Compute pasta values for day `idx` based on menuPlan[idx] */
private static void updateDay(int idx, int[][] pasta, int[] menuPlan) {
    final int MOD = 10000;
    int[] prev = pasta[idx - 1];
    int[] cur = pasta[idx];

    switch (menuPlan[idx]) {
        case 0:
            cur[0] = prev[1] % MOD;
            cur[2] = prev[3] % MOD;
            cur[4] = prev[5] % MOD;
            cur[1] = (prev[2] + prev[3] + prev[4] + prev[5]) % MOD;
            cur[3] = (prev[0] + prev[1] + prev[4] + prev[5]) % MOD;
            cur[5] = (prev[0] + prev[1] + prev[2] + prev[3]) % MOD;
            break;
        case 1:
            cur[0] = prev[1] % MOD;
            cur[1] = (prev[2] + prev[3] + prev[4] + prev[5]) % MOD;
            break;
        case 2:
            cur[2] = prev[3] % MOD;
            cur[3] = (prev[0] + prev[1] + prev[4] + prev[5]) % MOD;
            break;
        case 3:
            cur[4] = prev[5] % MOD;
            cur[5] = (prev[0] + prev[1] + prev[2] + prev[3]) % MOD;
            break;
        default:
            // do nothing – remains 0
    }
}

/* Sum the six entries of the last row */
private static int sumLastRow(int[][] pasta, int n) {
    int sum = 0;
    for (int i = 0; i < 6; i++) {
        sum += pasta[n - 1][i];
    }
    return sum;
}

