/** Reads N integers from the scanner into an array. */
private static int[] readArray(Scanner sc, int N) {
    int[] arr = new int[N];
    for (int i = 0; i < N; i++) {
        arr[i] = sc.nextInt();
    }
    return arr;
}

/** Returns true if every element in `arr` is >= limit. */
private static boolean allElementsAtLeast(int[] arr, int limit) {
    for (int value : arr) {
        if (value < limit) {
            return false;
        }
    }
    return true;
}

/** Constructs the difference (Imos) array for the current `as`. */
private static int[] buildImos(int[] as, int N) {
    int[] imos = new int[N + 1];
    for (int i = 0; i < N; i++) {
        int lower = Math.max(0, i - as[i]);
        int upper = Math.min(N - 1, i + as[i]);
        imos[lower] += 1;
        imos[upper + 1] -= 1;
    }
    return imos;
}

/** Converts a difference array into a prefix‑sum array (in‑place). */
private static void applyPrefixSum(int[] imos, int N) {
    for (int i = 0; i < N; i++) {
        imos[i + 1] += imos[i];
    }
}

/** Copies the first N values of `source` into `dest`. */
private static void copyFirstN(int[] source, int[] dest, int N) {
    for (int i = 0; i < N; i++) {
        dest[i] = source[i];
    }
}

