boolean isNear(int i, int j, int x, int y) {
    int dx = Math.abs(i - x);
    int dy = Math.abs(j - y);
    // Cells are adjacent (including diagonals) if the deltas are at most 1,
    // but they must not be the same cell.
    return (dx <= 1 && dy <= 1) && !(dx == 0 && dy == 0);
}

