/* ---------- helper methods ---------- */

private static int[] readArray(FastScanner sc, int n) {
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = sc.nextInt();
    }
    return arr;
}

/**
 * Sliding‑window algorithm that finds the longest sub‑array that can be turned
 * into all 1s by flipping at most {@code k} zeros.
 */
private static Result computeBestSegment(int[] a, int k) {
    int n = a.length;
    int s = 0, t = 0, zeros = 0;
    int maxLen = 0, bestStart = -1, bestEnd = -1;

    while (s < n && t < n) {
        // expand window while we may still flip zeros
        while (t < n && zeros < k) {
            if (a[t] == 0) {
                ++zeros;
            }
            ++t;
        }
        // once we have used all k flips, skip any trailing 1s
        while (t < n && a[t] == 1) {
            ++t;
        }

        if (t - s > maxLen) {
            maxLen = t - s;
            bestStart = s;
            bestEnd = t;
        }

        // shrink window from the left
        if (a[s] == 0) {
            --zeros;
        }
        ++s;
    }
    return new Result(bestStart, bestEnd, maxLen);
}

/**
 * Returns a copy of {@code original} where the segment
 * {@code [start, end)} is filled with 1s.
 */
private static int[] buildAnswer(int[] original, int start, int end) {
    int[] ans = Arrays.copyOf(original, original.length);
    for (int i = start; i < end; i++) {
        ans[i] = 1;
    }
    return ans;
}

/** Prints the length of the best segment followed by the resulting array. */
private static void printResult(int maxLen, int[] ans) {
    System.out.println(maxLen);
    for (int i = 0; i < ans.length; i++) {
        System.out.print(ans[i] + (i == ans.length - 1 ? "\n" : " "));
    }
}

/** Simple DTO to hold the result of the sliding‑window search. */
private static class Result {
    final int start;
    final int end;
    final int length;

    Result(int start, int end, int length) {
        this.start = start;
        this.end = end;
        this.length = length;
    }
}

