/**
 * Checks whether there exists an index reachable from {@code startPos}
 * by steps of size {@code step} that holds a larger number and is already
 * marked as B (ans == 1).
 */
private boolean hasWinningNeighbor(int step, int startPos, int[] a, int[] ans, int n) {
    // search to the left
    for (int j = startPos - step; j >= 0; j -= step) {
        if (a[j] > step && ans[j] == 1) {
            return true;
        }
    }
    // search to the right
    for (int j = startPos + step; j < n; j += step) {
        if (a[j] > step && ans[j] == 1) {
            return true;
        }
    }
    return false;
}

/**
