    for (int i = 0; i < n; i++) {
        posMap.put(a[i], i);
    }

    int[] ans = new int[n];
    ans[posMap.get(n)] = 1;                       // position of the largest element is a winning spot

    for (int i = n - 1; i > 0; i--) {
        int pos = posMap.get(i);
        if (hasWinningNeighbour(i, pos, a, ans, n)) {
            ans[pos] = -1;                         // losing position
        } else {
            ans[pos] = 1;                          // winning position
        }
    }

    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < n; i++) {
        sb.append(ans[i] == 1 ? 'B' : 'A');
    }
    out.println(sb.toString());
}

/**
 * Determines whether there exists an index j reachable from {@code pos}
 * by repeatedly adding or subtracting {@code step} such that:
 *   - a[j] > step
 *   - ans[j] == 1  (the neighbour is a winning position)
 *
 * The method returns as soon as the first qualifying neighbour is found.
 */
private boolean hasWinningNeighbour(int step, int pos, int[] a, int[] ans, int n) {
    // Scan to the left
    for (int j = pos - step; j >= 0; j -= step) {
        if (a[j] > step && ans[j] == 1) {
            return true;                          // guard clause
        }
    }
    // Scan to the right
    for (int j = pos + step; j < n; j += step) {
        if (a[j] > step && ans[j] == 1) {
            return true;                          // guard clause
        }
    }
    return false;
}

