/** Returns true if the graph matches a bus topology. */
private static boolean isBusTopology(int[] indeg, int n) {
    int count1 = 0, count2 = 0;
    for (int i = 1; i <= n; i++) {
        if (indeg[i] == 1) count1++;
        else if (indeg[i] == 2) count2++;
    }
    return count1 == 2 && count2 == n - 2;
}

/** Returns true if the graph matches a ring topology. */
private static boolean isRingTopology(int[] indeg, int n) {
    int count2 = 0;
    for (int i = 1; i <= n; i++) {
        if (indeg[i] == 2) count2++;
    }
    return count2 == n;
}

/** Returns true if the graph matches a star topology. */
private static boolean isStarTopology(int[] indeg, int n) {
    int count1 = 0;
    boolean isStar = false;
    for (int i = 1; i <= n; i++) {
        if (indeg[i] == 1) count1++;
        else if (indeg[i] == n - 1) isStar = true;
    }
    return isStar && count1 == n - 1;
}

