/* Helper class to hold the degree statistics */
private static class TopologyStats {
    final int countDegree1;
    final int countDegree2;
    final int isStar;      // 0 = false, 1 = true

    TopologyStats(int countDegree1, int countDegree2, int isStar) {
        this.countDegree1 = countDegree1;
        this.countDegree2 = countDegree2;
        this.isStar = isStar;
    }
}

/* Computes the three counters used for topology detection */
private static TopologyStats computeStats(int n, int[] indeg) {
    int count1 = 0;
    int count2 = 0;
    int isStar = 0;

    for (int i = 1; i <= n; i++) {
        if (indeg[i] == 1) {
            count1++;
        } else if (indeg[i] == 2) {
            count2++;
        } else if (indeg[i] == n - 1) {
            isStar = 1;
        }
    }
    return new TopologyStats(count1, count2, isStar);
}

/* Decides which topology description to return */
private static String determineTopology(TopologyStats stats, int n) {
    if (stats.countDegree1 == 2 && stats.countDegree2 == n - 2) {
        return "bus topology";
    }
    if (stats.countDegree2 == n) {
        return "ring topology";
    }
    if (stats.isStar == 1 && stats.countDegree1 == n - 1) {
        return "star topology";
    }
    return "unknown topology";
}

