/** Returns a max‑heap (priority queue) that orders indices by the values array. */
private static Queue<Integer> createMaxHeap(final long[] values) {
    return new PriorityQueue<>((i1, i2) -> {
        if (values[i1] < values[i2]) return 1;
        if (values[i1] > values[i2]) return -1;
        return i2 - i1;               // deterministic tie‑break
    });
}

/**
 * Executes the k operations, updating the heaps and storing prefix sums.
 * After each step the chosen row is decreased by m·p and the chosen column by n·p.
 */
private static void performIterations(int k, int n, int m, long p,
                                      long[] row, long[] col,
                                      Queue<Integer> rowHeap, Queue<Integer> colHeap,
                                      long[] prefixRow, long[] prefixCol) {
    for (int i = 1; i <= k; i++) {
        int rowIdx = rowHeap.poll();
        int colIdx = colHeap.poll();

        long rowVal = row[rowIdx];
        long colVal = col[colIdx];

        prefixRow[i] = prefixRow[i - 1] + rowVal;
        prefixCol[i] = prefixCol[i - 1] + colVal;

        row[rowIdx] -= m * p;
        col[colIdx] -= n * p;

        rowHeap.add(rowIdx);
        colHeap.add(colIdx);
    }
}

/** Computes the maximal value using the pre‑calculated prefix sums. */
private static long computeMaximum(long[] prefixRow, long[] prefixCol,
                                   long p, int k) {
    long max = Long.MIN_VALUE;
    for (int i = 0; i <= k; i++) {
        long cur = prefixRow[i] + prefixCol[k - i] - p * (long) i * (k - i);
        if (cur > max) {
            max = cur;
        }
    }
    return max;
}

