    System.out.println(max);
}

/* Reads the matrix and accumulates row‑ and column‑wise sums. */
private static void fillRowAndColumnSums(Scanner sc, int n, int m,
                                         long[] row, long[] col) {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            long v = sc.nextLong();
            row[i] += v;
            col[j] += v;
        }
    }
}

/* Creates a max‑heap (PriorityQueue) that orders indices by the
   corresponding values in the supplied array. */
private static Queue<Integer> createMaxHeap(long[] values) {
    return new PriorityQueue<>((i1, i2) -> {
        if (values[i1] == values[i2]) {
            return Integer.compare(i2, i1);          // tie‑breaker
        }
        return Long.compare(values[i2], values[i1]); // larger value first
    });
}

/* Computes the best possible total after exactly k operations
   and returns the maximum achievable score. */
private static long computeMaximumScore(long[] row, long[] col,
                                        int n, int m, int k, long p) {
    Queue<Integer> rowHeap = createMaxHeap(row);
    Queue<Integer> colHeap = createMaxHeap(col);

    // prefix sums for rows and columns
    long[] prefRow = new long[k + 1];
    long[] prefCol = new long[k + 1];

    for (int i = 1; i <= k; i++) {
        int rIdx = rowHeap.poll();
        int cIdx = colHeap.poll();

        prefRow[i] = prefRow[i - 1] + row[rIdx];
        prefCol[i] = prefCol[i - 1] + col[cIdx];

        // after taking a row/column we decrease its future contribution
        row[rIdx] -= m * p;
        col[cIdx] -= n * p;

        rowHeap.add(rIdx);
        colHeap.add(cIdx);
    }

    long best = Long.MIN_VALUE;
    for (int i = 0; i <= k; i++) {
        long cur = prefRow[i] + prefCol[k - i] - p * (long) i * (k - i);
        best = Math.max(best, cur);
    }
    return best;
}

