        this.y = y;
        this.value = value;
    }
}

/* ---------- step 1: read values into transformed grid ---------- */
private long[][] buildBaseMatrix(int rows, int cols,
                                 int n, int m, int minDiff) throws IOException {
    long[][] f = new long[rows][cols];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            int transformedRow = i + j;
            int transformedCol = i - j - minDiff;
            f[transformedRow][transformedCol] = nextInt();
        }
    }
    return f;
}

/* ---------- step 2: 2‑D prefix sum over the transformed grid ---------- */
private void compute2DPrefixSum(long[][] a) {
    for (int i = 0; i < a.length; i++) {
        for (int j = 0; j < a[i].length; j++) {
            if (i > 0) a[i][j] += a[i - 1][j];
            if (j > 0) a[i][j] += a[i][j - 1];
            if (i > 0 && j > 0) a[i][j] -= a[i - 1][j - 1];
        }
    }
}

/* ---------- step 3: build diagonal prefix tables ----------
   mainDiag – prefix along north‑west direction,
   secDiag  – prefix along north‑east direction                */
private long[][] buildDiagonalPrefix(int rows, int cols,
                                      long[][] src,
                                      boolean main) {
    long[][] dst = new long[rows][cols];
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            dst[i][j] = src[i][j];
            if (main) {
                if (i > 0 && j > 0) dst[i][j] += dst[i - 1][j - 1];
            } else {
                if (i > 0 && j < cols - 1) dst[i][j] += dst[i - 1][j + 1];
            }
        }
    }
    return dst;
}

/* ---------- step 4: iterate over all possible centres ---------- */
private Result evaluateBestCenter(int k, int n, int m, int minDiff,
                                 long[][] mainDiag, long[][] secDiag) {
    long bestValue = Long.MIN_VALUE;
    int bestX = -1, bestY = -1;

    for (int i = k - 1; i <= n - k; i++) {
        for (int j = k - 1; j <= m - k; j++) {
            int x = i + j;
            int y = i - j - minDiff;

            long cur = get(mainDiag, x + k - 1, y + k - 1)
                     - get(mainDiag, x - k - 1, y - k - 1);

            cur -= get(secDiag, x + k - 1, y - k)
                 - get(secDiag, x - k - 1, y + k);

            if (cur > bestValue) {
                bestValue = cur;
                bestX = i;
                bestY = j;
            }
        }
    }
    return new Result(bestX, bestY, bestValue);
}

