/** Returns true if the initial quick checks fail. */
private static boolean isInitiallyInvalid(int n, char[] a) {
    return (n % 2 == 1) || (a[0] == ')') || (a[n - 1] == '(');
}

/** Guarantees the first char is '(' and the last is ')'. */
private static void enforceEnds(char[] a) {
    a[0] = '(';
    a[a.length - 1] = ')';
}

/** How many '(' still have to be placed to reach n/2 total opens. */
private static int remainingOpensNeeded(int n, char[] a) {
    int needed = n / 2;
    for (char c : a) {
        if (c == '(') {
            needed--;
        }
    }
    return needed; // guaranteed ≥ 0 by previous validation
}

/** Replace each '?' with '(' while we still need openings, otherwise with ')'. */
private static void fillPlaceholders(char[] a, int opensNeeded) {
    for (int i = 0; i < a.length; i++) {
        if (a[i] == '?') {
            if (opensNeeded > 0) {
                a[i] = '(';
                opensNeeded--;
            } else {
                a[i] = ')';
            }
        }
    }
}

/**
 * Validates that the bracket sequence never becomes balanced before the
 * very last character and ends balanced.
 */
private static boolean isBalanced(char[] a) {
    int open = 0;
    for (int i = 0; i < a.length; i++) {
        if (a[i] == '(') {
            open++;
        } else { // ')'
            if (open == 1 && i == a.length - 1) {
                open--;                 // final closing makes the balance zero
            } else if (open > 1) {
                open--;                 // normal closing
            } else {
                return false;           // invalid closing or premature balance
            }
        }
    }
    return open == 0;
}

public static void main(String[] args) throws Exception {
