    if (earlyInvalid(n, a)) {
        out.println(":(");
        out.flush();
        out.close();
        return;
    }

    // force the required outer brackets
    a[0] = '(';
    a[n - 1] = ')';

    fillMissing(a, n);

    if (isBalanced(a)) {
        out.print(a);
    } else {
        out.println(":(");
    }
    out.flush();
    out.close();
}

/**
 * Returns true if the initial input cannot possibly be fixed:
 * - length is odd
 * - first character is ')'
 * - last character is '('
 */
private static boolean earlyInvalid(int n, char[] a) {
    return (n % 2 == 1) || (a[0] == ')') || (a[n - 1] == '(');
}

/**
 * Replaces every '?' with '(' or ')' so that the total number of '(' becomes n/2.
 * The first and last positions have already been forced to '(' and ')'.
 */
private static void fillMissing(char[] a, int n) {
    int neededOpens = n / 2;                     // total '(' required
    for (char c : a) {
        if (c == '(') {
            neededOpens--;                       // one '(' already present
        }
    }

    for (int i = 0; i < n; i++) {
        if (a[i] == '?') {
            if (neededOpens > 0) {
                a[i] = '(';
                neededOpens--;
            } else {
                a[i] = ')';
            }
        }
    }
}

/**
 * Checks whether the character array forms a correct parentheses sequence.
 * Standard stack‑less balance test: count '(' and decrement on ')'.
 * The sequence is valid iff the counter never becomes negative and ends at zero.
 */
private static boolean isBalanced(char[] a) {
    int balance = 0;
    for (char c : a) {
        if (c == '(') {
            balance++;
        } else { // c == ')'
            balance--;
            if (balance < 0) {
                return false;                    // more closing than opening
            }
        }
    }
    return balance == 0;
}

