/**
 * Returns the contribution of trying digit {@code j} at position {@code i}.
 * The logic mirrors the three mutually‑exclusive cases that existed in the
 * original method.
 */
private static long contribute(int i, int isequal, int nonzeros, int digit, int j) {
    // Skip the branch that was implicitly ignored in the original code
    if (isequal == 1 && j > digit) {
        return 0;
    }

    int nextNonZeros = (j == 0) ? nonzeros : nonzeros + 1;

    // Case 1: still equal to the prefix of the original number
    if (isequal == 1 && j == digit) {
        return dp(i + 1, 1, nextNonZeros);
    }

    // Case 2 & 3: already smaller (isequal == 0) or becomes smaller now (j < digit)
    // In both situations the next isequal flag is 0.
    return dp(i + 1, 0, nextNonZeros);
}

