/**
 * Counts how many pairs (a,b) appear later in the sorted array such that
 * a > currentMinA && b < currentMinB, respecting groups with equal 'a'.
 */
private static int countValidPairs(Pair[] arr) {
    if (arr == null || arr.length < 2) {
        return 0; // guard clause – nothing to count
    }

    int mina = arr[0].a;
    int minb = arr[0].b;
    int count = 0;
    int i = 1;

    while (i < arr.length) {
        // Skip over entries that share the same 'a' as the previous one,
        // checking each of them against the current minima.
        while (i < arr.length && arr[i].a == arr[i - 1].a) {
            if (isValid(arr[i], mina, minb)) {
                count++;
            }
            i++;
        }

        if (i >= arr.length) {
            break; // guard clause – reached the end after a group
        }

        // Possibly update the minima using the last element of the previous group.
        Pair previous = arr[i - 1];
        if (previous.b > minb) {
            mina = previous.a;
            minb = previous.b;
        }

        // Evaluate the current element.
        if (isValid(arr[i], mina, minb)) {
            count++;
        }
        i++;
    }

    return count;
}

/** Predicate used by {@link #countValidPairs}. */
private static boolean isValid(Pair p, int mina, int minb) {
    return p.a > mina && p.b < minb;
}

