private RMQ getNode(int from, int to) {
    assert (from >= this.from && to <= this.to && from < to);
    if (isWholeRange(from, to)) {
        return this;
    }

    RMQ left  = leftNode(from, to);
    RMQ right = rightNode(from, to);

    return choose(left, right);
}

/* Helper: full‑range shortcut */
private boolean isWholeRange(int from, int to) {
    return from == this.from && to == this.to;
}

/* Helper: obtain left child node when the range overlaps the left side */
private RMQ leftNode(int from, int to) {
    if (from < m) {
        return L.getNode(from, Math.min(to, m));
    }
    return null;
}

/* Helper: obtain right child node when the range overlaps the right side */
private RMQ rightNode(int from, int to) {
    if (m < to) {
        return R.getNode(Math.max(from, m), to);
    }
    return null;
}

/* Helper: pick the node with the smaller X value, handling nulls */
private RMQ choose(RMQ a, RMQ b) {
    if (a == null) {
        return b;
    }
    if (b == null) {
        return a;
    }
    return (a.X <= b.X) ? a : b;
}

