static boolean jikken() {
    boolean[] tree = new boolean[N + 1];
    for (int i = 1; i <= N; i++) {
        tree[i] = canReach(i, tree);
    }

    int[] hoge = new int[N + 1];
    for (int i = 0; i <= N; i++) {
        hoge[i] = tree[i] ? 1 : 0;
    }
    debug(hoge);
    return tree[N];
}

/**
 * Determines whether position i can be reached based on previously
 * computed values in {@code tree}. Returns true if any of the
 * allowed moves lands on a false entry, otherwise false.
 */
private static boolean canReach(int i, boolean[] tree) {
    // Move of size 1
    if (!tree[i - 1]) {
        return true;
    }
    // Move of size 2
    if (i >= 2 && !tree[i - 2]) {
        return true;
    }
    // Move of size K
    if (i >= K && !tree[i - K]) {
        return true;
    }
    // No reachable move found
    return false;
}

