/**
 * Returns the number of distinct characters in the given array.
 */
private static int countDistinctCharacters(char[] chars) {
    int[] seen = new int[300];
    int distinct = 0;
    for (char c : chars) {
        if (seen[c] == 0) {
            distinct++;
            seen[c] = 1;
        }
    }
    return distinct;
}

/**
 * Returns the length of the smallest contiguous sub‑array that contains
 * all distinct characters found in the whole array.
 */
private static int findMinimumWindowLength(char[] a, int distinctCount) {
    int n = a.length;
    int[] freq = new int[300];
    int left = 0, right = 0;
    int have = 0;
    int best = n; // worst case: the whole string

    // initialise window with the first character
    freq[a[0]] = 1;
    have = 1;

    while (left < n) {
        // expand the window until it contains all distinct characters
        while (right < n && have < distinctCount) {
            right++;
            if (right >= n) {
                break;
            }
            if (freq[a[right]] == 0) {
                have++;
            }
            freq[a[right]]++;
        }

        // update answer if current window is valid
        if (have == distinctCount) {
            best = Math.min(best, right - left + 1);
        }

        // contract the window from the left
        freq[a[left]]--;
        if (freq[a[left]] == 0) {
            have--;
        }
        left++;
    }

    return best;
}

