private static int[][] readEdges(Scanner in, int n) {
    int[][] deg = new int[2][2 * n + 1];
    for (int i = 0; i < n; i++) {
        int a = in.nextInt();
        int b = in.nextInt();
        deg[0][b]++;          // out‑degree of b
        deg[1][a]++;          // in‑degree of a
        g[a] = b;             // direct edge a → b
        G[b].add(a);          // reverse adjacency list
    }
    return deg;
}

/* Run first depth‑first search on all vertices that have not been
 * marked as “stay”. */
