        }
    }

    long twoPower = powTwo(cnt);
    ans = (ans * twoPower) % mod;
    return ans;
}

/* Compute 2^exp modulo `mod`. */
private static long powTwo(int exp) {
    long result = 1L;
    for (int i = 0; i < exp; i++) {
        result = (result * 2) % mod;
    }
    return result;
}

