/** Moves the cursor according to L / R commands, otherwise leaves it unchanged. */
private int moveCursor(char cmd, int cursor) {
    if (cmd == L) {
        return Math.max(0, cursor - 1);
    }
    if (cmd == R) {
        return cursor + 1;
    }
    return cursor;
}

/** Updates the segment tree at the current cursor position. */
private void updateTree(FastSegmentTree<EEditor.S> st, int cursor, char cmd) {
    if (cmd == PLUS) {
        st.value.init(1);
    } else if (cmd == MINUS) {
        st.value.init(-1);
    } else {
        st.value.init(0);
    }
    st.update(cursor);
}

/** Runs a full‑range query and returns the answer for the current state. */
private int evaluate(FastSegmentTree<EEditor.S> st) {
    st.query(0, st.n);          // assuming the tree exposes its size as 'n'
    return (st.value.sum[0] != 0 || st.value.min[0] < 0) ? -1 : st.value.max[0];
}

public void solve(int testNumber, InputReader in, PrintWriter out) {
