    int cursor = 0;
    List<Integer> answer = new ArrayList<>();

    for (char cmd : commands) {
        cursor = handleCommand(cmd, cursor, st);
        st.query(0, n);
        answer.add(evaluate(st));
    }

    out.println();
    out.println(Util.join(answer));
}

/** Returns the new cursor position after processing the command. */
private int handleCommand(char cmd, int cursor, FastSegmentTree<EEditor.S> st) {
    if (cmd == L) {
        return moveLeft(cursor);
    }
    if (cmd == R) {
        return moveRight(cursor);
    }
    if (cmd == PLUS) {
        applyUpdate(st, cursor, 1);
        return cursor;
    }
    if (cmd == MINUS) {
        applyUpdate(st, cursor, -1);
        return cursor;
    }
    // default case – any other character
    applyUpdate(st, cursor, 0);
    return cursor;
}

/** Moves cursor one step to the left, never below 0. */
private int moveLeft(int cursor) {
    cursor--;
    return cursor < 0 ? 0 : cursor;
}

/** Moves cursor one step to the right. */
private int moveRight(int cursor) {
    return cursor + 1;
}

/** Initializes the segment‑tree leaf at *pos* with *value* and updates the tree. */
private void applyUpdate(FastSegmentTree<EEditor.S> st, int pos, int value) {
    st.value.init(value);
    st.update(pos);
}

/** Returns the answer for the current state of the segment tree. */
private int evaluate(FastSegmentTree<EEditor.S> st) {
    if (st.value.sum[0] != 0 || st.value.min[0] < 0) {
        return -1;
    }
    return st.value.max[0];
}

