}

/**
 * Returns true if the number of differing bits between {@code a} and {@code x}
 * in the lowest {@code n} bit positions is at most {@code k}.
 */
private boolean isAcceptable(int a, int x, int n, int k) {
    return differingBits(a, x, n) <= k;
}

/**
 * Counts how many of the lowest {@code n} bits differ between {@code a} and {@code x}.
 * The difference is measured by the XOR of the two numbers.
 */
private int differingBits(int a, int x, int n) {
    int diff = a ^ x;               // bits that differ
    int mask = (1 << n) - 1;        // keep only the lowest n bits
    diff &= mask;

    // Count set bits in diff (standard bit‑count loop)
    int count = 0;
    while (diff != 0) {
        count++;
        diff &= diff - 1;           // clear the lowest set bit
    }
    return count;
}

public void solve(InputReader in, OutputWriter out) {
    PrintWriter pout = new PrintWriter(new BufferedOutputStream(System.out));
    int n = in.readInt();          // number of bits to consider
    int m = in.readInt();          // size of array A
    int k = in.readInt();          // maximum allowed differing bits
    int[] A = new int[m];
    for (int i = 0; i < m; i++) {
        A[i] = in.readInt();
    }
    int x = in.readInt();          // target value

    int f = 0;
    for (int value : A) {
        if (isWithinK(value, x, n, k)) {
            f++;
        }
    }

    pout.println(f);
    pout.close();
}

/**
 * Returns true if the Hamming distance between {@code a} and {@code b},
 * considering only the lowest {@code bits} bits, is less than or equal to {@code maxDiff}.
 */
private boolean isWithinK(int a, int b, int bits, int maxDiff) {
    // Mask to keep only the lowest 'bits' bits
    int mask = (bits >= 31) ? -1 : (1 << bits) - 1;
    int diff = (a ^ b) & mask;
    int distance = Integer.bitCount(diff);
    return distance <= maxDiff;
}

