    for (Interval interval : intervals) {
        Long candidate = evaluateInterval(interval, dayToHeight);
        if (candidate == null) {               // impossible configuration
            out.println("IMPOSSIBLE");
            return;
        }
        maxHeight = Math.max(maxHeight, candidate);
    }

