/* ------------------------------------------------------------------ */
/* Helper methods – each encapsulates a single logical responsibility. */
private List<Interval> buildIntervals(LinkedHashMap<Long, Long> map) {
    List<Interval> list = new ArrayList<>();
    Iterator<Map.Entry<Long, Long>> it = map.entrySet().iterator();

    long prevDay = it.next().getKey();          // map is guaranteed non‑empty
    while (it.hasNext()) {
        long currDay = it.next().getKey();
        list.add(new Interval(prevDay, currDay));
        prevDay = currDay;
    }
    return list;
}

/* When there is exactly one known day, the answer is the higher of the
   two possible extensions (to day 1 or to the final day). */
private long resultForSingleEntry(long days, LinkedHashMap<Long, Long> map) {
    long onlyDay = map.keySet().iterator().next();
    long height = map.get(onlyDay);
    return Math.max(height + onlyDay - 1, height + days - onlyDay);
}

/* Computes the maximum height contributed by the leftmost and rightmost
   boundaries (if they are not at day 1 or day = days). */
private long boundaryMaxHeight(long days,
                               LinkedHashMap<Long, Long> map,
                               List<Interval> intervals) {
    long max = -1L;

    Interval first = intervals.get(0);
    if (first.start != 1) {
        max = map.get(first.start) + (first.start - 1);
    }

    long lastEnd = intervals.get(intervals.size() - 1).end;
    if (lastEnd != days) {
        max = Math.max(max, map.get(lastEnd) + (days - lastEnd));
    }
    return max;
}

/* Evaluates a single interval. Returns the maximal height reachable inside
   the interval, or null if the interval makes the whole scenario impossible. */
private Long evaluateInterval(Interval interval,
                              Map<Long, Long> heights) {
    long hStart = heights.get(interval.start);
    long hEnd   = heights.get(interval.end);

    long diff   = Math.abs(hStart - hEnd);
    long slots  = interval.end - interval.start - 1;

    // Not enough slots to connect the two known heights.
    if (diff > slots + 1) {
        return null;
    }

    // Increase diff while there are spare slots – this yields the highest
    // possible peak inside the interval.
    while (diff < slots) {
        diff++;
        slots--;
    }

    // The peak is the higher of the lower endpoint plus the remaining diff.
    return Math.min(hStart, hEnd) + diff;
}

