private static List<Interval> buildIntervals(LinkedHashMap<Long, Long> map) {
    List<Interval> intervals = new ArrayList<>();
    Iterator<Map.Entry<Long, Long>> it = map.entrySet().iterator();

    long prevDay = it.next().getKey();          // first day is guaranteed to exist
    while (it.hasNext()) {
        long currDay = it.next().getKey();
        intervals.add(new Interval(prevDay, currDay));
        prevDay = currDay;
    }
    return intervals;
}

/**
 * Handles the two edge pieces (before the first known day and after the last known day).
 */
private static long computeBoundaryMaxHeight(LinkedHashMap<Long, Long> map,
                                             List<Interval> intervals,
                                             long days) {
    long maxHeight = -1;

    // before the first known day
    Interval first = intervals.get(0);
    if (first.start != 1) {
        maxHeight = map.get(first.start) + (first.start - 1);
    }

    // after the last known day
    Interval last = intervals.get(intervals.size() - 1);
    if (last.end != days) {
        long candidate = map.get(last.end) + (days - last.end);
        maxHeight = Math.max(maxHeight, candidate);
    }
    return maxHeight;
}

/**
 * Processes the interior intervals.
 * Returns null if the situation is impossible (already printed “IMPOSSIBLE”).
 */
private static Long evaluateIntervals(List<Interval> intervals,
                                      LinkedHashMap<Long, Long> map,
                                      long currentMax,
                                      PrintWriter out) {
    long maxHeight = currentMax;

    for (Interval interval : intervals) {
        long heightStart = map.get(interval.start);
        long heightEnd   = map.get(interval.end);
        long diff   = Math.abs(heightStart - heightEnd);
        long slots  = interval.end - interval.start - 1;

        // impossible to connect the two known heights
        if (diff > slots + 1) {
            out.println("IMPOSSIBLE");
            return null;
        }

        // bring diff up to the number of free slots (the “mountain” can be flattened)
        while (diff < slots) {
            diff++;
            slots--;
        }

        maxHeight = Math.max(maxHeight,
                Math.min(heightStart, heightEnd) + diff);
    }
    return maxHeight;
}

