private LinkedHashMap<Long, Long> readEntries(Scanner in, int entries) {
    LinkedHashMap<Long, Long> map = new LinkedHashMap<>();
    for (int i = 0; i < entries; i++) {
        long day = in.nextInt();
        long height = in.nextInt();
        map.put(day, height);
