private List<Interval> buildIntervals(LinkedHashMap<Long, Long> map) {
    List<Interval> intervals = new ArrayList<>();
    Iterator<Map.Entry<Long, Long>> it = map.entrySet().iterator();

    long prevDay = it.next().getKey();                 // map is never empty here
    while (it.hasNext()) {
        long currDay = it.next().getKey();
        intervals.add(new Interval(prevDay, currDay));
        prevDay = currDay;
    }
    return intervals;
}

/* Handles the case where there is only one recorded day (no intervals). */
private void handleSingleEntryCase(LinkedHashMap<Long, Long> map,
                                   long days,
                                   PrintWriter out) {
    long onlyDay = map.keySet().iterator().next();
    long height = map.get(onlyDay);
    long candidate1 = height + onlyDay - 1;          // climb from day 1
    long candidate2 = height + days - onlyDay;      // climb from the last day
    out.print(Math.max(candidate1, candidate2));
}

/* Computes the maximum height that can be achieved on the leftmost
   and rightmost edges of the timeline. */
private long initialEdgeMaxHeight(List<Interval> intervals,
                                  LinkedHashMap<Long, Long> map,
                                  long days) {
    long max = -1;

    // left edge (day 1 … first recorded day)
    if (intervals.get(0).start != 1) {
        long firstDay = intervals.get(0).start;
        max = map.get(firstDay) + (firstDay - 1);
    }

    // right edge (last recorded day … day 'days')
    long lastDay = intervals.get(intervals.size() - 1).end;
    if (lastDay != days) {
        long candidate = map.get(lastDay) + (days - lastDay);
        max = Math.max(max, candidate);
    }

    return max;
}

/* Validates a single interval and, if possible, updates the current
   maximum height via the supplied consumer. Returns true if the interval
   is feasible, false otherwise (the method already printed "IMPOSSIBLE"). */
private boolean processInterval(Interval interval,
                                 LinkedHashMap<Long, Long> map,
                                 PrintWriter out,
                                 java.util.function.Consumer<long[]> updateMax) {
    long startHeight = map.get(interval.start);
    long endHeight   = map.get(interval.end);
    long diff   = Math.abs(startHeight - endHeight);
    long slots  = interval.end - interval.start - 1; // days between the two records

    // not enough days to accommodate the required height change
    if (diff > slots + 1) {
        out.println("IMPOSSIBLE");
        return false;
    }

    // we can increase the diff (by making a peak) until it matches slots
    while (diff < slots) {
        diff++;
        slots--;
    }

    long possiblePeak = Math.min(startHeight, endHeight) + diff;
    updateMax.accept(new long[]{Math.max(possiblePeak, possiblePeak)}); // update external maxHeight
    return true;
}

