private boolean isDigit(int c) {
    return c >= '0' && c <= '9';
}

/**
 * Consumes an optional leading minus sign.
 * @return true if the number is negative
 */
private boolean readSign() {
    int b = peekByte();               // look ahead without consuming
    if (b == '-') {
        readByte();                   // consume the minus
        return true;
    }
    return false;
}

/**
 * Reads the first non‑sign byte and ensures it is a digit.
 * @return the first digit byte
 * @throws NumberFormatException if the byte is not a digit
 */
private int readFirstDigit() {
    int b = readByte();
    if (!isDigit(b)) {
        throw new NumberFormatException();
    }
    return b;
}

public long nextLong() {
    if (!hasNext()) {
        throw new NoSuchElementException();
    }

    boolean minus = readSign();          // handle leading '-'
    int b = readFirstDigit();            // first digit already validated

    long n = 0;
    while (isDigit(b)) {
        n = n * 10 + (b - '0');
        b = readByte();
    }

    // At this point b is the first non‑digit after the number.
    // Valid termination: EOF (-1) or a non‑printable character.
    if (b != -1 && isPrintableChar(b)) {
        throw new NumberFormatException();
    }

    return minus ? -n : n;
}

public long nextLong() {
    // Guard: no more input
    if (!hasNext()) {
        throw new NoSuchElementException();
    }

    // Read first byte and handle optional sign
    int b = readByte();
    boolean minus = false;
    if (b == '-') {
        minus = true;
        b = readByte();
    }

    // Guard: first non‑sign character must be a digit
    if (b < '0' || b > '9') {
        throw new NumberFormatException();
    }

    // Build the number (already have first digit)
    long value = readUnsignedLong(b - '0');

    return minus ? -value : value;
}

/**
 * Reads the remaining digits of a long value.
 * The caller has already validated that the first digit is present.
 *
 * @param firstDigit the numeric value of the first digit (0‑9)
 * @return the unsigned long represented by the consecutive digit characters
 */
