private void requireDigit(int c) {
    if (c < '0' || c > '9') {
        throw new NumberFormatException();
    }
}

/**
 * Accumulates a long value from printable digit characters.
 * The loop stops when a non‑printable character is encountered.
 * Any printable non‑digit character triggers NumberFormatException.
 */
private long readNumber(long current, int c) {
    long n = current;
    int cur = c;
    while (isPrintable(cur)) {
        if (cur >= '0' && cur <= '9') {
            n = n * 10 + (cur - '0');
        } else {
            throw new NumberFormatException();
        }
        cur = readByte();
    }
    return n;
}

