private boolean isDigit(int c) {
    return c >= '0' && c <= '9';
}

/**
 * Reads the remaining printable characters starting with {@code firstDigit},
 * builds the long value and validates that every printable character is a digit.
 * Throws NumberFormatException if a non‑digit printable character is encountered.
 */
private long readNumber(int firstDigit) {
    long result = 0;
    int ch = firstDigit;

    while (true) {
        // At this point {@code ch} is guaranteed to be a digit
        result = result * 10 + (ch - '0');

        ch = readByte();
        if (!isPrintable(ch)) {
            break;
        }
        if (!isDigit(ch)) {
            throw new NumberFormatException();
        }
    }
    return result;
}

