        ch = readByte();
    }

    // first character after optional sign must be a digit
    if (ch < '0' || ch > '9') {
        throw new NumberFormatException();
    }

    long value = parseNumber(ch);
    return minus ? -value : value;
}

/** Guard that the scanner has more input. */
private void ensureHasNext() {
    if (!hasNext()) {
        throw new NoSuchElementException();
    }
