/**
 * Consumes printable characters starting with {@code first}.
 * Accumulates a long value while characters are digits.
 * Throws {@link NumberFormatException} for any non‑digit printable
 * character.
 */
private long parseNumber(int first) {
    long n = 0;
    int cur = first;
    while (isPrintable(cur)) {
        if (cur >= '0' && cur <= '9') {
            n = n * 10 + (cur - '0');
        } else {
            throw new NumberFormatException();
        }
        cur = readByte();
    }
    return n;
}

