private int countModified(int threadHold, Map<Integer, Integer> map) {
        int currDist = map.size();
        int tmp = (int)(Math.log(currDist) / Math.log(2));
        if (Math.pow(2, tmp) < currDist) {
            tmp += 1;
        }
        while (tmp > threadHold) {
            currDist--;
            tmp = (int)(Math.log(currDist) / Math.log(2));
            if (Math.pow(2, tmp) < currDist) {
                tmp += 1;
            }
        }

        if (currDist == map.size()) {
            return 0;
        }

        int[] sum = new int[map.size()];
        int pnt = 0;
        for (int key : map.keySet()) {
            sum[pnt] = (pnt == 0 ? 0 : sum[pnt - 1]) + map.get(key);
            pnt++;
        }

        int change = Integer.MAX_VALUE;
        int changeKeys = map.size() - currDist;
        for (int i = 0; i <= changeKeys; i++) {
            int j = changeKeys - i;

            int sub = 0;
            sub += i == 0 ? 0 : sum[ i- 1];
            sub += j == 0 ? 0 : (sum[map.size() - 1] - sum[map.size() - 1 - j]);

            change = Math.min(change, sub);
        }

        return change;
    }

