/**
 * Sorts the given array in‑place by the {@code d1} field.
 */
private static void sortByD1(Node[] array) {
    Arrays.sort(array, Comparator.comparingInt(node -> node.d1));
}

/**
 * Merges the two sorted arrays and returns the accumulated sum according to
 * the original problem statement.
 */
private static long mergeAndSum(Node[] a, Node[] b) {
    int i = 0, j = 0;
    long sum = 0L;

    // Process elements that exist in both arrays
    while (i < a.length && j < b.length) {
        if (a[i].d1 < b[j].d1) {
            sum += a[i].d2;
            i++;
            continue;
        }
        if (a[i].d1 > b[j].d1) {
            sum += b[j].d2;
            j++;
            continue;
        }
        // a[i].d1 == b[j].d1
        sum += Math.max(a[i].d2, b[j].d2);
        i++;
        j++;
    }

    // Add remaining elements from a
    while (i < a.length) {
        sum += a[i].d2;
        i++;
    }

    // Add remaining elements from b
    while (j < b.length) {
        sum += b[j].d2;
        j++;
    }

    return sum;
}

