 *  and returns the accumulated sum. */
private static long mergeAndSum(Node[] a, Node[] b) {
    int i = 0, j = 0;
    long sum = 0;

    while (i < a.length && j < b.length) {
        if (a[i].d1 < b[j].d1) {
            sum += a[i].d2;
            i++;
            continue;               // guard clause
        }
        if (a[i].d1 > b[j].d1) {
            sum += b[j].d2;
            j++;
            continue;               // guard clause
        }
        // a[i].d1 == b[j].d1
        sum += Math.max(a[i].d2, b[j].d2);
        i++;
        j++;
    }

    while (i < a.length) {
        sum += a[i].d2;
        i++;
    }
    while (j < b.length) {
        sum += b[j].d2;
        j++;
    }
    return sum;
}

