public void run() {
    InputReader sc = new InputReader(System.in);
    PrintWriter w = new PrintWriter(System.out);

    int n = sc.nextInt();
    Point[] p = new Point[n];
    for (int i = 0; i < n; ++i) {
        p[i] = new Point(sc.nextInt(), sc.nextInt(),
                         sc.nextInt(), sc.nextInt());
    }

    PrefixArrays prefix = buildPrefix(p);
    SuffixArrays suffix = buildSuffix(p);

    int[] answer = findIntersection(prefix, suffix, n);
    if (answer != null) {
        w.print(answer[0] + " " + answer[1]);
    }
    w.close();
}

/* ---------- helper data containers ---------- */
private static class PrefixArrays {
    final int[] minX, maxX, minY, maxY;
    PrefixArrays(int[] minX, int[] maxX, int[] minY, int[] maxY) {
        this.minX = minX; this.maxX = maxX;
        this.minY = minY; this.maxY = maxY;
    }
}

private static class SuffixArrays {
    final int[] minX, maxX, minY, maxY;
    SuffixArrays(int[] minX, int[] maxX, int[] minY, int[] maxY) {
        this.minX = minX; this.maxX = maxX;
        this.minY = minY; this.maxY = maxY;
    }
}

/* ---------- prefix construction ---------- */
private static PrefixArrays buildPrefix(Point[] p) {
    int n = p.length;
    int[] pminx = new int[n];
    int[] pmaxx = new int[n];
    int[] pminy = new int[n];
    int[] pmaxy = new int[n];

    pminx[0] = p[0].x1;
    pmaxx[0] = p[0].x2;
    pminy[0] = p[0].y1;
    pmaxy[0] = p[0].y2;

    for (int i = 1; i < n; ++i) {
        pminx[i] = Math.max(pminx[i - 1], p[i].x1);
        pmaxx[i] = Math.min(pmaxx[i - 1], p[i].x2);
        pminy[i] = Math.max(pminy[i - 1], p[i].y1);
        pmaxy[i] = Math.min(pmaxy[i - 1], p[i].y2);
    }
    return new PrefixArrays(pminx, pmaxx, pminy, pmaxy);
}

/* ---------- suffix construction ---------- */
private static SuffixArrays buildSuffix(Point[] p) {
    int n = p.length;
    int[] sminx = new int[n];
    int[] smaxx = new int[n];
    int[] sminy = new int[n];
    int[] smaxy = new int[n];

    sminx[n - 1] = p[n - 1].x1;
    smaxx[n - 1] = p[n - 1].x2;
    sminy[n - 1] = p[n - 1].y1;
    smaxy[n - 1] = p[n - 1].y2;

    for (int i = n - 2; i >= 0; --i) {
        sminx[i] = Math.max(sminx[i + 1], p[i].x1);
        smaxx[i] = Math.min(smaxx[i + 1], p[i].x2);
        sminy[i] = Math.max(sminy[i + 1], p[i].y1);
        smaxy[i] = Math.min(smaxy[i + 1], p[i].y2);
    }
    return new SuffixArrays(sminx, smaxx, sminy, smaxy);
}

/* ---------- intersection search (guard clauses) ---------- */
private static int[] findIntersection(PrefixArrays pre,
                                      SuffixArrays suf,
                                      int n) {
    // case: ignore the first rectangle
    if (suf.minX[1] <= suf.maxX[1] && suf.minY[1] <= suf.maxY[1]) {
        return new int[]{suf.minX[1], suf.minY[1]};
    }

    // case: ignore the last rectangle
    if (pre.minX[n - 2] <= pre.maxX[n - 2] && pre.minY[n - 2] <= pre.maxY[n - 2]) {
        return new int[]{pre.minX[n - 2], pre.minY[n - 2]};
    }

    // case: ignore rectangle i (1 ≤ i ≤ n‑2)
    for (int i = 1; i <= n - 2; ++i) {
        int minX = Math.max(suf.minX[i + 1], pre.minX[i - 1]);
        int maxX = Math.min(suf.maxX[i + 1], pre.maxX[i - 1]);
        int minY = Math.max(suf.minY[i + 1], pre.minY[i - 1]);
        int maxY = Math.min(suf.maxY[i + 1], pre.maxY[i - 1]);

        if (minX <= maxX && minY <= maxY) {
            return new int[]{minX, minY};
        }
    }
    // no suitable point found
    return null;
}

public void run() {
    InputReader sc = new InputReader(System.in);
    PrintWriter w = new PrintWriter(System.out);

    int n = sc.nextInt();

    Point[] p = new Point[n];
    for (int i = 0; i < n; ++i) {
        p[i] = new Point(sc.nextInt(), sc.nextInt(),
                         sc.nextInt(), sc.nextInt());
    }

    int[] pminx = new int[n];
    int[] pmaxx = new int[n];
    int[] pminy = new int[n];
    int[] pmaxy = new int[n];
    computePrefix(p, pminx, pmaxx, pminy, pmaxy);

    int[] sminx = new int[n];
    int[] smaxx = new int[n];
    int[] sminy = new int[n];
    int[] smaxy = new int[n];
    computeSuffix(p, sminx, smaxx, sminy, smaxy);

    if (tryFirstEdge(w, sminx, smaxx, sminy, smaxy)) return;
    if (tryLastEdge(w, pminx, pmaxx, pminy, pmaxy, n)) return;
    if (tryMiddle(w, sminx, smaxx, sminy, smaxy,
                  pminx, pmaxx, pminy, pmaxy, n)) return;

    w.close();
}

/* ---------- helper methods ---------- */

private void computePrefix(Point[] p,
                           int[] minx, int[] maxx,
                           int[] miny, int[] maxy) {
    minx[0] = p[0].x1;
    maxx[0] = p[0].x2;
    miny[0] = p[0].y1;
    maxy[0] = p[0].y2;

    for (int i = 1; i < p.length; ++i) {
        minx[i] = Math.max(minx[i - 1], p[i].x1);
        maxx[i] = Math.min(maxx[i - 1], p[i].x2);
        miny[i] = Math.max(miny[i - 1], p[i].y1);
        maxy[i] = Math.min(maxy[i - 1], p[i].y2);
    }
}

private void computeSuffix(Point[] p,
                           int[] minx, int[] maxx,
                           int[] miny, int[] maxy) {
    int n = p.length;
    minx[n - 1] = p[n - 1].x1;
    maxx[n - 1] = p[n - 1].x2;
    miny[n - 1] = p[n - 1].y1;
    maxy[n - 1] = p[n - 1].y2;

    for (int i = n - 2; i >= 0; --i) {
        minx[i] = Math.max(minx[i + 1], p[i].x1);
        maxx[i] = Math.min(maxx[i + 1], p[i].x2);
        miny[i] = Math.max(miny[i + 1], p[i].y1);
        maxy[i] = Math.min(maxy[i + 1], p[i].y2);
    }
}

private boolean tryFirstEdge(PrintWriter w,
                             int[] sminx, int[] smaxx,
                             int[] sminy, int[] smaxy) {
    if (sminx[1] <= smaxx[1] && sminy[1] <= smaxy[1]) {
        outputAndClose(w, sminx[1], sminy[1]);
        return true;
    }
    return false;
}

private boolean tryLastEdge(PrintWriter w,
                            int[] pminx, int[] pmaxx,
                            int[] pminy, int[] pmaxy,
                            int n) {
    if (pminx[n - 2] <= pmaxx[n - 2] && pminy[n - 2] <= pmaxy[n - 2]) {
        outputAndClose(w, pminx[n - 2], pminy[n - 2]);
        return true;
    }
    return false;
}

private boolean tryMiddle(PrintWriter w,
                          int[] sminx, int[] smaxx,
                          int[] sminy, int[] smaxy,
                          int[] pminx, int[] pmaxx,
                          int[] pminy, int[] pmaxy,
                          int n) {
    for (int i = 1; i <= n - 2; ++i) {
        int minx = Math.max(sminx[i + 1], pminx[i - 1]);
        int maxx = Math.min(smaxx[i + 1], pmaxx[i - 1]);
        int miny = Math.max(sminy[i + 1], pminy[i - 1]);
        int maxy = Math.min(smaxy[i + 1], pmaxy[i - 1]);

        if (minx <= maxx && miny <= maxy) {
            outputAndClose(w, minx, miny);
            return true;
        }
    }
    return false;
}

private void outputAndClose(PrintWriter w, int x, int y) {
    w.print(x + " " + y);
    w.close();
}

