private int next() {
		int X = W[0], Y = W[1];
		int dx = T[0], dy = T[1];

		if (X == 1) dx =  1;
		if (X == N) dx = -1;
		if (Y == 1) dy =  1;
		if (Y == M) dy = -1;

		int t = INF;
		if (dx ==  1) t = min(t, N - X);
		if (dx == -1) t = min(t, X - 1);
		if (dy ==  1) t = min(t, M - Y);
		if (dy == -1) t = min(t, Y - 1);

		X += t * dx; Y += t * dy;

		W[0] = X; W[1] = Y;
		T[0] = dx; T[1] = dy;

		return t;
	}

