static void walkon(ArrayList<Character> walk, int x, int y) {
    // Guard clause – stop when we have reached the origin
    if (x == 0 && y == 0) {
        return;
    }

    char prevDir = walk.get(walk.size() - 1);
    Step next = determineNextStep(x, y, prevDir);

    walk.add(next.dir);
    walkon(walk, next.x, next.y);
}

/** Simple value holder for the next step. */
private static class Step {
    final int x;
    final int y;
    final char dir;

    Step(int x, int y, char dir) {
        this.x = x;
        this.y = y;
        this.dir = dir;
    }
}

/** Returns the next step (direction and new coordinates) based on the current position
 *  and the direction we arrived from. */
private static Step determineNextStep(int x, int y, char prevDir) {
    // ordered candidate directions for each possible previous direction
    char[] candidates;
    switch (prevDir) {
        case 'R': candidates = new char[]{'U', 'R', 'D'}; break;
        case 'U': candidates = new char[]{'L', 'U', 'R'}; break;
        case 'L': candidates = new char[]{'D', 'L', 'U'}; break;
        case 'D': candidates = new char[]{'R', 'D', 'L'}; break;
        default:  candidates = new char[0];
    }

    for (char cand : candidates) {
        if (wallExists(cand, x, y)) {
            return applyDirection(cand, x, y);
        }
    }
    // If none of the walls are open we stay in place (should never happen in valid input)
    return new Step(x, y, '1');
}

/** Checks whether a wall in the given direction is open (value == 1). */
private static boolean wallExists(char direction, int x, int y) {
    switch (direction) {
        case 'U':
            return y > 0 && verW[(y - 1) * 5 + x] == 1;
        case 'D':
            return y < 4 && verW[y * 5 + x] == 1;
        case 'L':
            return x > 0 && horW[x - 1 + 4 * y] == 1;
        case 'R':
            return x < 4 && horW[x + 4 * y] == 1;
        default:
            return false;
    }
}

/** Moves one step in the supplied direction and returns the resulting coordinates. */
private static Step applyDirection(char direction, int x, int y) {
    switch (direction) {
        case 'U': return new Step(x, y - 1, 'U');
        case 'D': return new Step(x, y + 1, 'D');
        case 'L': return new Step(x - 1, y, 'L');
        case 'R': return new Step(x + 1, y, 'R');
        default:  return new Step(x, y, direction);
    }
}

