}

/* -------------------------------------------------------------
   Helper: read problem data and fill the two arrays.
   ------------------------------------------------------------- */
private void readInput() throws IOException {
    n = nextInt();
    entries = new TEntry[n];
    input = new TEntry[n];

    for (int i = 0; i < n; i++) {
        TEntry e = new TEntry();
        e.s1 = nextToken();
        e.s2 = nextToken();
        input[i] = e;
    }

    for (int i = 0; i < n; i++) {
        int idx = nextInt() - 1;            // permutation is 1‑based
        entries[i] = input[idx];
    }
}

/* -------------------------------------------------------------
   Helper: evaluate whether a strictly increasing sequence exists.
   ------------------------------------------------------------- */
private boolean isSequencePossible() {
    // initialise with the smallest element of the first pair
    String last = entries[0].s1;
    if (entries[0].s2.compareTo(last) < 0) {
        last = entries[0].s2;
    }

    for (int i = 1; i < n; i++) {
        String next = nextGreater(last, entries[i]);
        if (next == null) {
            return false;                     // guard clause – impossible path
        }
        last = next;
    }
    return true;
}

/* -------------------------------------------------------------
   Helper: return the smallest string in the entry that is > last.
   If none exists, return null.
   ------------------------------------------------------------- */
private String nextGreater(String last, TEntry e) {
    String candidate = null;

    if (e.s1.compareTo(last) > 0) {
        candidate = e.s1;
    }
    if (e.s2.compareTo(last) > 0) {
        if (candidate == null || e.s2.compareTo(candidate) < 0) {
            candidate = e.s2;
        }
    }
    return candidate;   // null signals “no possible continuation”
}

public void Run() throws NumberFormatException, IOException {
    br = new BufferedReader(new InputStreamReader(System.in));
    pw = new PrintWriter(new OutputStreamWriter(System.out));

    n = nextInt();
    entries = new TEntry[n];
    input = new TEntry[n];
    for (int i = 0; i < n; i++) {
        input[i] = new TEntry();
        input[i].s1 = nextToken();
        input[i].s2 = nextToken();
    }
    for (int i = 0; i < n; i++) {
        int zn = nextInt() - 1;
        entries[i] = input[zn];
    }

    String lastStr = initialLast(entries[0]);

    boolean possible = true;
    for (int i = 1; i < n && possible; i++) {
        String candidate = chooseNewLast(entries[i], lastStr);
        if (candidate == null) {
            possible = false;               // guard clause – stop processing
        } else {
            lastStr = candidate;
        }
    }

    pw.println(possible ? "YES" : "NO");
    pw.flush();
    pw.close();
}

/** Returns the smaller of the two strings of the first entry. */
private String initialLast(TEntry first) {
    String last = first.s1;
    if (first.s2.compareTo(last) < 0) {
        last = first.s2;
    }
    return last;
}

/**
 * Determines the next possible “last” string for the given entry.
 * Returns null if neither string can be placed after {@code lastStr},
 * otherwise returns the chosen string.
 */
private String chooseNewLast(TEntry entry, String lastStr) {
    // case 1: s1 is larger than the current lastStr
    if (entry.s1.compareTo(lastStr) > 0) {
        String newLast = entry.s1;
        // if s2 is also larger and smaller than s1, pick s2 instead
        if (entry.s2.compareTo(lastStr) > 0 && entry.s2.compareTo(newLast) < 0) {
            newLast = entry.s2;
        }
        return newLast;
    }

    // case 2: s1 cannot be used, but s2 can
    if (entry.s2.compareTo(lastStr) > 0) {
        return entry.s2;
    }

    // case 3: neither string can follow lastStr
    return null;
}

