/**
 * Builds the rail distance matrix:
 *   - INF everywhere,
 *   - 0 on the diagonal,
 *   - 1 for each directly connected railway edge.
 */
private static int[][] buildRailDistMatrix(int n, int m) throws IOException {
    int[][] dist = new int[n][n];

    for (int i = 0; i < n; i++) {
        Arrays.fill(dist[i], INF);
        dist[i][i] = 0;
    }

    for (int i = 0; i < m; i++) {
        int a = sc.nextInt() - 1;
        int b = sc.nextInt() - 1;
        dist[a][b] = 1;
        dist[b][a] = 1;
    }
    return dist;
}

/**
 * Builds the road distance matrix as the complement of the rail matrix:
 *   - 1 where there is no railway,
 *   - INF where a railway exists,
 *   - diagonal stays at default 0 (unused later).
 */
private static int[][] buildRoadDistMatrix(int n, int[][] rail) {
    int[][] road = new int[n][n];

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i == j) {
                continue;
            }
            if (rail[i][j] == INF) {
                road[i][j] = 1;
            } else if (rail[i][j] == 1) {
                road[i][j] = INF;
            }
        }
    }
    return road;
}

/**
 * Prints the required shortest path length using guard clauses.
 * The logic matches the original conditional block exactly.
 */
private static void outputShortestPath(int[][] rail, int[][] road) {
    int n = rail.length;

    if (rail[0][n - 1] == 1 && road[0][n - 1] < INF) {
        out.println(road[0][n - 1]);
        return;
    }
    if (road[0][n - 1] == 1 && rail[0][n - 1] < INF) {
        out.println(rail[0][n - 1]);
        return;
    }
    out.println(-1);
}

static void main(String[] args) throws IOException {
    int n = sc.nextInt();
    int m = sc.nextInt();

    int[][] distRail = initRailDistances(n, m);
    int[][] distRoad = buildRoadDistances(n, distRail);

    floydWarshall(n, distRail);
    floydWarshall(n, distRoad);

    printResult(distRail, distRoad);
    out.close();
}

/** Reads the rail edges and creates the initial distance matrix for railways. */
private static int[][] initRailDistances(int n, int m) {
    int[][] rail = new int[n][n];
    // initialise with INF
    for (int i = 0; i < n; i++) {
        Arrays.fill(rail[i], INF);
        rail[i][i] = 0;
    }
    // read edges
    for (int i = 0; i < m; i++) {
        int a = sc.nextInt() - 1;
        int b = sc.nextInt() - 1;
        rail[a][b] = 1;
        rail[b][a] = 1;
    }
    return rail;
}

/** Constructs the road distance matrix: a road exists where no rail exists. */
private static int[][] buildRoadDistances(int n, int[][] rail) {
    int[][] road = new int[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i == j) {
                continue;               // guard clause – skip self‑loops
            }
            if (rail[i][j] == INF) {
                road[i][j] = 1;          // road where there is no rail
            } else if (rail[i][j] == 1) {
                road[i][j] = INF;        // no road where a rail exists
            }
        }
    }
    return road;
}

/** Chooses the correct answer according to the problem statement and prints it. */
private static void printResult(int[][] rail, int[][] road) {
    if (rail[0][rail.length - 1] == 1 && road[0][road.length - 1] < INF) {
        out.println(road[0][road.length - 1]);
        return;
    }
    if (road[0][road.length - 1] == 1 && rail[0][rail.length - 1] < INF) {
        out.println(rail[0][rail.length - 1]);
        return;
    }
    out.println(-1);
}

