/**
 * Determines the next move from {@code from} towards {@code to},
 * mutates {@code from} to the new position, and returns the step string
 * (e.g., "R", "L", "U", "D", "RU", …).
 */
private static String nextStep(Cell from, Cell to) {
    StringBuilder step = new StringBuilder();

    int deltaLetter = to.letter - from.letter;
    if (deltaLetter > 0) {
        step.append('R');
        from.letter++;               // move right
    } else if (deltaLetter < 0) {
        step.append('L');
        from.letter--;               // move left
    }

    int deltaDigit = to.digit - from.digit;
    if (deltaDigit > 0) {
        step.append('U');
        from.digit++;                // move up
    } else if (deltaDigit < 0) {
        step.append('D');
        from.digit--;                // move down
    }

    return step.toString();
}

