 */
private static Cell parseCell(String token) {
    int letter = "abcdefgh".indexOf(token.substring(0, 1).toLowerCase()) + 1;
    int digit = Integer.parseInt(token.substring(1, 2));
    return new Cell(letter, digit);
}

/**
 * Moves {@code from} one square toward {@code to} and returns the textual step.
 * The method mutates {@code from}.
 */
private static String nextStep(Cell from, Cell to) {
    StringBuilder step = new StringBuilder();

    if (to.letter > from.letter) {
        step.append("R");
        from.letter++;
    } else if (to.letter < from.letter) {
        step.append("L");
        from.letter--;
    }

    if (to.digit > from.digit) {
        step.append("U");
        from.digit++;
    } else if (to.digit < from.digit) {
        step.append("D");
        from.digit--;
    }

    return step.toString();
}

