/* Extracted helpers */

private static Cell parseCell(String token) {
    // token format: a single letter a‑h followed by a digit 1‑8, e.g. "e2"
    if (token == null || token.length() < 2) {
        throw new IllegalArgumentException("Invalid cell token: " + token);
    }
    int letter = "abcdefgh".indexOf(Character.toLowerCase(token.charAt(0))) + 1;
    int digit = Integer.parseInt(token.substring(1, 2));
    return new Cell(letter, digit);
}

private static boolean cellsEqual(Cell a, Cell b) {
    return a.digit == b.digit && a.letter == b.letter;
}

/**
 * Computes the direction string for a single move from {@code start} towards {@code end}
 * and updates {@code start} so that it reflects the moved position.
 *
 * Horizontal move:
 *   R – move right (letter +1)
 *   L – move left  (letter -1)
 *
 * Vertical move:
 *   U – move up    (digit  +1)
 *   D – move down  (digit  -1)
 *
 * The returned string may contain a horizontal component, a vertical component,
 * both, or be empty if {@code start} already equals {@code end}.
 */
private static String computeStep(Cell start, Cell end) {
    StringBuilder step = new StringBuilder();

    if (end.letter > start.letter) {
        step.append('R');
        start.letter++;
    } else if (end.letter < start.letter) {
        step.append('L');
        start.letter--;
    }

    if (end.digit > start.digit) {
        step.append('U');
        start.digit++;
    } else if (end.digit < start.digit) {
        step.append('D');
        start.digit--;
    }

    return step.toString();
}

