/**
 * Walks through the two sorted arrays {@code a} and {@code b} and records
 * all pairs (i, j) (1‑based) such that {@code a[i‑1] - x ≤ b[j‑1] ≤ a[i‑1] + y}.
 * The method uses guard clauses to keep the control flow flat.
 */
private void collectMatches(int[] a, int[] b, int x, int y,
                            List<Integer> u, List<Integer> v) {
    int i = 0, j = 0;
    while (i < a.length && j < b.length) {
        int ai = a[i];
        int bj = b[j];

        // b[j] is too small → advance j
        if (bj < ai - x) {
            j++;
            continue;
        }

        // b[j] is too large → advance i
        if (bj > ai + y) {
            i++;
            continue;
        }

        // Match found: store 1‑based indices
        i++;
        j++;
        u.add(i);
        v.add(j);
    }
}

