static long solve(int l, int r, int lc, int rc) throws Exception {
    // Guard‑clauses for base cases
    if (l > r) {
        return 1L;
    }
    if (l == r) {
        System.out.println(l);
        throw new Exception("Impossible");
    }
    if (dp[l][r][lc][rc] != -1) {
        return dp[l][r][lc][rc];
    }

    long ret = 0L;
    int curr = arr[l];

    // Sum contributions for i = 0 and i = 1
    for (int i = 0; i <= 1; i++) {
        ret = (ret + contribution(i, l, curr, r, lc, rc)) % mod;
    }

    dp[l][r][lc][rc] = ret;
    return ret;
}

/**
 * Computes the combined contribution for a specific choice of {@code i}.
 * The method encapsulates the two conditional branches that were previously
 * inside the loop of {@code solve}.
 */
private static long contribution(int i, int l, int curr, int r, int lc, int rc) throws Exception {
    long sum = 0L;

    // First branch: i must differ from left colour
    if (i != lc) {
        long left = solve(l + 1, curr - 1, i, 2);
        long right = solve(curr + 1, r, 2, rc);
        long now = (left * right) % mod;
        sum = (sum + now) % mod;
    }

    // Second branch: either there is room on the right side or i differs from right colour
    if ((curr + 1 <= r) || i != rc) {
        long left = solve(l + 1, curr - 1, 2, i);
        long right = solve(curr + 1, r, i, rc);
        long now = (left * right) % mod;
        sum = (sum + now) % mod;
    }

    return sum;
}

