/**
 * Returns true if the target (x2, y2) can be reached within {@code steps}
 * starting from (x1, y1) using the repeating command sequence {@code cmds}.
 */
private static boolean canReachInSteps(long steps, long x1, long y1,
                                       long x2, long y2, char[] cmds, long n) {
    long curX = x1;
    long curY = y1;

    for (int i = 0; i < n; i++) {
        long op = steps / n + (i < steps % n ? 1 : 0);
        switch (cmds[i]) {
            case 'U' -> curY += op;
            case 'D' -> curY -= op;
            case 'L' -> curX -= op;
            default  -> curX += op; // 'R'
        }
    }

    long distance = Math.abs(curX - x2) + Math.abs(curY - y2);
    return distance <= steps;
}

public void solve(int testNumber, InputReader in, PrintWriter out) {
    long x1 = in.ni(), y1 = in.ni(), x2 = in.ni(), y2 = in.ni();
    long n = in.ni();
    char[] c = in.next().toCharArray();

    final long INF = (long) 2e18;
    long low = 0, high = INF;
    int iterations = 100;                     // guarantees convergence for 64‑bit range

    while (iterations-- > 0) {
        long mid = (low + high) >>> 1;        // same as (low + high) / 2 without overflow risk
        if (canReach(mid, x1, y1, x2, y2, n, c)) {
            high = mid;
        } else {
            low = mid;
        }
    }

    if (high == INF) {
        out.println(-1);
    } else {
        out.println(high);
    }
}

/**
 * Returns true if the target (x2, y2) can be reached within {@code steps}
 * moves following the instruction pattern {@code c}.
 */
private boolean canReach(long steps, long x1, long y1, long x2, long y2,
                         long n, char[] c) {
    long[] pos = computeFinalPosition(steps, x1, y1, n, c);
    long dist = Math.abs(pos[0] - x2) + Math.abs(pos[1] - y2);
    return dist <= steps;
}

/**
 * Simulates the robot for {@code steps} total moves.
 * The instruction string {@code c} (length {@code n}) repeats,
 * each character receiving either ⌈steps/n⌉ or ⌊steps/n⌋ moves.
 *
 * @return array {@code [finalX, finalY]}
 */
private long[] computeFinalPosition(long steps, long startX, long startY,
                                    long n, char[] c) {
    long x = startX;
    long y = startY;
    long base = steps / n;                     // moves each instruction gets at least
    long extra = steps % n;                    // first {@code extra} instructions get one more

    for (int i = 0; i < n; i++) {
        long move = base + (i < extra ? 1 : 0);
        switch (c[i]) {
            case 'U' -> y += move;
            case 'D' -> y -= move;
            case 'L' -> x -= move;
            default  -> x += move;            // 'R'
        }
    }
    return new long[]{x, y};
}

