/** Returns true if any element violates the “value parity ≠ index parity” rule. */
private static boolean hasInvalidParity(int[] a) {
    for (int i = 0; i < a.length; i++) {
        if (a[i] % 2 == i % 2) {
            return true;
        }
    }
    return false;
}

/** Executes the series of swaps that transform the array into the identity permutation. */
private static void performSwaps(int n, int[] a) {
    for (int biggerVal = n, smallerVal = n - 1, gotoPos = n - 1;
         biggerVal > 1;
         biggerVal -= 2, smallerVal -= 2, gotoPos -= 2) {

        swap(indof(biggerVal, a), a);
        swap(indof(smallerVal, a) - 1, a);
        swap(indof(smallerVal, a) + 1, a);
        swap(2, a);
        swap(gotoPos, a);
    }
}

/** Checks that the array now equals [1, 2, … , n]; throws if not. */
private static void verifyIdentityPermutation(int[] a) {
    for (int i = 0; i < a.length; i++) {
        if (a[i] != i + 1) {
            throw null;
        }
    }
}

