/* ---------- helper methods ---------- */

private static long computeMaxProduct(List<Long> posAsc,
                                      List<Long> negAsc,
                                      boolean hasZero) {
    long best = hasZero ? 0 : Long.MIN_VALUE;

    // descending views (largest first)
    List<Long> posDesc = new ArrayList<>(posAsc);
    Collections.reverse(posDesc);
    List<Long> negDesc = new ArrayList<>(negAsc);
    Collections.reverse(negDesc);

    // 1) 2 smallest negatives, 3 largest positives
    best = Math.max(best, tryProduct(negAsc, 0, 2, posDesc, 0, 3));

    // 2) 4 smallest negatives, 1 largest positive
    best = Math.max(best, tryProduct(negAsc, 0, 4, posDesc, 0, 1));

    // 3) 5 largest positives
    best = Math.max(best, tryProduct(posDesc, 0, 5));

    // if we already have a non‑negative answer, it is maximal (original logic)
    if (best >= 0) {
        return best;
    }

    // 4) largest negative, 4 smallest positives
    best = Math.max(best, tryProduct(negDesc, 0, 1, posAsc, 0, 4));

    // 5) 3 largest negatives, 2 smallest positives
    best = Math.max(best, tryProduct(negDesc, 0, 3, posAsc, 0, 2));

    // 6) 5 largest negatives
    best = Math.max(best, tryProduct(negDesc, 0, 5));

    return best;
}

/* tries to multiply `count` elements starting at `start` in a single list.
   Returns Long.MIN_VALUE if the list does not contain enough elements. */
private static long tryProduct(List<Long> list, int start, int count) {
    if (list.size() < start + count) {
        return Long.MIN_VALUE;
    }
    long prod = 1L;
    for (int i = 0; i < count; i++) {
        prod *= list.get(start + i);
    }
    return prod;
}

/* tries to multiply `count1` elements from `list1` and `count2` elements from `list2`.
   Returns Long.MIN_VALUE if either list is too short. */
private static long tryProduct(List<Long> list1, int start1, int count1,
                               List<Long> list2, int start2, int count2) {
    if (list1.size() < start1 + count1 || list2.size() < start2 + count2) {
        return Long.MIN_VALUE;
    }
    long prod = 1L;
    for (int i = 0; i < count1; i++) {
        prod *= list1.get(start1 + i);
    }
    for (int i = 0; i < count2; i++) {
        prod *= list2.get(start2 + i);
    }
    return prod;
}

public void solve(int testNumber, Scanner in, PrintWriter out) {
    int t = in.nextInt();
    while (t-- > 0) {
        int n = in.nextInt();
        List<Long> pos = new ArrayList<>();
        List<Long> neg = new ArrayList<>();
        boolean zeroExists = false;

        for (int i = 0; i < n; i++) {
            long v = in.nextLong();
            if (v > 0) {
                pos.add(v);
            } else if (v == 0) {
                zeroExists = true;
            } else {
                neg.add(v);
            }
        }

        // sort once: positives descending, negatives ascending (most negative first)
        pos.sort(Collections.reverseOrder());
        neg.sort(Long::compareTo);

        long best = zeroExists ? 0 : Long.MIN_VALUE;

        best = Math.max(best, productIfPossible(pos, 5, null, 0));          // 5 positives
        best = Math.max(best, productIfPossible(neg, 5, null, 0));          // 5 negatives
        best = Math.max(best, productIfPossible(pos, 3, neg, 2));          // 3 pos + 2 neg
        best = Math.max(best, productIfPossible(pos, 1, neg, 4));          // 1 pos + 4 neg
        best = Math.max(best, productIfPossible(pos, 4, neg, 1));          // 4 pos + 1 neg
        best = Math.max(best, productIfPossible(pos, 2, neg, 3));          // 2 pos + 3 neg

        out.println(best);
    }
}

/**
 * Returns the product of the first {@code aCount} elements of {@code a}
 * and the first {@code bCount} elements of {@code b}. If the required
 * number of elements is not available, {@link Long#MIN_VALUE} is returned.
 * The second list may be {@code null} when only one list is needed.
 */
private static long productIfPossible(List<Long> a, int aCount,
                                      List<Long> b, int bCount) {
    if (a == null || a.size() < aCount) {
        return Long.MIN_VALUE;
    }
    if (b != null && b.size() < bCount) {
        return Long.MIN_VALUE;
    }
    long prod = 1L;
    for (int i = 0; i < aCount; i++) {
        prod *= a.get(i);
    }
    if (b != null) {
        for (int i = 0; i < bCount; i++) {
            prod *= b.get(i);
        }
    }
    return prod;
}

