    for (int i = 3; g > 0 || b > 0 || r > 0; ++time, ++i) {
        int[] updated = applyDecrement(i, r, g, b);
        r = updated[0];
        g = updated[1];
        b = updated[2];
    }

    out.println(time);
}

/**
 * Decrements the appropriate colour by 2 if it is still positive.
 * The colour to consider is determined by the iteration index {@code i}:
 * <ul>
 *   <li>i % 3 == 0 → red</li>
 *   <li>i % 3 == 1 → green</li>
 *   <li>i % 3 == 2 → blue</li>
 * </ul>
 *
 * @return an int[3] containing the updated values {red, green, blue}
 */
private int[] applyDecrement(int i, int r, int g, int b) {
    switch (i % 3) {
        case 0:
            if (r > 0) {
                r -= 2;
            }
            break;
        case 1:
            if (g > 0) {
                g -= 2;
            }
            break;
        case 2:
            if (b > 0) {
                b -= 2;
            }
            break;
        default:
            // never reached
    }
    return new int[]{r, g, b};
}

