/**
 * Tries to improve the DP cell (i, j) using the pair (a[j‑1], a[j]).
 * Guard‑clauses short‑circuit the method when the pair cannot be used.
 */
private static void updateDpCell(int i, int j, int[] a, int[] even, long[][] dp) {
    // only even positions may form a valid pair
    if (j % 2 != 0) {
        return;
    }
    // there must be exactly j/2 even numbers among the first j elements
    if (even[j - 1] != j / 2) {
        return;
    }
    int diff = Math.abs(a[j] - a[j - 1]);
    // not enough budget to take this pair
    if (i < diff) {
        return;
    }
    dp[i][j] = Math.max(dp[i][j], 1 + dp[i - diff][j - 1]);
}

