                dp[i][j] = Math.max(dp[i][j],
                                    1 + dp[i - cost][j - 1]);
            }
        }
    }
    return dp;
}

/* Guard method that encapsulates the two conditions required to use the pair (j‑1, j) */
private static boolean isPairUsable(int i, int j, int[] a, int[] even) {
    return even[j - 1] == j / 2 && i >= Math.abs(a[j] - a[j - 1]);
}

