/**
 * Determines whether the current digit {@code cur} can follow the previous digit {@code prev}
 * according to the problem's rule:
 *   - if the sum is even, {@code cur} must be exactly the average;
 *   - if the sum is odd, {@code cur} must be the average rounded up.
 *
 * @param prev the previous digit
 * @param cur  the current digit
 * @return {@code true} if the pair satisfies the rule, {@code false} otherwise
 */
private boolean isConsistent(int prev, int cur) {
    int sum = prev + cur;
    int avg = sum / 2;
    if (sum % 2 == 0) {
        return avg == cur;
    } else {
        return avg + 1 == cur;
    }
}

