public static int[] palindromeRadius(String s) {
        int n=s.length();
        int[] rad=new int[n];
        for(int i=0,j=0;i<n;) {
            while(j<n && i+i-j>=0 && s.charAt(j)==s.charAt(i+i-j))j++;
            rad[i]=j-i-1;
            for(int bi=i++;i<j && rad[bi+bi-i]!=rad[bi]+bi-i;i++) {
                rad[i] = Math.min(rad[bi]+bi-i,rad[bi+bi-i]);
            }
        }
        return rad;
    }

