public static void floodFill(ChestList curr, ChestList next, int N, int M) {
    	long[][] all = new long[N][M];
    	for (int r = 0; r < all.length; r++) {
    		Arrays.fill(all[r], Long.MAX_VALUE);
    	}

    	PQElt[] arr = new PQElt[curr.size()];
    	for (int i = 0; i < curr.size(); i++) {
    		Chest u = curr.get(i);
    		arr[i] = new PQElt(u.R, u.C, u.dist);
    	}
    	Arrays.sort(arr);

    	Queue<PQElt> q = new ArrayDeque<PQElt>();
    	int idx = 1;
    	PQElt init = arr[0];
    	q.add(init);
    	all[init.R][init.C] = init.dist;
    	while (!q.isEmpty()) {
    		PQElt pqe = q.poll();
    		while (idx < arr.length && arr[idx].dist == pqe.dist) {
    			PQElt elt = arr[idx++];
    			if (elt.dist < all[elt.R][elt.C]) {
    				q.add(elt);
    			}
    		}
    		long d = pqe.dist + 1;
    		for (int i = 0; i < DR.length; i++) {
    			int r = pqe.R + DR[i];
    			int c = pqe.C + DC[i];
    			if (r >= 0 && r < N && c >= 0 && c < M && d < all[r][c]) {
    				all[r][c] = d;
    				q.add(new PQElt(r, c, d));
    			}
    		}
    	}
    	for (Chest v : next) {
    		v.dist = all[v.R][v.C];
    	}
    }

public static int getMatches(int[] S, int[] W) {
		int P = 18211;
		int N = S.length;
		int M = W.length;
		long want = 0;
		long hash = 0;
		long top = 1;
		for (int i = 0; i < M; ++i) {
			hash = (hash * P) + S[i];
			want = (want * P) + W[i];
			top *= P;
		}
		int cnt = 0;
		int end = 0;
		for (int i = 0; i + M <= N; ++i) {
			if (hash == want && i >= end && checkSubarrayEqual(S, i, W, 0, M)) {
				++cnt;
				end = i + M;
			}
			if (i + M < N) {
				hash = (hash * P) + S[i + M];
				hash -= S[i] * top;
			}
		}
		return cnt;
	}

