        cord temp = que.poll();
        for (int i = 0; i < 4; i++) {
            int r = temp.x + dx[i];
            int c = temp.y + dy[i];

            if (isTargetVisited(r, c, end, arr)) {
                flag = 0;
                break;
            }

            if (isInsideAndFree(r, c, n, m, arr)) {
                arr[r][c] = 'X';
                cord xo = new cord();
                xo.x = r;
                xo.y = c;
                que.add(xo);
            }
        }
    }

    if (flag == 0)
        System.out.println("YES");
    else
        System.out.println("NO");
}

/**
 * Checks whether the coordinates point to the destination cell that has already
 * been marked as visited ('X').
 */
private boolean isTargetVisited(int r, int c, cord end, char[][] arr) {
    return r == end.x && c == end.y && arr[r][c] == 'X';
}

/**
 * Checks that the coordinates are inside the grid bounds and refer to an
 * unvisited free cell ('.').
 */
private boolean isInsideAndFree(int r, int c, int n, int m, char[][] arr) {
    return r >= 0 && r < n && c >= 0 && c < m && arr[r][c] == '.';
}

