/**
 * Determines whether the current token should be added to the first list (a1).
 *
 * @param token the accumulated characters of the current token
 * @param isNumberFlag true if every character seen so far is a digit
 * @return true if the token represents a valid number according to the original rules
 */
private static boolean shouldAddToFirstList(StringBuilder token, boolean isNumberFlag) {
    if (!isNumberFlag) {
        return false;
    }
    int len = token.length();
    if (len == 0) {
        return false;
    }
    // Leading zero is allowed only for the single‑character token "0"
    return token.charAt(0) != '0' || len == 1;
}

