					start = new Pair(i,j,0);
				else if(arr[j]=='E')
					end = new Pair(i,j,0);
				else
					mat[i][j] = arr[j]=='T'?-1:arr[j]-'0';
			}
		}

		PriorityQueue<Pair> queue = new PriorityQueue<Pair>(new Comparator<Pair>(){
			public int compare(Pair a, Pair b){
				return a.d-b.d;
			}
		});

		queue.add(end);
		while(queue.size()>0){
			Pair cur = queue.remove();
			int i=cur.x, j=cur.y;
			if(i<0 || j<0 || i>=n || j>=m || mat[i][j]==-1)
				continue;
			if(dist[i][j] != -1)
				continue;

			dist[i][j] = cur.d;
			queue.add(new Pair(i-1, j, cur.d+1));
			queue.add(new Pair(i, j-1, cur.d+1));
			queue.add(new Pair(i, j+1, cur.d+1));
			queue.add(new Pair(i+1, j, cur.d+1));
		}

