/**
 * Returns true when the current multiset of frequencies satisfies any of the
 * stopping conditions used by the original algorithm.
 */
private boolean isOkState(TreeMap<Integer, Integer> c) {
    // only one distinct frequency, and it occurs exactly once
    if (c.size() == 1 && c.firstEntry().getValue() == 1) {
        return true;
    }
    // two distinct frequencies that are consecutive numbers, and the larger one occurs once
    if (c.size() == 2 && c.firstKey() + 1 == c.lastKey() && c.lastEntry().getValue() == 1) {
        return true;
    }
    // two distinct frequencies where the smaller is 1 and occurs once
    if (c.size() == 2 && c.firstKey() == 1 && c.firstEntry().getValue() == 1) {
        return true;
    }
    // only one distinct frequency and it is the value 1
    if (c.size() == 1 && c.firstEntry().getKey() == 1) {
        return true;
    }
    return false;
}

