/**
 * Solves a single test case.
 *
 * @param br the input reader positioned at the first matrix row
 * @param m  number of rows
 * @param n  number of columns
 * @return the answer for this test case
 * @throws IOException if reading fails
 */
private static int solveTestCase(BufferedReader br, int m, int n) throws IOException {
    int[][] arr = new int[m][n];
    int[] colMax = new int[n];               // defaults to 0

    // read matrix and compute per‑column maximums
    for (int i = 0; i < m; i++) {
        StringTokenizer rowTok = new StringTokenizer(br.readLine());
        arr[i] = new int[n];
        processRow(rowTok, arr[i], colMax);
    }

    // minimum of column maxima
    int ans = colMax[0];
    for (int i = 1; i < n; i++) {
        ans = Math.min(ans, colMax[i]);
    }

    // guard clause – if condition satisfied we are done
    if (m <= n - 1) {
        return ans;
    }

    // otherwise compute the largest second‑largest element among rows
    int secondLargestOverall = 0;
    for (int i = 0; i < m; i++) {
        Arrays.sort(arr[i]);                       // ascending
        int secondLargestInRow = arr[i][n - 2];    // second from end
        secondLargestOverall = Math.max(secondLargestOverall, secondLargestInRow);
    }

    return Math.min(ans, secondLargestOverall);
}

/**
 * Fills a row of the matrix and updates the column‑wise maxima.
 *
 * @param rowTokens tokeniser for the current input line
 * @param row       the array that will hold the row values
 * @param colMax    current maximum for each column (updated in‑place)
 */
private static void processRow(StringTokenizer rowTokens, int[] row, int[] colMax) {
    for (int j = 0; j < row.length; j++) {
        int value = Integer.parseInt(rowTokens.nextToken());
        row[j] = value;
        if (value > colMax[j]) {
            colMax[j] = value;
        }
    }
}

