}

private static void processTestCase(BufferedReader br, PrintWriter out) throws IOException {
    // skip the possibly empty line separating test cases
    br.readLine();

    StringTokenizer st = new StringTokenizer(br.readLine());
    int m = Integer.parseInt(st.nextToken());
    int n = Integer.parseInt(st.nextToken());

    int[][] matrix = new int[m][n];
    int[] maxInColumn = new int[n];
    readMatrixAndTrackColumnMaximums(br, matrix, maxInColumn, m, n);

    int answer = minValue(maxInColumn, n);

    // guard clause – no need to look at second‑largest values
    if (m <= n - 1) {
        out.println(answer);
        return;
    }

    int secondLargest = overallSecondLargest(matrix, m, n);
    answer = Math.min(secondLargest, answer);
    out.println(answer);
}

private static void readMatrixAndTrackColumnMaximums(BufferedReader br,
                                                     int[][] matrix,
                                                     int[] maxInColumn,
                                                     int rows,
                                                     int cols) throws IOException {
    for (int i = 0; i < rows; i++) {
        StringTokenizer st = new StringTokenizer(br.readLine());
        for (int j = 0; j < cols; j++) {
            int value = Integer.parseInt(st.nextToken());
            matrix[i][j] = value;
            if (maxInColumn[j] < value) {
                maxInColumn[j] = value;
            }
        }
    }
}

private static int minValue(int[] values, int length) {
    int min = values[0];
    for (int i = 1; i < length; i++) {
        if (values[i] < min) {
            min = values[i];
        }
    }
    return min;
}

private static int overallSecondLargest(int[][] matrix, int rows, int cols) {
    int secondLargest = 0;
    for (int i = 0; i < rows; i++) {
        Arrays.sort(matrix[i]);               // row is sorted ascending
        int rowSecond = matrix[i][cols - 2]; // second largest in this row
        if (rowSecond > secondLargest) {
            secondLargest = rowSecond;
        }
    }
    return secondLargest;
}

