    BufferedReader bufferedReader = new BufferedReader(new InputStreamReader(System.in));
    PrintWriter out = new PrintWriter(new BufferedOutputStream(System.out));
    int T = Integer.parseInt(bufferedReader.readLine());

    while (T-- > 0) {
        // skip the empty line that separates test cases
        bufferedReader.readLine();

        StringTokenizer st = new StringTokenizer(bufferedReader.readLine());
        int m = Integer.parseInt(st.nextToken());
        int n = Integer.parseInt(st.nextToken());

        int[] maxPerColumn = new int[n];
        int[][] matrix = readMatrixAndTrackColumnMax(bufferedReader, m, n, maxPerColumn);

        int ans = minOfArray(maxPerColumn);
        if (m <= n - 1) {
            out.println(ans);
            continue;
        }

        int secLargest = maxRowSecondLargest(matrix);
        ans = Math.min(secLargest, ans);
        out.println(ans);
    }
    out.close();
}

/** Reads the m×n matrix, fills it and updates maxPerColumn with the column‑wise maxima. */
private static int[][] readMatrixAndTrackColumnMax(BufferedReader br, int m, int n, int[] maxPerColumn)
        throws IOException {
    int[][] arr = new int[m][n];
    for (int i = 0; i < m; i++) {
        StringTokenizer st = new StringTokenizer(br.readLine());
        for (int j = 0; j < n; j++) {
            arr[i][j] = Integer.parseInt(st.nextToken());
            if (maxPerColumn[j] < arr[i][j]) {
                maxPerColumn[j] = arr[i][j];
            }
        }
    }
    return arr;
}

/** Returns the smallest value in an int array. */
private static int minOfArray(int[] values) {
    int min = values[0];
    for (int i = 1; i < values.length; i++) {
        min = Math.min(min, values[i]);
    }
    return min;
}

/** For each row finds its second largest element and returns the maximum of those values. */
private static int maxRowSecondLargest(int[][] matrix) {
    int best = 0;
    for (int[] row : matrix) {
        Arrays.sort(row);
        int secondLargest = row[row.length - 2];
        if (secondLargest > best) {
            best = secondLargest;
        }
    }
    return best;
}

