/** Adds contributions to dp[i][j][k][0] (the “0” state). */
private static void updateZero(int[][][][] dp, int i, int j, int k, int t) {
    int sum = 0;
    for (int p = k + 1; p < 4; p++) {
        sum += dp[i - 1][j][p][0];
        if (j > 0) {
            sum += dp[i - 1][j - 1][p][1];
        }
    }
    dp[i][j][k][0] += sum;
}

/** Adds contributions to dp[i][j][k][1] (the “1” state). */
private static void updateOne(int[][][][] dp, int i, int j, int k) {
    int sum = 0;
    for (int p = 0; p < k; p++) {
        sum += dp[i - 1][j][p][0] + dp[i - 1][j][p][1];
    }
    dp[i][j][k][1] += sum;
}

