/** Returns the sum of the next up‑to K cells in column {@code col}
 *  starting at row {@code startRow}. */
private int windowSum(int[][] a, int startRow, int col, int K, int n) {
    int sum = 0;
    int limit = Math.min(startRow + K, n);
    for (int r = startRow; r < limit; ++r) {
