    int replace = 0;

    for (int col = 0; col < m; ++col) {
        int[] result = evaluateColumn(a, col, K);
        ans += result[0];      // best score for this column
        replace += result[1]; // number of 1's before the chosen window
    }

    out.println(ans + " " + replace);
}

/**
 * Evaluates a single column and returns an array where:
 * result[0] = maximum number of 1's in any window of length ≤ K that starts at a 1,
 * result[1] = count of 1's that appear before the window achieving that maximum.
 */
private static int[] evaluateColumn(int[][] a, int col, int K) {
    int bestScore = 0;
    int bestCount = 0;
    int curCount = 0;
    int n = a.length;

    for (int i = 0; i < n; ++i) {
        if (a[i][col] != 1) {
            continue;               // guard clause – reduces nesting
        }
        int tot = windowSum(a, col, i, K, n);
        if (tot > bestScore) {
            bestScore = tot;
            bestCount = curCount;
        }
        ++curCount;
    }
    return new int[]{bestScore, bestCount};
}

/**
 * Returns the sum of entries in column {@code col} from row {@code start}
 * up to {@code start + K - 1}, bounded by the matrix height {@code n}.
 */
private static int windowSum(int[][] a, int col, int start, int K, int n) {
    int sum = 0;
    int end = Math.min(start + K, n);
    for (int j = start; j < end; ++j) {
        sum += a[j][col];
    }
    return sum;
}

