        out.printLine(ans);
    }
}

/**
 * Computes the answer for a single query.
 *
 * The algorithm slides a window of length {@code k} over the string {@code s}.
 * It maintains:
 *   dCnt – number of 'D' characters inside the current window,
 *   mCnt – number of 'M' characters inside the current window,
 *   dmCnt – number of ordered pairs (D before M) inside the current window.
 *
 * For every 'C' encountered, the current {@code dmCnt} is added to the result.
 *
 * @param k window size
 * @param s input string consisting of characters D, M, C
 * @param n length of {@code s}
 * @return the computed answer for this query
 */
private long computeAnswer(int k, String s, int n) {
    long ans = 0;
    long dCnt = 0;
    long mCnt = 0;
    long dmCnt = 0;

    for (int j = 0; j < n; j++) {
        // Remove the character that falls out of the sliding window.
        if (j >= k) {
            char outChar = s.charAt(j - k);
            if (outChar == 'D') {
                dCnt--;
                dmCnt -= mCnt;   // all pairs that used this D are removed
            } else if (outChar == 'M') {
                mCnt--;
            }
        }

        // Add the current character to the window and update counters.
        char cur = s.charAt(j);
        if (cur == 'D') {
            dCnt++;
        } else if (cur == 'M') {
            mCnt++;
            dmCnt += dCnt;       // each existing D forms a new (D,M) pair
        } else if (cur == 'C') {
            ans += dmCnt;        // each existing (D,M) pair contributes to answer
        }
    }
    return ans;
}

