/**
 * Tries to use the first {@code pre} elements as the target sum.
 * Returns the resulting count if the whole array can be partitioned
 * into consecutive windows of that sum, otherwise returns {@code null}.
 */
private static Integer evaluatePrefix(int[] nums, int pre) {
    int n = nums.length;

    // Compute target sum of the prefix.
    int target = 0;
    for (int i = 0; i < pre; i++) {
        target += nums[i];
    }

    int count = pre - 1; // elements already considered in the prefix
    int i = pre;         // start scanning after the prefix

    while (i < n) {
        int windowSum = 0;
        // Build the next window until the sum reaches or exceeds target.
        while (i < n && windowSum < target) {
            windowSum += nums[i];
            count++;
            i++;
        }
        // Guard clause: if we overshoot the target, this prefix fails.
        if (windowSum != target) {
            return null;
        }
        // Adjust count because the last increment belongs to the next window start.
        count--;
    }
    return count;
}

