        for (int pre = 1; pre <= n; pre++) {
            target += nums[pre - 1];
            int[] countHolder = new int[]{pre - 1}; // mutable count

            if (canFormWithTarget(pre, target, nums, countHolder)) {
                System.out.println(countHolder[0]);
                break;
