    }

    Map<Integer, List<int[]>> data = buildComponentData(n, wa, wb, ds);

    int[][] ans = new int[data.size() + 1][w + 1];
    int cur = 0;
    for (List<int[]> component : data.values()) {
        cur++;
        ans[cur] = Arrays.copyOf(ans[cur - 1], w + 1);   // copy previous DP row
        applyComponentDp(component, ans, cur, w);
        propagateBest(ans[cur], w);
    }

    out.println(ans[data.size()][w]);
}

/**
 * Builds a map from component root to a list that starts with the summed
 * (wa, wb) of the component followed by each vertex's own (wa, wb).
 */
private static Map<Integer, List<int[]>> buildComponentData(int n, int[] wa, int[] wb, DS ds) {
    Map<Integer, List<int[]>> data = new HashMap<>();
    for (int i = 0; i < n; i++) {
        int root = ds.r(i);
        List<int[]> list = data.computeIfAbsent(root, k -> {
            List<int[]> l = new ArrayList<>();
            l.add(new int[2]);            // placeholder for the aggregated sums
            return l;
        });

        int[] aggregate = list.get(0);
        aggregate[0] += wa[i];
        aggregate[1] += wb[i];
        list.add(new int[] { wa[i], wb[i] });
    }
    return data;
}

/**
 * Updates the DP table for a single component.
 * The table row {@code cur} is updated using the previous row {@code cur‑1}.
 */
private static void applyComponentDp(List<int[]> component, int[][] dp, int cur, int capacity) {
    int[] prev = dp[cur - 1];
    int[] curRow = dp[cur];

    for (int[] item : component) {
        int weight = item[0];
        int value  = item[1];
        for (int used = 0; used <= capacity; used++) {
            // guard clause – stop when adding the current item would exceed capacity
            if (used + weight > capacity) {
                break;
            }
            int candidate = prev[used] + value;
            if (candidate > curRow[used + weight]) {
                curRow[used + weight] = candidate;
            }
        }
    }
}

/**
 * Ensures that for every capacity the DP table stores the best value achievable
 * with **at most** that capacity (i.e., makes the row non‑decreasing).
 */
private static void propagateBest(int[] row, int capacity) {
    for (int i = 1; i <= capacity; i++) {
        if (row[i - 1] > row[i]) {
            row[i] = row[i - 1];
        }
    }
}

