    int color = colors[start - 1];
    Stack<Integer> stack = new Stack<>();
    stack.push(start);

    Set<Integer> visited = new HashSet<>();
    visited.add(start);

    while (!stack.isEmpty()) {
        int node = stack.pop();
        for (int neighbor : tree.get(node - 1)) {
            // Guard: skip the edge we came from
            if (neighbor == prev) {
                continue;
            }
            // Guard: mismatched color – abort search
            if (colors[neighbor - 1] != color) {
                return -1;
            }
            // If not visited, add to visited set and schedule for processing
            if (visited.add(neighbor)) {
                stack.push(neighbor);
            }
        }
    }
    return color;
}

