/**
 * Checks whether the substring of length {@code l} starting at {@code x}
 * can be mapped character‑wise onto the substring starting at {@code y}
 * using the hashing technique described in the original solution.
 *
 * @return {@code true} if the mapping exists, {@code false} otherwise.
 */
private boolean isQueryOk(int x, int y, int l,
                          CharHash hashed31, CharHash hashed61) {
    boolean[] used = new boolean[27];   // tracks characters already matched on the right side

    for (char c = 'a'; c <= 'z'; c++) {
        int xHash31 = hashed31.hash(x, x + l - 1, c);
        int xHash61 = hashed61.hash(x, x + l - 1, c);

        if (!canMatchChar(xHash31, xHash61, y, l, hashed31, hashed61, used)) {
            return false;               // guard clause – no need to continue looping
        }
    }
    return true;
}

/**
 * Tries to find a character {@code d} (different from those already used)
 * such that the hashed values of the two substrings match.
 *
 * @return {@code true} if a matching character is found, {@code false} otherwise.
 */
private boolean canMatchChar(int xHash31, int xHash61,
                             int y, int l,
                             CharHash hashed31, CharHash hashed61,
                             boolean[] used) {
    for (char d = 'a'; d <= 'z' + 1; d++) {
        int idx = d - 'a';
        if (used[idx]) {
            continue;
        }
        int yHash31 = hashed31.hash(y, y + l - 1, d);
        int yHash61 = hashed61.hash(y, y + l - 1, d);
        if (xHash31 == yHash31 && xHash61 == yHash61) {
            used[idx] = true;
            return true;
        }
    }
    return false;
}

