private static int minThreeForValue(int a, int ones, int twos) {
    int best = INF;
    for (int i = 0; i <= ones; i++) {
        for (int j = 0; j <= twos; j++) {
            int remainder = a - i - (2 * j);
            // guard clause – skip impossible or non‑divisible remainders
            if (remainder < 0 || remainder % 3 != 0) {
                continue;
