 * and returns the updated move counter.
 */
private static int swapAndRecord(int[][] table,
                                 int r1, int c1, int r2, int c2,
                                 int[] x1, int[] y1, int[] x2, int[] y2,
                                 int moveIdx) {
    int tmp = table[r1][c1];
    table[r1][c1] = table[r2][c2];
    table[r2][c2] = tmp;

    x1[moveIdx] = r1 + 1;
    y1[moveIdx] = c1 + 1;
    x2[moveIdx] = r2 + 1;
    y2[moveIdx] = c2 + 1;
    return moveIdx + 1;
}

