void realSolve() {
    int n = in.nextInt();
    int h = in.nextInt();
    long[][] dp = new long[n + 1][n + 1];
    dp[1][1] = 1;
    dp[0][0] = 1;

    for (int cn = 2; cn <= n; cn++) {
        for (int curH = 1; curH <= n; curH++) {
            for (int id = 1; id <= cn; id++) {
                dp[cn][curH] += contribution(cn, curH, id, dp);
            }
        }
    }

    long res = 0;
    for (int hh = h; hh <= n; hh++) {
        res += dp[n][hh];
    }
    out.println(res);
}

/**
 * Computes the value that has to be added to dp[cn][curH] for the given
 * split position {@code id}. All the heavy inner loops are isolated here,
 * keeping the nesting depth of {@code realSolve} low.
 */
private static long contribution(int cn, int curH, int id, long[][] dp) {
    long v1 = 0, v2 = 0;
    // sum over heights smaller than curH
    for (int h1 = 0; h1 <= curH - 1; h1++) {
        v1 += dp[id - 1][h1];
        v2 += dp[cn - id][h1];
    }
    long term1 = v1 * dp[cn - id][curH - 1];
    long term2 = v2 * dp[id - 1][curH - 1];
    long overlap = dp[cn - id][curH - 1] * dp[id - 1][curH - 1];
    return term1 + term2 - overlap;
}

