public void solve(int testNumber, InputReader in, PrintWriter out) {
    int m = in.nextInt();
    int t = in.nextInt();
    int r = in.nextInt();

    int[] w = new int[m];
    for (int i = 0; i < m; i++) {
        w[i] = in.nextInt() + 500;
    }

    int[] timeLine = new int[1001];
    int res = 0;

    for (int i = 0; i < m; i++) {
        // Guard clause: already enough coverage → nothing to do
        if (timeLine[w[i]] >= r) {
            continue;
        }

        // Need additional repairs
        int required = r - timeLine[w[i]];
        res += applyRepairs(w[i], required, timeLine, t);

        // Verify that the repairs were sufficient
        if (timeLine[w[i]] < r) {
            out.println(-1);
            return;
        }
    }

    out.println(res);
}

/**
 * Adds the minimum number of repairs starting at {@code start} until {@code needed}
 * additional coverage is provided. Each repair increments the coverage of the interval
 * [start‑t, start+t) (capped at index 901). Returns the number of repairs performed.
 */
private int applyRepairs(int start, int needed, int[] timeLine, int t) {
    int added = 0;
    int j = start;

    while (needed > 0) {
        int left = j;
        int right = Math.min(901, left + t);
        for (int k = left; k < right; k++) {
            timeLine[k]++;
        }
        added++;
        j--;
        needed--;
    }
    return added;
}

