/**
 * Determines whether adding an edge between i and j would keep the shortest
 * path length from S to T unchanged.
 */
private static boolean shouldCount(int i, int j,
                                   int[] S_BFS, int[] T_BFS,
                                   int targetDist) {
    int viaItoJ = S_BFS[i] + 1 + T_BFS[j];
    int viaJtoI = S_BFS[j] + 1 + T_BFS[i];
    return viaItoJ >= targetDist && viaJtoI >= targetDist;
}

