/**
 * Updates dp[i][k] using the transition from position i+1 with orientation l.
 * Guard clauses are used to keep the nesting depth ≤ 3.
 */
private static void processState(int i, int k, int l) {
    String cur = (k > 0) ? reversed[i] : words[i];
    String next = (l > 0) ? reversed[i + 1] : words[i + 1];

    // Guard: the lexical order must be non‑decreasing and the next state must be reachable
    if (cur.compareTo(next) > 0 || dp[i + 1][l] == -1) {
        return;
    }

    long cost = dp[i + 1][l] + ((k > 0) ? energy[i] : 0);

    if (dp[i][k] == -1) {
        dp[i][k] = cost;
    } else {
        dp[i][k] = Math.min(dp[i][k], cost);
    }
}

