/**
 * Returns the distance between the 'S' and the 'G' characters in the string.
 * Positive value means 'S' is to the right of 'G'.
 */
private int computeDifference(String s, int m) {
    int gPos = -1;
    int sPos = -1;
    for (int k = 0; k < m; k++) {
        char ch = s.charAt(k);
        if (ch == 'G') {
            gPos = k;
        } else if (ch == 'S') {
            sPos = k;
        }
        // Both positions found – no need to continue scanning
        if (gPos != -1 && sPos != -1) {
            break;
        }
    }
    return sPos - gPos;
