/**
 * Searches for an m such that sqr(n) - sqr(n/m) == x.
 * If found, prints "n m" and returns true.
 * Otherwise returns false.
 */
private boolean findAndPrint(int n, int x) {
    int l = 1, h = n;

    while (l <= h) {
        int m = (l + h) >>> 1;
        int v = sqr(n) - sqr(n / m);

        if (v < x) {
            l = m + 1;
        } else if (v > x) {
            h = m - 1;
        } else {
            println(n + " " + m);
            return true;
        }
    }
    return false;
}

