/**
 * Decreases the values starting from position {@code start} by {@code amount}
 * using the disjoint‑set structure {@code par} to skip exhausted indices.
 *
 * @param start   starting index (0‑based)
 * @param amount  amount to subtract
 * @param left    current remaining values per position
 * @param par     parent array for the DSU
 * @param n       size of the underlying arrays
 */
private void applyDecrement(int start, int amount, int[] left, int[] par, int n) {
    int idx = root(start, par);
    int x = amount;

    while (idx < n && x > 0) {
        if (left[idx] > x) {
            left[idx] -= x;
            break;                     // guard clause – operation finished
        }
        // consume the whole bucket at idx
        x -= left[idx];
        left[idx] = 0;
        par[idx] = idx + 1;           // skip this index in future finds
        idx = root(idx, par);         // move to the next alive index
    }
}

