public static void main(String[] args) {
    Scanner sc = new Scanner(System.in);
    String x = sc.nextLine();      // the text
    String st = sc.nextLine();     // start pattern
    String en = sc.nextLine();     // end pattern

    Set<Long> hash = new HashSet<>();
    int n = x.length();

    // 1️⃣ Build marker arrays: 1 → position matches start / end pattern
    int[] startMarkers = buildMarkerArray(x, st, true);
    int[] endMarkers   = buildMarkerArray(x, en, false);

    int minLength = Math.max(st.length(), en.length());

    // 2️⃣ Scan every possible start position
    for (int i = 0; i < n; i++) {
        if (startMarkers[i] != 1) {
            continue;                     // guard‑clause → reduces nesting
        }
        collectHashesFrom(i, x, endMarkers, minLength, hash);
    }

    System.out.println(hash.size());
}

/**
 * Creates a marker array for a given pattern.
 *
 * @param text      the source string
 * @param pattern   the substring to look for
 * @param isStart   true → mark the *first* character of a match,
 *                  false → mark the *last* character of a match
 * @return an int[] where a cell is 1 if the position is a match, 0 otherwise
 */
private static int[] buildMarkerArray(String text, String pattern, boolean isStart) {
    int n = text.length();
    int[] markers = new int[n];
    int limit = n - pattern.length();

    for (int i = 0; i <= limit; i++) {
        if (text.substring(i, i + pattern.length()).equals(pattern)) {
            if (isStart) {
                markers[i] = 1;                              // start of pattern
            } else {
                markers[i + pattern.length() - 1] = 1;       // end of pattern
            }
        }
    }
    return markers;
}

/**
 * Walks forward from a confirmed start position, builds a rolling hash and
 * stores it when an end‑marker is encountered and the substring length meets
 * the required minimum.
 *
 * @param start      index of the confirmed start pattern
 * @param text       the source string
 * @param endMarkers marker array for the end pattern
 * @param minLength  smallest allowed substring length
 * @param result     collection that receives the distinct hashes
 */
private static void collectHashesFrom(int start, String text, int[] endMarkers,
                                      int minLength, Set<Long> result) {
    long hash = 0;
    for (int j = start; j < text.length(); j++) {
        hash = hash * 31 + (text.charAt(j) - 'a' + 1);   // rolling hash

        if (endMarkers[j] != 1) {
            continue;                                 // not an end → next char
        }

        int length = j - start + 1;
        if (length >= minLength) {
            result.add(hash);
        }
    }
}

