}

/* Marks every index where the substring starting at that index equals `st`. */
private static void markStartPositions(String text, String start, int[] startMark) {
    int limit = text.length() - start.length();
    for (int i = 0; i <= limit; i++) {
        if (text.substring(i, i + start.length()).equals(start)) {
            startMark[i] = 1;
        }
    }
}

/* Marks the index of the last character of each occurrence of `en`. */
private static void markEndPositions(String text, String end, int[] endMark) {
    int limit = text.length() - end.length();
    for (int i = 0; i <= limit; i++) {
        if (text.substring(i, i + end.length()).equals(end)) {
            endMark[i + end.length() - 1] = 1;
        }
    }
}

/* Generates rolling‑hash values for substrings that start at `startIdx`,
   end at a position marked in `endMark`, and satisfy the length constraint. */
private static void collectHashes(int startIdx,
                                  String text,
                                  int[] endMark,
                                  int minLen,
                                  Set<Long> result) {
    long hash = 0L;
    for (int j = startIdx; j < text.length(); j++) {
        hash = hash * 31 + (text.charAt(j) - 'a' + 1);

        if (endMark[j] != 1) {
            continue;               // guard clause – not an end position
        }

        int sz = j - startIdx + 1;
        if (sz < minLen) {
            continue;               // guard clause – too short
        }

        result.add(hash);
    }
}

