/**
 * Returns the maximum length of a substring that can be turned into the
 * character represented by {@code targetIdx} after changing at most
 * {@code maxReplacements} other characters.
 */
private static int maxLengthWithReplacements(char[] s, int targetIdx, int maxReplacements) {
    int left = 0;
    int otherChars = 0;
    int best = 0;

    for (int right = 0; right < s.length; right++) {
        // If the current character is not the target, we need a replacement.
        if (s[right] - 'a' != targetIdx) {
            otherChars++;
            // Shrink the window until the number of needed replacements fits.
            while (otherChars > maxReplacements) {
                // Decrease the count only when we move past a non‑target character.
                otherChars -= (s[left++] - 'a' != targetIdx) ? 1 : 0;
            }
        }
        best = Math.max(best, right - left + 1);
    }
    return best;
}

