/**
 * Returns the length of the longest substring that can be turned into
 * the character whose index is {@code target} by changing at most
 * {@code maxOther} other characters.
 */
private int maxSubstringLength(char[] s, int target, int maxOther) {
    int n = s.length;
    int left = 0;
    int otherCount = 0;
    int best = 0;

    for (int right = 0; right < n; right++) {
        if (s[right] - 'a' != target) {
            otherCount++;
        }

        // shrink window while we exceed the allowed number of other chars
        while (otherCount > maxOther) {
            if (s[left] - 'a' != target) {
                otherCount--;
            }
            left++;
        }

        best = Math.max(best, right - left + 1);
    }
    return best;
}

