/**
 * Counts all sub‑rectangles whose sum of marked cells is at least {@code k}.
 */
private int countRectangles(int[][] grid, int rows, int cols, int k) {
    int total = 0;

    // fix the top row
    for (int top = 0; top < rows; top++) {
        int[] colSum = new int[cols];          // cumulative sum for each column
        // expand the bottom row
        for (int bottom = top; bottom < rows; bottom++) {
            for (int col = 0; col < cols; col++) {
                colSum[col] += grid[bottom][col];
            }
            // count column intervals whose sum >= k
            total += countSubarraysAtLeastK(colSum, k);
        }
    }
    return total;
}

/**
 * For a non‑negative integer array returns the number of contiguous sub‑arrays
 * whose sum is at least {@code k}.  Uses a two‑pointer sliding window.
 */
private int countSubarraysAtLeastK(int[] arr, int k) {
    int count = 0;
    int left = 0;
    int sum = 0;
    int n = arr.length;

    for (int right = 0; right < n; right++) {
        sum += arr[right];

        // shrink window from the left while condition is satisfied
        while (left <= right && sum >= k) {
            // all windows [left, right], [left, right+1], … , [left, n-1] are valid
            count += n - right;
            sum -= arr[left];
            left++;
        }
    }
    return count;
}

