private boolean readLINE() throws IOException {
    // Guard: no data to read at all
    if ($readCount == EOF) {
        return false;
    }

    itr = 0;                       // start filling the line buffer
    while (true) {
        // Scan the current buffer for a line‐feed
        while ($index < $readCount) {
            // Guard: line terminator found
            if (buffer[$index] == NL) {
                $index++;          // skip the NL character
                return true;
            }

            // Ensure there is room in the line buffer
            if (itr == cBuff.length) {
                inc();
            }
            cBuff[itr++] = (char) buffer[$index++];
        }

        // Current buffer exhausted – try to read more data
        if (!fillBuffer()) {      // EOF reached
            // EOF without a trailing NL counts as a line
            return true;
        }
    }
}

/**
 * Reads the next chunk from {@code stream} into {@code buffer}.
 *
 * @return {@code true} if data was read, {@code false} if EOF was reached.
 */
private boolean fillBuffer() throws IOException {
    $index = 0;
    $readCount = stream.read(buffer);
    return $readCount != EOF;
}

