public static void main(String[] args) throws IOException {
    Scanner sc = new Scanner(System.in);
    int n = sc.nextInt();
    long W = sc.nextInt(), B = sc.nextInt(), X = sc.nextInt();

    int[] c = new int[n];
    int totalBirds = 0;                     // N in the original code
    for (int i = 0; i < n; i++) {
        totalBirds += c[i] = sc.nextInt();
    }

    int[] cost = new int[n];
    for (int i = 0; i < n; i++) {
        cost[i] = sc.nextInt();
    }

    int ans = 0;
    long[][] dp = new long[n + 1][totalBirds + 1];
    for (long[] row : dp) {
        Arrays.fill(row, -1);
    }
    for (int i = 0; i <= n; i++) {
        dp[i][0] = W;
    }

    for (int nest = 1; nest <= n; nest++) {
        for (int birds = 1; birds <= totalBirds; birds++) {
            long max = W + birds * B;
            for (int x = 0; x <= c[nest - 1] && x <= birds; x++) {
                if (tryUpdate(dp, nest, birds, x, max, cost[nest - 1], W, B, X)) {
                    ans = birds;                     // keep the largest reachable birds count
                }
            }
        }
    }

    PrintWriter pw = new PrintWriter(System.out);
    pw.println(ans);
    pw.close();
}

/**
 * Attempts to update dp[nest][birds] using {@code x} birds from the current nest.
 *
 * @return {@code true} if the dp table was updated (i.e., a feasible state was found)
 */
private static boolean tryUpdate(long[][] dp, int nest, int birds, int x, long max,
                                 int costPerBird, long W, long B, long X) {
    long prev = dp[nest - 1][birds - x];
    if (prev == -1) {
        return false;                         // guard‑clause 1
    }

    long newM = Math.min(W + (birds - x) * B, prev + X) - costPerBird * 1L * x;
    if (newM < 0) {
        return false;                         // guard‑clause 2
    }

    dp[nest][birds] = Math.max(dp[nest][birds], Math.min(newM, max));
    return true;
}

