        for (int e = n; e > s; e--) {
            segs.add(new Seg(e - s, s, e));
        }
    }
    Collections.sort(segs);

    int count = 0;
    while (!segs.isEmpty()) {
        // take the currently longest segment (last element because list is sorted)
        Seg big = segs.remove(segs.size() - 1);

        MergeResult result = tryMerge(big, segs, n);
        if (result == MergeResult.NONE || result == MergeResult.COUNTED) {
            // no merge possible OR merged segment already counted
            count++;
        }
        // else MERGED → nothing to count now; the new segment was re‑added to the list
    }

    System.out.println(count);
}

/** Result of attempting to merge a segment with the current list. */
private enum MergeResult { COUNTED, MERGED, NONE }

/**
 * Tries to merge {@code big} with a non‑overlapping segment from {@code segs}.
 * If a suitable partner is found:
 *   • a new merged segment is created;
 *   • if its length is smaller than {@code n} it is added back to {@code segs};
 *   • otherwise the merged segment is considered “counted”.
 *
 * @return {@link MergeResult#MERGED} if the new segment was added back,
 *         {@link MergeResult#COUNTED} if the merged segment should increase the count,
 *         {@link MergeResult#NONE} if no merge was possible.
 */
private static MergeResult tryMerge(Seg big, List<Seg> segs, int n) {
    for (int i = segs.size() - 1; i >= 0; i--) {
        Seg add = segs.get(i);
        // guard clause – keep only non‑overlapping segments
        if (add.s >= big.e || big.s >= add.e) {
            int s = Math.min(add.s, big.s);
            int e = Math.max(add.e, big.e);
            Seg merged = new Seg(e - s, s, e);
            segs.remove(i); // remove the partner segment

            if (merged.len < n) {
                segs.add(merged); // will be processed later
                return MergeResult.MERGED;
            } else {
                // merged segment already spans the whole range → count it now
                return MergeResult.COUNTED;
            }
        }
    }
    // no suitable partner found
    return MergeResult.NONE;
}

