/**
 * Returns the new position of {@code curr} after processing a single query.
 * If the query does not affect {@code curr}, the original value is returned.
 */
private static int applyQuery(int curr, tuple<Integer, Integer, Integer> query) {
    int type = query.getFirst();
    int left = query.getSecond();
    int right = query.getThird();

    // Guard clause: query does not cover the current position
    if (left > curr || right < curr) {
        return curr;
    }

    if (type == 1) {
        // Type‑1 query: shift left side to right side
        return (curr == left) ? right : curr - 1;
    } else {
        // Type‑2 query: reverse the segment [left, right]
        int segmentLength = right - left;
        int offset = curr - left;
        return left + (segmentLength - offset);
    }
}

