/**
 * Walks the queries backwards and determines the final index for a given starting
 * position (1‑based). The implementation uses guard clauses to keep nesting shallow.
 */
private static int resolvePosition(int startPos,
                                   ArrayList<tuple<Integer, Integer, Integer>> queries) {
    int curr = startPos;
    for (int idx = queries.size() - 1; idx >= 0; --idx) {
        tuple<Integer, Integer, Integer> q = queries.get(idx);
        int type = q.getFirst();
        int left = q.getSecond();
        int right = q.getThird();

        // Guard: query does not affect current position
        if (curr < left || curr > right) {
            continue;
        }

        // Guard: handle the two possible query types
        if (type == 1) {
            curr = applyTypeOne(curr, left, right);
        } else {
            curr = applyTypeTwo(curr, left, right);
        }
    }
    return curr;
}

/**
 * Type‑1 query: shift left inside the interval, wrapping the leftmost element to the rightmost.
 */
private static int applyTypeOne(int curr, int left, int right) {
    return (curr == left) ? right : curr - 1;
}

/**
 * Type‑2 query: reverse the interval and map the current position accordingly.
 */
private static int applyTypeTwo(int curr, int left, int right) {
    int intervalLength = right - left;
    int offset = curr - left;
    return intervalLength - offset + left;
}

