/**
 * Returns the total adjustment cost required to transform the array into an arithmetic
 * progression that starts with {@code start} and has a common difference {@code step}.
 * If any element would need an adjustment larger than 1, the candidate is invalid
 * and the method returns -1.
 */
private static int computeCost(int[] arr, int start, int step) {
    int sum = 0;
    int expected = start;
    for (int k = 1; k < arr.length; k++) {
        expected += step;
        int diff = Math.abs(arr[k] - expected);
        if (diff > 1) {
            return -1;               // guard clause – early exit on failure
        }
        sum += diff;
    }
    return sum;
}

