int bfs(int [][] graph, int root, int n) {
		Queue<Integer> q = new LinkedList<>();
		int [] dist = new int [n];
		int [] par = new int [n];
		Arrays.fill(dist, -1);
		Arrays.fill(par, -1);
		int min_dist = Integer.MAX_VALUE;

		q.add(root);
		dist[root] = 0;
		while (!q.isEmpty()) {
			int cur = q.poll();
			int len = dist[cur];
			for (int i = 0; i < n; i++) {
				if (graph[cur][i] == 1) {
					if (len > 1 && i == root) {
						min_dist = Math.min(min_dist, len + 1);
					}
					if (dist[i] < 0) {
						dist[i] = len+1;
						q.add(i);
						par[i] = cur;
					} else if (par[cur] != i) {
						min_dist = Math.min(min_dist, len + 1 + dist[i]);
					}
				}
			}
		}
		return min_dist;
	}

