/**
 * Updates dp for the state (i+1, j, l) using the current coin.
 * Guard clauses keep the nesting depth ≤ 3.
 */
private static void updateDP(int i, int j, int l, int coin) {
    int tmp1 = j - coin;
    int tmp2 = l - coin;

    // keep the previous state
    dp[i + 1][j][l] |= dp[i][j][l];

    // consider putting the coin into the first knapsack
    if (tmp1 < 0) {
        return;
    }
    dp[i + 1][j][l] |= dp[i][tmp1][l];

    // consider putting the coin into both knapsacks
    if (tmp2 >= 0) {
        dp[i + 1][j][l] |= dp[i][tmp1][tmp2];
    }
}

