}

/* DP initialisation and transition */
private static void fillDP(int n, int k) {
    dp[0][0][0] = true;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j <= k; j++) {
            for (int l = 0; l <= k; l++) {
                updateDP(i, j, l);
            }
        }
    }
}

/* One DP state update – nesting depth ≤ 2 */
private static void updateDP(int i, int j, int l) {
    int coin = coins[i];
    int tmp1 = j - coin;
    int tmp2 = l - coin;

    if (tmp1 >= 0) {
        dp[i + 1][j][l] |= dp[i][tmp1][l];
        if (tmp2 >= 0) {
            dp[i + 1][j][l] |= dp[i][tmp1][tmp2];
        }
    }
    dp[i + 1][j][l] |= dp[i][j][l];
}

/* Count reachable sums and mark them in 'res' */
private static int computeResultCount(int n, int k) {
    int cnt = 1;                     // sum 0 is always reachable
    for (int i = 0; i < k; i++) {
        for (int j = 0; j < n + 1; j++) {
            if (dp[j][k][i] && !res[i]) {
                res[i] = true;
                cnt++;
            }
        }
    }
    res[k] = true;                  // sum k is always reachable
    return cnt;
}

/* Print all reachable sums */
private static void printResults(PrintWriter out, int k) {
    for (int i = 0; i <= k; i++) {
