/**
 * Computes the value for dp[i][j] according to the original nested logic.
 *
 * @param i   current index in the input array
 * @param j   colour/state (0,1,2) for the current position
 * @param a   original input array
 * @param dp  DP table being filled
 * @return the minimal steps for dp[i][j]
 */
private static int computeCell(int i, int j, int[] a, int[][] dp) {
    int best = 1 + dp[i + 1][2];               // base case: paint current element
    for (int k = 0; k < 2; k++) {               // try to keep colour k (0 or 1)
        if ( ((1 << k) & a[i]) != 0 && k != j) { // k is present in a[i] and differs from j
            best = Math.min(best, dp[i + 1][k]);
        }
    }
    return best;
}

