}

/**
 * Computes the value for dp[i][j] according to the original nested logic.
 *
 * @param i  current index in the array (0‑based)
 * @param j  colour/state being considered (0‒2)
 * @param a  input array of bit masks
 * @param dp DP table already filled for positions > i
 * @return   the minimal cost for dp[i][j]
 */
private static int calculateDp(int i, int j, int[] a, int[][] dp) {
    int best = 1 + dp[i + 1][2];          // baseline transition
    for (int k = 0; k < 2; k++) {        // try alternative transitions
        if ( ((1 << k) & a[i]) != 0 && k != j ) {
            best = Math.min(best, dp[i + 1][k]);
        }
    }
    return best;
}

