/**
 * Returns the total number of prime‑factor occurrences of {@code value}.
 * Example: 12 = 2·2·3 → returns 3.
 */
private static int countPrimeFactors(long value) {
    int count = 0;
    for (long divisor = 2; divisor * divisor <= value; divisor++) {
        while (value % divisor == 0) {
            value /= divisor;
            count++;
        }
    }
    if (value > 1) {
        // The remaining value is a prime > sqrt(original value)
        count++;
    }
    return count;
}

