/**
 * Counts the total number of prime factors (with multiplicity) of the given positive number.
 *
 * @param value a positive long value
 * @return the number of prime factors
 */
private static int countPrimeFactors(long value) {
    int factorCount = 0;
    long m = value;
    for (long j = 2; j * j <= m; j++) {
        if (m % j != 0) {
            continue;                 // guard clause – skip non‑divisors
        }
        while (m % j == 0) {
            m /= j;
            factorCount++;
        }
    }
    if (m > 1) {
        factorCount++;                // the remaining m is a prime > sqrt(original)
    }
    return factorCount;
}

