/**
 * Updates b[j] according to the i‑th query.
 * Guard clauses keep the nesting depth ≤ 3.
 */
private static void applyOperation(int queryIdx, int bIdx) {
    int value = b[bIdx];
    int lower = min[queryIdx];
    int upper = max[queryIdx];

    // Guard: value not in the affected range → nothing to do
    if (value < lower || value > upper) {
        return;
    }

    if (t[queryIdx] == 1) {
        // decrement or wrap to the upper bound
        b[bIdx] = (value == lower) ? upper : value - 1;
    } else {
        // mirror around the interval
        b[bIdx] = upper - value + lower;
    }
}

