/** Returns true if value lies inside the inclusive interval [low, high]. */
private static boolean inRange(int value, int low, int high) {
    return value >= low && value <= high;
}

/**
 * Applies the i‑th query to the element b[bIndex].
 * Guard‑clauses keep the method flat (max nesting depth = 1).
 */
private static void applyTransformation(int bIndex, int queryIndex) {
    // Query type 1: decrement or wrap to max
    if (t[queryIndex] != 1) {
        b[bIndex] = max[queryIndex] - b[bIndex] + min[queryIndex];
        return;
    }

    // At this point t[queryIndex] == 1
    if (b[bIndex] == min[queryIndex]) {
        b[bIndex] = max[queryIndex];
    } else {
