/**
 * Returns the first pair of indices {@code [l, r]} (0‑based) such that the substring
 * {@code s[l..r]} contains an equal number of 'a' and 'b'.
 * If no such substring exists, returns {@code [-1, -1]}.
 */
private int[] findEqualAB(String s) {
    int n = s.length();
    for (int i = 0; i < n; i++) {
        int countA = 0;
        int countB = 0;
        for (int j = i; j < n; j++) {
            char c = s.charAt(j);
            if (c == 'a') {
                countA++;
            } else {
                countB++;
            }
            if (countA == countB) {
                return new int[]{i, j};    // guard clause – early exit when condition met
            }
        }
    }
    return new int[]{-1, -1};               // no balanced substring found
