/**
 * Returns the zero‑based start and end indexes of the first substring
 * where the count of 'a' equals the count of 'b'.
 * If no such substring exists, returns {-1, -1}.
 */
private int[] findBalanced(String s) {
    int n = s.length();
    for (int i = 0; i < n; i++) {
        int countA = 0, countB = 0;
        for (int j = i; j < n; j++) {
            char c = s.charAt(j);
            if (c == 'a') {
                countA++;
            } else {
                countB++;
            }
            if (countA == countB) {
                return new int[]{i, j};
            }
        }
    }
    return new int[]{-1, -1};
}

