/**
 * Determines whether the given mid value is sufficient to bring the remaining
 * height down to zero or below.
 *
 * @param a   sorted array of positions
 * @param h   initial height
 * @param mid candidate value
 * @return true if the remaining height becomes ≤ 0, false otherwise
 */
private boolean canAchieve(long[] a, long h, long mid) {
    long remain = h - mid;                 // subtract the first segment
    for (int i = 1; i < a.length; i++) {
        remain -= Math.min(a[i] - a[i - 1], mid);
        if (remain <= 0) {
