/**
 * Returns true if the element at index {@code idx} satisfies the "great"
 * condition: it is either shorter than half of every other length or longer
 * than twice every other length.
 */
private boolean isGreat(int idx, int[] len) {
    boolean allShorter = true;
    boolean allLonger = true;

    for (int j = 0; j < len.length; ++j) {
        if (j == idx) {
            continue;                     // guard clause – skip self‑comparison
        }
        if (len[idx] * 2 > len[j]) {
            allShorter = false;
        }
        if (len[idx] < len[j] * 2) {
            allLonger = false;
        }
        // early exit: once both possibilities are impossible we can stop
        if (!allShorter && !allLonger) {
            return false;
        }
    }
    return allShorter || allLonger;
}

