            Math.ceil((double) (hpy + h) / damMact) <=
            Math.ceil((double) hpm / damYact)) {
            continue;
        }

        // Condition satisfied: compute cost and return immediately (early exit).
        int actCost = a * cat + h * chp + d * cde;
        return new Result(actCost, d);
    }
    // No d satisfied the condition.
    return null;
