/**
 * Determines whether the fraction p/q (with base b) terminates.
 * Returns true for a finite representation, false otherwise.
 */
private boolean isFinite(long p, long q, long b) {
    // Guard clause – zero numerator is always finite.
    if (p == 0) {
        return true;
