/* Updates the best (max count, smallest numeric value) found so far */
private static void updateResult(int count, String sub, Result result) {
    if (count < result.max) {
        return;                               // guard clause
    }

    int value = Integer.valueOf(sub);

    if (count == result.max) {
        // tie – keep the smallest numeric value
        if (value < result.wmax) {
            result.wmax = value;
        }
    } else { // count > result.max
        result.max = count;
        result.wmax = value;
    }
}

