/**
 * Returns the number of non‑overlapping occurrences of {@code sub} in {@code whole}.
 * The original code used a replaceAll trick; this method keeps the same semantics.
 */
private static int frequency(String whole, String sub) {
    if (sub.isEmpty()) {
        return 0;
    }
    int removedLength = whole.replaceAll(sub, "").length();
    int coveredLength = whole.length() - removedLength;
    return coveredLength / sub.length();
}

/**
