 * and index 1 is the possibly‑updated wmax (the smallest integer value
 * achieving that frequency).
 *
 * Guard clauses are used inside the method to keep the logic flat.
 */
private static int[] updateBest(String sub, int freq, int currentMax, int currentWmax) {
    if (freq > currentMax) {
        return new int[]{freq, Integer.valueOf(sub)};
    }
    if (freq == currentMax) {
        int subVal = Integer.valueOf(sub);
        if (subVal < currentWmax) {
            return new int[]{currentMax, subVal};
        }
    }
    return new int[]{currentMax, currentWmax};
}

