 * sequence never dips below zero when scanned left‑to‑right.
 */
private static int countNeededInsertions(String s) {
    int cnt = 0;      // current balance
    int min = 0;      // most negative balance encountered
    int ans = 0;      // number of needed insertions

    for (int i = 0; i < s.length(); i++) {
        char ch = s.charAt(i);
        if (ch == '(') {
            cnt++;
            continue;                // guard clause – no further processing needed
        }

