 * smaller than any previous balance. This matches the original algorithm's
 * {@code ans} computation.
 */
private static int countUnmatchedClosingParentheses(String s) {
    int balance = 0;
    int minBalance = 0;
    int violations = 0;

    for (int i = 0; i < s.length(); i++) {
        char ch = s.charAt(i);
