/**
 * Returns the number of halving operations required to turn {@code value}
 * into {@code target}. If it is impossible, returns -1.
 */
private static int opsToReach(int value, int target) {
    if (value < target) {
        return -1;
    }
    int steps = 0;
    while (value > target) {
        value >>= 1;      // divide by 2
        steps++;
    }
    return (value == target) ? steps : -1;
}

