/**
 * Returns the number of times {@code value} must be divided by 2 to become {@code target}.
 * If {@code value} cannot become {@code target} (i.e., it becomes smaller than target),
 * the method returns -1.
 */
private static int divisionsNeeded(int value, int target) {
    if (value < target) {
        return -1;                                 // guard clause – impossible
    }
    int ops = 0;
    while (value > target) {
        value >>= 1;                               // same as value = value / 2
        ops++;
    }
    return (value == target) ? ops : -1;
}

