public void solve(FastReader in, PrintWriter out) {
    int n = in.nextInt();
    int msize = in.nextInt();
    int[] arr = new int[n];
    for (int i = 0; i < n; i++) {
        arr[i] = in.nextInt();
    }

    HashMap<Integer, Integer> mp = new HashMap<>();
    HashMap<Integer, Integer> grpsize = new HashMap<>();
    for (int i = 0; i < 256; i++) {
        mp.put(i, -1);
        grpsize.put(i, 1);
    }

    int[] res = new int[n];
    for (int i = 0; i < n; i++) {
        res[i] = computeResult(arr[i], msize, mp, grpsize);
    }

    for (int i = 0; i < n; i++) {
        out.print(res[i] + " ");
    }
}

/* ---------- helpers ---------- */

private static int computeResult(int value, int msize,
                                 HashMap<Integer, Integer> mp,
                                 HashMap<Integer, Integer> grpsize) {
    // Guard clause – value already belongs to a group
    if (mp.get(value) != -1) {
        return mp.get(value);
    }

    int leftBound = Math.max(0, value - msize + 1);
    GroupInfo info = findGroupInfo(value, leftBound, msize, mp, grpsize);

    // Fill maps for the newly created group [value … info.y]
    for (int j = value; j >= info.y; j--) {
        mp.put(j, info.y);
        grpsize.put(j, info.z);
    }
    return mp.get(value);
}

private static GroupInfo findGroupInfo(int value, int start, int msize,
                                       HashMap<Integer, Integer> mp,
                                       HashMap<Integer, Integer> grpsize) {
    int y = value;
    int z = -1;

    for (int j = value; j >= start; j--) {
        int mapped = mp.get(j);
        if (mapped != -1) {
            int possibleSize = grpsize.get(j) + value - j;
            if (possibleSize <= msize) {
                y = mapped;
                z = possibleSize;
                propagateGroupSize(j, mapped, z, mp, grpsize);
            }
            break; // a known entry was found – stop scanning
        } else {
            y = j; // keep the smallest index without a mapping
        }
    }

    if (z == -1) {
        z = value - y + 1; // no compatible previous group
    }
    return new GroupInfo(y, z);
}

/* propagate the computed group size backwards while the same group start is seen */
private static void propagateGroupSize(int from, int groupStart, int size,
                                       HashMap<Integer, Integer> mp,
                                       HashMap<Integer, Integer> grpsize) {
    int idx = from;
    while (idx >= 0 && mp.get(idx) == groupStart) {
        grpsize.put(idx, size);
        idx--;
    }
}

/* simple holder for the information returned by findGroupInfo */
private static class GroupInfo {
    final int y; // the leftmost index of the group
    final int z; // the size of the group
    GroupInfo(int y, int z) {
        this.y = y;
        this.z = z;
    }
}

