/**
 * Determines the character to output for a given cell.
 *
 * @param original the character read from input
 * @param row      current row number (1‑based)
 * @param col      current column number (1‑based)
 * @return the character that should be printed
 */
private static char pickChar(char original, int row, int col) {
    // Guard clause: keep any non‑dot character unchanged
    if (original != '.') {
        return original;
    }
    // For dot cells, alternate colors based on parity of (row + col)
    return ((row + col) % 2 == 0) ? 'B' : 'W';
}

