                    (a[1] - (d[0] + j))
                            * ((h[1] + a[0] + i - d[1] - 1) / (a[0] + i - d[1]))
                            + 1 - h[0]);
            if (hp * h[2] + i * a[2] + j * d[2] <= limit) {
                return true; // early exit – condition satisfied
            }
        }
    }
    return false; // no (i,j) pair satisfied the condition
}

