private static HashMap<Integer, Long> buildFrequencyMap(int[] a) {
    HashMap<Integer, Long> map = new HashMap<>();
    SparseTable s = new SparseTable(a);
    int n = a.length;
    for (int i = 0; i < n; i++) {
        processStartIndex(i, s, n, map);
    }
    return map;
}

/** Processes all segments that start at position `start`. */
private static void processStartIndex(int start, SparseTable s, int n,
                                      HashMap<Integer, Long> map) {
    int idx = start;
    while (true) {
        int g = s.query(start, idx);
        int nextIdx = findNextGreaterIndex(start, idx, g, s, n);
        long added = (long) (nextIdx - idx);
        map.merge(g, added, Long::sum);
        idx = nextIdx;
        if (nextIdx == n) {
            return; // guard clause – leaves the loop early
        }
    }
}

/** Binary‑searches for the first position > `idx` where the range‑minimum
 *  becomes strictly smaller than `target`. Returns `n` if no such position exists. */
private static int findNextGreaterIndex(int start, int idx, int target,
                                        SparseTable s, int n) {
    int lo = idx + 1;
    int hi = n - 1;
    int ans = n; // default when condition never satisfied
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1; // unsigned right shift for floor division by 2
        if (s.query(start, mid) < target) {
            ans = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return ans;
}

