/**
 * pours {@code amount} starting at index {@code startIdx},
 * respecting capacities and keeping {@code T} up‑to‑date.
 */
private static void fillCapacity(int startIdx, int amount,
                                 int[] cap, int[] fill,
                                 TreeSet<Integer> T) {
    int idx = T.ceiling(startIdx);
    while (amount > 0 && idx != Integer.MAX_VALUE) {
        int delta = Math.min(cap[idx] - fill[idx], amount);
        fill[idx] += delta;
        amount -= delta;

        if (fill[idx] == cap[idx]) {    // container becomes full
            T.remove(idx);
        }
        idx = T.ceiling(idx);           // next candidate
    }
}

