 * back to its starting position, i.e. the net vertical (r) and horizontal (c)
 * displacement are both zero.
 */
private boolean isClosedLoop(char[] s, int from, int to) {
    int r = 0;
    int c = 0;
    for (int k = from; k <= to; k++) {
        switch (s[k]) {
            case 'U' -> ++r;
            case 'D' -> --r;
            case 'R' -> ++c;
            case 'L' -> --c;
        }
    }
    return r == 0 && c == 0;
