public void solve(int testNumber, ScanReader in, PrintWriter out) {
    int b = in.scanInt();
    int d = in.scanInt();
    char[] ar = in.scanString().toCharArray();
    char[] br = in.scanString().toCharArray();

    int[] dp = new int[br.length];
    int[] dpPos = new int[br.length];
    computeDpAndPositions(ar, br, dp, dpPos);

    long cur = 0;
    int curB = 0;
    for (int i = 0; i < b; i++) {
        cur += dp[curB];
        curB = dpPos[curB];
    }
    out.println(cur / d);
}

/**
 * Fills {@code dp} with the number of complete matches of {@code br}
 * starting from each position, and {@code dpPos} with the next position
 * after processing the whole {@code ar} string.
 *
 * The implementation uses guard clauses to keep nesting depth ≤ 3.
 */
private void computeDpAndPositions(char[] ar, char[] br, int[] dp, int[] dpPos) {
    for (int start = 0; start < br.length; start++) {
        int curB = start;
        int matches = 0;

        for (int i = 0; i < ar.length; i++) {
            // guard clause – skip when characters do not match
            if (ar[i] != br[curB]) {
                continue;
            }
            curB = (curB + 1) % br.length;
            if (curB == 0) {
                matches++;
            }
        }
        dp[start] = matches;
        dpPos[start] = curB;
    }
}

