/** Holds a mutable integer so it can be updated inside helper methods. */
private static class Index {
    int value = 0;
}

/**
 * Executes one iteration of the inner loop.
 *
 * @return {@code true} if the algorithm can continue,
 *         {@code false} if an invalid state was detected (prints -1).
 */
private static boolean processStep(Stack<Integer> stack,
                                   int[] arr,
                                   int k,
                                   Index idx,
                                   StringBuilder sb) {
    if (idx.value < k) {                     // we still have elements from the input array
        int x = arr[idx.value++];
        if (x > stack.peek()) {               // guard clause – invalid configuration
            System.out.println(-1);
            return false;
        }
        stack.push(x);
        sb.append(stack.peek()).append(' ');
    } else {                                 // no more input values, decrement the top
        stack.push(stack.peek() - 1);
        sb.append(stack.peek()).append(' ');
    }
    return true;
}

