/**
 * Evaluates all possible meeting points (a,b) and returns the smallest
 * total number of used edges that satisfies both length limits.
 * Returns Integer.MAX_VALUE if no meeting configuration is feasible.
 */
private static int computeBestShared(int[][] dist,
                                     int s1, int t1, int l1,
                                     int s2, int t2, int l2) {
    int n = dist.length;
    int best = Integer.MAX_VALUE;

    for (int a = 0; a < n; a++) {
        for (int b = 0; b < n; b++) {
            int viaAB = dist[a][b];

            // orientation 1: both paths go a → b
            int path1 = dist[s1][a] + viaAB + dist[b][t1];
            int path2 = dist[s2][a] + viaAB + dist[b][t2];
            if (path1 <= l1 && path2 <= l2) {
                int total = dist[s1][a] + dist[s2][a] + viaAB + dist[b][t1] + dist[b][t2];
                best = Math.min(best, total);
            }

            // orientation 2: second path goes b → a
            int path2Alt = dist[s2][b] + viaAB + dist[a][t2];
            if (path1 <= l1 && path2Alt <= l2) {
                int total = dist[s1][a] + dist[s2][b] + viaAB + dist[b][t1] + dist[a][t2];
                best = Math.min(best, total);
            }
        }
    }
    return best;
}

