/**
 * Computes the longest substring length that can be obtained by changing at most
 * {@code allowedChanges} characters to the {@code targetChar}.
 * The implementation mirrors the original nested‑while logic but uses guard
 * clauses to keep nesting shallow.
 */
private static int maxLengthWithChanges(String s, int n, int allowedChanges, int targetChar) {
    int fp = 0;                 // left pointer of the window
    int ep = 0;                 // right pointer of the window
    int maxAns = 0;
    int countChange = 0;        // how many characters in the current window have been changed

    while (fp != n) {
        while (ep != n) {
            // Guard: the current right character is not the target one.
            if (s.charAt(ep) - 97 != targetChar) {
                // Too many changes already – stop expanding the window.
                if (countChange == allowedChanges) {
                    break;
                }
                // Accept this character as a change and continue expanding.
                ep++;
                countChange++;
                continue;
            }
            // Character matches target – expand without consuming a change.
            ep++;
        }

        // At this point the window [fp, ep) respects the allowed change budget.
        maxAns = Math.max(maxAns, ep - fp);

        // Move left pointer forward, adjusting the change count if we discard a changed char.
        if (s.charAt(fp) - 97 != targetChar) {
            countChange--;
        }
        fp++;
    }
    return maxAns;
}

