/**
 * Returns the longest substring length that can be turned into the target
 * character using at most {@code maxChanges} character replacements.
 *
 * @param s          the source string (lower‑case a‑z)
 * @param maxChanges maximum number of characters that may be changed
 * @param target     the target character as an int 0‑25 (0 = 'a')
 * @return the maximum length satisfying the constraint
 */
private static int maxLengthWithChanges(String s, int maxChanges, int target) {
    int n = s.length();
    int left = 0, right = 0;
    int changes = 0;
    int best = 0;

    while (left < n) {
        // Expand the right boundary while we stay within the change budget.
        while (right < n) {
            if (s.charAt(right) - 'a' != target) {
                if (changes == maxChanges) {
                    break;               // guard clause – cannot add more changes
                }
                changes++;
            }
            right++;
        }
        // Update best length for the current window.
        best = Math.max(best, right - left);

        // Shrink window from the left, adjusting the change counter if needed.
        if (s.charAt(left) - 'a' != target) {
            changes--;
        }
        left++;
    }
    return best;
}

