public int[] roll(String order) {
    int now_1 = 1;
    int now_2 = 2;
    int now_3 = 3;
    int[] array = getNum();

    // Process each direction character
    for (int i = 0; i < order.length(); i++) {
        char dir = order.charAt(i);
        int[] updated = rotate(now_1, now_2, now_3, dir);
        now_1 = updated[0];
        now_2 = updated[1];
        now_3 = updated[2];
    }

    int[] cp_array = new int[array.length];
    cp_array[1] = array[now_1];
    cp_array[2] = array[now_2];
    cp_array[3] = array[now_3];
    cp_array[4] = array[7 - now_3];
    cp_array[5] = array[7 - now_2];
    cp_array[6] = array[7 - now_1];
    return cp_array;
}

/**
 * Returns the new values of now_1, now_2, now_3 after applying the rotation
 * corresponding to the given direction.
 *
 * Directions:
 *   N – case 1
 *   E – case 2
 *   S – case 3
 *   W – case 4
 *
 * Any other character leaves the state unchanged.
 */
private int[] rotate(int now_1, int now_2, int now_3, char dir) {
    int tmp;
    switch (dir) {
        case 'N': // case 1
            tmp = now_1;
            now_1 = now_2;
            now_2 = 7 - tmp;
            break;
        case 'E': // case 2
            tmp = now_1;
            now_1 = 7 - now_3;
            now_3 = tmp;
            break;
        case 'S': // case 3
            tmp = now_1;
            now_1 = 7 - now_2;
            now_2 = tmp;
            break;
        case 'W': // case 4
            tmp = now_1;
            now_1 = now_3;
            now_3 = 7 - tmp;
            break;
        default:
            // No rotation for unrecognised characters
            break;
    }
    return new int[] { now_1, now_2, now_3 };
}

