/**
 * Returns true if {@code data} contains the pattern defined by {@code name}.
 * The pattern is: first character of {@code name} occurs at position k,
 * a later character equal to the second character of {@code name} occurs at
 * position m (m > k), and {@code check00} validates the occurrence.
 */
private static boolean matchesPattern(String data, String name) {
    // Guard clause – impossible to match if data is too short or name has <2 chars
    if (data == null || name == null || name.length() < 2 || data.length() < name.length()) {
        return false;
    }

    int maxK = data.length() - name.length();               // last possible start index
    for (int k = 0; k <= maxK; k++) {
        if (data.charAt(k) != name.charAt(0)) {
            continue; // first character does not match
        }

        int maxM = data.length() - (name.length() - 1);     // last possible second char index
        for (int m = k + 1; m <= maxM; m++) {
            if (data.charAt(m) != name.charAt(1)) {
                continue; // second character does not match
            }

            int dist = m - k;
            if (check00(name, data, 1, m, dist) == 1) {
                return true; // pattern satisfied
            }
        }
    }
    return false; // no valid pattern found
}

