public String nextLine() throws IOException {
    // Guard clause: no data at all
    if ($readCount == EOF) {
        return null;
    }

    int i = 0;
    while (true) {
        // Ensure there is data in the buffer; exit if stream is exhausted
        if (!refillBufferIfNeeded()) {
            // EOF reached after having read some characters
            return new String(charBuff, 0, i);
        }

        byte b = buffer[$index++];
        if (b == NL) {
            // End of line found
            return new String(charBuff, 0, i);
        }

        // Normal character handling
        if (i == charBuff.length) {
            doubleCharSize();
        }
        charBuff[i++] = (char) b;
    }
}

/**
 * Refills the internal buffer when the current index has reached the
 * number of bytes read. Returns {@code true} if new data is available,
 * {@code false} if the underlying stream has reached EOF.
 */
private boolean refillBufferIfNeeded() throws IOException {
    if ($index >= $readCount) {
        $readCount = stream.read(buffer);
        $index = 0;
        return $readCount != EOF;
    }
    return true;
}

public String nextLine() throws IOException {
    // Guard clause: stream already exhausted
    if ($readCount == EOF) {
        return null;
    }

    int i = 0;
    while (true) {
        // Consume the remaining bytes in the current buffer
        for (; $index < $readCount; $index++) {
            if (buffer[$index] == NL) {
                // New‑line reached – return the line built so far
                $index++; // move past the newline character
                return new String(charBuff, 0, i);
            }
            // Ensure the character buffer is large enough
            if (i == charBuff.length) {
                doubleCharSize();
            }
            charBuff[i++] = (char) buffer[$index];
        }

        // Current buffer exhausted – read the next chunk
        $readCount = stream.read(buffer);
        $index = 0;
        if ($readCount == EOF) {
            // EOF after reading some characters – return what we have
            return new String(charBuff, 0, i);
        }
    }
}

