 * Keeps the original algorithm while flattening nested conditionals.
 */
private static void processNode(int node,
                                HashSet<Integer>[] adjList,
                                Set<Integer> components) {
    // Guard clause – nothing to merge when there are no components yet.
    if (components.isEmpty()) {
        components.add(node);
        return;
    }

    Set<Integer> merged = new HashSet<>();

    // Iterate over a snapshot to avoid ConcurrentModificationException.
    for (int comp : new ArrayList<>(components)) {
        // Guard clause – if the current component is adjacent to the node,
        // we skip any merging logic for this component.
        if (adjList[comp].contains(node)) {
            continue;
        }

        // Intersect the neighbor sets and remember the component for removal.
        adjList[node].retainAll(adjList[comp]);
        merged.add(comp);
    }

    // Remove all components that were merged.
    for (int comp : merged) {
        components.remove(comp);
    }

    // Finally, add the current node as its own component.
