/**
 * Scans all triples (i, v, u) that form a triangle and returns the smallest
 * value of (deg(i)+deg(v)+deg(u)-6). If no triangle exists, returns the sentinel 5000.
 */
private static int findMinimumTriangle(List<Integer>[] adjList, boolean[][] con) {
    int min = 5000;                     // sentinel used in the original code
    int n = adjList.length;

    for (int i = 0; i < n; i++) {
        for (int v : adjList[i]) {
            for (int u : adjList[v]) {
                // guard clauses – flatten the nesting
                if (u == v) continue;
                if (!con[i][u]) continue;

                min = updateMinimum(adjList, i, v, u, min);
            }
        }
    }
    return min;
}

/**
 * Computes a new candidate minimum for the current triangle (i, v, u)
 * and returns the smaller of the old and the new value.
 */
private static int updateMinimum(List<Integer>[] adjList, int i, int v, int u, int currentMin) {
    int candidate = adjList[i].size() + adjList[v].size() + adjList[u].size() - 6;
    return Math.min(candidate, currentMin);
}

