/** Holds the hash sets and the number of distinct substrings. */
private static class ResultCount {
    final HashSet<Long> hs1;
    final HashSet<Long> hs2;
    final int distinctCount;

    ResultCount(HashSet<Long> hs1, HashSet<Long> hs2, int distinctCount) {
        this.hs1 = hs1;
        this.hs2 = hs2;
        this.distinctCount = distinctCount;
    }

    /** True when every possible binary string of length k appears. */
    boolean isAllPossible(int k) {
        return k <= 30 && (1 << k) == distinctCount;
    }
}

/** Computes the rolling‑hash sets for all substrings of length k and returns the count. */
private static ResultCount countDistinctSubstrings(String s, int n, int k) {
    HashSet<Long> hs1 = new HashSet<>();
    HashSet<Long> hs2 = new HashSet<>();

    long hash1 = 0, hash2 = 0;
    long pow1 = power(BASE, k - 1, MOD1);
    long pow2 = power(BASE, k - 1, MOD2);
    int cnt = 0;

    for (int i = 0; i < n; i++) {
        // extend the window
        hash1 = (hash1 * BASE) % MOD1;
        hash2 = (hash2 * BASE) % MOD2;
        hash1 = (hash1 + (s.charAt(i) - '0')) % MOD1;
        hash2 = (hash2 + (s.charAt(i) - '0')) % MOD2;

        if (i < k - 1) {
            continue;                       // guard‑clause, we haven't filled the window yet
        }

        // add current window hashes
        boolean added = hs1.add(hash1);
        added |= hs2.add(hash2);
        if (added) {
            cnt++;
        }

        // slide the window: remove the leftmost digit if it was '1'
        if (s.charAt(i - k + 1) == '1') {
            hash1 = ((hash1 - pow1) % MOD1 + MOD1) % MOD1;
            hash2 = ((hash2 - pow2) % MOD2 + MOD2) % MOD2;
        }
    }
    return new ResultCount(hs1, hs2, cnt);
}

/** Returns the smallest value (as a long) whose binary representation of length k
 *  is not present in both hash sets. */
private static long findMissingValue(HashSet<Long> hs1, HashSet<Long> hs2, int k) {
    long val = 0;
    long hash1 = 0, hash2 = 0;

    // hash of the all‑'1' string of length k
    for (int i = 0; i < k; i++) {
        hash1 = (hash1 * BASE) % MOD1;
        hash2 = (hash2 * BASE) % MOD2;
        hash1 = (hash1 + 1) % MOD1;
        hash2 = (hash2 + 1) % MOD2;
    }

    while (hs1.contains(hash1) && hs2.contains(hash2)) {
        // decrement both hashes synchronously
        hash1 = ((hash1 - 1) % MOD1 + MOD1) % MOD1;
        hash2 = ((hash2 - 1) % MOD2 + MOD2) % MOD2;
        val++;
    }
    return val;
}

/** Converts a value to a binary string of exactly k bits (leading zeros are kept). */
private static String toBinaryString(long value, int k) {
    StringBuilder sb = new StringBuilder(Long.toBinaryString(value));
    sb.reverse();
    while (sb.length() < k) {
        sb.append('0');
    }
    sb.reverse();
    return sb.toString().trim();
}

