/* Extracted helper – builds left/right and up/down links for a single row */
private static void populateLinksForRow(int i, char[][] a, int[][] L, int[][] R,
                                        int[][] U, int[][] D, int[] h) {
    int k = -1;
    for (int j = 0; j < a[i].length; j++) {
        if (a[i][j] == '.') {
