/**
 * Handles the bookkeeping for a non‑dot cell.
 * Returns the new “previous column” index for the current row.
 */
private static int processCell(int i, int j, int prevK,
                               int[][] L, int[][] R,
                               int[][] U, int[][] D,
                               int[] h) {
    // left neighbour
    L[i][j] = prevK;
    if (prevK != -1) {
        R[i][prevK] = j;
    }

    // upper neighbour
    U[i][j] = h[j];
    if (h[j] != -1) {
        D[h[j]][j] = i;
    }

    // update column tracker for this column
    h[j] = i;
    // current column becomes the new previous column
    return j;
}

/**
