/** Processes a single test case and prints YES/NO. */
private static void processCase(SimpleScanner scanner, PrintWriter writer, final int POW) {
    int n = scanner.nextInt();
    int[] cnt = new int[POW + 1];

    final int LIMIT = 1 << POW;          // maximum value that can be represented
    for (int i = 0; i < n; ++i) {
        int t = scanner.nextInt();

        // Guard clause: values larger than LIMIT cannot contribute.
        if (t > LIMIT) {
            continue;
        }

        int k = bitExponent(t);
        ++cnt[k];
    }

    // Propagate pairs upwards.
    for (int i = 0; i < POW; ++i) {
        cnt[i + 1] += cnt[i] / 2;
    }

    writer.println(cnt[POW] > 0 ? "YES" : "NO");
}

/**
 * Returns the smallest exponent k such that (1 << k) >= value.
 * Assumes value is positive and <= (1 << 31).
 */
private static int bitExponent(int value) {
    int k = 0;
    while ((1 << k) < value) {
        ++k;
    }
    return k;
}

