/**
 * Updates the DP tables for a concrete (len, digit, mask) combination.
 * A guard clause skips masks that would exceed the allowed number of distinct digits.
 */
private void updateMask(int len, int d, int mask, int bit) {
    int newMask = mask | bit;
    if (nbits[newMask] > k) {
        return;                     // guard clause – do not process this mask
    }

    // values from the previous length
    int prevCnt = dcnt[len - 1][mask];
    long prevSum = dsum[len - 1][mask];

    // update count for the new mask
    dcnt[len][newMask] = (dcnt[len][newMask] + prevCnt) % mod;

    // compute contribution of the current digit
    long subSum = (d * p10[len - 1] % mod) * prevCnt % mod;
    subSum = (subSum + prevSum) % mod;

    // update sum for the new mask
    dsum[len][newMask] = (dsum[len][newMask] + subSum) % mod;

    // if the digit is non‑zero, also update the “started” aggregates
    if (d != 0) {
        scnt[len] = (scnt[len] + prevCnt) % mod;
        ssum[len] = (ssum[len] + subSum) % mod;
    }
}

