/**
 * For a given prime number, increments the divisor‑count entry for each
 * multiple of the prime by the exponent of that prime in the multiple.
 */
private void markPrimeMultiples(int prime, int[] arr, int max) {
    for (int j = prime; j <= max; j += prime) {
        int temp = j;
        do {
            arr[j]++;
            temp /= prime;
        } while (temp % prime == 0);
