/**
 * For a given prime number {@code p}, increment the exponent count
 * for every multiple of {@code p} up to {@code max}.
 */
private static void processMultiples(int p, int max, int[] arr) {
    for (int j = p; j <= max; j += p) {
        int temp = j;
        while (temp % p == 0) {
            arr[j]++;
            temp /= p;
        }
    }
}

/**
 * Transforms {@code arr} into a prefix‑sum array in‑place.
 */
private static void buildPrefix(int[] arr) {
    for (int i = 1; i < arr.length; i++) {
        arr[i] += arr[i - 1];
    }
}

