    for (int s = 1; s < n; s <<= 1) {                 // level 1
        for (int i = 0; i < n; i += s << 1) {         // level 2
            for (int j = i; j < i + s; j++) {         // level 3
                processPair(a, j, j + s);
            }
        }
    }
}

/**
 * Handles the butterfly operation for indices j and k = j + s,
 * applying the modulus P adjustments.
 */
private static void processPair(int[] a, int j, int k) {
    int v = a[j];
    int u = a[k];

    int sum = v + u;
    if (sum >= P) {          // guard clause
        sum -= P;
    }
    a[j] = sum;

    int diff = v - u;
    if (diff < 0) {          // guard clause
        diff += P;
    }
    a[k] = diff;
}

