/**
 * Counts how many previously seen numbers form a pair with {@code value}
 * such that {@code value + previous = 2^k} for some k (0 ≤ k < 31).
 *
 * @param value the current array element
 * @param map   frequency map of previously processed elements
 * @param dp    pre‑computed powers of two
 * @return the number of matching pairs for {@code value}
 */
private long countMatchingPairs(int value, HashMap<Integer, Integer> map, int[] dp) {
    long count = 0L;
    for (int j = 0; j < dp.length; j++) {
        int q = dp[j] - value;
        if (q <= 0) {
            continue;               // guard clause – eliminates one nesting level
        }
        count += map.getOrDefault(q, 0);
    }
    return count;
}

