/**
 * Builds an array where dp[i] = 2^i.
 */
private int[] buildPowerOfTwoTable(int size) {
    int[] dp = new int[size];
    dp[0] = 1;
    for (int i = 1; i < size; i++) {
        dp[i] = dp[i - 1] << 1;   // multiply by 2
    }
    return dp;
}

/**
 * For the given value, counts how many previously seen numbers form a
 * pair (value + previous = 2^j) for any j in [0,30].
 */
private long countPairsForValue(int value,
                                HashMap<Integer, Integer> freqMap,
                                int[] dp) {
    long added = 0L;
    for (int power : dp) {
        int q = power - value;
        if (q <= 0) {
            continue;               // guard‑clause – avoids deeper nesting
        }
        added += freqMap.getOrDefault(q, 0);
    }
    return added;
}

/**
 * Increments the occurrence count of {@code key} in the map.
 */
private void incrementCount(HashMap<Integer, Integer> map, int key) {
    map.put(key, map.getOrDefault(key, 0) + 1);
}

