            if (bestIdx != -1) {
                recordSelection(ar, bestIdx, sec, indices, time);
                curLoss += ar.get(bestIdx).dec; // note: dec saved before removal
                ar.remove(bestIdx);
            }
        }

        cur -= curLoss;
        cur = Math.min(cur + reg, max);
        sec++;
    }

