/**
 * Returns the index of the scroll with the highest 'dec' whose
 * percentage requirement is satisfied. Returns -1 if none match.
 */
private static int findBestIndex(List<Scroll> scrolls, int cur, int max) {
    int bestIdx = -1;
    int bestDec = Integer.MIN_VALUE;
    double curPercent = (cur * 1.0 / max) * 100;

    for (int i = 0; i < scrolls.size(); i++) {
        Scroll s = scrolls.get(i);
        if (s.percent >= curPercent && s.dec > bestDec) {
            bestDec = s.dec;
            bestIdx = i;
        }
    }
    return bestIdx;
}

/**
 * Records the selection of a scroll at the given second.
 */
private static void recordSelection(List<Scroll> scrolls, int idx, int sec,
                                   List<Integer> indices, List<Integer> time) {
    Scroll s = scrolls.get(idx);
    indices.add(s.idx);
    time.add(sec);
}

