private static long computeDays(Scanner sc) {
    int n = sc.nextInt();
    long days = 0L;
    Stack<Long> st = new Stack<>();

    for (int j = 0; j < n; j++) {
        long x = sc.nextLong();

        // Guard‑clause: pop while top is greater than current value
        while (!st.isEmpty() && st.peek() > x) {
            st.pop();
            days++;
        }
        st.push(x);
    }
    return days;
}

