        int d = q0.dist[u] + 1;

        for (int i = 0; i < ec[u]; i++) {
            int v = e[u][i];

            // guard clause – skip already visited in this level
            if (q0.f[v]) {
                continue;
            }

            // first discovery of a “good” vertex
            if (good[v] && !gf[v]) {
                gf[v] = true;
                q1.add(v, 0);
            }

            // propagate distance if within limit
            if (d < q) {
                q0.add(v, d);
            }
        }
    }
}

/** Swaps the two frontier queues for the next iteration. */
private void swapQueues() {
    Q tmp = q0;
    q0 = q1;
    q1 = tmp;
}

