public boolean nextPermutation(String[] permutateString) {
    for (int i = permutateString.length - 1; i >= 1; i--) {
        if (permutateString[i].compareTo(permutateString[i - 1]) > 0) {
            // Pivot found – handle the rest and return the outcome
            return processPivot(permutateString, i);
        }
    }
    // No next permutation exists
    return false;
}

/**
 * Reverses the suffix starting at {@code start} and swaps the pivot element
 * (at {@code start-1}) with the smallest element larger than it.
 *
 * @return {@code true} if a swap was performed (i.e., a next permutation exists)
 */
private boolean processPivot(String[] arr, int start) {
    reverse(arr, start, arr.length);          // make suffix ascending
    for (int j = start; j < arr.length; j++) {
        if (arr[start - 1].compareTo(arr[j]) < 0) {
            swap(arr, start - 1, j);
            return true;
        }
    }
    return false; // Should never happen for a valid pivot, but keeps method safe
}

