/**
 * Returns the maximum value stored in the 3×3 sub‑grid whose
 * top‑left corner is (row, col).
 */
private int maxIn3x3(int[][] map, int row, int col) {
    int max = 0;
    for (int dr = 0; dr < 3; dr++) {
        for (int dc = 0; dc < 3; dc++) {
            max = max(max, map[row + dr][col + dc]);
        }
    }
    return max;
}

