/** Handles a single character while parsing the input line. */
private static void processChar(char c,
                                Deque<Node> stack,
                                StringBuilder num,
                                Tree tree) {
    switch (c) {
        case '[':
            handleOpenBracket(stack);
            break;
        case ']':
            handleCloseBracket(stack, num, tree);
            break;
        default:
            // accumulate digits (or any other characters) that belong to a number
            num.append(c);
    }
}

/** Creates a new node for '[' and attaches it to the current parent if any. */
private static void handleOpenBracket(Deque<Node> stack) {
    Node node = new Node();

    if (!stack.isEmpty()) {
        Node parent = stack.peek();
        node.parent = parent;
        parent.children.add(node);
    }

    stack.push(node);
}

/** Finalises the current node for ']' and updates the tree/root when needed. */
private static void handleCloseBracket(Deque<Node> stack,
                                       StringBuilder num,
                                       Tree tree) {
    if (num.length() > 0) {
        stack.peek().nums.add(Integer.parseInt(num.toString()));
        num.setLength(0);
    }

    if (stack.size() != 1) {
        stack.pop();
    } else {
        tree.root = stack.pop();
    }
}

