/**
 * Builds the prefix‑sum array of Wu‑values for a given query mask.
 * The result array has length 1201 where index i stores the total count of
 * elements in S whose Wu‑value (for this mask) is ≤ i.
 */
private static int[] computeWuPrefixSum(int queryMask, int[] S) {
    int[] freq = new int[1201];          // frequency of each Wu‑value
    int limit = 1 << n;                  // total number of possible masks

    for (int j = 0; j < limit; j++) {
        int count = S[j];
        if (count == 0) {
            continue;                    // guard‑clause, no need for extra nesting
        }
        int wu = getWuValue(queryMask, j);
        freq[wu] += count;
    }

    // turn frequencies into a cumulative (prefix) sum
    for (int i = 1; i < freq.length; i++) {
        freq[i] += freq[i - 1];
    }
    return freq;
}

