/**
 * Builds the prefix‑sum array of Wu‑values for a given query mask.
 *
 * @param queryMask the mask of the current query
 * @param S         frequency array of the original masks
 * @return an int[1201] where each position holds the cumulative count
 *         of masks whose Wu‑value ≤ index
 */
private static int[] buildWuValues(int queryMask, int[] S) {
    int[] wuValues = new int[1201];
    int limit = 1 << n;               // n is a class‑level field
    for (int mask = 0; mask < limit; mask++) {
        int cnt = S[mask];
        if (cnt == 0) {
            continue;                 // guard clause – no deeper nesting
        }
        int value = getWuValue(queryMask, mask);
        wuValues[value] += cnt;
    }
    // Convert to prefix sums
    for (int i = 1; i < wuValues.length; i++) {
        wuValues[i] += wuValues[i - 1];
    }
    return wuValues;
}

