/* Helper that counts the needed pieces for a single row */
private static void processRow(String row, Stats stats) {
    int dots = 0;
    for (int j = 0; j < row.length(); j++) {
        char c = row.charAt(j);
        if (c != '.') {
            // Non‑dot: finalize the run of dots seen so far
            stats.ones += dots % 2;
            stats.twos += dots / 2;
            dots = 0;
            continue;                 // guard‑clause – no deeper nesting
        }
        // Dot case
        dots++;
        stats.totalDots++;
    }
    // Finalise any trailing dots in the row
    stats.ones += dots % 2;
    stats.twos += dots / 2;
}

