/**
 * Adds characters that are directly adjacent (up, down, left, right)
 * to the provided set, guarding against out‑of‑bounds access.
 */
private static void addAdjacentChars(char[][] grid, int row, int col,
                                     int rows, int cols, HashSet<Character> set) {
    if (row > 0) {
        set.add(grid[row - 1][col]);          // up
    }
    if (row < rows - 1) {
        set.add(grid[row + 1][col]);          // down
    }
    if (col > 0) {
        set.add(grid[row][col - 1]);          // left
    }
    if (col < cols - 1) {
        set.add(grid[row][col + 1]);          // right
    }
}

