private static void collectNeighbors(int i, int j, char[][] grid, Set<Character> set) {
    addIfValid(i - 1, j, grid, set); // up
    addIfValid(i + 1, j, grid, set); // down
    addIfValid(i, j - 1, grid, set); // left
    addIfValid(i, j + 1, grid, set); // right
