private static int countRectanglesFrom(int fromX, int fromY, boolean[][] grid, int k) {
    int r = grid.length;
    int c = grid[0].length;
    int count = 0;

    for (int toX = fromX; toX < r; toX++) {
        for (int toY = fromY; toY < c; toY++) {
            int marked = countMarkedInRect(grid, fromX, fromY, toX, toY);
            if (marked < k) {
                continue;               // guard clause – skip rectangles that don’t satisfy the condition
            }
            count++;
        }
    }
    return count;
}

