/**
 * Counts how many substrings that start at {@code startIdx} (which holds a '1')
 * satisfy the condition (r‑l)+length >= binaryValue.
 * The search is limited to length ≤ 20 and stays inside the string.
 */
private static long countValidSubstrings(String s, int startIdx, int l, int r) {
    long count = 0;
    int maxLen = Math.min(20, s.length() - startIdx);

    for (int len = 1; len <= maxLen; len++) {
        int value = binaryValue(s, startIdx, len);
        if ((r - l) + len >= value) {
            count++;
        }
    }
    return count;
}

/**
 * Returns the integer value of the binary substring {@code s[start, start+len)}.
 * The substring contains only '0' and '1'.
 */
private static int binaryValue(String s, int start, int len) {
    int val = 0;
    int end = start + len;
    for (int i = start; i < end; i++) {
        val = (val << 1) + (s.charAt(i) == '1' ? 1 : 0);
    }
    return val;
}

