public static void main(String[] args) {
    Scanner input = new Scanner(System.in);
    int h = input.nextInt();
    int w = input.nextInt();
    input.nextLine();

    char[][] picture = new char[h][w];
    for (int i = 0; i < h; i++) {
        String line = input.nextLine();
        picture[i] = line.toCharArray();          // each line has exactly w characters
    }

    boolean answer = false;
    boolean ran = false;

    outer:
    for (int i = 1; i < h - 1; i++) {
        for (int j = 1; j < w - 1; j++) {
            if (!ran && isCrossCenter(picture, i, j)) {
                answer = true;
                clearCross(picture, i, j, h, w);
                ran = true;
                break outer;                       // no further centres are considered
            }
        }
    }

    // any remaining '*' means the picture is not a single cross
    for (int i = 0; i < h && answer; i++) {
        for (int j = 0; j < w; j++) {
            if (picture[i][j] == '*') {
                answer = false;
                break;
            }
        }
    }

    System.out.println(answer ? "YES" : "NO");
}

/**
 * Returns true if the cell (i,j) and its four orthogonal neighbours are '*'.
 */
private static boolean isCrossCenter(char[][] pic, int i, int j) {
    return pic[i][j] == '*'
            && pic[i + 1][j] == '*'
            && pic[i - 1][j] == '*'
            && pic[i][j - 1] == '*'
            && pic[i][j + 1] == '*';
}

/**
 * Replaces the centre and all contiguous '*' in the four directions with '.'.
 */
private static void clearCross(char[][] pic, int i, int j, int h, int w) {
    pic[i][j] = '.';

    for (int d = i + 1; d < h && pic[d][j] == '*'; d++) {
        pic[d][j] = '.';
    }
    for (int e = i - 1; e >= 0 && pic[e][j] == '*'; e--) {
        pic[e][j] = '.';
    }
    for (int p = j + 1; p < w && pic[i][p] == '*'; p++) {
        pic[i][p] = '.';
    }
    for (int f = j - 1; f >= 0 && pic[i][f] == '*'; f--) {
        pic[i][f] = '.';
    }
}

