public static void main(String[] args) throws IOException {
    BufferedReader fin = new BufferedReader(new InputStreamReader(System.in));
    StringTokenizer st = new StringTokenizer(fin.readLine());
    int N = Integer.parseInt(st.nextToken());
    int K = Integer.parseInt(st.nextToken());
    int[] days = new int[N];

    st = new StringTokenizer(fin.readLine());
    for (int i = 0; i < N; i++) {
        days[i] = Integer.parseInt(st.nextToken());
    }

    int negativeCount = 0;
    for (int d : days) {
        if (d < 0) {
            negativeCount++;
        }
    }

    System.out.println(computeMinimumOperations(days, K, negativeCount));
}

/**
 * Returns the minimal number of operations required, or -1 if impossible.
 */
private static int computeMinimumOperations(int[] days, int K, int negativeCount) {
    if (negativeCount > K) {
        return -1;
    }

    int left = K - negativeCount;     // remaining changes we can spend
    int current = 0;                  // length of the trailing positive segment
    int[] change = new int[days.length];
    int j = 0;
    boolean start = false;           // true once we have seen the first negative

    // Build lengths of positive segments that appear **after** each negative day
    for (int i = 0; i < days.length; i++) {
        if (days[i] < 0) {
            change[j] = current;
            current = 0;
            j++;
            start = true;
        } else if (start) {
            current++;
        }
    }

    Arrays.sort(change);

    // Use the smallest segment lengths first
    for (int i = 0; i < days.length; i++) {
        if (change[i] <= left) {
            left -= change[i];
            change[i] = 0;
        } else {
            break;
        }
    }

    int tot = 0;
    for (int len : change) {
        if (len > 0) {
            tot += 2;                 // each remaining segment costs two operations
        }
    }

    if (start) {
        tot++;                       // the first negative day adds one operation
    }

    if (current > left) {
        tot++;                       // trailing segment that couldn't be fully covered
    }

    return tot;
}

