/**
 * Builds the transposed character matrix, computes the start‑position
 * indicator matrix, collects those positions and invokes {@code count2}
 * for each of them.
 */
private static void processTransposedGrid(int n, int m, String[] a) {
    // re‑initialise shared buffers for the transposed view
    ind = new int[m][n];
    ch = new char[m][n];
    ai = new int[n * m];
    aj = new int[n * m];

    // transpose the original grid
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            ch[j][i] = a[i].charAt(j);
        }
    }

    // compute indicator matrix for the transposed grid
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (j == 0 && ch[i][j] == '.') {
                ind[i][j] = 1;
            }
            if (j - 1 >= 0 && ch[i][j - 1] == '*' && ch[i][j] == '.') {
                ind[i][j] = 1;
            }
        }
    }

    // collect coordinates where ind == 1
    int l = 0;
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (ind[i][j] == 1) {
                ai[l] = i;
                aj[l++] = j;
            }
        }
    }

    // invoke count2 for each collected coordinate
    for (int i = 0; i < l; i++) {
        count2(ai[i], aj[i], 1);
    }
}

