public static void main(String[] args) {
    Scanner in = new Scanner(System.in);

    int n = in.nextInt();
    int m = in.nextInt();
    int k = in.nextInt();

    boolean[][] table = new boolean[Math.max(n, m)][Math.min(n, m)];
    for (int x = 0; x < n; x++) {
        for (int y = 0; y < m; y++) {
            if (n >= m) {
                table[x][y] = in.nextInt() == 1;
            } else {
                table[y][x] = in.nextInt() == 1;
            }
        }
    }

    n = table.length;
    m = table[0].length;

    int result = n * m;

    if (n <= k) {
        for (int mask = 0; mask < (1 << m); mask++) {
            int current = 0;

            // flip first row according to mask
            for (int col = 0; col < m; col++) {
                if ((mask & (1 << col)) != 0) {
                    table[0][col] = !table[0][col];
                    current++;
                }
            }

            // cost of aligning remaining rows to the (already possibly flipped) first row
            current += costUsingFirstRow(table);
            result = Math.min(result, current);

            // revert first row to original state
            for (int col = 0; col < m; col++) {
                if ((mask & (1 << col)) != 0) {
                    table[0][col] = !table[0][col];
                }
            }
        }
    } else {
        for (int ref = 0; ref < table.length; ref++) {
            int current = costUsingReferenceRow(table, ref);
            result = Math.min(result, current);
        }
    }

    System.out.println(result > k ? -1 : result);
}

/** Computes the total flips needed when the current state of table[0] is the reference row. */
private static int costUsingFirstRow(boolean[][] table) {
    int m = table[0].length;
    int total = 0;
    for (int r = 1; r < table.length; r++) {
        int diff = 0;
        for (int c = 0; c < m; c++) {
            if (table[r][c] != table[0][c]) {
                diff++;
            }
        }
        total += Math.min(diff, m - diff);
    }
    return total;
}

/** Computes the total flips needed when row 'ref' is used as the reference. */
private static int costUsingReferenceRow(boolean[][] table, int ref) {
    int m = table[0].length;
    int total = 0;
    for (int r = 0; r < table.length; r++) {
        int diff = 0;
        for (int c = 0; c < m; c++) {
            if (table[r][c] != table[ref][c]) {
                diff++;
            }
        }
        total += Math.min(diff, m - diff);
    }
    return total;
}

public static void main(String[] args) {
    Scanner in = new Scanner(System.in);
    int n = in.nextInt();
    int m = in.nextInt();
    int k = in.nextInt();

    boolean[][] table = new boolean[Math.max(n, m)][Math.min(n, m)];
    for (int x = 0; x < n; x++) {
        for (int y = 0; y < m; y++) {
            if (n >= m) {
                table[x][y] = in.nextInt() == 1;
            } else {
                table[y][x] = in.nextInt() == 1;
            }
        }
    }

    n = table.length;
    m = table[0].length;
    int result = n * m;

    if (n <= k) {
        for (int mask = 0; mask < (1 << m); mask++) {
            int flips = Integer.bitCount(mask);
            // apply flips to the first row
            for (int col = 0; col < m; col++) {
                if ((mask & (1 << col)) != 0) {
                    table[0][col] = !table[0][col];
                }
            }
            int current = flips + computeCost(table, 0);
            result = Math.min(result, current);
            // revert flips
            for (int col = 0; col < m; col++) {
                if ((mask & (1 << col)) != 0) {
                    table[0][col] = !table[0][col];
                }
            }
        }
    } else {
        for (int row = 0; row < n; row++) {
            int current = computeCost(table, row);
            result = Math.min(result, current);
        }
    }

    System.out.println(result > k ? -1 : result);
}

/**
 * Computes the total cost of making every row look like the reference row.
 * For each non‑reference row the cost is the smaller of:
 *   – number of differing cells
 *   – number of cells that would need to be flipped the opposite way
 *
 * @param t   the boolean matrix (rows × columns)
 * @param ref the index of the reference row
 * @return the accumulated minimal flip count
 */
private static int computeCost(boolean[][] t, int ref) {
    int total = 0;
    int cols = t[0].length;
    for (int r = 0; r < t.length; r++) {
        if (r == ref) continue;
        int diff = 0;
        for (int c = 0; c < cols; c++) {
            if (t[r][c] != t[ref][c]) diff++;
        }
        total += Math.min(diff, cols - diff);
    }
    return total;
}

