/**
 * Builds the two pattern matrices used by the solution.
 * <p>
 * {@code first} follows a checker‑board pattern that repeats every two rows.
 * {@code second} is the bitwise complement of {@code first}.
 *
 * @param n      the dimension of the square matrices
 * @param first  matrix to be filled with the base pattern
 * @param second matrix to be filled with the complement of {@code first}
 */
private static void buildPatterns(int n, char[][] first, char[][] second) {
    // initialise the first two rows of the pattern
    first[0][0] = '0';
    if (n > 1) {
        first[1][0] = '1';
    }

    // fill first row alternating 0/1
    for (int col = 1; col < n; col++) {
        first[0][col] = (first[0][col - 1] == '0') ? '1' : '0';
    }

    // fill second row (if it exists) alternating 0/1
    if (n > 1) {
        for (int col = 1; col < n; col++) {
            first[1][col] = (first[1][col - 1] == '0') ? '1' : '0';
        }
    }

    // repeat the first two rows for the rest of the matrix
    for (int row = 2; row < n; row++) {
        first[row] = first[row - 2];
    }

    // second pattern is the complement of the first
    for (int row = 0; row < n; row++) {
        for (int col = 0; col < n; col++) {
            second[row][col] = (first[row][col] == '0') ? '1' : '0';
        }
    }
}

