/**
 * Scans the array looking for matching positive/negative pairs.
 * Returns the number of valid groups found, or -1 if the input is invalid.
 * On success, {@code splitIndices} is filled with the end‑index of each group.
 */
private static int processArray(int[] arr, List<Integer> splitIndices) {
    Map<Integer, Integer> map = new HashMap<>();
    int count = 0;
    int one = 0;          // number of unmatched positive values
    int two = 0;          // number of matched pairs in current segment
    int pre = -1;         // index of previous segment end

    for (int i = 0; i < arr.length; i++) {
        int val = arr[i];
        if (val > 0) {
            if (!map.containsKey(val)) {
                map.put(val, 1);
                one++;
            } else {
                return -1;                     // duplicate positive value
            }
        } else { // val < 0
            int pos = -val;
            Integer status = map.get(pos);
            if (status != null && status > 0) {
                map.put(pos, 0);
                two++;
                one--;

                if (i - pre == 2 * two) {    // segment completed
                    pre = i;
                    count++;
                    splitIndices.add(i);
                    one = 0;
                    two = 0;
                    map = new HashMap<>();
                }
            } else {
                return -1;                     // unmatched or already used negative
            }
        }
    }

    // after the loop any remaining unmatched positive makes the input invalid
    for (Integer key : map.keySet()) {
        if (key > 0) {
            return -1;
        }
    }
    return count;
}

