/**
 * Builds the required answer for the current candidate length {@code i},
 * prints it, and returns {@code true} if the outer search loop should stop.
 */
private static boolean handleValidCandidate(int i, int[] cnta, char[] b, PrintWriter pw) {
    int first = 0;
    for (int d = 1; d < 10; d++) {
        if (cnta[d] > 0) {
            first = d;
            break;
        }
    }

    if (first == 0 && b[0] == '0' && i != 1) return false; // not a valid candidate

    if (first > 0) {
        int[] ans = new int[i];
        int size = 0;
        cnta[first]--;
        ans[size++] = first;

        boolean bigger = false;
        for (int j = 1; j < b.length; j++) {
            if (b[j] != b[0]) {
                if (b[j] > b[0]) bigger = true;
                break;
            }
        }

        for (int d = 0; d < 10; d++) {
            if (d == b[0] - '0' && !bigger) {
                for (int j = 0; j < b.length; j++) ans[size++] = b[j] - '0';
            }
            for (int c = 0; c < cnta[d]; c++) ans[size++] = d;
            if (d == b[0] - '0' && bigger) {
                for (int j = 0; j < b.length; j++) ans[size++] = b[j] - '0';
            }
        }

        if (b[0] > '0') {
            int[] alt = new int[i];
            int altSize = 0;
            for (int j = 0; j < b.length; j++) alt[altSize++] = b[j] - '0';
            cnta[first]++; // restore for alternative construction
            for (int d = 0; d < 10; d++) {
                for (int c = 0; c < cnta[d]; c++) alt[altSize++] = d;
            }
            // choose the lexicographically larger array
            for (int p = 0; p < altSize; p++) {
                if (ans[p] > alt[p]) break;
                if (ans[p] < alt[p]) {
                    ans = alt.clone();
                    break;
                }
            }
        }

        for (int j = 0; j < size; j++) pw.print(ans[j]);
    } else {
        for (char c : b) pw.print(c);
        for (int z = 1; z <= cnta[0]; z++) pw.print(0);
    }
    return true;
}

