/**
 * Populates the colour‑match count arrays (R, G, B) and their
 * prefix‑sum equivalents (s_r, s_g, s_b) for the given string.
 *
 * For each position i the arrays indicate whether the character at i
 * matches the expected colour of the three possible patterns:
 *   pattern 0: R G B R G B ...
 *   pattern 1: G B R G B R ...
 *   pattern 2: B R G B R G ...
 *
 * The prefix sums allow O(1) range queries later in the algorithm.
 */
private static void fillCountsAndPrefixes(char[] res, int n,
                                          int[] R, int[] G, int[] B,
                                          int[] s_r, int[] s_g, int[] s_b) {
    for (int i = 0 ; i < n ; i++) {
        // pattern 0 (starts with R)
        if ((i % 3) == 0 && res[i] == 'R') R[i]++;
        if ((i % 3) == 1 && res[i] == 'G') R[i]++;
        if ((i % 3) == 2 && res[i] == 'B') R[i]++;

        // pattern 1 (starts with G)
        if ((i % 3) == 0 && res[i] == 'G') G[i]++;
        if ((i % 3) == 1 && res[i] == 'B') G[i]++;
        if ((i % 3) == 2 && res[i] == 'R') G[i]++;

        // pattern 2 (starts with B)
        if ((i % 3) == 0 && res[i] == 'B') B[i]++;
        if ((i % 3) == 1 && res[i] == 'R') B[i]++;
        if ((i % 3) == 2 && res[i] == 'G') B[i]++;

        if (i > 0) {
            s_r[i] = s_r[i-1] + R[i];
            s_g[i] = s_g[i-1] + G[i];
            s_b[i] = s_b[i-1] + B[i];
        } else {
            s_r[i] = R[i];
            s_g[i] = G[i];
            s_b[i] = B[i];
        }
    }
}

