    FastScanner in = new FastScanner(System.in);
    PrintWriter out = new PrintWriter(System.out);
    int R = in.nextInt();
    int C = in.nextInt();
    boolean[][] board = new boolean[R][C];

    for (int i = 0; i < R; i++) {
        String g = in.next();
        for (int j = 0; j < C; j++) {
            if (g.charAt(j) == '*')
                board[i][j] = true;
        }
    }

    int[][] q = new int[R][C];
    int[][] w = new int[R][C];
    int[][] e = new int[R][C];
    int[][] r = new int[R][C];

    // forward pass: counts upward and leftward
    for (int i = 1; i < R - 1; i++) {
        for (int j = 1; j < C - 1; j++) {
            if (board[i][j]) {
                if (board[i - 1][j])
                    q[i][j] = q[i - 1][j] + 1;
                if (board[i][j - 1])
                    w[i][j] = w[i][j - 1] + 1;
            }
        }
    }

    // backward pass: counts downward and rightward
    for (int i = R - 2; i >= 1; i--) {
        for (int j = C - 2; j >= 1; j--) {
            if (board[i][j]) {
                if (board[i + 1][j])
                    e[i][j] = e[i + 1][j] + 1;
                if (board[i][j + 1])
                    r[i][j] = r[i][j + 1] + 1;
            }
        }
    }

    List<int[]> x = new LinkedList<>();
    for (int i = 1; i < R - 1; i++) {
        for (int j = 1; j < C - 1; j++) {
            int result = Math.min(Math.min(q[i][j], w[i][j]), Math.min(e[i][j], r[i][j]));
            if (result > 0)
                x.add(new int[]{i + 1, j + 1, result});
        }
    }

    // -------------------- extracted validation --------------------
    verifyCoverage(board, x, R, C);
    // ----------------------------------------------------------------

    StringBuilder sb = new StringBuilder();
    sb.append(x.size()).append('\n');
    for (int[] temp : x)
        sb.append(temp[0]).append(' ').append(temp[1]).append(' ').append(temp[2]).append('\n');

    out.print(sb.toString());
    out.close();
}

/**
 * Builds the reconstructed board from the detected crosses and
 * checks whether it matches the original board. If a mismatch is found,
 * prints -1 and terminates the program (behaviour preserved).
 */
private static void verifyCoverage(boolean[][] board, List<int[]> crosses, int R, int C) {
    boolean[][] comp = new boolean[R][C];
    for (int[] temp : crosses) {
        int a = temp[0] - 1;   // convert to 0‑based
        int b = temp[1] - 1;
        int size = temp[2];
        comp[a][b] = true;
        for (int i = 1; i <= size; i++) {
            comp[a - i][b] = true;
            comp[a + i][b] = true;
            comp[a][b - i] = true;
            comp[a][b + i] = true;
        }
    }

    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            if (board[i][j] != comp[i][j]) {
                System.out.println(-1);
                System.exit(0);
            }
        }
    }
}

