private static boolean isMirrorPair(char left, char right) {
    // identical characters that are symmetric
    if (left == right) {
        return "AHIMOTUVWXY".indexOf(left) >= 0   // uppercase symmetric set
            || "ovwx".indexOf(left) >= 0;         // lowercase symmetric set
    }
    // cross‑character mirror pairs
    return (left == 'b' && right == 'd') ||
           (left == 'd' && right == 'b') ||
           (left == 'p' && right == 'q') ||
           (left == 'q' && right == 'p');
}

