/**
 * Handles the transition from cell (tr,tc) to its neighbour (nr,nc) according
 * to the direction index.
 *
 * @param dirIdx   0‑down, 1‑right, 2‑up, 3‑left
 * @param tr       current row
 * @param tc       current column
 * @param nr       neighbour row
 * @param nc       neighbour column
 * @param x        remaining horizontal moves matrix
 * @param y        remaining vertical moves matrix
 * @param lost     best known loss for each cell
 * @param heap     priority queue used by Dijkstra‑like search
 * @param curLoss  loss incurred to reach (tr,tc)
 */
private static void processNeighbour(int dirIdx, int tr, int tc, int nr, int nc,
                                     long[][] x, long[][] y, int[][] lost,
                                     PriorityQueue<Node> heap, int curLoss) {
    // vertical movement (dirIdx 0 or 2) – no cost, values unchanged
    if (dirIdx % 2 == 0) {
        x[nr][nc] = x[tr][tc];
        y[nr][nc] = y[tr][tc];
        if (curLoss < lost[nr][nc]) {
            heap.add(new Node(nr, nc, curLoss));
            lost[nr][nc] = curLoss;
        }
        return;
    }

    // left movement (dirIdx == 3) – consumes one horizontal move if available
    if (dirIdx == 3 && x[tr][tc] > 0) {
        x[nr][nc] = x[tr][tc] - 1;
        y[nr][nc] = y[tr][tc];
        if (curLoss + 1 < lost[nr][nc]) {
            heap.add(new Node(nr, nc, curLoss + 1));
            lost[nr][nc] = curLoss + 1;
        }
        return;
    }

    // right movement (dirIdx == 1) – consumes one vertical move if available
    if (dirIdx == 1 && y[tr][tc] > 0) {
        x[nr][nc] = x[tr][tc];
        y[nr][nc] = y[tr][tc] - 1;
        if (curLoss + 1 < lost[nr][nc]) {
            heap.add(new Node(nr, nc, curLoss + 1));
            lost[nr][nc] = curLoss + 1;
        }
    }
}

