/**
 * Examines the four orthogonal neighbours of {@code cur} and updates
 * the state (x, y, lost, heap) according to the problem rules.
 */
private static void exploreNeighbors(Node cur, int n, int m, String[] grid,
                                    long[][] x, long[][] y, int[][] lost,
                                    PriorityQueue<Node> heap) {
    int[] dr = {1, 0, -1, 0};
    int[] dc = {0, 1, 0, -1};

    for (int i = 0; i < 4; i++) {
        int nr = cur.x + dr[i];
        int nc = cur.y + dc[i];

        if (nr < 0 || nr >= n || nc < 0 || nc >= m)
            continue;
        if (grid[nr].charAt(nc) == '*')
            continue;

