        else if (dc[i] == -1 && x[cur.x][cur.y] > 0) {
            x[nr][nc] = x[cur.x][cur.y] - 1;
            y[nr][nc] = y[cur.x][cur.y];
            if (cur.l + 1 < lost[nr][nc]) {
