                lost[nr][nc] = cur.l + 1;
            }
        }
        // move right, consumes one y‑token
        else if (dc[i] == 1 && y[cur.x][cur.y] > 0) {
            x[nr][nc] = x[cur.x][cur.y];
            y[nr][nc] = y[cur.x][cur.y] - 1;
            if (cur.l + 1 < lost[nr][nc]) {
                heap.add(new Node(nr, nc, cur.l + 1));
                lost[nr][nc] = cur.l + 1;
