void solve() {
		int n = in.nextInt();
		int k = in.nextInt();
		String s = in.next();
		int[] pow = new int[n + 1];
		int[] hash = new int[n + 1];
		pow[0] = 1;
		for (int i = 1; i <= n; i++) {
			pow[i] = (int) (pow[i - 1] * 1L * mul % mod);
		}
		for (int i = 1; i <= n; i++) {
			hash[i] = (int) ((hash[i - 1] * 1L * mul + s.charAt(i - 1)) % mod);
		}
		int[] maxPref = new int[n];
		for (int len = 1; len <= n; len++) {
			if (len * k > n) {
				break;
			}
			long needHash = hash[len];
			long powTmp = pow[len];
			boolean ok = true;
			for (int i = 1; i < k; i++) {
				long curHash = (hash[len * (i + 1)] - hash[len * i] * powTmp)
						% mod;
				if (curHash < 0) {
					curHash += mod;
				}
				if (curHash != needHash) {
					ok = false;
					break;
				}
			}
			if (ok) {
				maxPref[len * k - 1] = len;
			}
		}
		int[] sum = new int[n];
		for (int i = 0; i < n; i++) {
			if (maxPref[i] == 0) {
				continue;
			}
			sum[i]++;
			int left = 0, right = maxPref[i] + 1;
			right = Math.min(right, n - i);
			while (right - left > 1) {
				int mid = (right + left) >> 1;
				long curHash = (hash[i + mid + 1] - hash[i + 1] *1L* pow[mid])
						% mod;
				if (curHash < 0) {
					curHash += mod;
				}
				if (curHash == hash[mid]) {
					left = mid;
				} else {
					right = mid;
				}
			}
			maxPref[i] = left;
			int next = i + maxPref[i] + 1;
			if (next < n) {
				sum[next]--;
			}
		}
