/**
 * Determines the type of the given line according to the original specification.
 * Returns 1 for type A, 2 for type B, or -1 for an invalid line.
 */
private int parseType(String line) {
    if (line == null || line.length() < 2) {
        return -1;
    }

    String prefix = line.substring(0, 2);
    if (prefix.equals(">'")) {                     // handle >' pattern
        int count = 0;
        int sharp = 0;

        for (int i = 2; i < line.length(); i++) {
            char c = line.charAt(i);

            if (c == '=') {
                count++;
            } else if (c == '#') {
                if (count > 0) {
                    count = -count;
                    sharp = 1;
                } else {
                    return -1;
                }
            } else if (c == '~') {
                if (i != line.length() - 1) {
                    return -1;
                }
                return (count == 0 && sharp == 1) ? 1 : -1;
            } else {
                return -1;
            }
        }
    } else if (prefix.equals(">^")) {              // handle >^ pattern
        int count = 0;

        for (int i = 2; i < line.length(); i++) {
            char c = line.charAt(i);

            // look for the terminating "~~"
            if (count % 2 == 0 && count >= 2 && c == '~') {
                if (i == line.length() - 1) {
                    return -1;
                }
                return (line.charAt(i + 1) == '~') ? 2 : -1;
            }

            // alternating Q and = characters
            if (i % 2 == 0) {               // even index after the prefix
                if (c != 'Q') {
                    return -1;
                }
                count++;
            } else {                         // odd index after the prefix
                if (c != '=') {
                    return -1;
                }
                count++;
            }

            // any other character is illegal
            if (c != 'Q' && c != '=' && c != '~') {
                return -1;
            }
        }
    }

    return -1;   // not matching any valid pattern
}

