 * vertices in the DSU. It returns the index of the first edge that
 * does *not* belong to the processed group.
 */
private static int processEqualCostGroup(int startIdx, Edge baseEdge,
                                         ArrayList<Integer> nodes) {
    int nextId = startIdx + 1;
    boolean hasNonTree = false;

    counter = 0;
    nodes.clear();

    while (nextId < edges.size() && edges.get(nextId).cost == baseEdge.cost) {
        Edge cur = edges.get(nextId);
        if (!dsu.isSameSet(cur.u, cur.v)) {
            hasNonTree = true;
            col[nextId] = 1;

            int pu = dsu.getParent(cur.u);
            int pv = dsu.getParent(cur.v);
            graph[pu].add(new Edge(pu, pv, cur.cost, cur.id));
            graph[pv].add(new Edge(pv, pu, cur.cost, cur.id));

            dfsnum[pu] = -1;
            dfsnum[pv] = -1;
            dfslow[pu] = -1;
            dfslow[pv] = -1;

            nodes.add(pu);
            nodes.add(pv);
        } else {
            col[nextId] = 0;
        }
        ++nextId;
    }

    if (hasNonTree) {
        // add the base edge to the temporary graph
        int pu = dsu.getParent(baseEdge.u);
        int pv = dsu.getParent(baseEdge.v);
        nodes.add(pu);
        nodes.add(pv);
        graph[pu].add(new Edge(pu, pv, baseEdge.cost, baseEdge.id));
        graph[pv].add(new Edge(pv, pu, baseEdge.cost, baseEdge.id));

        // run DFS from every untouched node in the group
        for (Integer a : nodes) {
            if (dfsnum[a] == -1) dfs(a, -1);
        }
    } else {
        col[baseEdge.id] = 2;
    }

    // clean temporary structures for the whole group
    for (int j = startIdx; j < nextId; j++) {
        Edge eg = edges.get(j);
        int pu = dsu.getParent(eg.u);
        int pv = dsu.getParent(eg.v);
        graph[pu].clear();
        graph[pv].clear();
        dfsnum[pu] = -1;
        dfsnum[pv] = -1;
        dfslow[pu] = -1;
        dfslow[pv] = -1;
    }

    // finally unite all edges of the group in the DSU
    for (int j = startIdx; j < nextId; j++) {
        Edge eg = edges.get(j);
        dsu.union(eg.u, eg.v);
    }

    return nextId;
}

