/** Returns a two‑element array: [firstPlayerWins, secondPlayerWins] */
private boolean[] detectWins(String[] board) {
    boolean win1 = false, win2 = false;
    // rows
    for (int r = 0; r < 3; ++r) {
        if (board[r].charAt(0) == board[r].charAt(1) && board[r].charAt(1) == board[r].charAt(2)) {
            char c = board[r].charAt(0);
            if (c == 'X') win1 = true;
            else if (c == '0') win2 = true;
        }
