        if (board[0].charAt(c) == board[1].charAt(c) && board[1].charAt(c) == board[2].charAt(c)) {
            char ch = board[0].charAt(c);
            if (ch == 'X') win1 = true;
            else if (ch == '0') win2 = true;
        }
    }
    // main diagonal
    if (board[0].charAt(0) == board[1].charAt(1) && board[1].charAt(1) == board[2].charAt(2)) {
        char c = board[0].charAt(0);
        if (c == 'X') win1 = true;
        else if (c == '0') win2 = true;
    }
    // anti‑diagonal
    if (board[0].charAt(2) == board[1].charAt(1) && board[1].charAt(1) == board[2].charAt(0)) {
        char c = board[0].charAt(2);
