/**
 * Handles the contribution of the i‑th bit of {@code n}.
 *
 * @param i         the current bit index
 * @param n         the target number
 * @param powers    array where powers[j] is the count of 2^j available
 * @param ansHolder single‑element array used to accumulate the answer
 * @return {@code true} if the bit can be satisfied, {@code false} otherwise
 */
private static boolean processBit(int i, long n, int[] powers, long[] ansHolder) {
    long mask = 1L << i;
    if ((n & mask) == 0) return true;                     // bit not required

    long tot = 0L;
    for (int j = 0; j <= i; j++) {
        tot += ((long) powers[j]) << j;                   // sum of available value up to i
    }

    if (tot >= mask) {                                    // we can cover the bit using smaller powers
        long need = mask;
        int start = i;
        while (need > 0 && start >= 0) {
            long unit = 1L << start;
            long have = unit * powers[start];
            if (have < need) {
                need -= have;
                powers[start] = 0;
            } else {
                long req = need / unit;
                need = 0L;
                powers[start] -= (int) req;
            }
            start--;
        }
    } else {                                              // need to break a higher power
        int reqPower = -1;
        for (int j = i + 1; j < powers.length; j++) {
            if (powers[j] > 0) {
                reqPower = j;
                break;
            }
        }
        if (reqPower == -1) return false;                 // impossible
        ansHolder[0] += reqPower - i;                     // count of operations
        powers[reqPower]--;
        for (int j = reqPower - 1; j >= i; j--) {
            powers[j]++;                                   // split the higher power
        }
    }
    return true;
}

