                        allDots+=getDots(used,dsu,i1*n+j+k);
                    }
                }

                for(int j1=j;j1<j+k;j1++){
                    if(i-1>=0&&field[i-1].charAt(j1)=='.'){
                        allDots+=getDots(used,dsu,(i-1)*n+j1);
                    }
                    if(i+k<n&&field[i+k].charAt(j1)=='.'){
                        allDots+=getDots(used,dsu,(i+k)*n+j1);
                    }
                }

                if(i==0&&j==0){
                    for(int i1=i;i1<i+k;i1++){
                        for(int j1=j;j1<j+k;j1++){
                            if(field[i1].charAt(j1)=='.'){
                                components[dsu.find(i1*n+j1)]++;
                                dots++;
                                if(components[dsu.find(i1*n+j1)]==dsu.size[dsu.find(i1*n+j1)]){
                                    except+=components[dsu.find(i1*n+j1)];
                                }
                            }
                        }
                    }
                }else{
                    int newDots = 0;
                    int oldDots = 0;
                    if(j==startJ){
                        for(int j1=j;j1<j+k;++j1){
                            if(field[i-1].charAt(j1)=='.'){
                                if(components[dsu.find((i-1)*n+j1)]==dsu.size[dsu.find((i-1)*n+j1)]){
                                    except-=dsu.size[dsu.find((i-1)*n+j1)];
                                }
                                components[dsu.find((i-1)*n+j1)]--;
                                oldDots++;
                            }
                        }
                        for(int j1=j;j1<j+k;++j1){
                            if(field[i+k-1].charAt(j1)=='.'){
                                components[dsu.find((i+k-1)*n+j1)]++;
                                if(components[dsu.find((i+k-1)*n+j1)]==dsu.size[dsu.find((i+k-1)*n+j1)]){
                                    except+=components[dsu.find((i+k-1)*n+j1)];
                                }
                                newDots++;
                            }
                        }
                    }else{
                        int prev = j-1;
                        int next = j+k-1;
                        if(i%2==1){
                            prev = j+k;
                            next = j;
                        }
                        for(int i1=i;i1<i+k;++i1){

                            if(field[i1].charAt(prev)=='.'){
                                if(components[dsu.find(i1*n+prev)]==dsu.size[dsu.find(i1*n+prev)]){
                                    except-=dsu.size[dsu.find(i1*n+prev)];
                                }
                                components[dsu.find(i1*n+prev)]--;
                                oldDots++;
                            }
                        }
                        for(int i1=i;i1<i+k;++i1){
                            if(field[i1].charAt(next)=='.'){
                                components[dsu.find(i1*n+next)]++;
                                if(components[dsu.find(i1*n+next)]==dsu.size[dsu.find(i1*n+next)]){
                                    except+=components[dsu.find(i1*n+next)];
                                }
                                newDots++;
                            }
                        }
                    }
                    dots+=(newDots-oldDots);
                }






                result = Math.max(result,allDots+k*k-dots+except);
            }
        }
        System.out.println(result);
    }

