		int m=in.nextInt();
		int k=in.nextInt();
		int q=in.nextInt();

		int[][] rec=new int[n][2];
		TreeSet<Integer> set=new TreeSet<>();
		long[][] dp=new long[n][2];
		int end=0;
		for(int[] r:rec) {
			Arrays.fill(r, -1);
		}
		for(int i=0;i<k;i++) {
			int r=in.nextInt()-1;
			int c=in.nextInt()-1;
			end=Math.max(r, end);
			if(rec[r][0]==-1) {
				rec[r][0]=c;
				rec[r][1]=c;
			}else {
				rec[r][0]=Math.min(rec[r][0], c);
				rec[r][1]=Math.max(rec[r][1], c);
			}
		}
		for(int i=0;i<q;i++) set.add(in.nextInt()-1);

		if(rec[0][0]!=-1) {
			dp[0][0]=2*rec[0][1]-rec[0][0];
			dp[0][1]=rec[0][1];
		}else {
			rec[0][0]=0;
			rec[0][1]=0;
		}
		if(end==0) return dp[0][1];
		for(int i=1;;i++) {

			if(rec[i][0]==-1) {
				dp[i][0]=dp[i-1][0]+1;
				dp[i][1]=dp[i-1][1]+1;
				rec[i][0]=rec[i-1][0];
				rec[i][1]=rec[i-1][1];
				continue;
			}
			int s1=rec[i-1][0],e1=rec[i-1][1],s2=rec[i][0],e2=rec[i][1];
			dp[i][0]=999999999999L;
			dp[i][1]=999999999999L;

			Integer a1=set.floor(s2);
			Integer a2=set.ceiling(s2);
			int dis=rec[i][1]-rec[i][0];
			if(a1!=null) {
				dp[i][1]=dp[i-1][0]+Math.abs(s1-a1)+Math.abs(s2-a1)+1+dis;
				dp[i][1]=Math.min(dp[i][1], dp[i-1][1]+Math.abs(e1-a1)+Math.abs(s2-a1)+1+dis);
			}
			if(a2!=null) {
				dp[i][1]=Math.min(dp[i][1], dp[i-1][0]+Math.abs(s1-a2)+Math.abs(s2-a2)+1+dis);
				dp[i][1]=Math.min(dp[i][1], dp[i-1][1]+Math.abs(e1-a2)+Math.abs(s2-a2)+1+dis);
			}


			Integer b1=set.floor(e2);
			Integer b2=set.ceiling(e2);
			if(b1!=null) {
				dp[i][0]=dp[i-1][0]+Math.abs(s1-b1)+Math.abs(e2-b1)+1+dis;
				dp[i][0]=Math.min(dp[i][0], dp[i-1][1]+Math.abs(e1-b1)+Math.abs(e2-b1)+1+dis);
			}
			if(b2!=null) {
				dp[i][0]=Math.min(dp[i][0], dp[i-1][0]+Math.abs(s1-b2)+Math.abs(e2-b2)+1+dis);
				dp[i][0]=Math.min(dp[i][0], dp[i-1][1]+Math.abs(e1-b2)+Math.abs(e2-b2)+1+dis);
			}

			if(i==end) {
				return Math.min(dp[i][0], dp[i][1]);
			}
		}
	}

