				h.get(h.size()-1).x2 = Math.max(h.get(h.size()-1).x2, ht.get(i).x2);
				i++;
			}
		}
		for(int i = 0; i < vt.size();)
		{
			v.add(vt.get(i++));
			while(i < vt.size() && vt.get(i).x1 == v.get(v.size()-1).x1)
			{
				if(vt.get(i).y1 > v.get(v.size()-1).y2) break;
				v.get(v.size()-1).y2 = Math.max(v.get(v.size()-1).y2, vt.get(i).y2);
				i++;
			}
		}
		long ret = 0;
		for(Line l : h)
		{
			ret += (long)l.x2-(long)l.x1+1;
		}
		for(Line l : v)
		{
			ret += (long)l.y2-(long)l.y1+1;
		}
		compress(h, v);
		BIT tree = new BIT(500_000);
		PriorityQueue<Pair> pq = new PriorityQueue<Pair>();
		int ptr = 0;
		Collections.sort(v, new VSort());
		for(int i = 0; i < h.size(); i++)
		{
			while(ptr < v.size() && v.get(ptr).y1 <= h.get(i).y1)
			{
				tree.update(v.get(ptr).x1, 1);
				pq.add(new Pair(v.get(ptr).y2, v.get(ptr).x1));
				ptr++;
			}
			while(pq.size() > 0 && pq.peek().val < h.get(i).y1)
			{
				Pair p = pq.poll();
				tree.update(p.idx, -1);
			}
			ret -= tree.query(h.get(i).x1, h.get(i).x2);
		}
		out.println(ret);
		in.close(); out.close();
	}

