 * points to a valid cell that is also filled.
 */
private static boolean matchesPattern(int i, int j, boolean[][] filled,
                                      int[] di, int[] dj) {
    for (int k = 0; k < di.length; k++) {
        int ni = i + di[k];
        int nj = j + dj[k];
        if (!valid(ni, nj) || !filled[ni][nj]) {
            return false;
        }
    }
    return true;
