            DoubleMap map = new DoubleMap();
            for (int i = 0; i < mapping.size(); i++) {
                map.add(mapping.get(i), i);
            }
            int sz = mapping.size();
            int[][] dp = new int[sz][sz];
            int[][] max_first = new int[7][sz];
            int[][] max_second = new int[sz][7];
            for (int i = 0; i < N; i++) {
                int index = map.get(arr[i]);
                int lower = map.get(arr[i] - 1);
                int higher = map.get(arr[i] + 1);
                dp[index][index] = Math.max(dp[index][index], max_second[index][arr[i] % 7] + 1);
                dp[index][index] = Math.max(dp[index][index], max_first[arr[i] % 7][index] + 1);
                if (lower != -1) {
                    dp[index][index] = Math.max(dp[index][index], Math.max(dp[index][lower], dp[lower][index]) + 1);
                }
                if (higher != -1) {
                    dp[index][index] = Math.max(dp[index][index], Math.max(dp[index][higher], dp[higher][index]) + 1);
                }
                max_first[arr[i] % 7][index] = dp[index][index];
                max_second[index][arr[i] % 7] = dp[index][index];
                for (int j = 0; j < sz; j++) {
                    if (j == index) {
                        continue;
                    }
                    if (lower != -1) {
                        dp[index][j] = Math.max(dp[index][j], dp[lower][j] + 1);
                    }
                    if (higher != -1) {
                        dp[index][j] = Math.max(dp[index][j], dp[higher][j] + 1);
                    }
                    dp[index][j] = Math.max(dp[index][j], max_first[arr[i] % 7][j] + 1);
                    max_first[arr[i] % 7][j] = dp[index][j];
                    max_second[index][mapping.get(j) % 7] = Math.max(max_second[index][mapping.get(j) % 7], dp[index][j]);
                }
                for (int j = 0; j < sz; j++) {
                    if (j == index) {
                        continue;
                    }
                    if (lower != -1) {
                        dp[j][index] = Math.max(dp[j][index], dp[j][lower] + 1);
                    }
                    if (higher != -1) {
                        dp[j][index] = Math.max(dp[j][index], dp[j][higher] + 1);
                    }
                    dp[j][index] = Math.max(dp[index][j], max_second[j][arr[i] % 7] + 1);
                    max_second[j][arr[i] % 7] = dp[index][j];
                    max_first[mapping.get(j) % 7][index] = Math.max(max_first[mapping.get(j) % 7][index], dp[index][j]);
                }
            }
            int res = 0;
            for (int i = 0; i < sz; i++) {
                for (int j = 0; j < sz; j++) {
                    res = Math.max(dp[i][j], res);
                }
            }
            out.println(res);
        }

