			if (a[i] == 1) {
				pos[0][++t1] = i;
				pre[0][i]++;
			} else {
				pos[1][++t2] = i;
				pre[1][i]++;
			}
		}

		for (int t = 1; t <= N; t++) {

			int idx = -1;
			int prevIdx = -1;
			int oneWins = 0, twoWins = 0;
			while (idx < N) {
				prevIdx = idx;
				int seenOnes = idx == -1 ? 0 : pre[0][idx], seenTwos = idx == -1 ? 0 : pre[1][idx];
