/** evaluates a specific set size {@code t}. Returns the winning Pair
 *  or {@code null} if the configuration does not satisfy the rules. */
private static Pair evaluateT(int t, int N, int[] a, int[][] pos, int[][] pre) {
    int idx = -1;
    int prevIdx = -1;
    int oneWins = 0, twoWins = 0;
    while (idx < N) {
        prevIdx = idx;
        int seenOnes = idx == -1 ? 0 : pre[0][idx];
        int seenTwos = idx == -1 ? 0 : pre[1][idx];
        if (t + seenOnes > N || t + seenTwos > N) break;

        int idxOne = pos[0][t + seenOnes];
        int idxTwo = pos[1][t + seenTwos];
        int nxtIdx;
        if (idxOne == -1) nxtIdx = idxTwo;
        else if (idxTwo == -1) nxtIdx = idxOne;
        else nxtIdx = (idxOne < idxTwo) ? idxOne : idxTwo;

        idx = nxtIdx;
        if (idx == -1) break;

        if (a[idx] == 1) oneWins++; else twoWins++;

        int onesInCurrentSet = pre[0][idx] - (prevIdx == -1 ? 0 : pre[0][prevIdx]);
        int twosInCurrentSet = pre[1][idx] - (prevIdx == -1 ? 0 : pre[1][prevIdx]);

        boolean endSet = (a[idx] == 1 && (onesInCurrentSet > t || onesInCurrentSet <= twosInCurrentSet))
                      || (a[idx] == 2 && (twosInCurrentSet > t || twosInCurrentSet <= onesInCurrentSet));
        if (endSet) break;
    }

    if (prevIdx == N - 1) {
        if (oneWins > twoWins && a[N - 1] == 1) return new Pair(oneWins, t);
        if (twoWins > oneWins && a[N - 1] == 2) return new Pair(twoWins, t);
    }
    return null;
}

