/**
 * Determines whether {@code to} is an allowed day relative to {@code from}.
 * The allowed days are:
 *   - the same day,
 *   - the day two positions forward in the week,
 *   - the day three positions forward in the week,
 * with wrap‑around.
 *
 * @param from the starting day
 * @param to   the day to validate
 * @param days ordered list of week days
 * @return {@code true} if {@code to} is allowed, {@code false} otherwise
 */
private static boolean isValidTransition(String from, String to, String[] days) {
    int idx = -1;
    for (int i = 0; i < days.length; i++) {
        if (days[i].equals(from)) {
            idx = i;
            break;
        }
    }
    if (idx == -1) {
        return false; // unknown day
    }
    if (to.equals(days[idx])) {
        return true; // same day
    }
    int second = (idx + 2) % days.length;
    int third  = (idx + 3) % days.length;
    return to.equals(days[second]) || to.equals(days[third]);
}

