/**
 * Computes the diameter of the connected component that contains {@code start},
 * marks all its vertices as visited and stores the diameter in {@code ds.path}
 * for the component’s representative.
 */
private static void processComponent(int start,
                                     ArrayList<Integer>[] adj,
                                     boolean[] visited,
                                     DisjointSet ds) {
    // First BFS – find a farthest node (last) in the component
    visited[start] = true;
    ArrayDeque<Integer> queue = new ArrayDeque<>();
    queue.add(start);

    int last = start;
    while (!queue.isEmpty()) {
        int node = queue.remove();
        last = node;
        for (int next : adj[node]) {
            if (!visited[next]) {
                visited[next] = true;
                queue.add(next);
            }
        }
    }

    // Second BFS – compute the diameter starting from 'last'
    queue.clear();
    queue.add(last);   // node
    queue.add(-1);     // parent placeholder
    queue.add(0);      // distance

    int path = 0;
    while (!queue.isEmpty()) {
        int node = queue.remove();
        int parent = queue.remove();
        int dist = queue.remove();

        if (dist > path) {
            path = dist;
        }

        for (int next : adj[node]) {
            if (next != parent) {
                queue.add(next);
                queue.add(node);
                queue.add(dist + 1);
            }
        }
    }

    ds.path[ds.find(start)] = path;
}

