/**
 * Sorts the {@code keys} array first by descending priority and, for entries with
 * equal priority, lexicographically.
 *
 * @param keys     array of keys to be sorted
 * @param priority map containing priority values for each key
 */
private static void sortKeysByPriorityAndLex(String[] keys, HashMap<String, Integer> priority) {
    // Selection‑sort by priority (descending)
    for (int i = 0; i < keys.length; i++) {
        int max = 0;
        int maxPos = i;
        for (int j = i; j < keys.length; j++) {
            int val = priority.get(keys[j]);
            if (val > max) {
                max = val;
                maxPos = j;
            }
        }
        swap(i, keys, maxPos);
    }

    // For equal‑priority groups, sort lexicographically
    for (int i = 0; i < keys.length - 1; i++) {
        int j;
        for (j = i + 1; j < keys.length; j++) {
            if (!priority.get(keys[j]).equals(priority.get(keys[i]))) {
                break;
            }
        }
        sortLex(i, j, keys);
        i = j - 1; // skip the already‑sorted group
    }
}

