private static String[] orderKeysByPriority(HashMap<String, Integer> priority) {
    String[] keys = priority.keySet().toArray(new String[0]);

    // selection‑sort by priority (descending)
    for (int i = 0; i < keys.length; i++) {
        int max = 0;
        int maxPos = i;
        for (int j = i; j < keys.length; j++) {
            int val = priority.get(keys[j]);
            if (val > max) {
                max = val;
                maxPos = j;
            }
        }
        swap(i, keys, maxPos);
    }

    // stable lexical sort within equal‑priority groups
    for (int i = 0; i < keys.length - 1; i++) {
        int j;
        for (j = i + 1; j < keys.length; j++) {
            if (!priority.get(keys[j]).equals(priority.get(keys[i]))) {
                break;
            }
        }
        sortLex(i, j, keys);
        i = j - 1;
    }
    return keys;
}

