public static void main(String[] args) throws Exception {
    Scanner s = new Scanner(System.in);
    int n = s.nextInt();
    int m = s.nextInt();

    char[][] arr = new char[n][m];
    for (int i = 0; i < n; i++) {
        String str = s.next();
        for (int j = 0; j < m; j++) {
            arr[i][j] = str.charAt(j);
        }
    }

    pair[][] dp = new pair[n][m];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            dp[i][j] = new pair(0, 0, 0, 0);
        }
    }

    // compute up and left counts
    for (int i = 1; i < n; i++) {
        for (int j = 1; j < m; j++) {
            dp[i][j].up = (arr[i - 1][j] == '*') ? dp[i - 1][j].up + 1 : 0;
            dp[i][j].left = (arr[i][j - 1] == '*') ? dp[i][j - 1].left + 1 : 0;
        }
    }

    // compute down and right counts
    for (int i = n - 2; i >= 0; i--) {
        for (int j = m - 2; j >= 0; j--) {
            dp[i][j].down = (arr[i + 1][j] == '*') ? dp[i + 1][j].down + 1 : 0;
            dp[i][j].right = (arr[i][j + 1] == '*') ? dp[i][j + 1].right + 1 : 0;
        }
    }

    int count = 0;
    StringBuilder sb = new StringBuilder();
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (arr[i][j] == '*' || arr[i][j] == 'x') {
                int ans = markCrossIfPossible(i, j, dp, arr, sb);
                if (ans > 0) {
                    count++;
                }
            }
        }
    }

    // check for any remaining '*'
    boolean hasStar = false;
    for (int i = 0; i < n && !hasStar; i++) {
        for (int j = 0; j < m && !hasStar; j++) {
            if (arr[i][j] == '*') {
                hasStar = true;
            }
        }
    }

    if (hasStar) {
        System.out.println(-1);
    } else {
        System.out.println(count);
        System.out.println(sb);
    }
}

/**
 * Determines the maximal size of a cross centred at (i,j).
 * If a cross of positive size exists, marks its arms with 'x',
 * appends the description to the supplied StringBuilder and
 * returns the arm length; otherwise returns 0.
 */
private static int markCrossIfPossible(int i, int j, pair[][] dp, char[][] arr, StringBuilder sb) {
    int upDown = Math.min(dp[i][j].up, dp[i][j].down);
    int leftRight = Math.min(dp[i][j].left, dp[i][j].right);
    int arm = Math.min(upDown, leftRight);

    if (arm == 0) {
        return 0;
    }

    // mark vertical arm
    for (int row = i - arm; row <= i + arm; row++) {
        arr[row][j] = 'x';
    }
    // mark horizontal arm
    for (int col = j - arm; col <= j + arm; col++) {
        arr[i][col] = 'x';
    }

    sb.append(i + 1).append(' ').append(j + 1).append(' ').append(arm).append('\n');
    return arm;
}

