/**
 * Fills {@code row} and {@code column} masks according to the symbols in {@code map}.
 * The logic is identical to the original nested loops in {@code main}.
 */
private static void populateRowAndColumnMasks(char[][] map, int[] row, int[] column) {
    int n = map.length;
    int m = map[0].length;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            switch (map[i][j]) {
                case '1':
                    if (i % 2 == 0) column[j] |= 1; else column[j] |= 2;
                    if (j % 2 == 0) row[i] |= 1; else row[i] |= 2;
                    break;
                case '2':
                    if (i % 2 == 0) column[j] |= 2; else column[j] |= 1;
                    if (j % 2 == 0) row[i] |= 1; else row[i] |= 2;
                    break;
                case '3':
                    if (i % 2 == 0) column[j] |= 2; else column[j] |= 1;
                    if (j % 2 == 0) row[i] |= 2; else row[i] |= 1;
                    break;
                case '4':
                    if (i % 2 == 0) column[j] |= 1; else column[j] |= 2;
                    if (j % 2 == 0) row[i] |= 2; else row[i] |= 1;
                    break;
                default:
                    // '.' or any other character contributes nothing
                    break;
            }
        }
    }
}

