/**
 * Initializes the cell at (i,j) when it has not been processed yet.
 * Returns the updated number of coloured blocks stored in {@code ab}.
 */
private static int handleUnfilledCell(String[] l, Block[][] b, Block black,
                                      Block[] ab, int abc, int i, int j,
                                      int m, int n) {
    if (l[i].charAt(j) == '0') {
        b[i][j] = black;
        // extend black vertically
        for (int ti = i; ti < m && l[ti].charAt(j) == '0'; ti++) {
            b[ti][j] = black;
        }
        // extend black horizontally
        for (int tj = j; tj < n && l[i].charAt(tj) == '0'; tj++) {
            b[i][tj] = black;
        }
    } else {
        char ch = l[i].charAt(j);
        Block nx = new Block();
        nx.color = ch;
        ab[abc++] = nx;

        int di = 0;
        while (i + di < m && l[i + di].charAt(j) == ch) di++;
        int dj = 0;
        while (j + dj < n && l[i].charAt(j + dj) == ch) dj++;

        for (int k = 0; k < dj; k++) {
            for (int o = 0; o < di; o++) {
                b[i + o][j + k] = nx;
            }
        }

        nx.td[0] = new int[]{i, j + dj};
        nx.td[1] = new int[]{i + di - 1, j + dj};
        nx.td[2] = new int[]{i + di, j + dj - 1};
        nx.td[3] = new int[]{i + di, j};
        nx.td[4] = new int[]{i + di - 1, j - 1};
        nx.td[5] = new int[]{i, j - 1};
        nx.td[6] = new int[]{i - 1, j};
        nx.td[7] = new int[]{i - 1, j + dj - 1};
    }
    return abc;
}

