/**
 * Counts the number of set bits for the current bit position inside the range [l, r].
 */
private static long countOnesInRange(int l, int r, int leftB, int rightB,
                                     int[] state, int[] reversed, int[] ones,
                                     int[] bleft, int[] bright) {
    long cnt = 0;
    if (leftB < rightB) {
        // left partial bucket
        for (int i = l; i < bright[leftB]; i++) {
            if (((state[i] + reversed[leftB]) & 1) == 1) {
                cnt++;
            }
        }
        // right partial bucket
        for (int i = bleft[rightB]; i <= r; i++) {
            if (((state[i] + reversed[rightB]) & 1) == 1) {
                cnt++;
            }
        }
        // full buckets in between
        for (int B = leftB + 1; B < rightB; B++) {
            cnt += ones[B];
        }
    } else {
        // single bucket
        for (int i = l; i <= r; i++) {
            if (((state[i] + reversed[leftB]) & 1) == 1) {
                cnt++;
            }
        }
    }
    return cnt;
}

/**
 * Toggles the bits for the current bit position inside the range [l, r] and updates
 * bucket metadata (ones count and lazy reversal flag).
 */
private static void applyToggleInRange(int l, int r, int leftB, int rightB,
                                       int[] state, int[] reversed, int[] ones,
                                       int[] bleft, int[] bright) {
    // materialise pending lazy flips for the left bucket
    ones[leftB] = 0;
    for (int i = bleft[leftB]; i < bright[leftB]; i++) {
        state[i] = (state[i] + reversed[leftB] + ((l <= i && i <= r) ? 1 : 0)) & 1;
        ones[leftB] += state[i];
    }
    reversed[leftB] = 0;

    if (leftB == rightB) {
        return;
    }

    // materialise pending lazy flips for the right bucket
    ones[rightB] = 0;
    for (int i = bleft[rightB]; i < bright[rightB]; i++) {
        state[i] = (state[i] + reversed[rightB] + ((l <= i && i <= r) ? 1 : 0)) & 1;
        ones[rightB] += state[i];
    }
    reversed[rightB] = 0;

    // toggle whole buckets that lie strictly between leftB and rightB
    for (int B = leftB + 1; B < rightB; B++) {
        ones[B] = (bright[B] - bleft[B]) - ones[B];
        reversed[B] = (reversed[B] + 1) & 1;
    }
}

