/**
 * Computes the answer for queries that occur after all possible operations
 * have been performed. The linked list has been exhausted into {@code arr},
 * so the answer is the first element and the element at position {@code v % (n‑1)}.
 */
private static void setAnswerFromArray(long v, int n, int[] arr, int[][] ans, int idx) {
    int el = (int) (v % (n - 1));
    if (el == 0) el = n - 1;
    ans[idx][0] = arr[0];
    ans[idx][1] = arr[el];
}

