private static int findIndex(String s, int k) {
    int count = 0;
    for (int i = 0; i < s.length(); i++) {
        char c = Character.toLowerCase(s.charAt(i));
        if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
            count++;
            if (count == k) {
                return i;
            }
        }
    }
    return -1;
}

