        int p = sieve[value];
        if (seen.add(p)) factors.add(p);
        value /= p;
    }
    return factors;
}

/** Finds the smallest integer ≥ start whose distinct prime factors are all in {@code tr},
 *  removes those factors from {@code tr}, and returns the integer. */
private int findNextAndConsume(int start, TreeSet<Integer> tr, int[] sieve) {
    for (int j = start; j < 200_000 + 1; j++) {
        List<Integer> primes = distinctPrimeFactors(j, sieve);
        boolean missing = false;
        for (int p : primes) {
            if (!tr.contains(p)) {
                missing = true;
                break;
            }
        }
        if (!missing) {
            for (int p : primes) tr.remove(p);
            return j;
        }
    }
    return start; // should never be reached with valid input
}

