/* verifies that every element of b exists in a */
private static boolean allElementsPresent(long[] a, long[] b) {
    HashMap<Long, Integer> map = new HashMap<>();
    for (long v : a) map.put(v, 0);
    for (long v : b) {
        if (!map.containsKey(v)) {
            return false;
        }
    }
    return true;
}

/* scans all three parts (before first b, between b’s, after last b) */
private static boolean processSegments(long[] a, long[] b) {
    int i = 0;

    // --- part before the first element of b ---
    boolean big = false;
    int ic = 0;
    while (a[i] != b[0]) {
        if (a[i] > b[0]) big = true;
        ic++;
        i++;
    }
    if (!validateSegment(big, ic)) return false;

    // --- parts between consecutive elements of b ---
    for (int j = 0; j < b.length - 1; j++) {
        big = false;
        ic = 0;
        long limit = Math.max(b[j], b[j + 1]);
        i++;                                   // skip the matched b[j]
        while (i < a.length && a[i] != b[j + 1]) {
            if (a[i] > limit) big = true;
            ic++;
            i++;
        }
        if (i >= a.length) break;
        if (!validateSegment(big, ic)) return false;
    }

    // --- part after the last element of b ---
    big = false;
    ic = 0;
    i++;                                   // move past the last matched b
    while (i < a.length) {
        if (a[i] > b[b.length - 1]) big = true;
        ic++;
        i++;
    }
    return validateSegment(big, ic);
}

