/**
 * Solves a single test case.
 * Populates the palindrome according to the given counts of zeros (z) and ones (o)
 * and prints the result or -1 if it is impossible.
 */
private static void solveCase(int z, int o, String s, PrintWriter writer) {
    int n = s.length();
    char[] c = new char[n];

    if (o + z != n) {
        writer.println("-1");
        return;
    }

    // Copy existing characters and adjust remaining counters
    for (int i = 0; i < n; i++) {
        char cc = s.charAt(i);
        c[i] = cc;
        if (cc == '0') z--;
        else if (cc == '1') o--;
    }

    boolean possible = true;

    // First pass – resolve pairs where one side is known and the other is '?'
    for (int i = 0; i < n / 2 && possible; i++) {
        char l = s.charAt(i);
        char r = s.charAt(n - i - 1);

        if ((l == '0' && r == '1') || (l == '1' && r == '0')) {
            possible = false;
            break;
        }

        if (l == '?' && r != '?') {
            if (r == '1') {
                if (o > 0) { c[i] = '1'; o--; }
                else possible = false;
            } else { // r == '0'
                if (z > 0) { c[i] = '0'; z--; }
                else possible = false;
            }
        } else if (r == '?' && l != '?') {
            if (l == '1') {
                if (o > 0) { c[n - i - 1] = '1'; o--; }
                else possible = false;
            } else { // l == '0'
                if (z > 0) { c[n - i - 1] = '0'; z--; }
                else possible = false;
            }
        } else if (l != r) {
            possible = false;
        }
    }

    // Second pass – fill pairs where both sides are '?'
    for (int i = 0; i < n / 2 && possible; i++) {
        char l = s.charAt(i);
        char r = s.charAt(n - i - 1);
        if (l == '?' && r == '?') {
            if (z >= 2) {
                c[i] = c[n - i - 1] = '0';
                z -= 2;
            } else if (o >= 2) {
                c[i] = c[n - i - 1] = '1';
                o -= 2;
            } else {
                possible = false;
            }
        }
    }

    // Handle middle character for odd length strings
    if (n % 2 != 0 && possible) {
        char mid = s.charAt(n / 2);
        if (mid == '?') {
            if (o > 0) {
                c[n / 2] = '1';
                o--;
            } else if (z > 0) {
                c[n / 2] = '0';
                z--;
            } else {
                possible = false;
            }
        }
    }

    // If any counters remain, the construction is invalid
    if (o > 0 || z > 0) possible = false;

    if (possible) {
        for (char ch : c) writer.print(ch);
        writer.println();
    } else {
        writer.println("-1");
    }
}

