              deque.addLast(B);
            } else {
              deque.addFirst(B);
              deque.addLast(A);
            }
          }
          if (finalDeq== null) {
            finalDeq = new ArrayList<>();
            for (Integer aa : deque) {
              finalDeq.add(aa);
            }
          }
          assert lastPerm == maxind;
          int left =(int) ((req.value - (1L +  maxind)) % ((long) (n - 1)));
