static List<Integer>[] adj;
static boolean[] relevant;
static boolean[] visited;
static int center1 = -1, center2 = -1;

private static class MaxDepth {
    int v, depth, max = 0, adjVisited = 0;
    MaxDepth(int v, int depth) { this.v = v; this.depth = depth; }
    void updateMax(int childMax) { max = Math.max(max, childMax + 1); }
}

private static class Result {
    int minEndpoint;
    int total;
}

/*--- extracted cohesive block -------------------------------------------*/
private static Result computeResult(int root, List<Integer>[] adj,
                                    boolean[] relevant, int count) {
    int n = adj.length;
    // 1) BFS to obtain one endpoint of the diameter
    Queue<Integer> q = new ArrayDeque<>();
    boolean[] visited = new boolean[n];
    q.offer(root);
    visited[root] = true;
    int farthest = root;
    while (!q.isEmpty()) {
        int cur = q.poll();
        farthest = cur;
        for (int nb : adj[cur]) {
            if (relevant[nb] && !visited[nb]) {
                visited[nb] = true;
                q.offer(nb);
            }
        }
    }

    // 2) DFS (iterative) to compute diameter and centre(s)
    int diameter = 0, minEndpoint = farthest;
    center1 = -1;
    center2 = -1;
    Stack<MaxDepth> stack = new Stack<>();
    stack.push(new MaxDepth(farthest, 0));
    visited[farthest] = false;               // reuse array as “unvisited”
    while (!stack.isEmpty()) {
        MaxDepth frame = stack.peek();
        if (frame.adjVisited < adj[frame.v].size()) {
            int nb = adj[frame.v].get(frame.adjVisited++);
            if (relevant[nb] && visited[nb]) {
                stack.push(new MaxDepth(nb, frame.depth + 1));
                visited[nb] = false;
            }
        } else {
            stack.pop();
            int depth2 = frame.depth * 2;
            if (depth2 == frame.max)               // exact centre
                center1 = frame.v;
            else if (depth2 - 1 == frame.max)      // left centre
                center1 = frame.v;
            else if (depth2 + 1 == frame.max)      // right centre
                center2 = frame.v;

            if (!stack.isEmpty())
                stack.peek().updateMax(frame.max);
            else
                diameter = frame.max;
        }
    }

    // 3) BFS from centre(s) to find the minimal endpoint at distance diameter/2
    int[] dist = new int[n];
    Arrays.fill(dist, -1);
    q.clear();
    visited = new boolean[n];

    q.offer(center1);
    visited[center1] = true;
    dist[center1] = 0;
    while (!q.isEmpty()) {
        int cur = q.poll();
        if (dist[cur] == diameter / 2 && cur < minEndpoint)
            minEndpoint = cur;
        for (int nb : adj[cur]) {
            if (relevant[nb] && !visited[nb] && nb != center2) {
                visited[nb] = true;
                dist[nb] = dist[cur] + 1;
                q.offer(nb);
            }
        }
    }

    if (center2 != -1) {
        q.offer(center2);
        visited[center2] = true;
        dist[center2] = 0;
        while (!q.isEmpty()) {
            int cur = q.poll();
            if (dist[cur] == diameter / 2 && cur < minEndpoint)
                minEndpoint = cur;
            for (int nb : adj[cur]) {
                if (relevant[nb] && !visited[nb]) {
                    visited[nb] = true;
                    dist[nb] = dist[cur] + 1;
                    q.offer(nb);
                }
            }
        }
    }

    Result r = new Result();
    r.minEndpoint = minEndpoint;
    r.total = diameter + 2 * (count - diameter - 1);
    return r;
}
