			long mask=graph[i]>>len1;
			rec3[i]=mask;
		}
		for(int i=0;i<len2;i++) {
			long mask=graph[i+len1]>>len1;
			rec2[i]=mask;
		}
		Arrays.fill(dp1,-1);
		Arrays.fill(dp2,-1);
		dp1[0]=0;
		dp2[0]=0;
