            for (int row = 0; row < n; row++) {
                int first = -1, last = -1;
                for (int col = 0; col < n; col++) {
                    if (B[row][col] == d) {
                        last = col;
                        if (first == -1) first = col;
                    }
                }
                ans[d] = Math.max(ans[d],
                        (long) (last - first) * Math.max(row, n - 1 - row));
            }
            // vertical scans
            for (int col = 0; col < n; col++) {
                int first = -1, last = -1;
                for (int row = 0; row < n; row++) {
                    if (B[row][col] == d) {
                        last = row;
                        if (first == -1) first = row;
                    }
                }
                ans[d] = Math.max(ans[d],
                        (long) (last - first) * Math.max(col, n - 1 - col));
            }
            // evaluate positions of digit d
            evaluateDigit(d, B, n, ans);
        }
        for (long v : ans)
            stringBuilder.append(v).append(' ');
        stringBuilder.append('\n');
    }
    System.out.println(stringBuilder);
}

/**
 * Finds all cells containing {@code digit}, sorts them, and updates
 * {@code ans[digit]} with the largest possible area formed using those cells.
 */
private static void evaluateDigit(int digit, int[][] grid, int n, long[] ans) {
    List<Game> all = new ArrayList<>();
    List<Game1> all1 = new ArrayList<>();

    for (int r = 0; r < n; r++) {
        for (int c = 0; c < n; c++) {
            if (grid[r][c] == digit) {
                all.add(new Game(r, c));
                all1.add(new Game1(r, c));
            }
        }
    }
    if (all.size() <= 1) return;          // nothing to improve

    Collections.sort(all);
    Collections.sort(all1);
    int m = all.size();

    for (int i = 0; i < m; i++) {
        int y = all.get(i).y;
        int x = all.get(i).x;
        long area = (long) Math.max(y, n - 1 - y)
                * Math.max(all.get(m - 1).x - x, x - all.get(0).x);
        ans[digit] = Math.max(ans[digit], area);
    }
    for (int i = 0; i < m; i++) {
        int y = all1.get(i).y;
        int x = all1.get(i).x;
        long area = (long) Math.max(x, n - 1 - x)
                * Math.max(all1.get(m - 1).y - y, y - all1.get(0).y);
        ans[digit] = Math.max(ans[digit], area);
    }
}

