/**
 * Processes a single horizontal line {@code z}.  It builds the auxiliary
 * structures for the first {@code limit} violas (those with row ≤ z),
 * then sweeps the rows from 0 … z while updating the running total.
 *
 * @return the contribution of this line to the final answer
 */
private static long processRow(int z, Viola[] violas, int limit,
                               int[] column, int c, int n, int k) {
    // collect violas whose row ≤ z
    List<Viola> list = new ArrayList<>(limit);
    for (int a = 0; a < limit; a++) {
        list.add(violas[a]);
    }
    Collections.sort(list);

    int[] left = new int[n + 2];
    int[] right = new int[n + 2];
    int[] side = new int[n + 2];
    long[] count = new long[n + 2];
    long total = 0L;

    // build doubly‑linked list (left / right) using the sorted order
    for (int b = 0; b < list.size(); b++) {
        int cur = list.get(b).index;
        int li = (b == 0) ? 0 : list.get(b - 1).index;
        int ri = (b == list.size() - 1) ? n + 1 : list.get(b + 1).index;

        left[cur] = li;
        right[li] = cur;
        right[cur] = ri;
        left[ri] = cur;
    }

    // initialise side[] and count[] for every node
    for (int d = 0; d < list.size(); d++) {
        int cur = list.get(d).index;

        if (d + k - 1 < list.size()) {
            side[cur] = list.get(d + k - 1).index;
        } else {
            side[cur] = n + 1;
        }

        count[cur] = (column[cur] - column[left[cur]]) *
                     (c - column[side[cur]]);
        total += count[cur];
    }

    long rowResult = 0L;
    int i = 0; // pointer used to remove violas whose row == e
    for (int e = 0; e <= z; e++) {
        rowResult += total;

        while (i < violas.length && violas[i].row == e) {
            int cur = violas[i].index;

            // remove cur from the structure
            total -= count[cur];
            left[right[cur]] = left[cur];
            right[left[cur]] = right[cur];

            // update right neighbour if it exists
            if (right[cur] <= n) {
                total -= count[right[cur]];
                int node = right[cur];
                count[node] = (column[node] - column[left[node]]) *
                              (c - column[side[node]]);
                total += count[node];
            }

            // walk k‑1 steps leftwards, fixing side[] and count[]
            int node = left[cur];
            for (int f = 0; f < k - 1; f++) {
                if (node == 0) {
                    break;
                }
                total -= count[node];

                if (side[node] <= n) {
                    side[node] = right[side[node]];
                }

                count[node] = (column[node] - column[left[node]]) *
                              (c - column[side[node]]);
                total += count[node];

                node = left[node];
            }
            i++;
        }
    }
    return rowResult;
}

