/**
 * Solves the problem for a small array by using matrix exponentiation
 * and binary search.
 */
private long solveWithMatrix(long[] a, long k) {
    int n = a.length;

    long[][] m1 = new long[1][n];
    for (int i = 0; i < n; i++) {
        m1[0][i] = a[i];
    }

    long[][] m2 = new long[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            m2[i][j] = 1;
        }
    }

    long lo = 0, hi = (long) 1e18;
    long res = -1;
    for (int bs = 0; bs < 100 && lo <= hi; bs++) {
        overflowed = false;
        long mid = (lo + hi) / 2;
        long[][] get = matrixExpo(m2, mid);
        get = matrixMultiply(m1, get);

        if (overflowed) {
            hi = mid - 1;
            res = mid;
            continue;
        }
        if (get[0][n - 1] >= k) {
            res = mid;
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return res;
}

