		int N = nextInt();
		int[] A = new int[N];
		for (int i = 0; i < N; i++) {
			A[i] = nextInt();
		}
		Arrays.sort(A);

		if (N == 1) {
			out.println(-1);
			return;
		}
		if (N == 2) {
			if (A[0] == A[1]) {
				out.println(1);
				out.println(A[0]);
			} else {
				if ( (A[1] - A[0]) % 2 == 1) {
					out.println(2);
					out.println( (A[0] - (A[1]-A[0])) + " " + (A[1] + (A[1]-A[0])) );
				} else {
					out.println(3);
					int mid = A[0] + (A[1] - A[0])/2;					
					out.println( (A[0] - (A[1]-A[0])) + " " + mid + " " + (A[1] + (A[1]-A[0])) );
				}
			}			
			return;
		}

		int[] D = new int[N-1];
		for (int i = 1; i < N; i++) {
			D[i-1] = A[i] - A[i-1];
		}

		boolean aSame = true;
		boolean dSame = true;

		for (int i = 1; i < N; i++) {
			if (A[i] != A[i-1]) aSame = false;
		}		
		for (int i = 1; i < N-1; i++) {
			if (D[i] != D[i-1]) dSame = false;
		}

		if (aSame) {
			out.println(1);
			out.println(A[0]);
			return;
		}
		else if (dSame) {
			out.println(2);
			out.println( (A[0] - D[0]) + " " + (A[N-1] + D[0]) );
			return;
		}

		HashMap<Integer, Integer> diffs = new HashMap<Integer, Integer>();
		for (int i = 0; i < N-1; i++) {
			if (diffs.containsKey(D[i])) {
				diffs.put(D[i], diffs.get(D[i])+1);
			} else {
				diffs.put(D[i], 1);
			}
		}

		if (diffs.size() > 2) {
			out.println(0);
			return;
		}

		int smallest = Integer.MAX_VALUE/2;
		int largest = -1;
		for (int d: diffs.keySet()) {
			smallest = Math.min(d, smallest);
			largest = Math.max(d, largest);
		}

		if (diffs.get(largest) > 1) {
			out.println(0);
			return;
		}

		if (largest/2 != smallest || largest % 2 == 1) {
			out.println(0);
			return;
		}

		out.println(1);
		for (int i = 0; i < N-1; i++) {
			if (D[i] == largest) {
				out.println( A[i] + largest/2);
			}			
		}

	}

