/**
 * Checks whether moving the given point by one step in any of the four
 * orthogonal/diagonal directions makes the triangle satisfy {@code almost}.
 *
 * @param mx   x‑coordinate of the point that may be moved
 * @param my   y‑coordinate of the point that may be moved
 * @param ox1  x‑coordinate of the first fixed point
 * @param oy1  y‑coordinate of the first fixed point
 * @param ox2  x‑coordinate of the second fixed point
 * @param oy2  y‑coordinate of the second fixed point
 * @return {@code true} if any single‑step move yields {@code true} from {@code almost}
 */
private static boolean isAlmostByMovingOneStep(int mx, int my,
                                               int ox1, int oy1,
                                               int ox2, int oy2) {
    // move right
    if (almost(mx + 1, my, ox1, oy1, ox2, oy2)) return true;
    // move left
    if (almost(mx - 1, my, ox1, oy1, ox2, oy2)) return true;
    // move diagonally up‑right
    if (almost(mx + 1, my + 1, ox1, oy1, ox2, oy2)) return true;
    // move down
    if (almost(mx, my - 1, ox1, oy1, ox2, oy2)) return true;
    return false;
}

