/**
 * Tries moving each point by one unit in the four cardinal directions.
 * If any such move makes the triangle satisfy {@code almost}, prints
 * "ALMOST" and returns true.
 */
private static boolean tryAlmostWithOneStep(int x1, int y1,
                                            int x2, int y2,
                                            int x3, int y3) {
    // deltas for a single step: right, left, up, down
    int[][] moves = { {1, 0}, {-1, 0}, {0, 1}, {0, -1} };
    // points array: each entry holds {x, y}
    int[][] pts = { {x1, y1}, {x2, y2}, {x3, y3} };

    for (int i = 0; i < 3; i++) {
        int origX = pts[i][0];
        int origY = pts[i][1];
        for (int[] d : moves) {
            pts[i][0] = origX + d[0];
            pts[i][1] = origY + d[1];
            if (almost(pts[0][0], pts[0][1],
                       pts[1][0], pts[1][1],
                       pts[2][0], pts[2][1])) {
                System.out.println("ALMOST");
                return true;
            }
        }
        // restore original point before moving to the next one
        pts[i][0] = origX;
        pts[i][1] = origY;
    }
    return false;
}

