/**
 * Returns true if every position containing a '1' in {@code arr}
 * can be covered by at least one still‑available position in {@code w}
 * that is exactly {@code x} cells to the left or right.
 */
private static boolean isValid(int[] arr, int[] w, int x) {
    int n = arr.length;
    for (int i = 0; i < n; i++) {
        if (arr[i] == 1) {
            boolean leftOk  = (i - x >= 0) && (w[i - x] == 1);
            boolean rightOk = (i + x <  n) && (w[i + x] == 1);
            if (!leftOk && !rightOk) return false;
        }
    }
    return true;
}

