private static int countOccurrences(int[] arr, int value) {
    int cnt = 0;
    for (int v : arr) {
        if (v == value) {
            cnt++;
        }
    }
    return cnt;
}

private static int findNextMin(int[] arr, int currentMin) {
    int next = 0;
    for (int v : arr) {
        if (v > currentMin) {
            if (next == 0 || v < next) {
                next = v;
            }
        }
    }
    return next;
}

