/**
 * Handles a song event (type == 1).
 *
 * @return true if the song can be assigned to a singer, false otherwise.
 */
private boolean processSongEvent(Event e,
                                 Song[] songs,
                                 Singer[] singers,
                                 Singer[] sortedSingers,
                                 int numSingers,
                                 int[] ans) {
    int l = -1;
    int r = numSingers - 1;
    int need = songs[e.id].r;

    // find first singer whose right endpoint >= need
    while (r - l > 1) {
        int m = (l + r) / 2;
        Singer s = sortedSingers[m];
        if (s.r >= need) {
            r = m;
        } else {
            l = m;
        }
    }
    if (sortedSingers[r].r < need) {
        return false;
    }

    int first = r;
    l = first - 1;
    r = numSingers - 1;

    // there must be at least one active singer from 'first' onward
    if (sum(first, numSingers - 1) == 0) {
        return false;
    }

    // binary search the leftmost active singer in the feasible range
    while (r - l > 1) {
        int m = (l + r) / 2;
        if (sum(first, m) > 0) {
            r = m;
        } else {
            l = m;
        }
    }

    Singer best = sortedSingers[r];
    --best.k;
    if (best.k == 0) {
        add(r, -1);
    }
    ans[e.id] = best.id;
    return true;
}

