private static void resolvePrefix(StringBuilder ans, int[] d, int k, int p, int map_sz) {
    while (true) {
        // If current digit is '9' we must backtrack
        if (ans.charAt(p) == '9') {
            p--;
            d[ans.charAt(p) - '0']--;
            if (d[ans.charAt(p) - '0'] == 0) map_sz--;
            continue;
