static void solve() {
    int n = sc.nextInt();
    int k = sc.nextInt();
    char[] s = sc.next().toCharArray();

    // If the whole string is the window, just verify the counts once.
    if (k == n && !initialCountsOk(s, k)) {
        pw.println("NO");
        return;
    }

    // Propagate known bits across distance k; abort on conflict.
    if (!propagateConstraints(s, n, k)) {
        pw.println("NO");
        return;
    }

    // After propagation, the first window must be valid.
    if (!initialCountsOk(s, k) || !slidingWindowOk(s, n, k)) {
        pw.println("NO");
        return;
    }

    pw.println("YES");
}

/** Returns false if a contradiction is found while copying known bits. */
private static boolean propagateConstraints(char[] s, int n, int k) {
    // forward pass
    for (int i = 0; i < n - k; i++) {
        if (s[i] != '?') {
            if (s[i + k] == '?') {
                s[i + k] = s[i];
            } else if (s[i + k] != s[i]) {
                return false;
            }
        }
    }
    // backward pass
    for (int i = n - 1; i >= k; i--) {
        if (s[i] != '?') {
            if (s[i - k] == '?') {
                s[i - k] = s[i];
            } else if (s[i - k] != s[i]) {
                return false;
            }
        }
    }
    // second forward pass to catch newly filled positions
    for (int i = 0; i < n - k; i++) {
        if (s[i] != '?') {
            if (s[i + k] == '?') {
                s[i + k] = s[i];
            } else if (s[i + k] != s[i]) {
                return false;
            }
        }
    }
    return true;
}

/** Checks that the first k characters contain at most k/2 ones and zeros. */
private static boolean initialCountsOk(char[] s, int k) {
    int ones = 0, zeros = 0;
    for (int i = 0; i < k; i++) {
        if (s[i] == '1') {
            ones++;
        } else if (s[i] == '0') {
            zeros++;
        }
    }
    return ones <= k / 2 && zeros <= k / 2;
}

/** Sliding‑window verification for every length‑k segment. */
private static boolean slidingWindowOk(char[] s, int n, int k) {
    int ones = 0, zeros = 0;
    // initial window [0, k‑1]
    for (int i = 0; i < k; i++) {
        if (s[i] == '1') {
            ones++;
        } else if (s[i] == '0') {
            zeros++;
        }
    }
    if (ones > k / 2 || zeros > k / 2) {
        return false;
    }

    // slide the window
    for (int start = 0, end = k; end < n; start++, end++) {
        if (s[end] == '1') {
            ones++;
        } else if (s[end] == '0') {
            zeros++;
        }
        if (s[start] == '1') {
            ones--;
        } else if (s[start] == '0') {
            zeros--;
        }
        if (ones > k / 2 || zeros > k / 2) {
            return false;
        }
    }
    return true;
}

