/** Returns a list of segments that are unique (no segment is
 *  strictly contained in another) and sorted by their left endpoint. */
private List<Segment> buildUniqueSortedSegments(TreeSet<Segment> allSegments) {
    TreeSet<Segment> uniqueSegments = new TreeSet<>();
    for (Segment segment : allSegments) {
        while (!uniqueSegments.isEmpty()
                && segment.compareTo(uniqueSegments.last()) < 0) {
            uniqueSegments.pollLast();
        }
        uniqueSegments.add(segment);
    }
    List<Segment> list = new ArrayList<>(uniqueSegments);
    list.sort((s1, s2) -> s1.left - s2.left);
    return list;
}

/** Finds the leftmost index in {@code segments} that can answer a query. */
private int findLeftIndex(List<Segment> segments, Segment q,
                          Comparator<Segment> compLeft) {
    int bs = Collections.binarySearch(segments, q, compLeft);
    return (bs >= 0) ? bs : -bs - 1;
}

/** Finds the rightmost index in {@code segments} that can answer a query. */
private int findRightIndex(List<Segment> segments, Segment q,
                           Comparator<Segment> compRight) {
    int bs = Collections.binarySearch(segments, q, compRight);
    if (bs >= 0) return bs;
    int ip = -bs - 1;
    return ip - 1;
}

