/* Handles the cases where one of the parity maps contains only one distinct value */
private static void processSingleMap(int firstValue, Map<Integer, Integer> otherMap, int half) {
    int mostFrequent = getMaxKey(otherMap);
    if (firstValue != mostFrequent) {
        System.out.println(half - otherMap.get(mostFrequent));
    } else {
        int second = getSecondMaxKey(otherMap, mostFrequent);
        System.out.println(half - otherMap.get(second));
    }
}

/* Returns the key with the highest count in the map */
private static int getMaxKey(Map<Integer, Integer> map) {
    int maxKey = -1;
    int maxCount = -1;
    for (Map.Entry<Integer, Integer> e : map.entrySet()) {
        if (e.getValue() > maxCount) {
            maxCount = e.getValue();
            maxKey = e.getKey();
        }
    }
    return maxKey;
}

/* Returns the key with the highest count, excluding a given key */
private static int getSecondMaxKey(Map<Integer, Integer> map, int exclude) {
    int maxKey = -1;
    int maxCount = -1;
    for (Map.Entry<Integer, Integer> e : map.entrySet()) {
        if (e.getKey() == exclude) continue;
        if (e.getValue() > maxCount) {
            maxCount = e.getValue();
            maxKey = e.getKey();
        }
    }
    return maxKey;
}

