/* Handles type‑1 queries: adds *delta* to all positions in [from, to]. */
private static void updateRange(int from, int to, int delta,
                                final int SIZE_OF_BLOCK, final int BLOCKS,
                                long[][] blocks, Integer[][] sorted,
                                int[] size, long[] ad) {
    int fromBlock = from / SIZE_OF_BLOCK;
    int toBlock   = to   / SIZE_OF_BLOCK;

    if (fromBlock == toBlock) {
        applyPending(blocks, ad, fromBlock, size[fromBlock]);
        int start = from % SIZE_OF_BLOCK;
        int end   = to % SIZE_OF_BLOCK;
        for (int i = start; i <= end; ++i) {
            blocks[fromBlock][i] += delta;
        }
        resort(sorted[fromBlock], 0, size[fromBlock], blocks[fromBlock]);
        return;
    }

    // left partial block
    applyPending(blocks, ad, fromBlock, size[fromBlock]);
    for (int i = from % SIZE_OF_BLOCK; i < size[fromBlock]; ++i) {
        blocks[fromBlock][i] += delta;
    }
    resort(sorted[fromBlock], 0, size[fromBlock], blocks[fromBlock]);

    // right partial block
    applyPending(blocks, ad, toBlock, size[toBlock]);
    for (int i = 0; i <= to % SIZE_OF_BLOCK; ++i) {
        blocks[toBlock][i] += delta;
    }
    resort(sorted[toBlock], 0, size[toBlock], blocks[toBlock]);

    // fully covered middle blocks – lazy addition
    for (int b = fromBlock + 1; b < toBlock; ++b) {
        ad[b] += delta;
    }
}

/* Flushes any pending lazy addition for a whole block. */
private static void applyPending(long[][] blocks, long[] ad,
                                 int blockIdx, int blockSize) {
    if (ad[blockIdx] != 0) {
        for (int i = 0; i < blockSize; ++i) {
            blocks[blockIdx][i] += ad[blockIdx];
        }
        ad[blockIdx] = 0;
    }
}

/* Handles type‑2 queries: returns (maxIndex‑minIndex) of *target*,
   or a negative value when the target does not appear. */
private static int queryRange(int target,
                              final int SIZE_OF_BLOCK, final int BLOCKS,
                              long[][] blocks, Integer[][] sorted,
                              int[] size, long[] ad) {
    int min = -1;
    int max = -2;

    for (int block = 0; block < BLOCKS; ++block) {
        int left = -1;
        int right = size[block];

        // binary search for the rightmost element ≤ target
        while (right - left > 1) {
            int middle = (left + right) >>> 1;
            if (blocks[block][sorted[block][middle]] + ad[block] <= target) {
                left = middle;
            } else {
                right = middle;
            }
        }

        if (left >= 0 &&
            blocks[block][sorted[block][left]] + ad[block] == target) {
            max = sorted[block][left] + SIZE_OF_BLOCK * block;

            if (min == -1) {
                // binary search for the leftmost element == target
                right = left + 1;
                left = -1;
                while (right - left > 1) {
                    int middle = (left + right) >>> 1;
                    if (blocks[block][sorted[block][middle]] + ad[block] < target) {
                        left = middle;
                    } else {
                        right = middle;
                    }
                }
                min = sorted[block][right] + SIZE_OF_BLOCK * block;
            }
        }
    }
    return max - min;
}

