/**
 * Updates the DP table for the transition from position {@code i} to {@code i+1}.
 * All indices are zero‑based.  The method mutates the provided {@code dp} matrix.
 */
private void updateDp(int i, int j, int indeg, int outdeg,
                     int s, int e,
                     int[] x, int[] a, int[] b, int[] c, int[] d,
                     long[][] dp, int n) {

    if (i + 1 == s) {
        dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + d[i] - x[i]);
        if (j > 0) {
            dp[i + 1][j - 1] = Math.min(dp[i + 1][j - 1], dp[i][j] + c[i] + x[i]);
        }
        return;
    }

    if (i + 1 == e) {
        if (j + 1 <= n) {
            dp[i + 1][j + 1] = Math.min(dp[i + 1][j + 1], dp[i][j] + b[i] - x[i]);
        }
        if (outdeg > 0) {
            dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + a[i] + x[i]);
        }
        return;
    }

    if (j + 1 <= n) {
        dp[i + 1][j + 1] = Math.min(dp[i + 1][j + 1],
                dp[i][j] + b[i] + d[i] - 2L * x[i]);
    }
    if (j > 0 && indeg > 0) {
        dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + c[i] + b[i]);
    }
    if (outdeg > 0) {
        dp[i + 1][j] = Math.min(dp[i + 1][j], dp[i][j] + d[i] + a[i]);
    }
    if (j > 0 && indeg > 0 && outdeg > 0) {
        dp[i + 1][j - 1] = Math.min(dp[i + 1][j - 1],
                dp[i][j] + a[i] + c[i] + 2L * x[i]);
    }
