/**
 * Computes cumulative costs in the four cardinal directions.
 * The results are stored in the class‑level arrays {@code right},
 * {@code left}, {@code down} and {@code up}.
 */
private static void computeDirectionalCosts(int[][] grid, int[] delta) {
    // right
    for (int a = 0; a < H; a++) {
        for (int b = 1; b < W; b++) {
            int change = grid[a][b] - grid[a][b - 1];
            right[a][b] = right[a][b - 1] + delta[(int) (Math.signum(change) + 1)];
        }
    }
    // left
    for (int a = 0; a < H; a++) {
        for (int b = W - 2; b >= 0; b--) {
            int change = grid[a][b] - grid[a][b + 1];
            left[a][b] = left[a][b + 1] + delta[(int) (Math.signum(change) + 1)];
        }
    }
    // down
    for (int b = 0; b < W; b++) {
        for (int a = 1; a < H; a++) {
            int change = grid[a][b] - grid[a - 1][b];
            down[a][b] = down[a - 1][b] + delta[(int) (Math.signum(change) + 1)];
        }
    }
    // up
    for (int b = 0; b < W; b++) {
        for (int a = H - 2; a >= 0; a--) {
            int change = grid[a][b] - grid[a + 1][b];
            up[a][b] = up[a + 1][b] + delta[(int) (Math.signum(change) + 1)];
