/** BFS to fill depth, atlevel, index and binary‑lifting table dp. */
private void bfsAndPreprocess() {
    ArrayDeque<Integer> q = new ArrayDeque<>();
    boolean[] visited = new boolean[parent.length];
    depth = new int[parent.length];
    q.add(0);
    visited[0] = true;

    while (!q.isEmpty()) {
        int i = q.poll();
        atlevel[depth[i]].add(i);
        index[i] = atlevel[depth[i]].size() - 1;
        for (int child : arrayList[i]) {
            if (!visited[child]) {
                visited[child] = true;
                q.add(child);
                dp[0][child] = i;
                depth[child] = depth[i] + 1;
            }
        }
    }
    for (int k = 1; k <= D; k++) {
        for (int i = 0; i < dp[0].length; i++) {
            int mid = dp[k - 1][i];
            if (mid != -1) dp[k][i] = dp[k - 1][mid];
        }
    }
}

/** Returns the number of nodes on the same depth as v whose LCA with v is u. */
private int countInSubtree(int v, int p) {
    int u = walk(v, p);
    if (u == 0 || u == -1) return 0;

    int lev = depth[v];
    int lower = binarySearchBound(u, lev, 0, index[v], true);
    int upper = binarySearchBound(u, lev, index[v], atlevel[lev].size() - 1, false);
    return upper - lower + 1;
}

/**
 * Binary search on atlevel[ level ].
 * If {@code findFirst} is true, returns the first position where ancestor stays LCA,
 * otherwise returns the last such position.
 */
private int binarySearchBound(int ancestor, int level, int lo, int hi, boolean findFirst) {
    int res = -1;
    while (lo <= hi) {
        int mid = (lo + hi) >>> 1;
        int b = atlevel[level].get(mid);
        int lca = lca(ancestor, b);
        if (lca == ancestor) {
            res = mid;
            if (findFirst) hi = mid - 1;
            else lo = mid + 1;
        } else {
            if (findFirst) lo = mid + 1;
            else hi = mid - 1;
        }
    }
    return res;
}

