private void processIndex(int i, long[] a, Info[][] f) {
    if (a[i] != -1) {                     // value at i is known
        f[i][0].a = a[i];
        f[i][0].f = Math.min(f[i - 1][0].f, f[i - 1][1].f) + 1;
        f[i][0].len = 1;
        f[i][0].d = oo;

        long dPrev = f[i - 1][1].d;
        long a0Prev = f[i - 1][1].a;
        long lenPrev = f[i - 1][1].len;
        int vPrev = f[i - 1][1].i;

        if (dPrev == oo) {
            if (a0Prev == oo) {
                f[i][1].a = a[i];
                f[i][1].len = lenPrev + 1;
                f[i][1].d = oo;
                f[i][1].f = f[i - 1][1].f;
                f[i][1].i = (int) lenPrev + 1;
            } else {
                if (lenPrev == 1) {
                    f[i][1].a = a0Prev;
                    f[i][1].len = f[i - 1][1].len + 1;
                    f[i][1].d = a[i] - a0Prev;
                    f[i][1].f = f[i - 1][1].f;
                } else {
                    if ((a[i] - a0Prev) % (lenPrev - vPrev + 1) == 0) {
                        long td = (a[i] - a0Prev) / (lenPrev - vPrev + 1);
                        if (a0Prev - td * (vPrev - 1) > 0) {
                            f[i][1].a = a0Prev - td * (vPrev - 1);
                            f[i][1].len = f[i - 1][1].len + 1;
                            f[i][1].d = td;
                            f[i][1].f = f[i - 1][1].f;
                            f[i][1].i = 1;
                        }
                    }
                }
            }
        } else {
            if (a[i] == a0Prev + dPrev * lenPrev) {
                f[i][1].a = a0Prev;
                f[i][1].len = f[i - 1][1].len + 1;
                f[i][1].d = dPrev;
                f[i][1].f = f[i - 1][1].f;
            }
        }
    } else {                               // value at i is unknown
        f[i][0].a = oo;
        f[i][0].d = oo;
        f[i][0].len = 1;
        f[i][0].f = Math.min(f[i - 1][0].f, f[i - 1][1].f) + 1;

        long dPrev = f[i - 1][1].d;
        long a0Prev = f[i - 1][1].a;
        long lenPrev = f[i - 1][1].len;
