        if (dPrev == oo) {
            f[i][1].d = oo;
            f[i][1].a = a0Prev;
            f[i][1].len = lenPrev + 1;
            f[i][1].f = f[i - 1][1].f;
            f[i][1].i = f[i - 1][1].i;
        } else {
            long a1 = a0Prev - dPrev * (vPrev - 1);
            long x = a1 + dPrev * lenPrev;
            if (x > 0) {
                f[i][1].d = dPrev;
                f[i][1].a = a0Prev;
                f[i][1].len = lenPrev + 1;
                f[i][1].f = f[i - 1][1].f;
                f[i][1].i = f[i - 1][1].i;
            }
        }
    }

    // If the second state is still infinite, copy the first one
    if (f[i][1].f == oo) {
        f[i][1] = new Info(f[i][0]);
    }
