        int[] mat = new int[k];
        for (int j = 0; j < k; ++j) {
            mat[j] = sc.nextInt();
        }

        int curMask = encodeMask(mat, k);

        // a row without any 1‑s makes the answer YES immediately
        if (curMask == 0) {
            w.print("YES");
            w.close();
            return;
        }

        // does any previously stored mask fit together with this row?
        if (hasCompatibleMask(curMask, k, map)) {
            w.print("YES");
            w.close();
            return;
        }

        // store the current row mask for future comparisons
        map.put(curMask, 1);
    }

    w.print("NO");
    w.close();
}

/**
 * Encodes the given row into a bit mask.
 * Bit i (0‑based) is 1 iff mat[i] == 1.
 */
private int encodeMask(int[] mat, int k) {
    int mask = 0;
    if (k > 0) mask |= mat[0];
    if (k > 1) mask |= (mat[1] << 1);
    if (k > 2) mask |= (mat[2] << 2);
    if (k > 3) mask |= (mat[3] << 3);
    return mask;
}

/**
 * Returns true if there exists a previously stored mask that does not share
 * a 1‑bit with the current row mask. This implements the original nested‑loop
 * compatibility check.
 */
private boolean hasCompatibleMask(int curMask, int k, Map<Integer, Integer> map) {
    int limit = 1 << k;                 // all possible masks for k ≤ 4
    for (int mask = 0; mask < limit; ++mask) {
        // mask is compatible when it has no 1‑bits where curMask has 1‑bits
        if ((mask & curMask) == 0 && map.containsKey(mask)) {
            return true;
        }
    }
    return false;
}

