/* Helper: count all ‘B’ cells */
private static int countBs(char[][] grid, int rows, int cols) {
    int cnt = 0;
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (grid[i][j] == 'B') cnt++;
        }
    }
    return cnt;
}

/* Helper: first row that contains a ‘B’, or -1 if none */
private static int findTop(char[][] grid, int rows, int cols) {
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            if (grid[i][j] == 'B') return i;
        }
    }
    return -1;
}

/* Helper: last row that contains a ‘B’, or -1 if none */
private static int findBottom(char[][] grid, int rows, int cols) {
    for (int i = rows - 1; i >= 0; i--) {
        for (int j = 0; j < cols; j++) {
            if (grid[i][j] == 'B') return i;
        }
    }
    return -1;
}

/* Helper: first column that contains a ‘B’, or -1 if none */
private static int findLeft(char[][] grid, int rows, int cols) {
    for (int j = 0; j < cols; j++) {
        for (int i = 0; i < rows; i++) {
            if (grid[i][j] == 'B') return j;
        }
    }
    return -1;
}

/* Helper: last column that contains a ‘B’, or -1 if none */
private static int findRight(char[][] grid, int rows, int cols) {
    for (int j = cols - 1; j >= 0; j--) {
        for (int i = 0; i < rows; i++) {
            if (grid[i][j] == 'B') return j;
        }
    }
    return -1;
}

