/* Handles requests that contain a single size (e.g. "S", "M", …) */
private static void allocateSingleSizes(String[] sizes, String[] output, int[] stock, int n) {
    for (int i = 1; i <= n; i++) {
        String req = sizes[i];
        switch (req) {
            case "S":
                stock[0]--;
                output[i] = "S";
                break;
            case "M":
                stock[1]--;
                output[i] = "M";
                break;
            case "L":
                stock[2]--;
                output[i] = "L";
                break;
            case "XL":
                stock[3]--;
                output[i] = "XL";
                break;
            case "XXL":
                stock[4]--;
                output[i] = "XXL";
                break;
            case "XXXL":
                stock[5]--;
                output[i] = "XXXL";
                break;
            default:
                // do nothing – handled later as a pair request
        }
    }
}

/* Handles requests that contain two alternative sizes (e.g. "S,M") */
private static void allocateSizePair(String[] sizes, String[] output, int[] stock,
                                     String pair, int n) {
    String[] parts = pair.split(",");
    String first = parts[0];
    String second = parts[1];
    int idxFirst = sizeIndex(first);
    int idxSecond = sizeIndex(second);

    for (int i = 1; i <= n; i++) {
        if (pair.equals(sizes[i])) {
            if (stock[idxFirst] > 0) {
                stock[idxFirst]--;
                output[i] = first;
            } else {
                stock[idxSecond]--;
                output[i] = second;
            }
        }
    }
}

/* Converts a size label to its index inside the stock array */
private static int sizeIndex(String size) {
    return switch (size) {
        case "S" -> 0;
        case "M" -> 1;
        case "L" -> 2;
        case "XL" -> 3;
        case "XXL" -> 4;
        case "XXXL" -> 5;
        default -> -1; // never reached with valid input
    };
}

/* Returns true if any stock entry is negative */
private static boolean anyNegative(int[] stock) {
    for (int v : stock) {
        if (v < 0) {
            return true;
        }
    }
    return false;
}

