            m[y][x + 1] = '-';
            if (i + 1 < s.length()) {
                char next = s.charAt(i + 1);
                if (next == '[') {
                    x++;
                    y++;
                }
                if (next == ']') {
                    x += 4;
                }
            }
        } else {
            m[y][x] = '+';
            m[y][x - 1] = '-';
            if (i + 1 < s.length()) {
                char next = s.charAt(i + 1);
                if (next == '[') {
                    x++;
                }
                if (next == ']') {
                    x++;
                    y--;
                }
            }
        }
    }

