/**
 * Draws the vertical connectors, the bottom line and returns the overall height.
 */
private static int drawVerticalAndBottom(char[][] m, String s, int[][] xy, int maxY, int maxX) {
    int height = 0;
    for (int i = 0; i < s.length(); i++) {
        int cx = xy[i][0];
        int cy = xy[i][1];
        int dist = maxY - cy;

        // vertical line from the current node down to the base line
        for (int j = 1; j <= dist; j++) {
            m[cy + j][cx] = '|';
        }
        // line at the base (maxY + 1)
        m[maxY + 1][cx] = '|';
        // extension below the base line
        for (int j = 1; j <= dist; j++) {
            m[maxY + 1 + j][cx] = '|';
        }
        // bottom corner
        m[maxY + dist + 2][cx] = '+';
        if (s.charAt(i) == '[') {
            m[maxY + dist + 2][cx + 1] = '-';
        } else {
            m[maxY + dist + 2][cx - 1] = '-';
        }
        height = Math.max(height, maxY + dist + 2);
    }
    return height;
}

