/**
 * Runs Dijkstra from a single source, filling distance, index and ordering arrays.
 *
 * @param source   starting vertex (0‑based)
 * @param graph    adjacency list of the graph
 * @param dist     output array – distance from source to each vertex
 * @param index    output array – position of each vertex in the ordered list
 * @param order    output array – vertices sorted by non‑decreasing distance
 */
private void dijkstra(int source,
                      ArrayList<Edge>[] graph,
                      long[] dist,
                      int[] index,
                      int[] order) {
    PriorityQueue<State> pq = new PriorityQueue<>();
    Arrays.fill(dist, oo);
    dist[source] = 0;
    pq.offer(new State(source, 0));
    int pos = 0;
    while (!pq.isEmpty()) {
        State cur = pq.poll();
        if (dist[cur.pos] < cur.dist)
            continue;
        index[cur.pos] = pos;
        order[pos++] = cur.pos;
        for (Edge e : graph[cur.pos]) {
            long nd = dist[cur.pos] + e.dist;
            if (dist[e.dest] > nd) {
                dist[e.dest] = nd;
                pq.offer(new State(e.dest, nd));
            }
        }
    }
}

