    return n < 2;
}

private static boolean isBasePrime(int n) {
    return n == 2 || n == 3;
}

private static boolean hasSmallDivisor(int n) {
    return n % 2 == 0 || n % 3 == 0;
}

private static boolean has6kPlusMinusOneDivisor(int n) {
    int limit = (int) Math.sqrt(n) + 1;
    for (int i = 6; i <= limit; i += 6) {
        if (n % (i - 1) == 0 || n % (i + 1) == 0) {
            return true;
        }
    }
    return false;
}

