/** evaluates every possible team size (1 … maxSkill) and returns the best total */
private long bestTotal(LinkedHashMap<Integer, Skills> skills, int maxSkill) {
    long best = 0;
    for (int size = 1; size <= maxSkill; size++) {
        long cur = totalForTeamSize(size, skills);
        if (cur > best) {
            best = cur;
        }
    }
    return best;
}

/**
 * Returns the total contribution for a concrete team size.
 * While iterating, groups whose contribution is non‑positive are removed
 * from the map so they are not considered for larger team sizes.
 */
private long totalForTeamSize(int teamSize, LinkedHashMap<Integer, Skills> skills) {
    long total = 0;
    Iterator<Map.Entry<Integer, Skills>> it = skills.entrySet().iterator();

    while (it.hasNext()) {
        Map.Entry<Integer, Skills> entry = it.next();
        long sum = entry.getValue().getSum(teamSize);
        if (sum > 0) {
            total += sum;
        } else {
            // group cannot contribute for this or any larger team size
            it.remove();
        }
    }
    return total;
}

