/** sort each bucket, build its prefix sums and return the maximal bucket size */
private int prepareSkills(LinkedHashMap<Integer, Skills> skills) {
    int max = 0;
    for (Skills s : skills.values()) {
        s.calcPrefixSum();                     // builds prefix sums inside the object
        max = Math.max(s.al.size(), max);      // longest list determines loop bound
    }
    return max;
}

/** for a given team size, sum all positive contributions and discard buckets that become non‑positive */
private long computePositiveTotalForSize(int size, Map<Integer, Skills> skills) {
    long total = 0;
    List<Integer> toRemove = new ArrayList<>();

    for (Map.Entry<Integer, Skills> e : skills.entrySet()) {
        long sum = e.getValue().getSum(size);
        if (sum <= 0) {
            toRemove.add(e.getKey()); // guard‑clause: nothing to add, remember for removal
            continue;
        }
        total += sum;
    }

    // safe removal after iteration
    for (Integer key : toRemove) {
        skills.remove(key);
    }
    return total;
}

