private void populateSkills(LinkedHashMap<Integer, Skills> skills, int n, InputReader in) {
    for (int i = 0; i < n; i++) {
        int teamIdx = in.nextInt() - 1;   // make it zero‑based
        int skill   = in.nextInt();
        skills.get(teamIdx).al.add(skill);
    }
    // build prefix sums for every team
    for (Skills s : skills.values()) {
        s.calcPrefixSum();
