    int max = 0;
    for (Skills s : skills.values()) {
        max = Math.max(s.al.size(), max);
    }
    return max;
}

/**
 * For each possible group size (1 … maxSkill) we sum the positive
 * contributions of all teams. Teams whose contribution is ≤ 0 are removed
 * because they can never improve any larger group size.
 */
private long computeBestTotal(LinkedHashMap<Integer, Skills> skills, int maxSkill) {
    long best = 0L;

    for (int groupSize = 1; groupSize <= maxSkill; groupSize++) {
        long total = 0L;
        List<Integer> toRemove = new ArrayList<>();

        for (Map.Entry<Integer, Skills> e : skills.entrySet()) {
            long contribution = e.getValue().getSum(groupSize);
            if (contribution <= 0) {
                toRemove.add(e.getKey());   // guard clause – skip adding
                continue;
            }
            total += contribution;
        }

        // remove teams that cannot contribute any more
        for (Integer key : toRemove) {
            skills.remove(key);
        }

        best = Math.max(best, total);
    }
    return best;
}

