/**
 * Returns true if adding a point at (x, y) would complete a 2×2 block
 * with already‑filled points. The four possible orientations are checked
 * separately with clear guard clauses.
 */
private boolean formsClosedTriangle(boolean[][] point, int x, int y, int n, int m) {
    // upper‑left corner
    if (x - 1 > 0 && y - 1 > 0 &&
        point[x - 1][y - 1] && point[x - 1][y] && point[x][y - 1]) {
        return true;
    }
    // lower‑left corner
    if (x + 1 <= n && y - 1 > 0 &&
        point[x + 1][y] && point[x][y - 1] && point[x + 1][y - 1]) {
        return true;
    }
    // lower‑right corner
    if (x + 1 <= n && y + 1 <= m &&
        point[x + 1][y] && point[x + 1][y + 1] && point[x][y + 1]) {
        return true;
    }
    // upper‑right corner
    if (x - 1 > 0 && y + 1 <= m &&
        point[x][y + 1] && point[x - 1][y + 1] && point[x - 1][y]) {
        return true;
    }
    return false;
}

