/**
 * Returns true if putting a point at (x, y) would complete a 2×2 square
 * that already has its other three corners set in {@code point}.
 */
private boolean createsSquareWithThreeExistingCorners(int x, int y,
                                                      boolean[][] point,
                                                      int maxRow, int maxCol) {
    boolean completes = false;

    // upper‑left corner missing
    if (x - 1 > 0 && y - 1 > 0) {
        completes |= point[x - 1][y - 1] && point[x - 1][y] && point[x][y - 1];
    }
    // lower‑left corner missing
    if (x + 1 <= maxRow && y - 1 > 0) {
        completes |= point[x + 1][y] && point[x][y - 1] && point[x + 1][y - 1];
    }
    // lower‑right corner missing
    if (x + 1 <= maxRow && y + 1 <= maxCol) {
        completes |= point[x + 1][y] && point[x + 1][y + 1] && point[x][y + 1];
    }
    // upper‑right corner missing
    if (x - 1 > 0 && y + 1 <= maxCol) {
        completes |= point[x][y + 1] && point[x - 1][y + 1] && point[x - 1][y];
    }
    return completes;
}

