/** Builds the list of segment lengths (differences) for a circular road. */
private List<Integer> computeDifferences(int[] positions, int n, int l) {
    List<Integer> diffs = new ArrayList<>(n);
    for (int i = 1; i < n; i++) {
        diffs.add(positions[i] - positions[i - 1]);
    }
    diffs.add(l - positions[n - 1] + positions[0]);
    return diffs;
}

/** Checks whether two lists are identical up to a circular rotation. */
private boolean areCyclicallyEqual(List<Integer> a, List<Integer> b) {
    int size = a.size();
    if (size != b.size()) {
        return false;
    }
    List<Integer> rotated = new ArrayList<>(a);
    for (int i = 0; i < size; i++) {
        if (rotated.equals(b)) {
            return true;
        }
        Collections.rotate(rotated, 1);
    }
    return false;
}

