    st = new StringTokenizer(br.readLine());
    for (int i = 0; i < n; i++) stock[i] = Long.parseLong(st.nextToken());

    st = new StringTokenizer(br.readLine());
    for (int i = 0; i < n; i++) price[i] = Long.parseLong(st.nextToken());

    // ----- build and sort the helper array ---------------------------------
    for (int i = 0; i < n; i++) pair[i] = new Pair(i, price[i]);
    Arrays.sort(pair, new Pair.First().thenComparing(new Pair.Second()));

    // pointer to the first still‑available cheapest item
    int[] nextAvailable = new int[]{0};

    // ----- process each order ---------------------------------------------
    for (int i = 0; i < m; i++) {
        st = new StringTokenizer(br.readLine());
        int idx = Integer.parseInt(st.nextToken()) - 1;   // zero‑based
        int qty = Integer.parseInt(st.nextToken());

        long cost = processOrder(idx, qty, stock, price, pair, nextAvailable);
        pw.println(cost);
    }
    pw.flush();
}

/**
 * Computes the total cost of an order.
 *
 * @param index       the requested item (zero‑based)
 * @param needed      amount requested
 * @param stock       mutable array of remaining quantities
 * @param price       immutable array of unit prices
 * @param sorted      items sorted by price (Pair objects)
 * @param nextIdx     mutable single‑element array pointing to the cheapest
 *                    still‑available item in {@code sorted}
 * @return the total cost, or 0 if the order cannot be fully satisfied
 */
private static long processOrder(int index, int needed, long[] stock, long[] price,
                                 Pair[] sorted, int[] nextIdx) {
    // take from the requested item first
    long take = Math.min(stock[index], needed);
    stock[index] -= take;
    needed -= take;
    long cost = take * price[index];

    // then use the cheapest remaining items
    while (nextIdx[0] < sorted.length && needed > 0) {
        int cur = sorted[nextIdx[0]].index;
        long use = Math.min(stock[cur], needed);
        stock[cur] -= use;
        needed -= use;
        cost += use * price[cur];

        if (stock[cur] == 0) {
            nextIdx[0]++;          // move to the next cheapest item
        }
    }

    // guard clause: not enough stock → cost is defined as 0
    return needed > 0 ? 0L : cost;
}

