public static void main(String[] args) throws java.lang.Exception {
    FastReader sc = new FastReader();

    int n = sc.nextInt();
    int[] a = new int[n];
    int[] b = new int[n];

    // read arrays
    for (int i = 0; i < n; i++) {
        a[i] = sc.nextInt();
    }
    for (int i = 0; i < n; i++) {
        b[i] = sc.nextInt();
    }

    int[] ans = computeAnswers(b, buildIndex(a), n);

    // output
    for (int value : ans) {
        System.out.print(value + " ");
    }
    System.out.println();
}

/**
 * Builds the lookup table: for each value v (1‑based) stores the position
 * of v in array {@code a}. The table size is fixed to the problem constraints
 * (200 001) and is zero‑filled for values that never appear.
 */
private static int[] buildIndex(int[] a) {
    final int MAX_VAL = 200_001;
    int[] index = new int[MAX_VAL];
    // index is already zero‑filled; we store (position + 1) to keep 0 as “absent”
    for (int i = 0; i < a.length; i++) {
        index[a[i] - 1] = i;
    }
    return index;
}

/**
 * Computes the answer array according to the sliding‑window rule.
 *
 * @param b     the second input array (1‑based values)
 * @param index lookup table produced by {@link #buildIndex(int[])}
 * @param n     size of the problem (also the upper bound for the window)
 * @return an int array where {@code ans[i]} follows the original logic
 */
private static int[] computeAnswers(int[] b, int[] index, int n) {
    int[] ans = new int[n];
    int min = 0;               // left boundary of the current window
    int max = n - 1;           // right boundary is constant for the whole run

    for (int i = 0; i < n; i++) {
        int curr = index[b[i] - 1];   // position of b[i] in the original array a

        // Guard‑clause: if curr is outside the current window, answer is 0
        if (curr < min || curr > max) {
            ans[i] = 0;
            continue;
        }

        // Inside the window – compute answer and move the window forward
        ans[i] = curr - min + 1;
        min = curr + 1;
    }
    return ans;
}

