/* -------------------------------------------------------------
 * Compute the product of the non‑zero decimal digits of `n`.
 * ------------------------------------------------------------- */
private static int productOfNonZeroDigits(int n) {
    int product = 1;
    while (n > 0) {
        int digit = n % 10;
        if (digit > 0) {
            product *= digit;
        }
        n /= 10;
    }
    return product;
}

