/* Returns the product of the non‑zero digits of n */
private static int digitProduct(int n) {
    int product = 1;
    while (n > 0) {
        int d = n % 10;
        if (d != 0) {
            product *= d;          // guard clause: skip zeros
        }
        n /= 10;
    }
    return product;
}

